-- PROD_SCHEMA_GROUND_TRUTH.sql
-- Dumped from remote D1 open-energy-db on 2026-07-14 (read-only sqlite_master dump).
-- REBUILD_PLAN.md risk R3: the real prod schema, captured BEFORE any v2 code was written.
-- 945 tables, 2309 indexes, 0 other objects.

CREATE TABLE _cf_KV (
        key TEXT PRIMARY KEY,
        value BLOB
      ) WITHOUT ROWID;

CREATE TABLE action_queue (
  id TEXT PRIMARY KEY,
  type TEXT NOT NULL,
  priority TEXT DEFAULT 'normal' CHECK (priority IN ('low','normal','high','urgent')),
  actor_id TEXT REFERENCES participants(id),
  assignee_id TEXT REFERENCES participants(id),
  entity_type TEXT,
  entity_id TEXT,
  title TEXT NOT NULL,
  description TEXT,
  status TEXT DEFAULT 'pending' CHECK (status IN ('pending','in_progress','completed','cancelled')),
  due_date TEXT,
  completed_at TEXT,
  completed_by TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE activity_dependencies (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL,
  predecessor_id TEXT NOT NULL,
  successor_id TEXT NOT NULL,
  link_type TEXT NOT NULL CHECK (link_type IN ('FS','SS','FF','SF')),
  lag_days REAL NOT NULL DEFAULT 0,
  created_at TEXT NOT NULL,
  UNIQUE(predecessor_id, successor_id)
);

CREATE TABLE admin_billing_runs (
  id              TEXT PRIMARY KEY,
  run_type        TEXT NOT NULL CHECK (run_type IN ('monthly','adhoc','correction')),
  period_start    TEXT NOT NULL,
  period_end      TEXT NOT NULL,
  status          TEXT NOT NULL DEFAULT 'pending'
    CHECK (status IN ('pending','running','completed','failed','partially_completed')),
  tenants_billed  INTEGER NOT NULL DEFAULT 0,
  total_zar       REAL NOT NULL DEFAULT 0,
  started_at      TEXT,
  completed_at    TEXT,
  error_message   TEXT,
  initiated_by    TEXT,
  created_at      TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE admin_feature_flag_overrides (
  id              TEXT PRIMARY KEY,
  flag_key        TEXT NOT NULL,
  scope_type      TEXT NOT NULL CHECK (scope_type IN ('global','tenant','user')),
  scope_id        TEXT,
  previous_value  TEXT,
  new_value       TEXT NOT NULL,
  actor_id        TEXT NOT NULL,
  reason          TEXT,
  occurred_at     TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE admin_tenant_lifecycle_events (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT NOT NULL,
  event_type      TEXT NOT NULL CHECK (event_type IN (
    'provisioned','activated','plan_changed','kyc_approved','kyc_rejected',
    'suspended','reactivated','offboarded','data_exported','data_erased'
  )),
  actor_id        TEXT NOT NULL,
  occurred_at     TEXT NOT NULL DEFAULT (datetime('now')),
  reason          TEXT,
  payload_json    TEXT
);

CREATE TABLE advisory_locks (
  lock_key TEXT PRIMARY KEY,             -- 'contract_sign:<id>' or 'trade_match:<o1>:<o2>'
  holder_id TEXT NOT NULL,               -- participant_id of lock holder
  acquired_at TEXT NOT NULL DEFAULT (datetime('now')),
  expires_at TEXT NOT NULL,              -- holder must heartbeat or release before this
  context TEXT                           -- optional JSON for debugging
);

CREATE TABLE ai_classification_logs (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL,
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  input_text          TEXT NOT NULL,                 -- the line item / invoice description
  input_amount        REAL,
  input_unit          TEXT,
  -- Model output
  model_id            TEXT,                          -- e.g. '@cf/meta/llama-3.1-8b-instruct'
  suggested_activity_code TEXT,
  suggested_scope     INTEGER,
  suggested_scope3_category INTEGER,
  confidence          REAL,
  reasoning           TEXT,
  alternatives_json   TEXT,                          -- JSON array of top-3 alternatives
  -- User outcome
  user_accepted       INTEGER DEFAULT 0,             -- 0/1
  user_override_code  TEXT,
  resolved_at         TEXT,
  created_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ai_decisions (
  id              TEXT PRIMARY KEY,
  surface         TEXT NOT NULL,        -- 'rejection_explainer' | 'order_size_suggest' | 'risk_narrative' | ...
  participant_id  TEXT,
  intent          TEXT,
  prompt_hash     TEXT,
  prompt_summary  TEXT,
  response_text   TEXT,
  response_json   TEXT,
  model           TEXT,
  fallback        INTEGER NOT NULL DEFAULT 0,
  accepted        INTEGER,              -- NULL = not yet acted on, 0 = dismissed, 1 = accepted
  related_entity_type TEXT,
  related_entity_id   TEXT,
  created_at      TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE ai_lender_advice (
  id                   TEXT PRIMARY KEY,
  covenant_test_id     TEXT NOT NULL,
  covenant_id          TEXT NOT NULL,
  lender_participant_id TEXT,
  recommendation       TEXT NOT NULL CHECK (recommendation IN (
    'cure_plan','waiver','amendment','acceleration','workout','no_action'
  )),
  rationale            TEXT NOT NULL,
  confidence           REAL,
  source               TEXT NOT NULL DEFAULT 'deterministic'
    CHECK (source IN ('deterministic','ai_gateway','fallback')),
  accepted_at          TEXT,
  accepted_by          TEXT,
  dismissed_at         TEXT,
  created_at           TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE ai_settlement_run_failures (
  id                   TEXT PRIMARY KEY,
  run_id               TEXT,                     -- settlement_runs.id
  dlq_id               TEXT,                     -- settlement_dlq.id (if reachable)
  failure_code         TEXT,                     -- e.g. 'metering_gap', 'tariff_validation_failed'
  failure_message      TEXT,
  explanation          TEXT NOT NULL,
  suggested_action     TEXT,
  confidence           REAL,                     -- 0..1
  source               TEXT NOT NULL DEFAULT 'deterministic'
    CHECK (source IN ('deterministic','ai_gateway','fallback')),
  accepted_at          TEXT,
  accepted_by          TEXT,
  dismissed_at         TEXT,
  created_at           TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE ai_trade_amendments (
  id                   TEXT PRIMARY KEY,
  participant_id       TEXT NOT NULL,
  order_id             TEXT NOT NULL,              -- target order
  suggestion_kind      TEXT NOT NULL CHECK (suggestion_kind IN (
    're_price','resize','cancel','convert_to_ioc','split'
  )),
  current_state        TEXT NOT NULL,              -- JSON snapshot of order at time of suggestion
  suggested_state      TEXT NOT NULL,              -- JSON of suggested fields
  rationale            TEXT NOT NULL,              -- single-line "why"
  confidence           REAL,
  source               TEXT NOT NULL DEFAULT 'deterministic'
    CHECK (source IN ('deterministic','ai_gateway','fallback')),
  accepted_at          TEXT,
  accepted_by          TEXT,
  dismissed_at         TEXT,
  created_at           TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE ancillary_service_awards (
  id TEXT PRIMARY KEY,
  tender_id TEXT NOT NULL REFERENCES ancillary_service_tenders(id),
  bid_id TEXT NOT NULL REFERENCES ancillary_service_bids(id),
  awarded_capacity_mw REAL NOT NULL,
  clearing_price_zar_mw_h REAL NOT NULL,
  awarded_at TEXT NOT NULL DEFAULT (datetime('now')),
  awarded_by TEXT REFERENCES participants(id)
);

CREATE TABLE ancillary_service_bids (
  id TEXT PRIMARY KEY,
  tender_id TEXT NOT NULL REFERENCES ancillary_service_tenders(id),
  participant_id TEXT NOT NULL REFERENCES participants(id),
  capacity_offered_mw REAL NOT NULL,
  price_zar_mw_h REAL NOT NULL,
  site_id TEXT,
  submitted_at TEXT NOT NULL DEFAULT (datetime('now')),
  status TEXT NOT NULL DEFAULT 'submitted' CHECK (status IN (
    'submitted','withdrawn','rejected','awarded_full','awarded_partial','lost'
  )),
  awarded_capacity_mw REAL,
  awarded_price_zar_mw_h REAL
);

CREATE TABLE ancillary_service_deliveries (
  id TEXT PRIMARY KEY,
  award_id TEXT NOT NULL REFERENCES ancillary_service_awards(id),
  period_start TEXT NOT NULL,
  period_end TEXT NOT NULL,
  contracted_mw REAL NOT NULL,
  delivered_mw REAL,
  availability_percentage REAL,
  penalty_zar REAL,
  settled BOOLEAN DEFAULT 0,
  settled_at TEXT
);

CREATE TABLE ancillary_service_products (
  id TEXT PRIMARY KEY,
  product_code TEXT UNIQUE NOT NULL,
  product_name TEXT NOT NULL,
  service_type TEXT NOT NULL CHECK (service_type IN (
    'fcr','afrr','mfrr','reserve_10min','reserve_ramp','black_start','reactive_power','voltage_support'
  )),
  description TEXT,
  min_capacity_mw REAL DEFAULT 0,
  product_duration_hours REAL,      -- block length
  enabled BOOLEAN DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE ancillary_service_tenders (
  id TEXT PRIMARY KEY,
  tender_number TEXT UNIQUE NOT NULL,
  product_id TEXT NOT NULL REFERENCES ancillary_service_products(id),
  delivery_window_start TEXT NOT NULL,
  delivery_window_end TEXT NOT NULL,
  capacity_required_mw REAL NOT NULL,
  ceiling_price_zar_mw_h REAL,
  gate_closure_at TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'open' CHECK (status IN (
    'draft','open','closed','evaluated','awarded','cancelled'
  )),
  notes TEXT,
  published_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE assurance_engagements (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL REFERENCES participants(id),
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  reporting_year      INTEGER NOT NULL,
  scope               TEXT NOT NULL,                 -- 'scope1','scope2_location','scope2_market','scope3_all','scope3_cat1','financed_emissions'
  auditor_name        TEXT,                          -- e.g. 'KPMG','Deloitte','EY','PwC','SGS','Bureau Veritas'
  auditor_email       TEXT,
  assurance_standard  TEXT NOT NULL CHECK (assurance_standard IN ('ISAE_3000','ISAE_3410','AA1000AS','ISO_14064_3','custom')),
  assurance_level     TEXT NOT NULL CHECK (assurance_level IN ('limited','reasonable')),
  engagement_status   TEXT DEFAULT 'planned'
                       CHECK (engagement_status IN ('planned','in_progress','field_work','draft_opinion','final_opinion','withdrawn')),
  opinion             TEXT,                          -- 'clean','qualified','adverse','disclaimer'
  opinion_letter_r2_key TEXT,
  opinion_date        TEXT,
  scope_emissions_assured REAL,
  notes               TEXT,
  created_at          TEXT DEFAULT (datetime('now')),
  updated_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE assurance_evidence (
  id                  TEXT PRIMARY KEY,
  engagement_id       TEXT NOT NULL REFERENCES assurance_engagements(id),
  artefact_type       TEXT NOT NULL,                 -- 'invoice','meter_read','contract','methodology','calculation_workbook','transaction_export'
  description         TEXT,
  source_table        TEXT,
  source_id           TEXT,
  r2_key              TEXT NOT NULL,
  uploaded_by         TEXT,
  uploaded_at         TEXT DEFAULT (datetime('now')),
  hash_sha256         TEXT
);

CREATE TABLE assurance_findings (
  id                  TEXT PRIMARY KEY,
  engagement_id       TEXT NOT NULL REFERENCES assurance_engagements(id),
  finding_ref         TEXT,                          -- auditor's reference code
  severity            TEXT CHECK (severity IN ('observation','minor','significant','material','critical')),
  category            TEXT,                          -- 'data_quality','methodology','boundary','factor_age','restatement'
  title               TEXT NOT NULL,
  description         TEXT,
  affected_table      TEXT,                          -- e.g. 'esg_activity_transactions'
  affected_id         TEXT,
  management_response TEXT,
  status              TEXT DEFAULT 'open'
                       CHECK (status IN ('open','in_remediation','remediated','accepted','rejected')),
  due_date            TEXT,
  resolved_at         TEXT,
  resolved_by         TEXT,
  created_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE audit_chain (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  sequence_no     INTEGER NOT NULL,                  -- monotonically increasing within tenant
  entity_table    TEXT NOT NULL,
  entity_id       TEXT NOT NULL,
  operation       TEXT NOT NULL CHECK (operation IN ('INSERT','UPDATE','DELETE','RESTATE','VOID')),
  actor_id        TEXT,
  payload_json    TEXT NOT NULL,                     -- canonical-JSON serialisation of the record
  prev_hash       TEXT,                               -- SHA-256 hex of prior chain entry
  this_hash       TEXT NOT NULL,                     -- SHA-256(prev_hash || payload_json)
  created_at      TEXT DEFAULT (datetime('now'))
, domain TEXT);

CREATE TABLE audit_chain_anchors (
  anchor_date   TEXT NOT NULL,           -- YYYY-MM-DD (UTC)
  anchor_hour   TEXT NOT NULL,           -- HH (UTC, 00-23)
  r2_key        TEXT NOT NULL,           -- object-lock bucket path written
  chain_count   INTEGER NOT NULL,        -- number of chains snapshotted
  head_count    INTEGER NOT NULL,        -- total rows across snapshotted chains
  anchor_hash   TEXT NOT NULL,           -- SHA256 over the snapshot envelope
  anchored_at   TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (anchor_date, anchor_hour)
);

CREATE TABLE audit_chain_state (
  entity_type     TEXT PRIMARY KEY,
  head_hash       TEXT NOT NULL,
  head_sequence   INTEGER NOT NULL,
  updated_at      TEXT NOT NULL DEFAULT (datetime('now')),
  last_verified_at TEXT,
  last_verified_seq INTEGER
);

CREATE TABLE audit_events (
  id            TEXT PRIMARY KEY,
  entity_type   TEXT NOT NULL,         -- 'trading' | 'settlement' | …
  entity_id     TEXT,                  -- the affected row's id (nullable for bulk events)
  event_type    TEXT NOT NULL,         -- 'order.placed' | 'order.amended' | …
  actor_id      TEXT NOT NULL,         -- participant id that caused the event
  payload_json  TEXT NOT NULL,         -- canonical JSON (sorted keys)
  prev_hash     TEXT NOT NULL,         -- 64-char hex; '00…' for sequence_no=1
  content_hash  TEXT NOT NULL,         -- SHA256(prev_hash || payload_json)
  sequence_no   INTEGER NOT NULL,      -- 1-indexed, monotonic per entity_type
  created_at    TEXT NOT NULL DEFAULT (datetime('now')), preimage_version INTEGER NOT NULL DEFAULT 1,
  UNIQUE (entity_type, sequence_no)
);

CREATE TABLE audit_exports (
  id              TEXT PRIMARY KEY,
  entity_type     TEXT NOT NULL,
  from_ts         TEXT NOT NULL,
  to_ts           TEXT NOT NULL,
  row_count       INTEGER NOT NULL,
  csv_r2_key      TEXT NOT NULL,        -- the data file in open-energy-vault
  manifest_r2_key TEXT NOT NULL,        -- the SHA-256 manifest + chain head
  chain_head_hash TEXT NOT NULL,        -- the audit_chain_state head at export time
  generated_by    TEXT NOT NULL,        -- actor_id
  generated_at    TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE audit_log_archives (
  id TEXT PRIMARY KEY,
  day_bucket TEXT NOT NULL,            -- YYYY-MM-DD
  r2_key TEXT NOT NULL,
  row_count INTEGER,
  bytes_compressed INTEGER,
  sha256 TEXT,
  earliest_created_at TEXT,
  latest_created_at TEXT,
  archived_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE audit_logs (
  id TEXT PRIMARY KEY,
  actor_id TEXT REFERENCES participants(id),
  action TEXT NOT NULL,
  entity_type TEXT NOT NULL,
  entity_id TEXT NOT NULL,
  changes TEXT,
  ip_address TEXT,
  user_agent TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE audit_recon_breaks (
  id            TEXT PRIMARY KEY,
  run_id        TEXT NOT NULL,
  break_type    TEXT NOT NULL,           -- 'missing_in_ours' | 'missing_in_theirs' | 'field_mismatch'
  external_ref  TEXT,
  our_value     TEXT,                    -- canonical JSON of our row
  their_value   TEXT,                    -- canonical JSON of their row
  field         TEXT,                    -- which field differs (when break_type='field_mismatch')
  resolution    TEXT,                    -- 'open' | 'investigating' | 'accepted_ours' | 'accepted_theirs' | 'cancelled'
  resolution_notes TEXT,
  resolved_at   TEXT,
  resolved_by   TEXT,
  FOREIGN KEY (run_id) REFERENCES audit_recon_runs(id)
);

CREATE TABLE audit_recon_runs (
  id              TEXT PRIMARY KEY,
  entity_type     TEXT NOT NULL,
  source          TEXT NOT NULL,        -- 'counterparty' | 'verra' | 'eskom' | …
  uploaded_csv_r2_key TEXT NOT NULL,
  row_count       INTEGER NOT NULL,
  matched_count   INTEGER NOT NULL DEFAULT 0,
  break_count     INTEGER NOT NULL DEFAULT 0,
  status          TEXT NOT NULL DEFAULT 'running'
                  CHECK (status IN ('running','complete','failed')),
  started_at      TEXT NOT NULL DEFAULT (datetime('now')),
  finished_at     TEXT,
  started_by      TEXT NOT NULL
);

CREATE TABLE backup_log (
  id            TEXT PRIMARY KEY,
  key           TEXT NOT NULL,
  size_bytes    INTEGER NOT NULL,
  total_rows    INTEGER NOT NULL,
  table_count   INTEGER NOT NULL,
  generated_at  TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE baseline_activities (
  baseline_id TEXT NOT NULL,
  activity_id TEXT NOT NULL,
  planned_start TEXT,
  planned_finish TEXT,
  duration_days REAL,
  PRIMARY KEY(baseline_id, activity_id)
);

CREATE TABLE briefing_reports (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  report_date TEXT NOT NULL,
  market_summary TEXT,
  priorities TEXT,
  portfolio_positions TEXT,
  intelligence_summary TEXT,
  generated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE brp_period_nominations (
  brp_participant_id TEXT NOT NULL REFERENCES participants(id),
  period_start TEXT NOT NULL,               
  period_end TEXT NOT NULL,
  scheduled_mwh REAL NOT NULL,
  actual_mwh REAL,                           
  source TEXT DEFAULT 'brp' CHECK (source IN ('brp','metering','sro','backfill')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (brp_participant_id, period_start)
);

CREATE TABLE business_day_calendar (
  date           TEXT NOT NULL,                  -- YYYY-MM-DD
  market_zone    TEXT NOT NULL DEFAULT 'ZA',
  is_business_day INTEGER NOT NULL DEFAULT 1     -- 0 = closed
    CHECK (is_business_day IN (0, 1)),
  holiday_name   TEXT,
  observed       INTEGER NOT NULL DEFAULT 0      -- 1 if a moved-to-monday observance
    CHECK (observed IN (0, 1)),
  notes          TEXT,
  PRIMARY KEY (date, market_zone)
);

CREATE TABLE calendar_exceptions (
  id TEXT PRIMARY KEY,
  calendar_id TEXT NOT NULL,
  exception_date TEXT NOT NULL,
  hours REAL NOT NULL,
  reason TEXT,
  UNIQUE(calendar_id, exception_date)
);

CREATE TABLE carbon_fund_capital_calls (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  call_no         INTEGER NOT NULL,
  call_date       TEXT NOT NULL,
  due_date        TEXT,
  total_called_zar REAL NOT NULL,
  purpose         TEXT,
  status          TEXT DEFAULT 'issued' CHECK (status IN ('issued','funded','partial','overdue','cancelled')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE carbon_fund_cobenefits (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,                              
  sdg_target      TEXT NOT NULL,                     
  metric_name     TEXT,                              
  baseline_value  REAL,
  current_value   REAL,
  target_value    REAL,
  unit            TEXT,
  reporting_period TEXT,
  verified_by     TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE carbon_fund_fees (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  fee_type        TEXT NOT NULL CHECK (fee_type IN ('management','performance','admin','transaction','side_pocket')),
  reporting_period TEXT NOT NULL,
  basis           TEXT,                              
  base_zar        REAL,
  rate_pct        REAL,
  fee_zar         REAL NOT NULL,
  status          TEXT DEFAULT 'accrued' CHECK (status IN ('accrued','invoiced','paid','disputed','waived')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE carbon_fund_lps (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),  
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  lp_name         TEXT NOT NULL,
  lp_jurisdiction TEXT,
  commitment_zar  REAL NOT NULL,
  drawn_zar       REAL DEFAULT 0,
  distributed_zar REAL DEFAULT 0,
  remaining_commitment_zar REAL,
  share_class     TEXT,                              
  side_letter     INTEGER DEFAULT 0,
  status          TEXT DEFAULT 'active' CHECK (status IN ('committed','active','defaulted','redeemed','transferred')),
  joined_at       TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE carbon_fund_nav (
  id TEXT PRIMARY KEY,
  fund_id TEXT NOT NULL REFERENCES participants(id),
  nav_date TEXT NOT NULL,
  total_units REAL NOT NULL,
  nav_per_unit REAL NOT NULL,
  assets_under_management REAL,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE carbon_fund_nav_history (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  as_of_date      TEXT NOT NULL,
  gross_asset_value_zar REAL NOT NULL,
  cash_zar        REAL DEFAULT 0,
  liabilities_zar REAL DEFAULT 0,
  net_asset_value_zar REAL NOT NULL,
  nav_per_unit_zar REAL,
  units_outstanding REAL,
  ytd_return_pct  REAL,
  itd_irr_pct     REAL,                              
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now')),
  UNIQUE (participant_id, as_of_date)
);

CREATE TABLE carbon_fund_pipeline (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_lead    TEXT NOT NULL,
  technology      TEXT,
  expected_tco2e_yr REAL,
  ticket_size_zar REAL,
  developer_name  TEXT,
  stage           TEXT DEFAULT 'sourced' CHECK (stage IN ('sourced','screening','term_sheet','dd','approval','signed','withdrawn','rejected')),
  source          TEXT,
  owner_user_id   TEXT,
  next_action     TEXT,
  next_action_due TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE carbon_fund_term_sheets (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  pipeline_id     TEXT,
  developer_name  TEXT,
  version         TEXT,
  total_tco2e     REAL,
  price_zar_per_tco2e REAL,
  prepayment_zar  REAL,
  conditions_precedent TEXT,
  document_r2_key TEXT,
  status          TEXT DEFAULT 'drafting' CHECK (status IN ('drafting','sent','negotiating','signed','expired','withdrawn')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE carbon_holdings (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  project_id TEXT NOT NULL REFERENCES carbon_projects(id),
  credit_type TEXT NOT NULL,
  quantity REAL NOT NULL,
  vintage_year INTEGER,
  acquisition_date TEXT,
  cost_basis REAL,
  status TEXT DEFAULT 'available' CHECK (status IN ('available','reserved','retired')),
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE carbon_mrv_workflow (
  id                  TEXT PRIMARY KEY,
  project_id          TEXT NOT NULL,
  participant_id      TEXT NOT NULL,
  period_start        TEXT NOT NULL,
  period_end          TEXT NOT NULL,
  status              TEXT NOT NULL DEFAULT 'draft'
    CHECK (status IN ('draft','submitted','under_verification','verified','rejected','published')),
  submitted_at        TEXT,
  submitted_by        TEXT,
  verified_at         TEXT,
  verified_by         TEXT,
  verifier_org        TEXT,
  reduction_tco2e     REAL,
  evidence_r2_key     TEXT,
  rejection_reason    TEXT,
  notes               TEXT,
  created_at          TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE carbon_options (
  id TEXT PRIMARY KEY,
  seller_id TEXT NOT NULL REFERENCES participants(id),
  project_id TEXT NOT NULL REFERENCES carbon_projects(id),
  option_type TEXT NOT NULL CHECK (option_type IN ('call','put')),
  strike_price REAL NOT NULL,
  volume_tco2 REAL NOT NULL,
  expiry_date TEXT NOT NULL,
  premium_per_tco2 REAL,
  status TEXT DEFAULT 'open' CHECK (status IN ('open','exercised','expired','cancelled')),
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE carbon_projects (
  id TEXT PRIMARY KEY,
  project_name TEXT NOT NULL,
  project_number TEXT UNIQUE NOT NULL,
  project_type TEXT NOT NULL,
  methodology TEXT NOT NULL,
  host_country TEXT NOT NULL,
  developer_id TEXT NOT NULL REFERENCES participants(id),
  credits_issued REAL DEFAULT 0,
  credits_available REAL DEFAULT 0,
  credits_retired REAL DEFAULT 0,
  status TEXT DEFAULT 'pending' CHECK (status IN ('pending','active','verified','suspended','expired')),
  registration_date TEXT,
  verification_date TEXT,
  expiry_date TEXT,
  registry_link TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE carbon_registries (
  id TEXT PRIMARY KEY,
  registry_code TEXT UNIQUE NOT NULL,
  registry_name TEXT NOT NULL,
  registry_type TEXT NOT NULL CHECK (registry_type IN (
    'voluntary','compliance','domestic'
  )),
  api_base_url TEXT,
  webhook_url TEXT,
  accepts_methodologies_json TEXT,
  sa_carbon_tax_eligible BOOLEAN DEFAULT 0,  -- per DFFE list 1
  enabled BOOLEAN DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE carbon_registry_sync_log (
  id TEXT PRIMARY KEY,
  registry_id TEXT NOT NULL REFERENCES carbon_registries(id),
  sync_type TEXT NOT NULL,                 -- 'project_metadata','credit_issuance','retirement_push'
  external_ref TEXT,
  status TEXT NOT NULL CHECK (status IN ('pending','success','failed','retrying')),
  request_body TEXT,
  response_body TEXT,
  error_message TEXT,
  attempt INTEGER DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE carbon_retirement_certificates (
  id                      TEXT PRIMARY KEY,
  retirement_id           TEXT NOT NULL,
  participant_id          TEXT NOT NULL,
  beneficiary_name        TEXT,
  beneficiary_email       TEXT,
  retired_volume_tco2e    REAL NOT NULL,
  certificate_number      TEXT UNIQUE NOT NULL,
  status                  TEXT NOT NULL DEFAULT 'queued'
    CHECK (status IN ('queued','issued','delivered','revoked')),
  issued_at               TEXT,
  delivered_at            TEXT,
  delivery_method         TEXT,
  pdf_r2_key              TEXT,
  notes                   TEXT,
  created_at              TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE carbon_retirements (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  project_id TEXT NOT NULL REFERENCES carbon_projects(id),
  quantity REAL NOT NULL,
  retirement_reason TEXT,
  certificate_number TEXT,
  beneficiary_name TEXT,
  beneficiary_country TEXT,
  retirement_date TEXT,
  created_by TEXT NOT NULL REFERENCES participants(id),
  created_at TEXT DEFAULT (datetime('now'))
, chain_status TEXT NOT NULL DEFAULT 'requested', scope TEXT NOT NULL DEFAULT 'voluntary', sla_deadline_at TEXT, last_sla_breach_at TEXT, escalation_level INTEGER NOT NULL DEFAULT 0, validation_notes TEXT, rejection_reason TEXT, certificate_hash TEXT);

CREATE TABLE carbon_tax_offset_claims (
  id TEXT PRIMARY KEY,
  taxpayer_participant_id TEXT NOT NULL REFERENCES participants(id),
  tax_year INTEGER NOT NULL,
  gross_tax_liability_zar REAL NOT NULL,
  offset_limit_pct REAL NOT NULL,         -- 5 or 10 per industry
  offset_limit_zar REAL NOT NULL,
  credits_applied_tco2e REAL,
  offset_value_zar REAL,                  -- credits × prevailing CT rate
  net_tax_liability_zar REAL,
  sars_reference TEXT,
  status TEXT DEFAULT 'draft' CHECK (status IN ('draft','submitted','accepted','rejected','adjusted')),
  submitted_at TEXT,
  created_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE carbon_tax_offset_retirements (
  id TEXT PRIMARY KEY,
  claim_id TEXT NOT NULL REFERENCES carbon_tax_offset_claims(id) ON DELETE CASCADE,
  retirement_id TEXT NOT NULL REFERENCES carbon_retirements(id),
  credits_applied_tco2e REAL NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE (retirement_id)                   -- one retirement → one claim, by law
);

CREATE TABLE carbon_trades (
  id TEXT PRIMARY KEY,
  buyer_id TEXT NOT NULL REFERENCES participants(id),
  seller_id TEXT NOT NULL REFERENCES participants(id),
  project_id TEXT NOT NULL REFERENCES carbon_projects(id),
  credit_type TEXT NOT NULL CHECK (credit_type IN ('CER','VER','EUA','SAEA')),
  volume_tco2 REAL NOT NULL,
  price_per_tco2 REAL NOT NULL,
  currency TEXT DEFAULT 'ZAR',
  status TEXT DEFAULT 'pending' CHECK (status IN ('matched','settled','cancelled')),
  certificate_reference TEXT,
  vintage_year INTEGER,
  settlement_id TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE carbon_vintage_workflow (
  id                    TEXT PRIMARY KEY,
  vintage_id            TEXT NOT NULL,
  participant_id        TEXT NOT NULL,
  current_stage         TEXT NOT NULL DEFAULT 'issued'
    CHECK (current_stage IN ('issued','validated','listed','traded','retired_partial','retired_full','expired')),
  validated_at          TEXT,
  validated_by          TEXT,
  listed_at             TEXT,
  retired_volume_tco2e  REAL NOT NULL DEFAULT 0,
  outstanding_tco2e     REAL NOT NULL DEFAULT 0,
  notes                 TEXT,
  created_at            TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at            TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE cascade_dlq (
  id TEXT PRIMARY KEY,
  event TEXT NOT NULL,                   -- e.g. 'contract.signed'
  entity_type TEXT NOT NULL,
  entity_id TEXT NOT NULL,
  actor_id TEXT,                         -- audit carry-through
  payload TEXT NOT NULL,                 -- JSON of the CascadeContext.data
  stage TEXT NOT NULL,                   -- 'audit' | 'notifications' | 'webhooks' | 'special'
  error_message TEXT NOT NULL,
  error_stack TEXT,
  attempt_count INTEGER NOT NULL DEFAULT 1,
  first_seen_at TEXT NOT NULL DEFAULT (datetime('now')),
  last_attempt_at TEXT NOT NULL DEFAULT (datetime('now')),
  next_attempt_at TEXT,                  -- null if not scheduled for retry
  status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'resolved', 'abandoned')),
  resolved_at TEXT,
  resolved_by TEXT,                      -- participant_id (support operator) or 'auto_retry'
  resolution_note TEXT
);

CREATE TABLE cdr_buffer_pool (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT NOT NULL REFERENCES cdr_projects(id),
  total_contributed_tco2e REAL NOT NULL,
  reserved_tco2e  REAL DEFAULT 0,
  released_tco2e  REAL DEFAULT 0,
  buffer_pct      REAL NOT NULL,                     -- typically 10-30% of project lifetime credits
  release_schedule TEXT,                              -- JSON: when buffer releases back
  reason          TEXT,                              -- 'reversal_risk','permanence_risk','baseline_uncertainty'
  status          TEXT DEFAULT 'active' CHECK (status IN ('active','released','liquidated','retired_for_reversal')),
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE cdr_client_attribution (
  id              TEXT PRIMARY KEY,
  fund_participant_id TEXT NOT NULL REFERENCES participants(id),  -- the carbon fund
  client_participant_id TEXT,                                       -- internal client; nullable for external
  client_name     TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  retirement_id   TEXT NOT NULL REFERENCES cdr_retirements(id),
  attributed_tco2e REAL NOT NULL,
  reporting_year  INTEGER NOT NULL,
  proof_of_offset_url TEXT,                          -- public attestation URL
  share_token     TEXT,                              -- client portal token
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE cdr_due_diligence (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT NOT NULL REFERENCES cdr_projects(id),
  dd_step         TEXT NOT NULL CHECK (dd_step IN (
                    'technical_review','methodology_review','additionality_test',
                    'leakage_assessment','permanence_assessment','baseline_validation',
                    'site_visit','financial_review','legal_review','co_benefits',
                    'mrv_review','registry_check'
                  )),
  reviewer        TEXT,
  outcome         TEXT CHECK (outcome IN ('pass','conditional','fail','withdrawn')),
  conditions      TEXT,
  rating_score    INTEGER CHECK (rating_score BETWEEN 1 AND 10),
  evidence_r2_key TEXT,
  completed_at    TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE cdr_offtakes (
  id                  TEXT PRIMARY KEY,
  buyer_id            TEXT NOT NULL REFERENCES participants(id),
  project_id          TEXT NOT NULL REFERENCES cdr_projects(id),
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  total_tco2e         REAL NOT NULL,
  delivered_tco2e     REAL DEFAULT 0,
  retired_tco2e       REAL DEFAULT 0,
  price_zar_per_tco2e REAL NOT NULL,
  total_zar           REAL,
  start_vintage_year  INTEGER NOT NULL,
  end_vintage_year    INTEGER,
  status              TEXT DEFAULT 'contracted'
                       CHECK (status IN ('drafted','contracted','active','complete','cancelled','disputed')),
  payment_schedule    TEXT,                              -- JSON
  delivery_schedule   TEXT,                              -- JSON
  evidence_r2_key     TEXT,
  signed_at           TEXT,
  created_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE cdr_projects (
  id                  TEXT PRIMARY KEY,
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  developer_id        TEXT REFERENCES participants(id),
  project_name        TEXT NOT NULL,
  technology          TEXT NOT NULL CHECK (technology IN (
                        'afforestation','reforestation','soil_carbon','biochar',
                        'enhanced_weathering','direct_air_capture','ocean_alkalinity',
                        'beccs','blue_carbon','peatland','agroforestry','rock_dust',
                        'mineralisation','mceor','wood_burial','other'
                      )),
  category            TEXT NOT NULL CHECK (category IN ('nature','engineered','hybrid')),
  permanence_years    INTEGER,                          -- expected storage horizon
  registry            TEXT,                              -- 'puro_earth','verra_vcs','isometric','carbonplan','custom'
  registry_id         TEXT,
  host_country        TEXT,
  description         TEXT,
  expected_tco2e_yr   REAL,
  total_tco2e_committed REAL,
  price_zar_per_tco2e REAL,
  vintage_first_year  INTEGER,
  status              TEXT DEFAULT 'listed'
                       CHECK (status IN ('listed','contracted','delivering','delivered','retired','withdrawn')),
  third_party_audit   TEXT,
  evidence_r2_key     TEXT,
  cobenefits          TEXT,                              -- JSON: biodiversity, community, water
  risk_rating         TEXT,                              -- 'high','medium','low'
  created_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE cdr_retirements (
  id              TEXT PRIMARY KEY,
  offtake_id      TEXT NOT NULL REFERENCES cdr_offtakes(id),
  participant_id  TEXT NOT NULL,
  tco2e_retired   REAL NOT NULL,
  vintage_year    INTEGER,
  reporting_year  INTEGER NOT NULL,
  serial_number   TEXT,
  beneficiary     TEXT,
  reason          TEXT,
  retired_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE cfe_hourly_generation (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  source_type     TEXT NOT NULL CHECK (source_type IN ('ppa','on_site','rec_unbundled','rec_hourly_certified','grid_clean')),
  source_ref      TEXT,                              -- contract / rec serial / project id
  technology      TEXT,                              -- 'solar','wind','battery'
  hour_utc        TEXT NOT NULL,
  generation_kwh  REAL NOT NULL,
  grid_zone       TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE cfe_hourly_load (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  site_id         TEXT,
  hour_utc        TEXT NOT NULL,                     -- ISO datetime truncated to hour
  load_kwh        REAL NOT NULL,
  grid_zone       TEXT,                              -- 'ZA-NPC','ZA-Western',… (for grid intensity lookup)
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE cfe_match_summary (
  participant_id          TEXT NOT NULL,
  tenant_id               TEXT DEFAULT 'default' NOT NULL,
  reporting_period_start  TEXT NOT NULL,
  reporting_period_end    TEXT NOT NULL,
  total_load_kwh          REAL,
  total_carbon_free_kwh   REAL,
  cfe_match_pct           REAL,                        -- carbon-free / total load
  hours_with_full_match   INTEGER,
  hours_with_zero_match   INTEGER,
  avg_grid_intensity_kg_kwh REAL,
  emissions_avoided_tco2e REAL,
  computed_at             TEXT DEFAULT (datetime('now')),
  PRIMARY KEY (participant_id, reporting_period_start, reporting_period_end, tenant_id)
);

CREATE TABLE chain_signatories (
  id TEXT PRIMARY KEY,
  entity_type TEXT NOT NULL,            -- the Meridian chain key (e.g. 'ppa_contract_chain')
  entity_id TEXT NOT NULL,              -- the chain row id
  participant_id TEXT NOT NULL REFERENCES participants(id),
  signatory_name TEXT,
  signatory_designation TEXT,
  signed INTEGER DEFAULT 0,
  signed_at TEXT,
  signature_r2_key TEXT,                -- vault artifact pointer (R2)
  document_hash_at_signing TEXT,        -- hash bound at the moment of signing
  tenant_id TEXT DEFAULT 'default',
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE clearing_disclosure_snapshots (
  id                              TEXT PRIMARY KEY,
  as_of_date                      TEXT NOT NULL,
  -- CPMI-IOSCO §6 (Margin)
  initial_margin_total_zar        REAL NOT NULL DEFAULT 0,
  variation_margin_total_zar      REAL NOT NULL DEFAULT 0,
  margin_coverage_pct             REAL NOT NULL DEFAULT 0,     -- IM / 99% VaR over lookback
  -- CPMI-IOSCO §7 (Liquidity)
  qualifying_liquid_resources_zar REAL NOT NULL DEFAULT 0,
  largest_member_exposure_zar     REAL NOT NULL DEFAULT 0,
  liquidity_coverage_ratio        REAL NOT NULL DEFAULT 0,     -- QLR / largest exposure
  -- CPMI-IOSCO §4 (Credit)
  default_fund_balance_zar        REAL NOT NULL DEFAULT 0,
  default_fund_required_zar       REAL NOT NULL DEFAULT 0,
  default_fund_coverage_ratio     REAL NOT NULL DEFAULT 0,     -- balance / required
  -- CPMI-IOSCO §15 (General business risk)
  ccp_capital_zar                 REAL NOT NULL DEFAULT 0,
  ccp_capital_skin_in_game_zar    REAL NOT NULL DEFAULT 0,     -- 25% of capital
  -- CPMI-IOSCO §17 (Operational risk)
  settlement_finality_pct         REAL NOT NULL DEFAULT 0,     -- settled / (settled + failed)
  failed_instruction_count        INTEGER NOT NULL DEFAULT 0,
  -- Member metrics
  active_member_count             INTEGER NOT NULL DEFAULT 0,
  -- Audit
  computed_by                     TEXT,
  computed_at                     TEXT NOT NULL DEFAULT (datetime('now')),
  -- Publishing flags
  published                       INTEGER NOT NULL DEFAULT 0,
  published_at                    TEXT,
  published_by                    TEXT
);

CREATE TABLE clearing_obligations (
  id              TEXT PRIMARY KEY,
  run_id          TEXT NOT NULL REFERENCES clearing_runs(id),
  participant_id  TEXT NOT NULL,
  counterparty_id TEXT,
  net_zar         REAL NOT NULL,
  direction       TEXT CHECK (direction IN ('pay','receive')),
  status          TEXT DEFAULT 'pending'
);

CREATE TABLE clearing_runs (
  id              TEXT PRIMARY KEY,
  trading_day     TEXT NOT NULL,
  shard_key       TEXT,
  status          TEXT DEFAULT 'running' CHECK (status IN ('running','complete','failed')),
  trades_in       INTEGER DEFAULT 0,
  obligations_out INTEGER DEFAULT 0,
  net_zar         REAL DEFAULT 0,
  created_by      TEXT,
  started_at      TEXT DEFAULT (datetime('now')),
  finished_at     TEXT
);

CREATE TABLE climate_maturity_assessments (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL,
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  reporting_year      INTEGER NOT NULL,
  -- Five maturity pillars, each scored 0..100
  measurement_score   REAL,        -- How completely they measure emissions
  governance_score    REAL,        -- Board oversight, climate policies
  target_score        REAL,        -- SBTi-aligned, net-zero
  action_score        REAL,        -- Reduction initiatives delivered
  disclosure_score    REAL,        -- CDP/TCFD/etc. submission quality
  overall_score       REAL,        -- weighted composite
  band                TEXT CHECK (band IN ('starter','beginner','intermediate','advanced','leader')),
  assessed_at         TEXT DEFAULT (datetime('now')),
  notes               TEXT
);

CREATE TABLE climate_scenarios (
  code            TEXT PRIMARY KEY,
  family          TEXT NOT NULL,   -- 'NGFS','IEA','IPCC','Watershed_custom'
  name            TEXT NOT NULL,
  category        TEXT NOT NULL,   -- 'orderly','disorderly','hot_house','too_little_too_late','net_zero'
  temperature_2100_c REAL,
  carbon_price_2030_usd REAL,
  carbon_price_2050_usd REAL,
  transition_risk TEXT,             -- 'low','medium','high','very_high'
  physical_risk   TEXT,             -- 'low','medium','high','very_high'
  description     TEXT,
  pathway_doc_url TEXT
);

CREATE TABLE collateral_accounts (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  account_type    TEXT DEFAULT 'cash' CHECK (account_type IN ('cash','letter_of_credit','bank_guarantee','tbills','other')),
  balance_zar     REAL NOT NULL DEFAULT 0,
  status          TEXT DEFAULT 'active' CHECK (status IN ('active','frozen','closed')),
  reference       TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now')),
  updated_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE collateral_movements (
  id              TEXT PRIMARY KEY,
  account_id      TEXT NOT NULL REFERENCES collateral_accounts(id),
  movement_type   TEXT NOT NULL CHECK (movement_type IN ('deposit','withdrawal','margin_call','release')),
  amount_zar      REAL NOT NULL,
  balance_after_zar REAL,
  reference       TEXT,
  created_by      TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE community_engagements (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  stakeholder_id TEXT REFERENCES community_stakeholders(id),
  engagement_type TEXT NOT NULL CHECK (engagement_type IN (
    'public_meeting','one_on_one','notice_issued','complaint_received','grievance','workshop','focus_group','site_visit','ceremony'
  )),
  engagement_date TEXT NOT NULL,
  attendees_count INTEGER,
  topic TEXT,
  outcome TEXT,
  commitments TEXT,
  follow_up_date TEXT,
  evidence_r2_key TEXT,
  logged_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE community_engagements_v2 (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,
  engagement_type TEXT NOT NULL CHECK (engagement_type IN (
                    'open_day','consultation','community_trust_meeting','grievance',
                    'cosi_funding','sed_funding','ed_funding','jobs_event','training_event'
                  )),
  engagement_date TEXT NOT NULL,
  location        TEXT,
  attendees       INTEGER,
  topic           TEXT,
  outcome         TEXT,
  grievance_severity TEXT CHECK (grievance_severity IN ('minor','significant','material')),
  grievance_status TEXT CHECK (grievance_status IN ('logged','investigating','resolved','escalated')),
  evidence_r2_key TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE community_stakeholders (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  stakeholder_name TEXT NOT NULL,
  stakeholder_type TEXT CHECK (stakeholder_type IN (
    'municipality','traditional_authority','community_trust','landowner','civic_org','union','ngo','school','clinic','other'
  )),
  contact_person TEXT,
  phone TEXT,
  email TEXT,
  notes TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE connection_queue (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),  -- the grid operator
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  applicant_name  TEXT NOT NULL,
  applicant_participant_id TEXT,
  application_no  TEXT,
  project_name    TEXT,
  capacity_mw     REAL NOT NULL,
  technology      TEXT,
  request_voltage_kv REAL,
  connection_point TEXT,
  grid_zone       TEXT,
  queue_position  INTEGER,
  request_date    TEXT NOT NULL,
  budget_quote_zar REAL,
  cua_signed_at   TEXT,                              -- Connection Use of System Agreement
  status          TEXT DEFAULT 'in_queue' CHECK (status IN (
                    'submitted','study_in_progress','budget_quote','cua_offer',
                    'cua_signed','in_construction','energised','withdrawn','rejected'
                  )),
  expected_energised TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE consumption_profiles (
  id TEXT PRIMARY KEY,
  delivery_point_id TEXT NOT NULL REFERENCES offtaker_delivery_points(id),
  profile_date TEXT NOT NULL,        -- YYYY-MM-DD
  half_hour_kwh_json TEXT,           -- 48-element JSON array
  total_kwh REAL,
  peak_kw REAL,
  peak_time TEXT,
  load_factor REAL,
  source TEXT DEFAULT 'meter',       -- 'meter','estimated','aggregated'
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE contract_documents (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  document_type TEXT NOT NULL CHECK (document_type IN (
    'loi','term_sheet','hoa','ppa_wheeling','ppa_btm','carbon_purchase',
    'carbon_option_isda','forward','epc','wheeling_agreement','offtake_agreement','nda'
  )),
  phase TEXT DEFAULT 'draft' CHECK (phase IN (
    'draft','loi','term_sheet','hoa','draft_agreement','legal_review',
    'statutory_check','execution','active','amended','terminated','expired'
  )),
  creator_id TEXT NOT NULL REFERENCES participants(id),
  counterparty_id TEXT NOT NULL REFERENCES participants(id),
  project_id TEXT,
  commercial_terms TEXT,
  r2_key TEXT,
  integrity_seal TEXT,
  template_id TEXT,
  version TEXT DEFAULT 'v1.0',
  tenant_id TEXT DEFAULT 'default',
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE contract_templates (
  id TEXT PRIMARY KEY,
  code TEXT UNIQUE NOT NULL,
  name TEXT NOT NULL,
  category TEXT NOT NULL CHECK (category IN (
    'commercial','financing','operations','grid','carbon','governance','preliminary'
  )),
  document_type TEXT NOT NULL,
  description TEXT,
  sa_law_references TEXT,
  jurisdiction TEXT NOT NULL DEFAULT 'South Africa',
  governing_law TEXT NOT NULL DEFAULT 'Laws of the Republic of South Africa',
  template_body TEXT NOT NULL,
  variables_json TEXT,
  version TEXT DEFAULT 'v1.0',
  published INTEGER DEFAULT 1,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE counterparty_data_requests (
  id                  TEXT PRIMARY KEY,
  requestor_id        TEXT NOT NULL REFERENCES participants(id),
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  counterparty_name   TEXT NOT NULL,
  counterparty_email  TEXT,
  share_token         TEXT NOT NULL UNIQUE,         -- url-safe random token
  reporting_year      INTEGER NOT NULL,
  scope_requested     TEXT NOT NULL,                -- 'scope1_only','scope1_and_2','all_scopes','custom'
  asset_class         TEXT,                          -- joins to pcaf_asset_classes if PCAF-driven
  exposure_zar        REAL,
  status              TEXT DEFAULT 'sent'
                       CHECK (status IN ('drafted','sent','viewed','submitted','accepted','rejected','expired')),
  sent_at             TEXT,
  expires_at          TEXT,
  reminder_count      INTEGER DEFAULT 0,
  notes               TEXT,
  created_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE counterparty_submissions (
  id                  TEXT PRIMARY KEY,
  request_id          TEXT NOT NULL REFERENCES counterparty_data_requests(id),
  submitter_email     TEXT,
  submitter_role      TEXT,                          -- 'cfo','sustainability_head','operations','other'
  revenue_zar         REAL,
  evic_zar            REAL,
  scope1_tco2e        REAL,
  scope2_tco2e        REAL,
  scope3_tco2e        REAL,
  reporting_standard  TEXT,                          -- 'GHG Protocol','ISO 14064','custom'
  assurance_provider  TEXT,
  assurance_level     TEXT,                          -- 'none','limited','reasonable'
  evidence_r2_key     TEXT,
  attestation         TEXT,                          -- text attestation by submitter
  ip_address          TEXT,
  user_agent          TEXT,
  submitted_at        TEXT DEFAULT (datetime('now'))
);

CREATE TABLE covenant_tests (
  id TEXT PRIMARY KEY,
  covenant_id TEXT NOT NULL REFERENCES covenants(id),
  test_period TEXT NOT NULL,           -- 'Q2-2026', '2026-04', etc
  test_date TEXT NOT NULL,
  measured_value REAL,
  measured_value_text TEXT,            -- for non-numeric covenants
  result TEXT NOT NULL CHECK (result IN ('pass','warn','breach','not_tested','waived')),
  evidence_r2_key TEXT,
  narrative TEXT,
  waiver_id TEXT REFERENCES covenant_waivers(id),
  tested_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE covenant_waivers (
  id TEXT PRIMARY KEY,
  covenant_id TEXT NOT NULL REFERENCES covenants(id),
  requested_by TEXT REFERENCES participants(id),
  reason TEXT NOT NULL,
  requested_until TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'requested' CHECK (status IN (
    'requested','reviewing','granted','rejected','expired'
  )),
  granted_by TEXT REFERENCES participants(id),
  granted_at TEXT,
  conditions TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE covenants (
  id TEXT PRIMARY KEY,
  project_id TEXT REFERENCES ipp_projects(id),
  lender_participant_id TEXT REFERENCES participants(id),
  covenant_code TEXT NOT NULL,         -- 'DSCR_12M','LLCR','AVAILABILITY_95','INSURANCE','DEBT_RATIO'
  covenant_name TEXT NOT NULL,
  covenant_type TEXT NOT NULL CHECK (covenant_type IN (
    'financial','operational','insurance','reporting','legal','environmental','governance'
  )),
  operator TEXT NOT NULL CHECK (operator IN ('gte','lte','eq','gt','lt','between')),
  threshold REAL,
  threshold_upper REAL,                -- used for 'between'
  measurement_frequency TEXT NOT NULL CHECK (measurement_frequency IN (
    'monthly','quarterly','semi_annual','annual','on_event'
  )),
  first_test_date TEXT,
  waivable BOOLEAN DEFAULT 1,
  material_adverse_effect BOOLEAN DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'active' CHECK (status IN ('active','suspended','terminated')),
  notes TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE credit_limits (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  limit_zar       REAL NOT NULL,
  basis           TEXT DEFAULT 'aggregate',
  scope           TEXT DEFAULT 'platform',  
  scope_id        TEXT,
  effective_from  TEXT NOT NULL,
  effective_to    TEXT,
  set_by          TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE credit_serials (
  id TEXT PRIMARY KEY,
  vintage_id TEXT NOT NULL REFERENCES credit_vintages(id),
  owner_participant_id TEXT REFERENCES participants(id),
  serial_start INTEGER NOT NULL,
  serial_end INTEGER NOT NULL,
  quantity INTEGER NOT NULL,
  status TEXT NOT NULL DEFAULT 'held' CHECK (status IN ('held','transferred','retired','cancelled')),
  acquired_at TEXT NOT NULL DEFAULT (datetime('now')),
  retired_at TEXT,
  retirement_ref TEXT REFERENCES carbon_retirements(id)
);

CREATE TABLE credit_vintages (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES carbon_projects(id),
  registry_id TEXT NOT NULL REFERENCES carbon_registries(id),
  vintage_year INTEGER NOT NULL,
  serial_prefix TEXT NOT NULL,
  serial_start INTEGER NOT NULL,
  serial_end INTEGER NOT NULL,
  credits_issued INTEGER NOT NULL,
  credits_retired INTEGER DEFAULT 0,
  methodology TEXT,
  issuance_date TEXT NOT NULL,
  sa_carbon_tax_eligible BOOLEAN DEFAULT 0,
  verification_id TEXT,                     -- ref to MRV verification
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE (project_id, registry_id, vintage_year)
);

CREATE TABLE curtailment_notices (
  id TEXT PRIMARY KEY,
  notice_number TEXT UNIQUE NOT NULL,
  issued_at TEXT NOT NULL DEFAULT (datetime('now')),
  effective_from TEXT NOT NULL,
  effective_to TEXT,
  affected_zone TEXT,
  reason TEXT NOT NULL,
  curtailment_mw REAL,
  severity TEXT CHECK (severity IN ('advisory','mandatory','emergency')),
  status TEXT DEFAULT 'active' CHECK (status IN ('active','lifted','cancelled')),
  lifted_at TEXT,
  issued_by TEXT REFERENCES participants(id)
);

CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);

CREATE TABLE data_tier_snapshots (
  id TEXT PRIMARY KEY,
  snapshot_at TEXT NOT NULL DEFAULT (datetime('now')),
  metering_rows INTEGER,
  metering_bytes INTEGER,
  audit_log_rows INTEGER,
  audit_log_bytes INTEGER,
  ona_forecast_rows INTEGER,
  archives_rows INTEGER,
  archives_bytes INTEGER,
  total_db_bytes INTEGER,
  notes TEXT
);

CREATE TABLE day_ahead_blocks (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  delivery_date   TEXT NOT NULL,
  block_type      TEXT NOT NULL CHECK (block_type IN ('base','peak','off_peak','super_peak','solar_hours','wind_hours')),
  side            TEXT NOT NULL CHECK (side IN ('buy','sell')),
  volume_mwh      REAL NOT NULL,
  price_zar_per_mwh REAL NOT NULL,
  energy_type     TEXT,
  status          TEXT DEFAULT 'submitted' CHECK (status IN ('submitted','cleared','rejected','withdrawn','partial')),
  cleared_volume_mwh REAL,
  cleared_price_zar REAL,
  cleared_at      TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE deal_room_investors (
  id TEXT PRIMARY KEY,
  deal_room_id TEXT NOT NULL REFERENCES deal_rooms(id),
  investor_participant_id TEXT NOT NULL REFERENCES participants(id),
  status TEXT DEFAULT 'interested' CHECK (status IN ('interested','diligence','committed','rejected')),
  interest_level TEXT,
  committed_amount REAL,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE deal_room_messages (
  id TEXT PRIMARY KEY,
  deal_room_id TEXT NOT NULL REFERENCES deal_rooms(id),
  participant_id TEXT NOT NULL REFERENCES participants(id),
  message TEXT NOT NULL,
  attachments TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE deal_room_terms (
  id TEXT PRIMARY KEY,
  deal_room_id TEXT NOT NULL REFERENCES deal_rooms(id),
  term_key TEXT NOT NULL,
  term_value TEXT NOT NULL,
  proposed_by TEXT NOT NULL REFERENCES participants(id),
  proposed_at TEXT DEFAULT (datetime('now')),
  status TEXT DEFAULT 'proposed' CHECK (status IN ('proposed','accepted','rejected','amended')),
  responded_by TEXT,
  responded_at TEXT,
  notes TEXT
);

CREATE TABLE deal_rooms (
  id TEXT PRIMARY KEY,
  deal_name TEXT NOT NULL,
  deal_type TEXT NOT NULL,
  target_amount REAL,
  currency TEXT DEFAULT 'ZAR',
  sector TEXT,
  stage TEXT DEFAULT 'sourcing' CHECK (stage IN ('sourcing','diligence','term_sheet','closing','funded','exited')),
  issuer_participant_id TEXT NOT NULL REFERENCES participants(id),
  target_irr_percentage REAL,
  min_investment REAL,
  term_sheet_key TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE delivery_schedule (
  id TEXT PRIMARY KEY,
  match_id TEXT NOT NULL REFERENCES trade_matches(id),
  scheduled_date TEXT NOT NULL,
  scheduled_volume_mwh REAL NOT NULL,
  actual_volume_mwh REAL,
  variance_percent REAL,
  delivery_point TEXT,
  meter_reading_key TEXT,
  status TEXT DEFAULT 'scheduled' CHECK (status IN ('scheduled','nomination','confirmed','delivered','disputed','short_delivery')),
  quality_inspection TEXT,
  notes TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE demand_response_events (
  id              TEXT PRIMARY KEY,
  program_id      TEXT NOT NULL REFERENCES demand_response_programs(id),
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  event_start     TEXT NOT NULL,
  event_end       TEXT NOT NULL,
  called_load_mw  REAL,
  delivered_load_mw REAL,
  compensation_zar REAL,
  performance_pct REAL,                              -- (delivered / called) * 100
  status          TEXT DEFAULT 'scheduled' CHECK (status IN ('scheduled','called','responding','delivered','missed','cancelled')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE demand_response_programs (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  program_name    TEXT NOT NULL,
  program_type    TEXT NOT NULL CHECK (program_type IN ('iol','dispatchable_load','vpp','peak_clipping','tou_arbitrage')),
  baseline_load_mw REAL NOT NULL,
  reducible_load_mw REAL NOT NULL,
  notice_period_minutes INTEGER,
  recovery_period_minutes INTEGER,
  compensation_zar_per_mwh REAL,
  max_events_per_month INTEGER,
  status          TEXT DEFAULT 'enrolled' CHECK (status IN ('draft','enrolled','active','suspended','terminated')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE determinations_register (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  consultation_id TEXT REFERENCES public_consultations(id),
  determination_ref TEXT NOT NULL UNIQUE,
  title           TEXT NOT NULL,
  category        TEXT,                              -- 'tariff','licence','enforcement','code_amendment'
  affected_parties TEXT,
  decision_date   TEXT,
  effective_from  TEXT,
  expires_at      TEXT,
  document_r2_key TEXT,
  status          TEXT DEFAULT 'draft' CHECK (status IN ('draft','published','appealed','superseded','revoked')),
  appealed_at     TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE disbursement_requests (
  id TEXT PRIMARY KEY,
  facility_id TEXT NOT NULL,
  project_id TEXT,
  milestone_id TEXT,
  amount REAL NOT NULL,
  currency TEXT DEFAULT 'ZAR',
  status TEXT DEFAULT 'pending',
  approved_by TEXT,
  approved_at TEXT,
  requested_by TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE disclosure_jurisdictions (
  code            TEXT PRIMARY KEY,
  name            TEXT NOT NULL,
  region          TEXT,
  effective_year  INTEGER,
  mandatory       INTEGER DEFAULT 1,
  description     TEXT
);

CREATE TABLE disclosure_submissions (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL,
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  jurisdiction        TEXT NOT NULL REFERENCES disclosure_jurisdictions(code),
  reporting_year      INTEGER NOT NULL,
  source_disclosure_id TEXT REFERENCES esg_disclosures(id),  -- the underlying scope rollup
  status              TEXT DEFAULT 'draft'
                       CHECK (status IN ('draft','queued','submitted','accepted','rejected','withdrawn')),
  submitted_at        TEXT,
  acknowledged_at     TEXT,
  external_reference  TEXT,
  filing_pack_r2_key  TEXT,
  notes               TEXT,
  created_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE dispatch_instructions (
  id TEXT PRIMARY KEY,
  instruction_number TEXT UNIQUE NOT NULL,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  site_id TEXT,
  instruction_type TEXT NOT NULL CHECK (instruction_type IN (
    'curtail','redispatch','ramp_up','ramp_down','start','stop','islanding','black_start'
  )),
  issued_at TEXT NOT NULL DEFAULT (datetime('now')),
  effective_from TEXT NOT NULL,
  effective_to TEXT,
  target_mw REAL,
  reason TEXT NOT NULL,
  grid_constraint_id TEXT REFERENCES grid_constraints(id),
  status TEXT NOT NULL DEFAULT 'issued' CHECK (status IN (
    'issued','acknowledged','compliant','non_compliant','cancelled','expired'
  )),
  acknowledged_at TEXT,
  acknowledgement_by TEXT REFERENCES participants(id),
  compliance_evidence_r2_key TEXT,
  penalty_amount_zar REAL,
  issued_by TEXT REFERENCES participants(id)
);

CREATE TABLE dispatch_schedule_periods (
  id TEXT PRIMARY KEY,
  schedule_id TEXT NOT NULL REFERENCES dispatch_schedules(id) ON DELETE CASCADE,
  period_start TEXT NOT NULL,       -- ISO datetime
  period_end TEXT NOT NULL,
  site_id TEXT,                     -- FK target depends on site model; kept loose
  participant_id TEXT REFERENCES participants(id),
  scheduled_mwh REAL NOT NULL,
  cleared_price_zar_mwh REAL,
  zone TEXT                         -- nodal_zones.code
);

CREATE TABLE dispatch_schedules (
  id TEXT PRIMARY KEY,
  schedule_type TEXT NOT NULL CHECK (schedule_type IN ('day_ahead','intraday','real_time','balancing')),
  trading_day TEXT NOT NULL,        -- YYYY-MM-DD
  gate_closure_at TEXT NOT NULL,
  published_at TEXT,
  status TEXT NOT NULL DEFAULT 'draft' CHECK (status IN ('draft','published','cleared','cancelled')),
  total_scheduled_mwh REAL,
  published_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE document_signatories (
  id TEXT PRIMARY KEY,
  document_id TEXT NOT NULL REFERENCES contract_documents(id),
  participant_id TEXT NOT NULL REFERENCES participants(id),
  signatory_name TEXT,
  signatory_designation TEXT,
  signed INTEGER DEFAULT 0,
  signed_at TEXT,
  signature_r2_key TEXT,
  document_hash_at_signing TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ed_sed_spend (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  category TEXT NOT NULL CHECK (category IN (
    'ownership','management_control','skills_development','enterprise_development',
    'supplier_development','socio_economic_development','preferential_procurement','localisation','jobs_created'
  )),
  period TEXT NOT NULL,             -- 'Q2-2026'
  amount_zar REAL NOT NULL,
  beneficiary TEXT,
  description TEXT,
  reipppp_bid_window TEXT,
  evidence_r2_key TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE email_verification_tokens (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id) ON DELETE CASCADE,
  token_hash TEXT NOT NULL UNIQUE,
  expires_at TEXT NOT NULL,
  used_at TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE emission_factors (
  id TEXT PRIMARY KEY,
  country TEXT DEFAULT 'South Africa',
  energy_source TEXT NOT NULL,
  factor_value REAL NOT NULL,
  unit TEXT DEFAULT 'kgCO2/kWh',
  source TEXT,
  valid_from TEXT NOT NULL,
  valid_until TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE energy_funds (
  id TEXT PRIMARY KEY,
  fund_name TEXT NOT NULL,
  fund_type TEXT NOT NULL,
  target_size REAL,
  currency TEXT DEFAULT 'ZAR',
  vintage_year INTEGER,
  tenure_years INTEGER,
  deployment_start_date TEXT,
  deployment_end_date TEXT,
  status TEXT DEFAULT 'active' CHECK (status IN ('active','closed','liquidating')),
  total_commitments REAL DEFAULT 0,
  total_deployed REAL DEFAULT 0,
  total_distributions REAL DEFAULT 0,
  irr_percentage REAL,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE env_compliance_obligations (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,
  obligation_type TEXT NOT NULL CHECK (obligation_type IN (
                    'ea_condition','ael_condition','wul_condition','noise',
                    'avifauna_monitoring','bats_monitoring','flora_monitoring',
                    'rehab','water_quality','dust','community_trust_distribution'
                  )),
  source_doc      TEXT,                              -- ROD or licence ref
  description     TEXT NOT NULL,
  due_date        TEXT,
  frequency       TEXT,                              -- 'annual','quarterly','monthly','event'
  status          TEXT DEFAULT 'open' CHECK (status IN ('open','in_progress','completed','overdue','waived')),
  responsible_party TEXT,
  evidence_r2_key TEXT,
  closed_at       TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE environmental_authorisations (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  authorisation_type TEXT NOT NULL CHECK (authorisation_type IN (
    'environmental_authorisation_s24','waste_licence','water_use_licence','air_emission_licence',
    'heritage_permit','biodiversity_permit','scoping_report','eir_submitted','amendment'
  )),
  reference_number TEXT,
  competent_authority TEXT,          -- e.g. 'DFFE','NWA','SAHRA','Provincial'
  applied_date TEXT,
  decision_date TEXT,
  decision TEXT CHECK (decision IN ('granted','granted_with_conditions','refused','appealed','pending','withdrawn')),
  conditions_text TEXT,
  expiry_date TEXT,
  document_r2_key TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE environmental_compliance (
  id TEXT PRIMARY KEY,
  authorisation_id TEXT NOT NULL REFERENCES environmental_authorisations(id) ON DELETE CASCADE,
  condition_reference TEXT NOT NULL,
  condition_text TEXT NOT NULL,
  due_date TEXT,
  compliance_status TEXT DEFAULT 'pending' CHECK (compliance_status IN (
    'pending','in_progress','compliant','non_compliant','waived'
  )),
  evidence_r2_key TEXT,
  last_tested_at TEXT
);

CREATE TABLE epc_contractors (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  contractor_name TEXT NOT NULL,
  registration_no TEXT,
  bbbee_level     INTEGER CHECK (bbbee_level BETWEEN 1 AND 8),
  technologies    TEXT,                              -- comma-list
  countries_served TEXT,
  rating          TEXT CHECK (rating IN ('approved','preferred','probation','blacklisted','withdrawn')),
  primary_contact TEXT,
  primary_email   TEXT,
  primary_phone   TEXT,
  bonds_capacity_zar REAL,                           -- performance-bond capacity
  insurance_capacity_zar REAL,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE epc_contracts (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  contract_document_id TEXT REFERENCES contract_documents(id),
  epc_contractor_participant_id TEXT REFERENCES participants(id),
  contractor_name TEXT NOT NULL,
  lump_sum_zar REAL,
  target_completion_date TEXT,
  commissioning_date TEXT,
  taking_over_certificate_date TEXT,
  defects_liability_until TEXT,
  performance_security_zar REAL,
  ld_cap_percentage REAL,            -- cap on liquidated damages, typically 10-15%
  status TEXT NOT NULL DEFAULT 'draft' CHECK (status IN (
    'draft','executed','construction','testing','taking_over','defects_period','closed','terminated'
  )),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE epc_liquidated_damages (
  id TEXT PRIMARY KEY,
  epc_contract_id TEXT NOT NULL REFERENCES epc_contracts(id) ON DELETE CASCADE,
  event_type TEXT NOT NULL CHECK (event_type IN ('delay','performance','availability','guaranteed_output')),
  event_date TEXT NOT NULL,
  description TEXT,
  calculated_amount_zar REAL NOT NULL,
  capped_amount_zar REAL,
  status TEXT DEFAULT 'assessed' CHECK (status IN ('assessed','disputed','paid','waived')),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE epc_variations (
  id TEXT PRIMARY KEY,
  epc_contract_id TEXT NOT NULL REFERENCES epc_contracts(id) ON DELETE CASCADE,
  variation_number TEXT NOT NULL,
  description TEXT NOT NULL,
  value_zar REAL NOT NULL,          -- signed: +ve price up, -ve price down
  time_impact_days INTEGER DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'proposed' CHECK (status IN ('proposed','approved','rejected','disputed')),
  raised_at TEXT NOT NULL DEFAULT (datetime('now')),
  decided_at TEXT,
  decided_by TEXT REFERENCES participants(id)
);

CREATE TABLE error_log (
  id              TEXT PRIMARY KEY,
  req_id          TEXT NOT NULL,
  source          TEXT NOT NULL CHECK (source IN ('server', 'client')),
  severity        TEXT NOT NULL CHECK (severity IN ('info', 'warn', 'error', 'fatal')) DEFAULT 'error',
  route           TEXT,
  method          TEXT,
  status          INTEGER,
  participant_id  TEXT,
  tenant_id       TEXT,
  error_name      TEXT,
  error_message   TEXT,
  error_stack     TEXT,
  user_agent      TEXT,
  ip              TEXT,
  url             TEXT,
  created_at      TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE escrow_accounts (
  id TEXT PRIMARY KEY,
  match_id TEXT NOT NULL REFERENCES trade_matches(id),
  amount REAL NOT NULL,
  currency TEXT DEFAULT 'ZAR',
  status TEXT DEFAULT 'held' CHECK (status IN ('held','released','refunded','disputed','claim')),
  release_conditions TEXT,
  held_by TEXT,
  release_at TEXT,
  released_at TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE escrow_movements (
  id TEXT PRIMARY KEY,
  escrow_id TEXT NOT NULL REFERENCES escrow_accounts(id),
  amount REAL NOT NULL,
  type TEXT NOT NULL CHECK (type IN ('deposit','release','refund','claim','interest')),
  reference TEXT,
  notes TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esg_activity_transactions (
  id                    TEXT PRIMARY KEY,
  participant_id        TEXT NOT NULL REFERENCES participants(id),
  tenant_id             TEXT DEFAULT 'default' NOT NULL,
  
  activity_code         TEXT NOT NULL,            
  scope                 INTEGER NOT NULL CHECK (scope IN (1,2,3)),
  scope3_category       INTEGER CHECK (scope3_category BETWEEN 1 AND 15),
  
  region                TEXT,                     
  facility_id           TEXT,                     
  delivery_point_id     TEXT,                     
  
  activity_date         TEXT NOT NULL,            
  period_start          TEXT,                     
  period_end            TEXT,
  quantity              REAL NOT NULL,
  unit                  TEXT NOT NULL,            
  
  counterparty_id       TEXT,                     
  counterparty_name     TEXT,
  invoice_id            TEXT,                     
  
  factor_id             TEXT REFERENCES esg_emission_factors(id),
  factor_value          REAL,                     
  emissions_kg_co2e     REAL,                     
  
  rec_certificate_id    TEXT,                     
  scope2_method         TEXT DEFAULT 'location' CHECK (scope2_method IN ('location','market','both')),
  
  data_source           TEXT,                     
  data_quality          TEXT DEFAULT 'measured' CHECK (data_quality IN ('measured','calculated','estimated','industry_average')),
  uncertainty_pct       REAL,                     
  evidence_r2_key       TEXT,                     
  
  status                TEXT DEFAULT 'final' CHECK (status IN ('draft','final','restated','voided')),
  restated_from_id      TEXT REFERENCES esg_activity_transactions(id),
  notes                 TEXT,
  tags                  TEXT,                     
  created_by            TEXT,
  created_at            TEXT DEFAULT (datetime('now')),
  updated_at            TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esg_annual_rollup (
  participant_id        TEXT NOT NULL,
  tenant_id             TEXT DEFAULT 'default' NOT NULL,
  reporting_year        INTEGER NOT NULL,
  scope1_tco2e          REAL DEFAULT 0,
  scope2_location_tco2e REAL DEFAULT 0,
  scope2_market_tco2e   REAL DEFAULT 0,
  scope3_tco2e          REAL DEFAULT 0,
  scope3_by_category    TEXT,                     
  total_tco2e_location  REAL DEFAULT 0,
  total_tco2e_market    REAL DEFAULT 0,
  energy_consumption_mwh REAL DEFAULT 0,
  renewable_mwh         REAL DEFAULT 0,
  renewable_pct         REAL DEFAULT 0,
  revenue_zar           REAL,                     
  intensity_kgco2e_zar  REAL,
  data_quality_score    REAL,                     
  computed_at           TEXT DEFAULT (datetime('now')),
  PRIMARY KEY (participant_id, reporting_year, tenant_id)
);

CREATE TABLE esg_anomaly_flags (
  id                      TEXT PRIMARY KEY,
  transaction_id          TEXT NOT NULL REFERENCES esg_activity_transactions(id),
  participant_id          TEXT NOT NULL,
  tenant_id               TEXT DEFAULT 'default' NOT NULL,
  rule                    TEXT NOT NULL,             -- 'spike_30d','factor_mismatch','duplicate','unit_inconsistency','restatement_needed','impossible_value'
  severity                TEXT DEFAULT 'medium' CHECK (severity IN ('low','medium','high','critical')),
  detail                  TEXT,
  expected_value          REAL,
  observed_value          REAL,
  status                  TEXT DEFAULT 'open' CHECK (status IN ('open','dismissed','resolved')),
  detected_at             TEXT DEFAULT (datetime('now')),
  resolved_at             TEXT,
  resolved_by             TEXT
);

CREATE TABLE esg_data (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  metric_id TEXT NOT NULL REFERENCES esg_metrics(id),
  reporting_period TEXT NOT NULL,
  value REAL NOT NULL,
  quality_evidence TEXT,
  verification_status TEXT DEFAULT 'pending' CHECK (verification_status IN ('pending','verified','rejected')),
  verified_by TEXT,
  verified_at TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esg_decarbonisation_pathways (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  scope TEXT NOT NULL CHECK (scope IN ('scope1','scope2','scope3')),
  baseline_year INTEGER,
  baseline_emissions REAL,
  target_year INTEGER,
  target_reduction_percentage REAL,
  actions TEXT,
  status TEXT DEFAULT 'active' CHECK (status IN ('active','achieved','superseded')),
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esg_disclosures (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL REFERENCES participants(id),
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  framework           TEXT NOT NULL,              
  reporting_year      INTEGER NOT NULL,
  period_start        TEXT NOT NULL,
  period_end          TEXT NOT NULL,
  scope1_tco2e        REAL,
  scope2_location_tco2e REAL,
  scope2_market_tco2e REAL,
  scope3_tco2e        REAL,
  intensity_value     REAL,
  intensity_unit      TEXT,
  renewable_pct       REAL,
  assurance_level     TEXT,                       
  assurance_provider  TEXT,
  status              TEXT DEFAULT 'draft' CHECK (status IN ('draft','submitted','published','restated','withdrawn')),
  submitted_at        TEXT,
  submitted_to        TEXT,                       
  external_reference  TEXT,                       
  r2_pdf_key          TEXT,
  notes               TEXT,
  created_at          TEXT DEFAULT (datetime('now')),
  updated_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esg_emission_factors (
  id              TEXT PRIMARY KEY,
  source          TEXT NOT NULL,                  
  source_version  TEXT,                            
  region          TEXT,                            
  activity_code   TEXT NOT NULL,                   
  activity_name   TEXT NOT NULL,
  scope           INTEGER NOT NULL CHECK (scope IN (1,2,3)),
  scope3_category INTEGER CHECK (scope3_category BETWEEN 1 AND 15),
  unit_in         TEXT NOT NULL,                   
  unit_out        TEXT NOT NULL DEFAULT 'kgCO2e',
  
  factor          REAL NOT NULL,
  factor_ch4      REAL DEFAULT 0,
  factor_n2o      REAL DEFAULT 0,
  gwp_horizon     INTEGER DEFAULT 100,             
  valid_from      TEXT NOT NULL,
  valid_to        TEXT,
  certainty       TEXT DEFAULT 'medium' CHECK (certainty IN ('high','medium','low')),
  notes           TEXT,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esg_initiatives (
  id                    TEXT PRIMARY KEY,
  participant_id        TEXT NOT NULL REFERENCES participants(id),
  tenant_id             TEXT DEFAULT 'default' NOT NULL,
  name                  TEXT NOT NULL,
  category              TEXT,                     
  scopes_targeted       TEXT,                     
  abatement_tco2e_yr    REAL,                     
  capex_zar             REAL,
  opex_zar_yr           REAL,
  lifetime_years        INTEGER,
  marginal_abatement_cost_zar_tco2e REAL,         
  start_date            TEXT,
  end_date              TEXT,
  status                TEXT DEFAULT 'planned' CHECK (status IN ('planned','approved','in_progress','delivered','cancelled')),
  
  reduces_target_id     TEXT REFERENCES esg_targets(id),
  description           TEXT,
  created_at            TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esg_materiality_topics (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL,
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  topic_code          TEXT NOT NULL,              
  topic_name          TEXT NOT NULL,
  esrs_alignment      TEXT,                       
  impact_materiality  REAL,                       
  financial_materiality REAL,                     
  assessed_at         TEXT,
  assessed_by         TEXT,
  notes               TEXT,
  created_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esg_metrics (
  id TEXT PRIMARY KEY,
  metric_name TEXT NOT NULL,
  category TEXT NOT NULL CHECK (category IN ('environmental','social','governance')),
  unit TEXT NOT NULL,
  description TEXT,
  calculation_method TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esg_rec_certificates (
  id                    TEXT PRIMARY KEY,
  participant_id        TEXT NOT NULL REFERENCES participants(id),
  tenant_id             TEXT DEFAULT 'default' NOT NULL,
  serial_number         TEXT UNIQUE NOT NULL,
  registry              TEXT NOT NULL,            
  source_project_id     TEXT,                     
  technology            TEXT,                     
  vintage_year          INTEGER NOT NULL,
  vintage_month         INTEGER,
  mwh_certified         REAL NOT NULL,
  mwh_remaining         REAL NOT NULL,
  issue_date            TEXT,
  expiry_date           TEXT,
  status                TEXT DEFAULT 'active' CHECK (status IN ('active','partially_retired','retired','expired','cancelled')),
  acquisition_cost_zar  REAL,
  acquisition_date      TEXT,
  notes                 TEXT,
  created_at            TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esg_rec_retirements (
  id                  TEXT PRIMARY KEY,
  certificate_id      TEXT NOT NULL REFERENCES esg_rec_certificates(id),
  participant_id      TEXT NOT NULL,
  mwh_retired         REAL NOT NULL,
  reporting_year      INTEGER NOT NULL,
  scope2_method       TEXT DEFAULT 'market',
  beneficiary         TEXT,
  reason              TEXT,
  retired_at          TEXT DEFAULT (datetime('now')),
  tenant_id           TEXT DEFAULT 'default' NOT NULL
);

CREATE TABLE esg_reports (
  id TEXT PRIMARY KEY,
  report_title TEXT NOT NULL,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  reporting_year INTEGER NOT NULL,
  reporting_period TEXT NOT NULL,
  status TEXT DEFAULT 'draft' CHECK (status IN ('draft','in_review','published','verified')),
  total_ghg_emissions_tco2e REAL,
  renewable_energy_percentage REAL,
  water_usage_m3 REAL,
  waste_recycled_percentage REAL,
  safety_incidents INTEGER,
  training_hours REAL,
  board_diversity_percentage REAL,
  transparency_score INTEGER,
  published_at TEXT,
  created_by TEXT NOT NULL REFERENCES participants(id),
  created_at TEXT DEFAULT (datetime('now'))
, template_id  TEXT, title        TEXT, period_start TEXT, period_end   TEXT, generated_at TEXT, r2_key       TEXT, narrative    TEXT);

CREATE TABLE esg_reports_sections (
  id TEXT PRIMARY KEY,
  report_id TEXT NOT NULL REFERENCES esg_reports(id),
  section_type TEXT NOT NULL CHECK (section_type IN ('tcfd','cdp','gri','jse_srl','king_iv','ai_narrative')),
  content TEXT,
  narrative_ai_generated TEXT,
  file_key TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esg_risks (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL,
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  risk_type           TEXT NOT NULL CHECK (risk_type IN ('physical_acute','physical_chronic','transition_policy','transition_market','transition_technology','transition_reputation')),
  title               TEXT NOT NULL,
  description         TEXT,
  time_horizon        TEXT,                       
  likelihood          REAL,                       
  impact_zar          REAL,                       
  scenario            TEXT,                       
  mitigation          TEXT,
  status              TEXT DEFAULT 'identified',
  created_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esg_supplier_engagements (
  id                    TEXT PRIMARY KEY,
  participant_id        TEXT NOT NULL REFERENCES participants(id),
  supplier_id           TEXT NOT NULL,            
  supplier_name         TEXT,
  scope3_category       INTEGER NOT NULL CHECK (scope3_category BETWEEN 1 AND 15),
  survey_type           TEXT,                     
  invited_at            TEXT DEFAULT (datetime('now')),
  responded_at          TEXT,
  status                TEXT DEFAULT 'invited' CHECK (status IN ('invited','reminded','partial','complete','declined','expired')),
  response_emissions_kg REAL,                     
  response_period_start TEXT,
  response_period_end   TEXT,
  data_quality          TEXT,
  evidence_r2_key       TEXT,
  notes                 TEXT,
  tenant_id             TEXT DEFAULT 'default' NOT NULL,
  created_at            TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esg_targets (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL REFERENCES participants(id),
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  target_type         TEXT NOT NULL CHECK (target_type IN ('absolute','intensity','net_zero','renewable_mix','sbti_15c','sbti_2c')),
  framework           TEXT,                       
  scopes_covered      TEXT NOT NULL,              
  base_year           INTEGER NOT NULL,
  base_value          REAL NOT NULL,              
  base_intensity_unit TEXT,                       
  target_year         INTEGER NOT NULL,
  target_value        REAL NOT NULL,              
  target_pct          REAL,                       
  validated_by        TEXT,                       
  validated_at        TEXT,
  status              TEXT DEFAULT 'committed' CHECK (status IN ('committed','approved','progressing','achieved','revised','retired')),
  description         TEXT,
  created_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE esums_carbon_credits (
  id TEXT PRIMARY KEY,
  station_id TEXT NOT NULL REFERENCES solax_stations(id),
  participant_id TEXT NOT NULL,
  period_start TEXT NOT NULL,
  period_end TEXT NOT NULL,
  kwh_generated REAL NOT NULL DEFAULT 0,
  carbon_tco2e REAL NOT NULL DEFAULT 0,
  carbon_intensity_gco2_per_kwh REAL NOT NULL DEFAULT 950,
  tariff_rate_zar_per_kwh REAL NOT NULL DEFAULT 0,
  revenue_zar REAL NOT NULL DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'provisional'
    CHECK (status IN ('provisional', 'verified', 'retired', 'voided')),
  cascade_fired INTEGER NOT NULL DEFAULT 0,
  notes TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now')), registry_ref TEXT, retired_at   TEXT, carbon_value_zar REAL NOT NULL DEFAULT 0,
  UNIQUE(station_id, period_start)
);

CREATE TABLE esums_data_sources (
  id                   TEXT PRIMARY KEY,
  participant_id       TEXT NOT NULL REFERENCES participants(id) ON DELETE CASCADE,
  site_id              TEXT REFERENCES om_sites(id) ON DELETE SET NULL,
  label                TEXT NOT NULL,
  source_type          TEXT NOT NULL CHECK (source_type IN (
                         'modbus_tcp','sunspec','modbus_rtu_ip',
                         'mqtt','rest_api','opc_ua','push_ingest')),
  -- TCP/IP fields (modbus_tcp, sunspec, modbus_rtu_ip, opc_ua)
  host                 TEXT,
  port                 INTEGER,
  unit_id              INTEGER,         -- Modbus unit ID 1–247
  -- MQTT fields
  topic_prefix         TEXT,
  -- REST API fields
  api_url              TEXT,
  api_method           TEXT DEFAULT 'GET',
  api_auth_type        TEXT DEFAULT 'none', -- none | bearer | basic | api_key
  api_json_path        TEXT,             -- dot-path to reading value
  -- Common
  polling_interval_sec INTEGER DEFAULT 60,
  status               TEXT NOT NULL DEFAULT 'inactive'
                         CHECK (status IN ('inactive','active','error','testing')),
  last_read_at         TEXT,
  last_error           TEXT,
  config_json          TEXT NOT NULL DEFAULT '{}',
  created_at           TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at           TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE esums_projects (id TEXT PRIMARY KEY, participant_id TEXT NOT NULL REFERENCES participants(id) ON DELETE CASCADE, name TEXT NOT NULL, description TEXT, shard_key TEXT UNIQUE, site_count INTEGER NOT NULL DEFAULT 0, total_capacity_kw REAL NOT NULL DEFAULT 0, status TEXT NOT NULL DEFAULT 'active' CHECK (status IN ('active','archived')), created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')), project_type TEXT NOT NULL DEFAULT 'standalone' CHECK(project_type IN ('ipp','standalone')), ipp_project_id TEXT REFERENCES ipp_projects(id) ON DELETE SET NULL);

CREATE TABLE esums_settlement_invoices (
  id TEXT PRIMARY KEY,
  station_id TEXT NOT NULL REFERENCES solax_stations(id),
  from_participant_id TEXT NOT NULL,
  to_participant_id TEXT NOT NULL,
  period_start TEXT NOT NULL,
  period_end TEXT NOT NULL,
  kwh_delivered REAL NOT NULL DEFAULT 0,
  tariff_rate_zar_per_kwh REAL NOT NULL DEFAULT 0,
  gross_revenue_zar REAL NOT NULL DEFAULT 0,
  vat_rate_pct REAL NOT NULL DEFAULT 15,
  vat_amount_zar REAL NOT NULL DEFAULT 0,
  total_zar REAL NOT NULL DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'draft'
    CHECK (status IN ('draft', 'issued', 'paid', 'disputed', 'voided')),
  invoice_number TEXT,
  issued_at TEXT,
  paid_at TEXT,
  notes TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE(station_id, period_start)
);

CREATE TABLE esums_telemetry (id TEXT PRIMARY KEY, device_id TEXT NOT NULL, site_id TEXT NOT NULL, project_id TEXT, ts TEXT NOT NULL, ac_kw REAL, dc_kw REAL, yield_kwh REAL, interval_kwh REAL, voltage_v REAL, current_a REAL, frequency_hz REAL, temperature_c REAL, irradiance_w_m2 REAL, status_code TEXT, quality TEXT NOT NULL DEFAULT 'valid');

CREATE TABLE feature_flag_overrides (
  id TEXT PRIMARY KEY,
  flag_id TEXT NOT NULL REFERENCES feature_flags(id) ON DELETE CASCADE,
  tenant_id TEXT REFERENCES tenants(id),
  participant_id TEXT REFERENCES participants(id),
  value TEXT NOT NULL,
  reason TEXT,
  expires_at TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  CHECK (tenant_id IS NOT NULL OR participant_id IS NOT NULL)
);

CREATE TABLE feature_flags (
  id TEXT PRIMARY KEY,
  flag_key TEXT UNIQUE NOT NULL,
  description TEXT,
  default_value TEXT NOT NULL DEFAULT 'false',  -- JSON scalar: true|false|number|string
  rollout_strategy TEXT NOT NULL DEFAULT 'off' CHECK (rollout_strategy IN (
    'off','all','percentage','by_tier','by_tenant','by_role'
  )),
  rollout_config_json TEXT,                    -- { tiers: ['pro','enterprise'], percentage: 25, tenant_ids: [...] }
  enabled BOOLEAN DEFAULT 1,
  created_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE fee_schedule (
  id TEXT PRIMARY KEY,
  fee_type TEXT NOT NULL CHECK (fee_type IN ('trading_commission','carbon_transaction','escrow','disbursement','management','platform','currency')),
  description TEXT,
  rate_type TEXT NOT NULL CHECK (rate_type IN ('fixed','percentage','tiered')),
  rate_value REAL NOT NULL,
  currency TEXT DEFAULT 'ZAR',
  min_amount REAL,
  max_amount REAL,
  effective_from TEXT NOT NULL,
  effective_until TEXT,
  active INTEGER DEFAULT 1,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE frequency_response_markets (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  market_type     TEXT NOT NULL CHECK (market_type IN ('FCR','FRR_a','FRR_m','RR','synthetic_inertia','black_start')),
  product_window_start TEXT NOT NULL,
  product_window_end TEXT NOT NULL,
  required_mw     REAL NOT NULL,
  procured_mw     REAL DEFAULT 0,
  clearing_price_zar_per_mw_per_h REAL,
  status          TEXT DEFAULT 'open' CHECK (status IN ('open','clearing','cleared','settled','cancelled')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE frequency_response_offers (
  id              TEXT PRIMARY KEY,
  market_id       TEXT NOT NULL REFERENCES frequency_response_markets(id),
  bidder_id       TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  offered_mw      REAL NOT NULL,
  offered_price_zar_per_mw_per_h REAL NOT NULL,
  award_mw        REAL DEFAULT 0,
  status          TEXT DEFAULT 'submitted' CHECK (status IN ('submitted','accepted','partial','rejected','withdrawn')),
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE fund_commitments (
  id TEXT PRIMARY KEY,
  fund_id TEXT NOT NULL REFERENCES energy_funds(id),
  investor_participant_id TEXT NOT NULL REFERENCES participants(id),
  commitment_amount REAL NOT NULL,
  currency TEXT DEFAULT 'ZAR',
  called_amount REAL DEFAULT 0,
  contributed_amount REAL DEFAULT 0,
  distributed_amount REAL DEFAULT 0,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE fund_investments (
  id TEXT PRIMARY KEY,
  fund_id TEXT NOT NULL REFERENCES energy_funds(id),
  project_id TEXT REFERENCES ipp_projects(id),
  investment_type TEXT NOT NULL,
  amount REAL NOT NULL,
  currency TEXT DEFAULT 'ZAR',
  investment_date TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE generated_documents (
  id           TEXT PRIMARY KEY,
  doc_type     TEXT NOT NULL,          -- invoice | carbon_cert | covenant_report | work_order | stage_gate | settlement | audit_export
  entity_type  TEXT NOT NULL,
  entity_id    TEXT NOT NULL,
  r2_key       TEXT,                   -- vault path, set only when persisted to R2
  generated_by TEXT NOT NULL,
  generated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE grid_aggregated_forecasts (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  forecast_for_date TEXT NOT NULL,
  forecast_made_at TEXT DEFAULT (datetime('now')),
  technology      TEXT NOT NULL CHECK (technology IN ('solar','wind','hydro','demand')),
  grid_zone       TEXT,
  hourly_mw_json  TEXT NOT NULL,                     
  total_mwh       REAL,
  source          TEXT,                              
  confidence_pct  REAL,
  notes           TEXT
);

CREATE TABLE grid_ancillary_award_events (
  id                  TEXT PRIMARY KEY,
  award_id            TEXT NOT NULL,
  event_type          TEXT NOT NULL CHECK (event_type IN (
    'awarded','accepted','declined','delivered','failed','settled'
  )),
  actor_id            TEXT NOT NULL,
  occurred_at         TEXT NOT NULL DEFAULT (datetime('now')),
  notes               TEXT
);

CREATE TABLE grid_connection_applications (
  id TEXT PRIMARY KEY,
  application_number TEXT UNIQUE NOT NULL,
  applicant_participant_id TEXT NOT NULL REFERENCES participants(id),
  project_id TEXT REFERENCES ipp_projects(id),
  substation TEXT NOT NULL,
  voltage_kv REAL NOT NULL,
  requested_capacity_mw REAL NOT NULL,
  technology TEXT,
  connection_type TEXT NOT NULL CHECK (connection_type IN (
    'new_generator','capacity_increase','voltage_upgrade','new_consumer','relocation'
  )),
  status TEXT NOT NULL DEFAULT 'enquiry' CHECK (status IN (
    'enquiry','screening','grid_study','cost_estimate','budget_quote',
    'cost_letter_issued','cost_letter_accepted','gca_drafted','gca_signed',
    'construction','commissioning','energised','rejected','withdrawn'
  )),
  grid_study_fee_zar REAL,
  connection_cost_estimate_zar REAL,
  confirmed_capacity_mw REAL,
  target_energisation_date TEXT,
  actual_energisation_date TEXT,
  assigned_engineer_id TEXT REFERENCES participants(id),
  rejection_reason TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE grid_connection_events (
  id TEXT PRIMARY KEY,
  application_id TEXT NOT NULL REFERENCES grid_connection_applications(id) ON DELETE CASCADE,
  event_type TEXT NOT NULL,
  event_date TEXT NOT NULL,
  description TEXT,
  document_r2_key TEXT,
  actor_id TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE grid_connections (
  id TEXT PRIMARY KEY,
  project_id TEXT REFERENCES ipp_projects(id),
  connection_point TEXT NOT NULL,
  voltage_kv REAL,
  export_capacity_mw REAL,
  import_capacity_mw REAL,
  meter_id TEXT,
  connected_date TEXT,
  status TEXT DEFAULT 'pending' CHECK (status IN ('pending','active','suspended','disconnected')),
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE grid_constraints (
  id TEXT PRIMARY KEY,
  constraint_type TEXT NOT NULL CHECK (constraint_type IN ('transmission','distribution','generation','demand')),
  location TEXT NOT NULL,
  severity TEXT DEFAULT 'medium' CHECK (severity IN ('low','medium','high','critical')),
  available_capacity_mw REAL,
  affected_participants TEXT,
  start_date TEXT,
  end_date TEXT,
  status TEXT DEFAULT 'forecast' CHECK (status IN ('forecast','active','resolved')),
  description TEXT,
  resolution_notes TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE grid_contingency_runs (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  run_date        TEXT NOT NULL,
  run_type        TEXT NOT NULL CHECK (run_type IN ('n_minus_1','n_minus_2','cascade','black_start')),
  contingency_set TEXT,                              
  pre_contingency_loading_pct REAL,
  post_contingency_loading_pct REAL,
  pre_contingency_voltage_pu REAL,
  post_contingency_voltage_pu REAL,
  outcome         TEXT CHECK (outcome IN ('secure','warn','breach','blackout')),
  remedy_actions  TEXT,                              
  computed_at     TEXT DEFAULT (datetime('now')),
  notes           TEXT
);

CREATE TABLE grid_curtailment_events (
  id                  TEXT PRIMARY KEY,
  curtailment_id      TEXT NOT NULL,
  event_type          TEXT NOT NULL CHECK (event_type IN (
    'issued','acknowledged','disputed','partial_lift','full_lift','escalated'
  )),
  actor_id            TEXT NOT NULL,
  occurred_at         TEXT NOT NULL DEFAULT (datetime('now')),
  notes               TEXT,
  payload_json        TEXT
);

CREATE TABLE grid_dispatch_schedules (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  schedule_date   TEXT NOT NULL,
  schedule_type   TEXT NOT NULL CHECK (schedule_type IN ('day_ahead','intra_day','real_time')),
  published_at    TEXT,
  generator_id    TEXT,
  generator_name  TEXT,
  
  hourly_mwh_json TEXT NOT NULL,
  total_mwh       REAL,
  status          TEXT DEFAULT 'draft' CHECK (status IN ('draft','published','superseded','withdrawn')),
  notes           TEXT
);

CREATE TABLE grid_imbalance (
  id TEXT PRIMARY KEY,
  period_start TEXT NOT NULL,
  period_end TEXT NOT NULL,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  scheduled_kwh REAL,
  actual_kwh REAL,
  imbalance_kwh REAL,
  imbalance_rate REAL,
  imbalance_charge REAL,
  within_tolerance INTEGER DEFAULT 0,
  settled INTEGER DEFAULT 0,
  settled_at TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE grid_intraday_balancing (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  trading_hour    TEXT NOT NULL,                     
  generation_forecast_mw REAL,
  load_forecast_mw REAL,
  imbalance_mw    REAL,
  balancing_action_mw REAL,
  action_direction TEXT CHECK (action_direction IN ('up','down','none')),
  balancing_cost_zar REAL,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE grid_outage_coordination (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  outage_ref      TEXT,
  asset_descr     TEXT NOT NULL,
  outage_type     TEXT NOT NULL CHECK (outage_type IN ('planned','forced','emergency','protective')),
  scheduled_start TEXT,
  scheduled_end   TEXT,
  actual_start    TEXT,
  actual_end      TEXT,
  capacity_out_mw REAL,
  reason          TEXT,
  coordinated_with TEXT,                             
  status          TEXT DEFAULT 'requested' CHECK (status IN ('requested','approved','active','restored','cancelled','overrun')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE grid_outage_responses (
  id                  TEXT PRIMARY KEY,
  outage_id           TEXT NOT NULL,
  responder_id        TEXT NOT NULL,
  response_type       TEXT NOT NULL CHECK (response_type IN (
    'acknowledged','dispatched_crew','rerouted','restored','escalated','closed'
  )),
  notes               TEXT,
  eta_minutes         INTEGER,
  responded_at        TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE grid_outage_updates (
  id TEXT PRIMARY KEY,
  outage_id TEXT NOT NULL REFERENCES grid_outages(id) ON DELETE CASCADE,
  update_at TEXT NOT NULL DEFAULT (datetime('now')),
  update_text TEXT NOT NULL,
  affected_load_mw REAL,
  restored_load_mw REAL,
  posted_by TEXT REFERENCES participants(id)
);

CREATE TABLE grid_outages (
  id TEXT PRIMARY KEY,
  outage_number TEXT UNIQUE NOT NULL,
  outage_type TEXT NOT NULL CHECK (outage_type IN (
    'planned','unplanned','forced','emergency','load_shedding','maintenance'
  )),
  severity TEXT CHECK (severity IN ('low','medium','high','critical')),
  reported_at TEXT NOT NULL,
  started_at TEXT,
  estimated_restoration_at TEXT,
  restored_at TEXT,
  affected_zone TEXT,
  affected_substations TEXT,        -- JSON array
  affected_customers INTEGER,
  affected_load_mw REAL,
  cause TEXT,
  status TEXT NOT NULL DEFAULT 'open' CHECK (status IN (
    'open','investigating','in_progress','partial_restoration','restored','closed'
  )),
  commander_id TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE grid_reactive_dispatch (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  observed_at     TEXT NOT NULL,
  zone_id         TEXT,                              
  reactive_dispatched_mvar REAL,
  resource_type   TEXT,                              
  voltage_set_point_pu REAL,
  achieved_voltage_pu REAL,
  cost_zar        REAL,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE grid_scada_snapshots (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  substation_code TEXT NOT NULL,
  observed_at     TEXT NOT NULL,
  voltage_kv      REAL,
  voltage_pu      REAL,
  active_mw       REAL,
  reactive_mvar   REAL,
  frequency_hz    REAL,
  loading_pct     REAL,
  health_status   TEXT,                              
  scada_source    TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE grid_wheeling_agreements (
  id TEXT PRIMARY KEY,
  host_participant_id TEXT NOT NULL REFERENCES participants(id),
  wheeling_participant_id TEXT NOT NULL REFERENCES participants(id),
  injection_point TEXT NOT NULL,
  offtake_point TEXT NOT NULL,
  capacity_mw REAL NOT NULL,
  energy_kwh REAL NOT NULL,
  wheeling_rate_per_kwh REAL,
  start_date TEXT NOT NULL,
  end_date TEXT NOT NULL,
  status TEXT DEFAULT 'active' CHECK (status IN ('draft','pending','active','suspended','terminated')),
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE idempotency_keys (
  key TEXT PRIMARY KEY,                  -- client-provided UUID (scoped below)
  scope TEXT NOT NULL,                   -- participant_id || tenant_id || 'anon'
  method TEXT NOT NULL,
  path TEXT NOT NULL,
  request_hash TEXT NOT NULL,            -- sha256(method+path+body) for safety
  response_status INTEGER NOT NULL,
  response_body TEXT NOT NULL,           -- JSON blob as stored; replayed verbatim
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  expires_at TEXT NOT NULL               -- default +24h from write
);

CREATE TABLE ie_certifications (
  id TEXT PRIMARY KEY,
  disbursement_id TEXT REFERENCES project_disbursements(id),
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  ie_participant_id TEXT NOT NULL REFERENCES participants(id),
  cert_number TEXT UNIQUE NOT NULL,
  cert_type TEXT NOT NULL CHECK (cert_type IN (
    'monthly_progress','milestone_completion','drawdown','commissioning','performance_test','taking_over','final'
  )),
  period TEXT,
  physical_progress_pct REAL,
  financial_progress_pct REAL,
  recommended_drawdown_zar REAL,
  certified_amount_zar REAL,
  qualifications TEXT,                 -- any qualifications / caveats on the cert
  site_visit_date TEXT,
  cert_issue_date TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'draft' CHECK (status IN (
    'draft','submitted','under_review','certified','qualified','rejected'
  )),
  document_r2_key TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE imbalance_monthly_totals (
  brp_participant_id TEXT NOT NULL REFERENCES participants(id),
  period TEXT NOT NULL,                        
  periods_count INTEGER NOT NULL,
  scheduled_mwh_total REAL NOT NULL,
  actual_mwh_total REAL NOT NULL,
  imbalance_mwh_long REAL NOT NULL,
  imbalance_mwh_short REAL NOT NULL,
  net_charge_zar REAL NOT NULL,
  long_charge_zar REAL NOT NULL,
  short_charge_zar REAL NOT NULL,
  on_target_period_pct REAL NOT NULL,
  settled INTEGER NOT NULL DEFAULT 0,
  settled_at TEXT,
  invoice_id TEXT REFERENCES invoices(id),
  computed_at TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (brp_participant_id, period)
);

CREATE TABLE imbalance_prices (
  period_start TEXT PRIMARY KEY,              
  period_end TEXT NOT NULL,
  long_price_zar_mwh REAL NOT NULL,
  short_price_zar_mwh REAL NOT NULL,
  tolerance_mwh REAL DEFAULT 0.05,
  published_by TEXT REFERENCES participants(id),
  published_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE imbalance_settlement_runs (
  id TEXT PRIMARY KEY,
  period_from TEXT NOT NULL,
  period_to TEXT NOT NULL,
  run_by TEXT REFERENCES participants(id),
  periods_settled INTEGER DEFAULT 0,
  brps_settled INTEGER DEFAULT 0,
  net_charge_zar_total REAL DEFAULT 0,
  status TEXT DEFAULT 'running' CHECK (status IN ('running','succeeded','failed')),
  error_message TEXT,
  started_at TEXT NOT NULL DEFAULT (datetime('now')),
  finished_at TEXT
);

CREATE TABLE imbalance_settlements (
  id TEXT PRIMARY KEY,
  run_id TEXT NOT NULL,                       
  brp_participant_id TEXT NOT NULL REFERENCES participants(id),
  period_start TEXT NOT NULL,
  period_end TEXT NOT NULL,
  scheduled_mwh REAL NOT NULL,
  actual_mwh REAL NOT NULL,
  imbalance_mwh REAL NOT NULL,
  direction TEXT NOT NULL CHECK (direction IN ('long','short','balanced')),
  price_applied_zar_mwh REAL NOT NULL,
  imbalance_charge_zar REAL NOT NULL,         
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE (brp_participant_id, period_start)
);

CREATE TABLE industry_benchmarks (
  id              TEXT PRIMARY KEY,
  sector_nace     TEXT NOT NULL,
  sector_name     TEXT NOT NULL,
  region          TEXT NOT NULL,
  reporting_year  INTEGER NOT NULL,
  metric          TEXT NOT NULL,                     -- 'scope1_per_revenue','scope2_per_kwh','total_per_employee','renewable_pct'
  p25             REAL,
  p50             REAL,
  p75             REAL,
  unit            TEXT,
  sample_size     INTEGER,
  source          TEXT,
  UNIQUE (sector_nace, region, reporting_year, metric)
);

CREATE TABLE insurance_claims (
  id TEXT PRIMARY KEY,
  policy_id TEXT NOT NULL REFERENCES insurance_policies(id),
  claim_number TEXT NOT NULL,
  loss_event_date TEXT,
  notified_at TEXT,
  quantum_zar REAL,
  paid_amount_zar REAL,
  status TEXT DEFAULT 'open' CHECK (status IN ('open','under_assessment','accepted','rejected','paid','closed')),
  description TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE insurance_policies (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  policy_number TEXT NOT NULL,
  policy_type TEXT NOT NULL CHECK (policy_type IN (
    'car','operational_all_risks','business_interruption','public_liability',
    'directors_and_officers','environmental_liability','marine_cargo','delay_in_start_up','other'
  )),
  insurer TEXT NOT NULL,
  broker TEXT,
  period_start TEXT NOT NULL,
  period_end TEXT NOT NULL,
  sum_insured_zar REAL,
  premium_zar REAL,
  deductible_zar REAL,
  lenders_noted BOOLEAN DEFAULT 0,
  document_r2_key TEXT,
  status TEXT DEFAULT 'active' CHECK (status IN ('active','lapsed','renewed','cancelled')),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
, expiry_status TEXT NOT NULL DEFAULT 'green', last_warning_at TEXT, last_cycle_1_at TEXT, last_cycle_2_at TEXT, last_cycle_3_at TEXT, last_escalated_at TEXT, last_acknowledged_at TEXT, last_acknowledged_by TEXT);

CREATE TABLE insurance_policies_v2 (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,
  policy_type     TEXT NOT NULL CHECK (policy_type IN (
                    'construction_all_risk','operational_all_risk','marine_cargo',
                    'erection_all_risk','public_liability','professional_indemnity',
                    'business_interruption','delay_in_start_up','political_risk',
                    'cyber','directors_officers','environmental_impairment','warranty'
                  )),
  insurer_name    TEXT NOT NULL,
  broker_name     TEXT,
  policy_number   TEXT,
  sum_insured_zar REAL NOT NULL,
  premium_zar     REAL,
  deductible_zar  REAL,
  effective_from  TEXT NOT NULL,
  effective_to    TEXT NOT NULL,
  lender_endorsement INTEGER DEFAULT 0,              -- lender named on policy
  status          TEXT DEFAULT 'active' CHECK (status IN ('quote','bound','active','expired','cancelled','claim_open')),
  evidence_r2_key TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE intelligence_items (
  id TEXT PRIMARY KEY,
  participant_id TEXT REFERENCES participants(id),
  type TEXT NOT NULL,
  severity TEXT DEFAULT 'info' CHECK (severity IN ('info','warning','critical')),
  title TEXT NOT NULL,
  description TEXT,
  entity_type TEXT,
  entity_id TEXT,
  action_required TEXT,
  resolved INTEGER DEFAULT 0,
  resolved_at TEXT,
  resolved_by TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE intraday_orders (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  delivery_hour   TEXT NOT NULL,                     -- ISO datetime, hour-truncated
  side            TEXT NOT NULL CHECK (side IN ('buy','sell')),
  volume_mwh      REAL NOT NULL,
  limit_price_zar REAL NOT NULL,
  energy_type     TEXT,
  status          TEXT DEFAULT 'open' CHECK (status IN ('open','filled','partial','cancelled','expired')),
  filled_volume_mwh REAL DEFAULT 0,
  vwap_zar        REAL,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE invoice_confirmations (
  id               TEXT PRIMARY KEY,
  invoice_id       TEXT NOT NULL,
  party            TEXT NOT NULL CHECK (party IN ('issuer','payer')),
  confirmed_by     TEXT NOT NULL,                -- participant_id
  confirmed_at     TEXT NOT NULL DEFAULT (datetime('now')),
  status           TEXT NOT NULL CHECK (status IN ('confirmed','rejected')),
  notes            TEXT,
  UNIQUE (invoice_id, party)                     -- one decision per side
);

CREATE TABLE invoice_line_items (
  id                  TEXT PRIMARY KEY,
  invoice_id          TEXT NOT NULL,
  sequence_no         INTEGER NOT NULL,
  line_type           TEXT NOT NULL CHECK (line_type IN (
    'energy_charge','take_or_pay_uplift','wheeling_charge','system_charge',
    'imbalance_charge','ancillary_charge','tax','adjustment','credit_note'
  )),
  description         TEXT NOT NULL,
  quantity            REAL,                           -- e.g. MWh delivered; null for fixed-fee lines
  unit                TEXT,                           -- 'MWh' | 'kWh' | 'unit'
  unit_price_zar      REAL,                           -- null for fixed-fee lines
  amount_zar          REAL NOT NULL,                  -- signed; +ve owed, -ve credit
  contract_id         TEXT,
  period_start        TEXT,
  period_end          TEXT,
  formula_explanation TEXT,                           -- e.g. "27.4 MWh × R1,650/MWh = R45,210"
  meta_json           TEXT,                           -- arbitrary structured context (rule applied, etc.)
  created_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE invoice_sequences (
  tenant_id    TEXT NOT NULL,
  year         INTEGER NOT NULL,
  next_value   INTEGER NOT NULL,
  updated_at   TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (tenant_id, year)
);

CREATE TABLE invoices (
  id TEXT PRIMARY KEY,
  invoice_number TEXT UNIQUE NOT NULL,
  match_id TEXT REFERENCES trade_matches(id),
  project_id TEXT,
  from_participant_id TEXT NOT NULL REFERENCES participants(id),
  to_participant_id TEXT NOT NULL REFERENCES participants(id),
  invoice_type TEXT NOT NULL CHECK (invoice_type IN ('energy','capacity','carbon','ancillary','balancing','disbursement','management')),
  period_start TEXT NOT NULL,
  period_end TEXT NOT NULL,
  line_items TEXT NOT NULL,
  subtotal REAL NOT NULL,
  vat_rate REAL DEFAULT 0.15,
  vat_amount REAL NOT NULL,
  total_amount REAL NOT NULL,
  currency TEXT DEFAULT 'ZAR',
  status TEXT DEFAULT 'draft' CHECK (status IN ('draft','issued','viewed','paid','partial','overdue','cancelled','disputed')),
  due_date TEXT NOT NULL,
  issued_at TEXT,
  paid_at TEXT,
  paid_amount REAL DEFAULT 0,
  r2_invoice_key TEXT,
  notes TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
, tenant_id TEXT DEFAULT 'default' NOT NULL, confirmation_status TEXT DEFAULT 'pending');

CREATE TABLE ipp_bond_notices (
  id TEXT PRIMARY KEY,
  bond_id TEXT NOT NULL REFERENCES ipp_performance_bonds(id),
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  cycle INTEGER NOT NULL CHECK (cycle IN (0, 1, 2, 3)),
  title TEXT NOT NULL,
  body_json TEXT,
  status TEXT NOT NULL DEFAULT 'issued' CHECK (status IN ('issued','acknowledged','superseded','escalated')),
  issued_at TEXT NOT NULL DEFAULT (datetime('now')),
  issued_by TEXT NOT NULL DEFAULT 'system',
  cure_deadline_at TEXT NOT NULL,
  acknowledged_at TEXT,
  acknowledged_by TEXT,
  escalated_at TEXT,
  parent_notice_id TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE ipp_commissioning_tests (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,
  test_phase      TEXT NOT NULL CHECK (test_phase IN ('hot','cold','sat','perf','reliability','grid_compliance','final_acceptance')),
  test_name       TEXT NOT NULL,
  test_code       TEXT,                              -- 'PT-001'
  scheduled_at    TEXT,
  executed_at     TEXT,
  witnesses       TEXT,
  pass_fail       TEXT CHECK (pass_fail IN ('pass','fail','partial','retest_required')),
  measured_value  REAL,
  target_value    REAL,
  unit            TEXT,
  evidence_r2_key TEXT,
  punch_list_items TEXT,                             -- JSON
  status          TEXT DEFAULT 'scheduled' CHECK (status IN ('scheduled','in_progress','complete','failed','rescheduled')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ipp_decommissioning_plans (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,
  plan_version    TEXT NOT NULL,
  -- Strategy
  strategy        TEXT NOT NULL CHECK (strategy IN ('decommission','repower','life_extension','sell','hand_back')),
  expected_eol_date TEXT,                            -- end-of-life
  estimated_decom_cost_zar REAL,
  decom_provision_zar REAL,                          -- amount already provisioned
  -- Residual values
  module_residual_zar REAL,
  steel_residual_zar REAL,
  inverter_residual_zar REAL,
  bess_residual_zar REAL,
  recycling_partner TEXT,
  rehab_obligations TEXT,
  status          TEXT DEFAULT 'planning' CHECK (status IN ('planning','approved','provisioned','in_execution','complete','superseded')),
  approved_by     TEXT,
  approved_at     TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ipp_drawdown_requests (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,
  loan_id         TEXT,                              -- joins loan_originations(id) when available
  drawdown_no     INTEGER,
  requested_amount_zar REAL NOT NULL,
  purpose         TEXT,                              -- 'epc_milestone_5','io_phase_2','soft_costs'
  supporting_invoices_r2_key TEXT,
  ie_cert_id      TEXT,                              -- independent engineer cert ref
  requested_at    TEXT DEFAULT (datetime('now')),
  approved_amount_zar REAL,
  approved_at     TEXT,
  approved_by     TEXT,
  disbursed_amount_zar REAL,
  disbursed_at    TEXT,
  status          TEXT DEFAULT 'requested' CHECK (status IN ('requested','reviewing','approved','disbursed','partial','rejected','cancelled')),
  rejection_reason TEXT,
  notes           TEXT
);

CREATE TABLE ipp_financial_models (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,
  model_version   TEXT NOT NULL,                     -- 'v1.0','v1.1','TS_v1','CC_pack'
  yield_estimate_id TEXT REFERENCES ipp_yield_estimates(id),
  -- Inputs
  capacity_mw     REAL NOT NULL,
  capex_zar       REAL NOT NULL,
  opex_zar_yr     REAL,
  ppa_tariff_zar_mwh REAL,
  tariff_escalation_pct REAL DEFAULT 0,              -- annual
  operating_life_yrs INTEGER DEFAULT 25,
  debt_ratio_pct  REAL DEFAULT 70,
  debt_tenor_yrs  REAL,
  interest_rate_pct REAL,
  tax_rate_pct    REAL DEFAULT 27,                   -- SA corporate tax
  -- Outputs (computed)
  lcoe_zar_per_mwh REAL,                             -- levelised cost of energy
  project_irr_pct REAL,
  equity_irr_pct  REAL,
  npv_zar         REAL,
  payback_years   REAL,
  min_dscr        REAL,
  avg_dscr        REAL,
  scenario_set_json TEXT,                            -- JSON: array of sensitivity scenarios with shifted inputs/outputs
  status          TEXT DEFAULT 'draft' CHECK (status IN ('draft','reviewed','approved','dd_certified','archived')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ipp_info_memorandums (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,
  im_version      TEXT NOT NULL,
  im_title        TEXT NOT NULL,
  -- Contents
  executive_summary TEXT,
  project_description TEXT,
  capacity_mw     REAL,
  capex_zar       REAL,
  funding_requested_zar REAL,
  ppa_summary     TEXT,
  yield_estimate_id TEXT REFERENCES ipp_yield_estimates(id),
  financial_model_id TEXT REFERENCES ipp_financial_models(id),
  -- Distribution
  prepared_by     TEXT,
  shared_with_lenders TEXT,                          -- JSON list of participant ids
  share_link_token TEXT,
  status          TEXT DEFAULT 'drafting' CHECK (status IN ('drafting','reviewed','released','withdrawn')),
  document_r2_key TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ipp_nominations (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,
  delivery_date   TEXT NOT NULL,
  nomination_type TEXT NOT NULL CHECK (nomination_type IN ('day_ahead','intra_day','operational','re_nomination')),
  submitted_at    TEXT DEFAULT (datetime('now')),
  -- Hourly volumes 0..23 stored as JSON to keep one row per nomination
  hourly_mwh_json TEXT NOT NULL,
  total_mwh       REAL,
  scheduled_at    TEXT,                              -- when grid operator confirmed
  acknowledged_by_so INTEGER DEFAULT 0,
  scheduling_reference TEXT,                         -- SO ref number
  curtailed_mwh   REAL DEFAULT 0,
  curtailment_reason TEXT,
  status          TEXT DEFAULT 'submitted' CHECK (status IN ('submitted','acknowledged','scheduled','partial','curtailed','rejected','withdrawn')),
  notes           TEXT
);

CREATE TABLE ipp_performance_bonds (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  bond_number TEXT NOT NULL,
  bond_type TEXT NOT NULL CHECK (bond_type IN (
    'performance','advance_payment','retention','warranty',
    'environmental_rehabilitation','parental_guarantee','letter_of_credit','bank_guarantee'
  )),
  issuer TEXT NOT NULL,
  beneficiary TEXT,
  face_value_zar REAL NOT NULL,
  currency TEXT NOT NULL DEFAULT 'ZAR',
  issued_at TEXT NOT NULL,
  expiry_at TEXT NOT NULL,
  release_conditions TEXT,
  document_r2_key TEXT,
  status TEXT NOT NULL DEFAULT 'active' CHECK (status IN (
    'active','call_pending','released','expired','forfeited','replaced'
  )),
  -- Wave 10 escalation columns.
  expiry_status TEXT NOT NULL DEFAULT 'green' CHECK (expiry_status IN (
    'green','warning','cycle_1','cycle_2','cycle_3','escalated'
  )),
  last_warning_at TEXT,
  last_cycle_1_at TEXT,
  last_cycle_2_at TEXT,
  last_cycle_3_at TEXT,
  last_escalated_at TEXT,
  last_acknowledged_at TEXT,
  last_acknowledged_by TEXT,
  -- When operator/insurer files a renewal that supersedes this bond.
  replaced_by_bond_id TEXT,
  -- Claim/forfeit metadata when status flips to call_pending/forfeited.
  claim_amount_zar REAL,
  claim_reason TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE ipp_permits (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,
  permit_type     TEXT NOT NULL CHECK (permit_type IN (
                    'environmental_authorisation','water_use_licence',
                    'air_emissions_licence','nersa_generation_licence',
                    'nersa_distribution_licence','spluma_consent',
                    'heritage_authorisation','aviation_clearance','sabs_certificate',
                    'building_plan','occupational_health_safety','waste_management'
                  )),
  application_no  TEXT,
  authority       TEXT,                              -- 'DFFE','DWS','NERSA','SACAA','SANRAL','Local Municipality'
  applied_at      TEXT,
  expected_decision_at TEXT,
  decided_at      TEXT,
  outcome         TEXT CHECK (outcome IN ('pending','granted','granted_with_conditions','refused','appealed','withdrawn','expired')),
  conditions      TEXT,
  valid_from      TEXT,
  valid_to        TEXT,
  document_r2_key TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ipp_projects (
  id TEXT PRIMARY KEY,
  project_name TEXT NOT NULL,
  developer_id TEXT NOT NULL REFERENCES participants(id),
  structure_type TEXT NOT NULL CHECK (structure_type IN ('build_operate_transfer','build_own_operate','private_wire','direct_agreement')),
  technology TEXT NOT NULL,
  capacity_mw REAL NOT NULL,
  location TEXT NOT NULL,
  coordinates TEXT,
  grid_connection_point TEXT,
  interconnection_capacity_mw REAL,
  status TEXT DEFAULT 'development' CHECK (status IN ('development','construction','commissioning','commercial_operations','decommissioned')),
  construction_start_date TEXT,
  commercial_operation_date TEXT,
  expiry_date TEXT,
  ppa_volume_mwh REAL,
  ppa_price_per_mwh REAL,
  ppa_duration_years INTEGER,
  renewable_energy_certificate_eligible INTEGER DEFAULT 0,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ipp_resource_campaigns (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  site_assessment_id TEXT,
  campaign_name   TEXT NOT NULL,
  campaign_type   TEXT NOT NULL CHECK (campaign_type IN (
                    'met_mast','pyranometer','lidar','sodar','reference_satellite'
                  )),
  start_date      TEXT NOT NULL,
  end_date        TEXT,
  installed_height_m REAL,                           -- met-mast hub height
  data_recovery_pct REAL,                            -- % data validity
  raw_data_r2_key TEXT,
  status          TEXT DEFAULT 'planning' CHECK (status IN ('planning','installed','collecting','analysing','complete','decommissioned')),
  vendor          TEXT,
  cost_zar        REAL,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ipp_site_assessments (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  site_name       TEXT NOT NULL,
  lat             REAL,
  lng             REAL,
  province        TEXT,                              -- ZA province
  technology      TEXT,                              -- 'solar','wind','hybrid','bess'
  hectares        REAL,
  grid_distance_km REAL,                             -- to nearest connection point
  nearest_substation TEXT,
  substation_capacity_mw REAL,
  -- Solar-specific
  ghi_kwh_per_m2_yr REAL,                            -- Global Horizontal Irradiance
  dni_kwh_per_m2_yr REAL,                            -- Direct Normal Irradiance
  -- Wind-specific
  avg_wind_speed_ms REAL,                            -- at hub height
  wind_class      TEXT,                              -- IEC class I / II / III / IV
  -- Site rating
  capex_estimate_zar_per_mw REAL,
  preliminary_lcoe_zar_per_mwh REAL,
  go_decision     TEXT CHECK (go_decision IN ('go','no_go','hold','escalate')),
  rating_score    INTEGER CHECK (rating_score BETWEEN 1 AND 10),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ipp_spares_inventory (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,
  part_number     TEXT,
  description     TEXT NOT NULL,
  manufacturer    TEXT,
  category        TEXT,                              -- 'inverter','transformer','module','blade','gearbox','sensor','consumable'
  location        TEXT,                              -- warehouse / site
  unit_of_measure TEXT,
  on_hand_qty     REAL DEFAULT 0,
  reorder_point   REAL,
  reorder_qty     REAL,
  unit_cost_zar   REAL,
  last_received_at TEXT,
  last_issued_at  TEXT,
  shelf_life_months INTEGER,
  warranty_until  TEXT,
  status          TEXT DEFAULT 'in_stock' CHECK (status IN ('in_stock','low_stock','out_of_stock','obsolete','on_order')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ipp_tender_bidders (
  id              TEXT PRIMARY KEY,
  tender_id       TEXT NOT NULL REFERENCES ipp_tenders(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  bidder_name     TEXT NOT NULL,
  contractor_id   TEXT,                              -- joins epc_contractors(id)
  bid_amount_zar  REAL,
  bid_tenor_years REAL,
  bid_warranties_years REAL,
  -- Evaluation matrix scores 0..100
  technical_score REAL,
  commercial_score REAL,
  bbbee_score     REAL,
  experience_score REAL,
  total_score     REAL,
  rank            INTEGER,
  status          TEXT DEFAULT 'submitted' CHECK (status IN ('invited','submitted','clarifying','shortlisted','rejected','withdrawn','awarded')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ipp_tenders (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,
  tender_name     TEXT NOT NULL,
  tender_type     TEXT NOT NULL CHECK (tender_type IN ('epc','om','civils','grid_connection','module_supply','turbine_supply','transformer','bess','professional_services')),
  scope           TEXT,
  issued_at       TEXT,
  closing_at      TEXT,
  expected_award_zar REAL,
  evaluation_criteria TEXT,                          -- JSON
  status          TEXT DEFAULT 'drafting' CHECK (status IN ('drafting','issued','clarifications','evaluation','award','cancelled')),
  awarded_to      TEXT,                              -- bidder id or name
  awarded_amount_zar REAL,
  awarded_at      TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ipp_work_orders (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,
  wo_number       TEXT,
  wo_type         TEXT NOT NULL CHECK (wo_type IN ('preventive','corrective','breakdown','inspection','retrofit','calibration','warranty')),
  asset_id        TEXT,                              -- joins to ipp assets if available
  asset_descr     TEXT,
  failure_mode    TEXT,
  priority        TEXT DEFAULT 'medium' CHECK (priority IN ('low','medium','high','critical','outage')),
  scheduled_start TEXT,
  scheduled_end   TEXT,
  actual_start    TEXT,
  actual_end      TEXT,
  downtime_hours  REAL,
  energy_loss_mwh REAL,
  -- Resources
  labour_hours    REAL,
  labour_cost_zar REAL,
  parts_cost_zar  REAL,
  external_cost_zar REAL,
  total_cost_zar  REAL,
  technicians     TEXT,                              -- comma list
  status          TEXT DEFAULT 'open' CHECK (status IN ('open','assigned','in_progress','on_hold','complete','cancelled','invoiced')),
  root_cause      TEXT,
  corrective_action TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ipp_yield_estimates (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  site_assessment_id TEXT,
  project_id      TEXT,
  estimate_round  INTEGER DEFAULT 1,                 -- preliminary / detailed / due-diligence
  capacity_mw     REAL NOT NULL,
  -- PVsyst / WindPRO outputs
  p50_gwh_yr      REAL NOT NULL,
  p75_gwh_yr      REAL,
  p90_gwh_yr      REAL,
  net_capacity_factor REAL,                          -- decimal e.g. 0.27
  -- Assumptions
  module_or_turbine TEXT,                            -- 'Trina 600W Vertex' or 'Vestas V162-7.2MW'
  inverter_or_converter TEXT,
  module_count    INTEGER,
  turbine_count   INTEGER,
  pr_or_availability REAL,                           -- performance ratio (PV) or availability (wind)
  losses_pct      REAL,
  long_term_correction_pct REAL,
  software        TEXT,                              -- 'PVsyst','WindPRO','OpenWind','GENESYS'
  software_version TEXT,
  report_r2_key   TEXT,
  status          TEXT DEFAULT 'preliminary' CHECK (status IN ('preliminary','detailed','dd_certified','final')),
  certified_by    TEXT,                              -- DNV / UL / Fichtner / Tractebel
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE journey_feature_config (
  id           TEXT PRIMARY KEY,
  role         TEXT NOT NULL,
  feature_key  TEXT NOT NULL,
  status       TEXT NOT NULL DEFAULT 'optional' CHECK (status IN ('required','optional','unavailable')),
  charge_zar   REAL,
  charge_event TEXT,
  updated_by   TEXT,
  updated_at   TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE (role, feature_key)
);

CREATE TABLE land_leases (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  project_id      TEXT,                              -- joins projects(id)
  property_description TEXT NOT NULL,
  erf_number      TEXT,
  title_deed      TEXT,
  landowner_name  TEXT,
  landowner_contact TEXT,
  hectares        REAL,
  zoning          TEXT,                              -- 'agricultural','industrial','mixed','consent_use'
  lease_start_date TEXT,
  lease_end_date  TEXT,
  rental_zar_per_yr REAL,
  escalation_pct  REAL,
  payment_frequency TEXT DEFAULT 'annual' CHECK (payment_frequency IN ('monthly','quarterly','semi_annual','annual')),
  status          TEXT DEFAULT 'option' CHECK (status IN ('option','signed','active','renewal_due','terminated','expired')),
  consent_use_secured INTEGER DEFAULT 0,             -- requires consent use under SPLUMA
  evidence_r2_key TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE land_parcels (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  parcel_number TEXT,                -- e.g. 'Rem Ptn 3 of Farm 123'
  sg_diagram TEXT,                   -- Surveyor-General reference
  lpi TEXT,                          -- Land Parcel Identifier
  ownership_type TEXT CHECK (ownership_type IN ('owned','leased','servitude','option','communal','state_land')),
  area_hectares REAL,
  registered_owner TEXT,
  title_deed_number TEXT,
  deed_registration_date TEXT,
  lease_start_date TEXT,
  lease_end_date TEXT,
  monthly_rent_zar REAL,
  splumap_rezoning_status TEXT,      -- 'none','applied','approved','refused'
  status TEXT DEFAULT 'secured' CHECK (status IN ('identified','negotiating','secured','in_dispute','released')),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE ledger_transactions (
  id                  TEXT PRIMARY KEY,
  tenant_id           TEXT DEFAULT 'default' NOT NULL,

  
  module              TEXT NOT NULL CHECK (module IN (
                        'trading','settlement','carbon','carbon_registry',
                        'procurement','funder','grid','grid_operator',
                        'ipp','ona','esg','offtaker','admin'
                      )),
  event_type          TEXT NOT NULL,                
  business_date       TEXT NOT NULL,                
  effective_date      TEXT,                          

  
  actor_id            TEXT NOT NULL REFERENCES participants(id),
  actor_role          TEXT NOT NULL,
  party_a_id          TEXT,                          
  party_a_role        TEXT,
  party_b_id          TEXT,                          
  party_b_role        TEXT,

  
  amount_zar          REAL,                          
  amount_currency     TEXT DEFAULT 'ZAR',
  fx_rate             REAL,                          
  amount_zar_equiv    REAL,                          
  quantity            REAL,                          
  quantity_unit       TEXT,                          
  price               REAL,                          
  price_unit          TEXT,                          

  
  source_table        TEXT NOT NULL,
  source_id           TEXT NOT NULL,

  
  contract_id         TEXT,
  project_id          TEXT,
  rfp_id              TEXT,
  loi_id              TEXT,
  invoice_id          TEXT,
  facility_id         TEXT,
  certificate_id      TEXT,

  
  status              TEXT NOT NULL DEFAULT 'recorded'
                       CHECK (status IN ('draft','recorded','settled','reversed','disputed','void')),
  reversed_by_id      TEXT REFERENCES ledger_transactions(id),
  reverses_id         TEXT REFERENCES ledger_transactions(id),

  
  external_reference  TEXT,                          
  evidence_r2_keys    TEXT,                          
  ip_address          TEXT,
  user_agent          TEXT,
  hash_prev           TEXT,                          
  hash_self           TEXT,                          

  
  tags                TEXT,                          
  notes               TEXT,

  
  created_at          TEXT DEFAULT (datetime('now')),
  updated_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE lender_covenant_actions (
  id                  TEXT PRIMARY KEY,
  covenant_test_id    TEXT NOT NULL,              -- covenant_tests.id
  covenant_id         TEXT NOT NULL,              -- covenants.id (denorm for fast filter)
  lender_participant_id TEXT,                     -- denorm from covenant for queue lookup
  status              TEXT NOT NULL DEFAULT 'open'
    CHECK (status IN ('open','investigating','resolved','rejected')),
  action_type         TEXT NOT NULL CHECK (action_type IN (
    'cure_plan','waiver_request','amendment_request','acceleration_notice','workout','no_action'
  )),
  severity            TEXT NOT NULL DEFAULT 'medium'
    CHECK (severity IN ('low','medium','high','critical')),
  filed_by            TEXT NOT NULL,
  filed_at            TEXT NOT NULL DEFAULT (datetime('now')),
  notes               TEXT,
  resolution_outcome  TEXT CHECK (resolution_outcome IN (
    'cured','waived','amended_terms','accelerated','written_off','no_action'
  )),
  resolution_notes    TEXT,
  resolved_at         TEXT,
  resolved_by         TEXT,
  cure_deadline       TEXT,                       -- ISO; when the cure plan must be complete
  updated_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE lender_credit_risk (
  id              TEXT PRIMARY KEY,
