  pd_1yr_pct      REAL,                              
  pd_lifetime_pct REAL,
  lgd_pct         REAL,                              
  ead_zar         REAL,                              
  ccf_pct         REAL,                              
  risk_weight_pct REAL,                              
  rwa_zar         REAL,                              
  expected_loss_zar REAL,                            
  rating_internal TEXT,                              
  rating_external TEXT,
  watchlist       INTEGER DEFAULT 0,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE lender_deal_pipeline (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
