  expected_close  TEXT,
  probability_pct REAL,
  source          TEXT,                              
  owner_user_id   TEXT,
  stage           TEXT DEFAULT 'sourcing' CHECK (stage IN ('sourcing','qualified','term_sheet','due_diligence','credit_committee','signed','closed','lost','withdrawn')),
  next_action     TEXT,
  next_action_due TEXT,
