  as_of_date      TEXT,
  notes           TEXT
);

CREATE TABLE lender_pricing_models (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
