  paid_at         TEXT,
  status          TEXT DEFAULT 'invoiced' CHECK (status IN ('invoiced','paid','overdue','waived','in_dispute')),
  invoice_ref     TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE loan_covenants (
