  status TEXT DEFAULT 'clean',
  notes TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE loan_facilities (
  id TEXT PRIMARY KEY,
  facility_name TEXT NOT NULL,
  project_id TEXT,
  lender_participant_id TEXT NOT NULL,
  borrower_participant_id TEXT,
  facility_type TEXT,
  committed_amount REAL,
  drawn_amount REAL DEFAULT 0,
  currency TEXT DEFAULT 'ZAR',
  interest_rate_pct REAL,
  tenor_months INTEGER,
  dscr_covenant REAL DEFAULT 1.20,
  status TEXT DEFAULT 'active',
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE loan_originations (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),  -- the lender
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  borrower_id     TEXT REFERENCES participants(id),           -- internal demo borrower or NULL for external
  borrower_name   TEXT NOT NULL,
  project_id      TEXT,
  facility_type   TEXT NOT NULL CHECK (facility_type IN (
                    'term_loan','revolving','syndicated','bridge','mezzanine',
                    'green_bond','sustainability_linked','vendor_finance'
                  )),
  proposed_amount_zar REAL NOT NULL,
  proposed_tenor_years REAL,
  proposed_margin_bps INTEGER,
  reference_rate  TEXT,                              -- 'JIBAR','PRIME','SOFR'
  stage           TEXT DEFAULT 'pipeline' CHECK (stage IN (
                    'pipeline','origination','term_sheet','credit_committee',
                    'documentation','signing','financial_close','disbursed','withdrawn','declined'
                  )),
  credit_committee_date TEXT,
  credit_committee_outcome TEXT CHECK (credit_committee_outcome IN ('approved','approved_with_conditions','deferred','declined')),
  conditions_precedent TEXT,                         -- JSON list
  expected_close_date TEXT,
  actual_close_date TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE loan_workouts (
  id              TEXT PRIMARY KEY,
  loan_id         TEXT NOT NULL REFERENCES loan_originations(id),
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  workout_type    TEXT NOT NULL CHECK (workout_type IN (
                    'standstill','reschedule','restructure','enforcement','write_down','dpo'
                  )),
  opened_at       TEXT DEFAULT (datetime('now')),
  closed_at       TEXT,
  trigger_event   TEXT,                              -- 'dscr_breach','payment_default','covenant_breach','ea_breach','restructuring_pending'
  exposure_at_default_zar REAL,
  expected_recovery_zar REAL,
  loss_given_default_pct REAL,
  status          TEXT DEFAULT 'open' CHECK (status IN ('open','negotiating','agreed','executed','closed','litigation')),
  legal_counsel   TEXT,
  notes           TEXT
);

CREATE TABLE login_attempts (
  id TEXT PRIMARY KEY,
  email TEXT NOT NULL,
  ip TEXT,
  succeeded INTEGER NOT NULL DEFAULT 0,
  reason TEXT,
  attempted_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE loi_drafts (
  id TEXT PRIMARY KEY,
  from_participant_id TEXT NOT NULL,
  to_participant_id TEXT,
  project_id TEXT,
  mix_json TEXT NOT NULL,
  body_md TEXT,
  -- drafted  = created, not yet delivered (internal)
  -- sent     = delivered (cascade fired, counterparty action queue populated)
  -- signed   = IPP accepted; counterparty_contract_document_id is populated
  -- withdrawn= IPP declined OR offtaker rescinded
  -- expired  = response window elapsed
  status TEXT DEFAULT 'drafted' CHECK (status IN ('drafted','sent','signed','withdrawn','expired')),
  horizon_years INTEGER,
  annual_mwh REAL,
  blended_price REAL,
  notes TEXT,
  decline_reason TEXT,
  resulting_contract_document_id TEXT,
  sent_at TEXT,
  resolved_at TEXT,
  resolved_by TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE manufacturer_credentials (id TEXT PRIMARY KEY, participant_id TEXT NOT NULL REFERENCES participants(id) ON DELETE CASCADE, manufacturer TEXT NOT NULL, auth_type TEXT NOT NULL, client_id TEXT, client_secret TEXT, api_key TEXT, token TEXT, username TEXT, password TEXT, access_token TEXT, token_expires_at TEXT, base_url TEXT, site_id TEXT, extra_config TEXT, status TEXT NOT NULL DEFAULT 'active' CHECK(status IN ('active','inactive','error')), last_tested_at TEXT, last_error TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, tariff_rate_zar_per_kwh REAL, customer_tariff_rate_zar_per_kwh REAL, carbon_intensity_gco2_per_kwh REAL NOT NULL DEFAULT 950);

CREATE TABLE margin_calls (
  id                       TEXT PRIMARY KEY,
  participant_id           TEXT NOT NULL,
  as_of                    TEXT NOT NULL,
  exposure_zar             REAL DEFAULT 0,
  initial_margin_zar       REAL DEFAULT 0,
  variation_margin_zar     REAL DEFAULT 0,
  posted_collateral_zar    REAL DEFAULT 0,
  shortfall_zar            REAL DEFAULT 0,
  due_by                   TEXT,
  status                   TEXT DEFAULT 'open' CHECK (status IN ('open','met','escalated','breached')),
  created_at               TEXT DEFAULT (datetime('now')),
  resolved_at              TEXT
);

CREATE TABLE margin_enforcement_state (
  member_id           TEXT PRIMARY KEY,
  gate_status         TEXT NOT NULL DEFAULT 'clear',
  open_call_count     INTEGER NOT NULL DEFAULT 0,
  overdue_call_count  INTEGER NOT NULL DEFAULT 0,
  total_call_amount_zar REAL NOT NULL DEFAULT 0,
  earliest_deadline   TEXT,
  last_evaluated_at   TEXT NOT NULL DEFAULT (datetime('now')),
  manual_override     INTEGER NOT NULL DEFAULT 0,
  override_reason     TEXT,
  override_by         TEXT,
  override_at         TEXT
);

CREATE TABLE margin_reservations (
  id              TEXT PRIMARY KEY,
  order_id        TEXT NOT NULL,
  participant_id  TEXT NOT NULL,
  amount_zar      REAL NOT NULL,
  status          TEXT NOT NULL DEFAULT 'reserved'
                    CHECK (status IN ('reserved','released','consumed')),
  reserved_at     TEXT NOT NULL DEFAULT (datetime('now')),
  resolved_at     TEXT,
  resolution_note TEXT
);

CREATE TABLE mark_prices (
  id                  TEXT PRIMARY KEY,
  energy_type         TEXT NOT NULL,
  delivery_date       TEXT,
  mark_date           TEXT NOT NULL,
  mark_price_zar_mwh  REAL NOT NULL,
