  computed_at         TEXT DEFAULT (datetime('now'))
);

CREATE TABLE market_prints (
  shard_key       TEXT NOT NULL,
  minute_bucket   TEXT NOT NULL,
  energy_type     TEXT,
  delivery_date   TEXT,
  open_price      REAL,
  high_price      REAL,
  low_price       REAL,
  close_price     REAL,
  vwap            REAL,
  volume_mwh      REAL,
  trade_count     INTEGER DEFAULT 0,
  PRIMARY KEY (shard_key, minute_bucket)
