CREATE TABLE marketplace_inquiries (
  id TEXT PRIMARY KEY,
  listing_id TEXT NOT NULL REFERENCES marketplace_listings(id),
  buyer_id TEXT NOT NULL REFERENCES participants(id),
  message TEXT,
  status TEXT DEFAULT 'pending' CHECK (status IN ('pending','responded','accepted','rejected')),
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE marketplace_listings (
  id TEXT PRIMARY KEY,
  seller_id TEXT NOT NULL REFERENCES participants(id),
  listing_type TEXT NOT NULL CHECK (listing_type IN ('energy','capacity','carbon','equipment','service')),
  title TEXT NOT NULL,
  description TEXT,
  price REAL,
  price_unit TEXT,
  currency TEXT DEFAULT 'ZAR',
  volume_available REAL,
  volume_unit TEXT,
  delivery_start TEXT,
  delivery_end TEXT,
  status TEXT DEFAULT 'active' CHECK (status IN ('active','pending','sold','withdrawn')),
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE meter_ingest_channels (
  id TEXT PRIMARY KEY,
  connection_id TEXT NOT NULL,          -- references grid_connections(id); kept loose for external connections
  channel_type TEXT NOT NULL CHECK (channel_type IN (
    'scada_mqtt','scada_opc_ua','https_push','sftp','manual','modbus'
  )),
  endpoint_url TEXT,
  auth_method TEXT,                     -- 'mtls','hmac','bearer','ip_allowlist'
  auth_ref_kv_key TEXT,                 -- KV key for credentials (never in DB)
  protocol_version TEXT,
  sampling_interval_seconds INTEGER DEFAULT 60,
  expected_points_per_day INTEGER,
  last_received_at TEXT,
  last_error_at TEXT,
  last_error_message TEXT,
  health_status TEXT DEFAULT 'unknown' CHECK (health_status IN ('healthy','degraded','offline','unknown')),
  enabled BOOLEAN DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE meter_ingest_raw (
  id TEXT PRIMARY KEY,
  channel_id TEXT NOT NULL REFERENCES meter_ingest_channels(id),
  session_id TEXT REFERENCES meter_ingest_sessions(id),
  received_at TEXT NOT NULL DEFAULT (datetime('now')),
  timestamp_utc TEXT,                  -- payload timestamp, if declared
  raw_payload TEXT NOT NULL,
  normalised BOOLEAN DEFAULT 0,
  normalised_reading_id TEXT,
  normalisation_error TEXT,
  hash_sha256 TEXT                     -- dedupe key
);

CREATE TABLE meter_ingest_sessions (
  id TEXT PRIMARY KEY,
  channel_id TEXT NOT NULL REFERENCES meter_ingest_channels(id),
  opened_at TEXT NOT NULL DEFAULT (datetime('now')),
  closed_at TEXT,
  points_received INTEGER DEFAULT 0,
  bytes_received INTEGER DEFAULT 0,
  peer_ip TEXT,
  user_agent TEXT,
  status TEXT DEFAULT 'active' CHECK (status IN ('active','closed','errored'))
);

CREATE TABLE metering_readings (
  id TEXT PRIMARY KEY,
  connection_id TEXT NOT NULL REFERENCES grid_connections(id),
  reading_date TEXT NOT NULL,
  export_kwh REAL,
  import_kwh REAL,
  peak_demand_kw REAL,
  power_factor REAL,
  reading_type TEXT DEFAULT 'actual' CHECK (reading_type IN ('actual','estimated','adjusted')),
  validated INTEGER DEFAULT 0,
  validated_by TEXT,
  validated_at TEXT,
  ona_ingested INTEGER DEFAULT 0,
  notes TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE metering_readings_archives (
  id TEXT PRIMARY KEY,
  connection_id TEXT NOT NULL,
  month_bucket TEXT NOT NULL,          -- YYYY-MM
  r2_key TEXT NOT NULL,
  row_count INTEGER,
  bytes_compressed INTEGER,
