CREATE TABLE modules (
  id TEXT PRIMARY KEY,
  module_key TEXT UNIQUE NOT NULL,
  display_name TEXT NOT NULL,
  description TEXT,
  enabled INTEGER DEFAULT 1,
  required_role TEXT,
  price_monthly REAL,
  created_at TEXT DEFAULT (datetime('now'))
