  participant_id        TEXT NOT NULL,
  key_hash              TEXT NOT NULL UNIQUE,  -- SHA-256 of the raw key
  key_preview           TEXT NOT NULL,         -- last 4 chars + prefix shown in UI
  name                  TEXT NOT NULL,
  scopes                TEXT,                  -- JSON array of allowed scopes
  rate_limit_per_minute INTEGER NOT NULL DEFAULT 60,
  last_used_at          TEXT,
  last_used_ip          TEXT,
  expires_at            TEXT,                  -- NULL = no expiry
  revoked               INTEGER NOT NULL DEFAULT 0,
  revoked_reason        TEXT,
  created_by            TEXT NOT NULL,
  created_at            TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_appeals (
  id              TEXT PRIMARY KEY,
  decision_id     TEXT NOT NULL,
  appellant_id    TEXT NOT NULL,
  forum           TEXT NOT NULL,                 -- nersa_review | high_court_jhb |
                                                  -- supreme_court_of_appeal | constitutional_court
  grounds         TEXT NOT NULL,
  filed_at        TEXT NOT NULL DEFAULT (datetime('now')),
  status          TEXT NOT NULL DEFAULT 'filed',
                                                  -- filed | heard | dismissed | upheld |
                                                  -- remitted_for_reconsideration | settled
  outcome_body    TEXT,
  outcome_at      TEXT,
  matter_number   TEXT,                          -- court case number
  doc_r2_prefix   TEXT
);

CREATE TABLE oe_article6_adjustments (
  id                          TEXT PRIMARY KEY,
  retirement_id               TEXT NOT NULL,           -- credit_serials retirement event / carbon_retirements.id
  certificate_id              TEXT,                    -- carbon_retirement_certificates.id (nullable until issued)
  host_country_iso            TEXT NOT NULL,           -- where the reduction occurred (SA = ZAF)
  beneficiary_country_iso     TEXT NOT NULL,           -- who is claiming the reduction
  tco2e                       REAL NOT NULL,
  vintage_year                INTEGER,
  registry                    TEXT,                    -- verra / gold_standard / cdm / sa_redd
  serial_range                TEXT,                    -- 'VCS-PRJ-001-2024-1000-1999'
  registry_uri                TEXT,                    -- deterministic anchor URL
  article_6_track             TEXT NOT NULL
    CHECK (article_6_track IN ('6.2','6.4','voluntary_oc','paris_only')),
  -- Lifecycle:
  --   draft           — captured at certificate issuance
  --   dffe_pending    — submitted to host-country NDC authority (DFFE for SA)
  --   dffe_cleared    — host authority has acknowledged
  --   unfccc_ledger   — UNFCCC central ledger entry posted
  --   blocked         — flagged as double-counting risk; not redeemable
  ca_status                   TEXT NOT NULL DEFAULT 'draft'
    CHECK (ca_status IN ('draft','dffe_pending','dffe_cleared','unfccc_ledger','blocked')),
  dffe_submitted_at           TEXT,
  dffe_clearance_ref          TEXT,
  dffe_clearance_at           TEXT,
  unfccc_ledger_ref           TEXT,
  unfccc_posted_at            TEXT,
  blocked_reason              TEXT,
  created_by                  TEXT NOT NULL,
  created_at                  TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at                  TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_asset_prognostics (
  id                            TEXT PRIMARY KEY,
  site_id                       TEXT NOT NULL,
  device_id                     TEXT,
  asset_label                   TEXT,
  technology                    TEXT,                 -- solar | wind | bess | hybrid
  status                        TEXT NOT NULL DEFAULT 'predicted',
  tier                          TEXT NOT NULL DEFAULT 'minor',
  prediction_type               TEXT,                 -- pr_degradation | anomaly | rul | fault_fingerprint
  fault_mode                    TEXT,                 -- engine FaultMode
  fault_mode_confidence         REAL DEFAULT 0,
  safety_implicated             INTEGER NOT NULL DEFAULT 0,
  evidence_json                 TEXT,                 -- JSON array of evidence strings
  health_score                  INTEGER DEFAULT 100,  -- 0-100 composite
  performance_ratio             REAL,                 -- IEC 61724 PR (NULL for non-PV)
  anomaly_score                 REAL DEFAULT 0,       -- 0-1 ensemble severity
  anomaly_confidence            REAL DEFAULT 0,       -- 0-1 method agreement
  methods_triggered_json        TEXT,                 -- JSON array of AnomalyMethod
  degradation_slope_per_day     REAL DEFAULT 0,
  degradation_r_squared         REAL DEFAULT 0,
  degradation_direction         TEXT DEFAULT 'stable',
  rul_days                      INTEGER,              -- remaining useful life
  rul_confidence                REAL DEFAULT 0,
  rul_basis                     TEXT,                 -- trend | stable | already_failed
  lost_kwh_per_day              REAL DEFAULT 0,
  tariff_zar_per_mwh            REAL DEFAULT 0,
  revenue_at_risk_zar           REAL DEFAULT 0,
  reactive_cost_zar             REAL DEFAULT 0,       -- run-to-failure cost
  predictive_cost_zar           REAL DEFAULT 0,       -- planned intervention cost
  savings_zar                   REAL DEFAULT 0,       -- reactive - predictive
  savings_pct                   REAL DEFAULT 0,
  benchmark_savings_zar         REAL DEFAULT 0,       -- what the 30% NTT/industry benchmark would save
  incremental_vs_benchmark_zar  REAL DEFAULT 0,       -- how much MORE than the benchmark
  lead_time_days                INTEGER DEFAULT 0,    -- how early we caught it (RUL at detection)
  predicted_failure_at          TEXT,
  detected_at                   TEXT,
  status_entered_at             TEXT,
  sla_deadline                  TEXT,
  sla_breached                  INTEGER NOT NULL DEFAULT 0,
  is_reportable                 INTEGER NOT NULL DEFAULT 0,
  work_order_id                 TEXT,
  recurrence_count              INTEGER NOT NULL DEFAULT 0,
  assigned_to                   TEXT,
  notes                         TEXT,
  created_at                    TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at                    TEXT
);

CREATE TABLE oe_asset_prognostics_events (
