CREATE TABLE oe_audit_chain_block (
  id                                          TEXT PRIMARY KEY,
  block_height                                INTEGER NOT NULL,
  block_number                                TEXT UNIQUE NOT NULL,
  block_cadence                               TEXT NOT NULL CHECK (block_cadence IN (
    'hourly','daily','weekly','monthly','quarterly'
  )),

  -- Cross-chain bridges (W113 EVM + W114 doc control + W115 submittals
  -- + W116 RFIs + W117 change orders). Each Phase-A chain has its rows
  -- ingested into W118 blocks via merkle_root_segment fingerprint.
  w113_evm_ref                                TEXT,
  w114_doc_control_ref                        TEXT,
  w115_submittal_ref                          TEXT,
  w116_rfi_ref                                TEXT,
  w117_change_order_ref                       TEXT,

  -- 5 floor flags (FLOOR-AT-MONTHLY / FLOOR-AT-QUARTERLY at 2+)
  signature_chain_break_detected              INTEGER NOT NULL DEFAULT 0,
  hash_collision_suspected                    INTEGER NOT NULL DEFAULT 0,
  regulator_audit_active                      INTEGER NOT NULL DEFAULT 0,
  cross_border_witness_required               INTEGER NOT NULL DEFAULT 0,
  sox_404_attestation_pending                 INTEGER NOT NULL DEFAULT 0,

  -- Block content + cryptographic spine
  source_chain_count                          INTEGER NOT NULL DEFAULT 0,
  segment_count                               INTEGER NOT NULL DEFAULT 0,
  merkle_root                                 TEXT,
  parent_block_hash                           TEXT,
  block_self_hash                             TEXT,
  signing_pubkey_fingerprint                  TEXT,
  signature_bytes                             TEXT,
  anchor_method                               TEXT,
  anchor_uri                                  TEXT,

  -- Independent verification + Byzantine quorum
  independent_verifier_count                  INTEGER NOT NULL DEFAULT 0,
  independent_verifier_quorum_met             INTEGER NOT NULL DEFAULT 0,

  -- Reconciliation matrix (5 source chains)
  reconciliation_status_w113_evm              INTEGER NOT NULL DEFAULT 0,
  reconciliation_status_w114_doc              INTEGER NOT NULL DEFAULT 0,
  reconciliation_status_w115_sub              INTEGER NOT NULL DEFAULT 0,
  reconciliation_status_w116_rfi              INTEGER NOT NULL DEFAULT 0,
  reconciliation_status_w117_co               INTEGER NOT NULL DEFAULT 0,
  cross_chain_break_count                     INTEGER NOT NULL DEFAULT 0,

  -- Composite indexes + bands
  current_tier                                TEXT NOT NULL CHECK (current_tier IN (
    'hourly','daily','weekly','monthly','quarterly'
  )),
  authority_required                          TEXT CHECK (authority_required IN (
    'auditor','CISO','CFO','BoardAudit'
  )),
  urgency_band                                TEXT,
  block_health_band                           TEXT,
  block_completeness_index                    INTEGER NOT NULL DEFAULT 0,
  integrity_index                             INTEGER NOT NULL DEFAULT 0,
  hash_collision_risk_score                   INTEGER NOT NULL DEFAULT 0,
  block_age_hours                             INTEGER NOT NULL DEFAULT 0,
  regulator_export_window_hours               INTEGER NOT NULL DEFAULT 0,
  days_to_quarterly_attestation               INTEGER NOT NULL DEFAULT 0,

  -- Narrative + reason codes
  title                                       TEXT,
  reason_code                                 TEXT,
  reject_reason                               TEXT,
  suspend_reason                              TEXT,
  restate_reason                              TEXT,
  fork_reason                                 TEXT,

  is_reportable                               INTEGER NOT NULL DEFAULT 0,
  regulator_relevant                          INTEGER NOT NULL DEFAULT 0,
  regulator_reason_text                       TEXT,

  -- 10 forward + 4 branch lifecycle timestamps
  chain_status                                TEXT NOT NULL CHECK (chain_status IN (
    'block_proposed','segments_collected','merkle_built',
    'integrity_verified','block_signed','anchored','published',
    'independently_verifiable','reconciled','archived',
    'rejected','suspended','restated','forked'
  )),
  block_proposed_at                           TEXT,
  segments_collected_at                       TEXT,
  merkle_built_at                             TEXT,
  integrity_verified_at                       TEXT,
  block_signed_at                             TEXT,
  anchored_at                                 TEXT,
  published_at                                TEXT,
  independently_verifiable_at                 TEXT,
  reconciled_at                               TEXT,
  archived_at                                 TEXT,
  rejected_at                                 TEXT,
  suspended_at                                TEXT,
  restated_at                                 TEXT,
  forked_at                                   TEXT,

  -- Regulator crossing
  regulator_crossed_at                        TEXT,
  regulator_inbox_ref                         TEXT,
  regulator_ref                               TEXT,

  -- SLA (HOURS, INVERTED polarity)
  sla_target_hours                            INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                             TEXT,
  last_sla_breach_at                          TEXT,
  sla_breached                                INTEGER NOT NULL DEFAULT 0,
  escalation_level                            INTEGER NOT NULL DEFAULT 0,

  tenant_id                                   TEXT,
  created_by                                  TEXT NOT NULL,
  created_at                                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_audit_chain_block_events (
  id                  TEXT PRIMARY KEY,
  block_id            TEXT NOT NULL,
  event_type          TEXT NOT NULL,
  from_status         TEXT,
  to_status           TEXT,
  actor_id            TEXT,
  actor_party         TEXT,
  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_audit_findings (
  id          TEXT PRIMARY KEY,
  audit_id    TEXT NOT NULL,
  finding_ref TEXT NOT NULL,
  severity    TEXT NOT NULL,                     -- minor | major | critical
  category    TEXT NOT NULL,                     -- licence_condition | grid_code |
                                                  -- safety | reporting | financial
  description TEXT NOT NULL,
  remediation_required TEXT,
  remediation_deadline TEXT,
  status      TEXT NOT NULL DEFAULT 'open',
                                                  -- open | remediated | escalated | closed
  remediated_at TEXT,
  created_at  TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_audit_merkle_roots (
  id                  TEXT PRIMARY KEY,
  entity_type         TEXT NOT NULL,
  day                 TEXT NOT NULL,        -- YYYY-MM-DD (UTC)
  event_count         INTEGER NOT NULL,
  first_sequence_no   INTEGER NOT NULL,
  last_sequence_no    INTEGER NOT NULL,
  merkle_root         TEXT NOT NULL,        -- hex SHA-256
  platform_signature  TEXT,                 -- base64 Ed25519 sig of root
  attestor_id         TEXT,
  attestor_signature  TEXT,                 -- third-party co-sign
  attestor_received_at TEXT,
  generated_at        TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE (entity_type, day)
);

CREATE TABLE oe_audit_proof_requests (
  id                  TEXT PRIMARY KEY,
  event_id            TEXT NOT NULL,
  requester_email     TEXT,
  requester_role      TEXT,
  proof_path          TEXT,                 -- JSON Merkle inclusion proof
  computed_root       TEXT,
  matches_root        INTEGER,              -- 0/1
  generated_at        TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_availability_guarantee_events (
  id                 TEXT PRIMARY KEY,
  guarantee_id       TEXT NOT NULL,
  event_type         TEXT NOT NULL,
  from_status        TEXT,
  to_status          TEXT,
  actor_id           TEXT,
  actor_party        TEXT,
  notes              TEXT,
  payload            TEXT,
  created_at         TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_availability_guarantees (
  id                            TEXT PRIMARY KEY,
  case_number                   TEXT UNIQUE NOT NULL,

  -- Provenance (e.g. a PR-underperformance escalation or a metering rollup)
  source_event                  TEXT,
  source_entity_type            TEXT,
  source_entity_id              TEXT,
  source_wave                   TEXT,

  -- Parties (single-party write; contractual party captured via actor_party)
  owner_party_id                TEXT NOT NULL,
  owner_party_name              TEXT NOT NULL,
  contractor_party_id           TEXT NOT NULL,
  contractor_party_name         TEXT NOT NULL,

  -- Asset
  site_id                       TEXT,
  site_name                     TEXT NOT NULL,
  site_province                 TEXT,
  technology                    TEXT NOT NULL,     -- solar_pv / wind / bess / hydro / hybrid
  capacity_mw                   REAL,
  contract_ref                  TEXT,              -- O&M service agreement ref

  -- Reporting period
  reporting_period              TEXT NOT NULL,     -- e.g. 2026-04
  period_start                  TEXT,
  period_end                    TEXT,

  -- Availability figures (percentage points)
  guaranteed_availability_pct   REAL NOT NULL,     -- e.g. 98.0
  bonus_threshold_pct           REAL,              -- e.g. 99.5 (bonus above this)
  measured_availability_pct     REAL,              -- raw metered availability
  excused_downtime_hours        REAL,              -- grid / FM / owner-caused
  adjusted_availability_pct     REAL,              -- after excused-downtime credit
  shortfall_pp                  REAL,              -- guaranteed - adjusted (pp); <=0 means met

  -- Severity + money
  shortfall_tier                TEXT NOT NULL CHECK (shortfall_tier IN (
    'minor_shortfall','moderate_shortfall','material_shortfall',
    'severe_shortfall','critical_shortfall'
  )),
  ld_rate_zar_per_pp            REAL,              -- liquidated damages per pp
  ld_cap_zar                    REAL,              -- LD cap (R)
  ld_assessed_zar               REAL,              -- assessed LD (R)
  bonus_zar                     REAL,              -- availability bonus (R)
  settlement_zar                REAL,              -- net settlement (R)

  -- Refs
  measurement_ref               TEXT,
  adjustment_ref                TEXT,
  reconciliation_ref            TEXT,
  ld_assessment_ref             TEXT,
  cure_plan_ref                 TEXT,
  settlement_ref                TEXT,
  dispute_ref                   TEXT,
  regulator_ref                 TEXT,

  -- Narrative
  measurement_basis             TEXT,
  adjustment_basis              TEXT,
  shortfall_basis               TEXT,
  ld_basis                      TEXT,
  cure_plan                     TEXT,
  settlement_basis              TEXT,
  dispute_basis                 TEXT,
  reason_code                   TEXT,
  notes                         TEXT,

  dispute_round                 INTEGER NOT NULL DEFAULT 0,

  -- State + lifecycle
  chain_status                  TEXT NOT NULL CHECK (chain_status IN (
    'period_open','measurement_submitted','adjustment_review','reconciled',
    'meets_guarantee','shortfall_flagged','ld_assessed','cure_period',
    'settled','disputed','dispute_resolved','withdrawn'
  )),
  period_open_at                TEXT NOT NULL,
  measurement_submitted_at      TEXT,
  adjustment_review_at          TEXT,
  reconciled_at                 TEXT,
  meets_guarantee_at            TEXT,
  shortfall_flagged_at          TEXT,
  ld_assessed_at                TEXT,
  cure_period_at                TEXT,
  settled_at                    TEXT,
  disputed_at                   TEXT,
  dispute_resolved_at           TEXT,
  withdrawn_at                  TEXT,

  is_reportable                 INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at               TEXT,
  last_sla_breach_at            TEXT,
  escalation_level              INTEGER NOT NULL DEFAULT 0,

  created_by                    TEXT NOT NULL,
  created_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_benchmark_transition_events (
  id                 TEXT PRIMARY KEY,
  transition_id      TEXT NOT NULL,
