  source_wave                     TEXT,

  -- Trade identity
  trade_ref                       TEXT NOT NULL,
  instrument_type                 TEXT NOT NULL CHECK (instrument_type IN (
    'irs','basis_swap','fra','syndicated_loan','frn','structured_note','cross_currency_swap'
  )),
