  seller_id         TEXT NOT NULL,
  energy_type       TEXT NOT NULL,
  delivery_date     TEXT,
  volume_mwh        REAL NOT NULL,
  price_zar_mwh     REAL NOT NULL,
  value_zar         REAL NOT NULL,
  trade_time        TEXT NOT NULL,
  reported_at       TEXT NOT NULL DEFAULT (datetime('now')),
  status            TEXT NOT NULL DEFAULT 'reported',
                                                  -- reported | confirmed | published |
                                                  -- rejected | bust
  publication_delay_minutes INTEGER NOT NULL DEFAULT 15,
  published_at      TEXT,
  bust_reason       TEXT
);

CREATE TABLE oe_capital_adequacy_reports (
  id                      TEXT PRIMARY KEY,
  participant_id          TEXT NOT NULL,
  bank_tier               TEXT NOT NULL CHECK(bank_tier IN ('smaller','mid_tier','large','systemically_important')),
  report_period           TEXT NOT NULL, -- e.g. "2026-Q1"
  reporting_date          TEXT NOT NULL, -- quarter end date

  -- Capital ratios (percentages)
  cet1_ratio              REAL,          -- Common Equity Tier 1
  tier1_ratio             REAL,          -- Total Tier 1
  total_capital_ratio     REAL,          -- Total Capital
  leverage_ratio          REAL,          -- Basel III Leverage Ratio

  -- RWA breakdown (ZAR)
  rwa_credit_risk         REAL,
  rwa_market_risk         REAL,
  rwa_operational_risk    REAL,
  rwa_total               REAL,

  -- Capital buffers
  capital_conservation_buffer REAL DEFAULT 2.5,
  countercyclical_buffer  REAL DEFAULT 0,
  systemic_risk_buffer    REAL DEFAULT 0,

  -- SARB reference
  sarb_submission_ref     TEXT,
  sarb_accepted_at        TEXT,
  ba900_form_ref          TEXT,

  -- Queries
  query_count             INTEGER DEFAULT 0,
  last_query_at           TEXT,
  last_response_at        TEXT,

  -- Remediation
  remediation_description TEXT,
  remediation_deadline    TEXT,

  -- Breach details
  breach_description      TEXT,
  breach_cet1_ratio       REAL,          -- actual CET1 at time of breach

  -- State machine
  chain_status            TEXT NOT NULL DEFAULT 'data_gathering' CHECK(chain_status IN (
    'data_gathering','rwa_calculation','capital_aggregation','icaap_review',
    'board_review','submitted_sarb','under_review','queries_raised',
    'queries_responded','accepted','remediation_required','remediation',
    'capital_breach','withdrawn'
  )),
  sla_deadline            TEXT NOT NULL,
  sla_breached            INTEGER NOT NULL DEFAULT 0,
  regulator_notified      INTEGER NOT NULL DEFAULT 0,

  actor_id                TEXT,
  reason                  TEXT,
  created_at              TEXT NOT NULL,
  updated_at              TEXT NOT NULL
);

CREATE TABLE oe_carbon_budget_obligations (
  id TEXT PRIMARY KEY,
  registration_id TEXT NOT NULL REFERENCES oe_carbon_budget_registrations(id),
  reporting_year INTEGER NOT NULL,
  obligation_type TEXT NOT NULL CHECK(obligation_type IN
    ('annual_return','quarterly_estimate','coas_submission','sars_payment',
     'cbam_report','dffe_ncs_update','audit_submission')),
  due_date TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending'
    CHECK(status IN ('pending','in_progress','submitted','overdue','waived','completed')),
  days_overdue INTEGER DEFAULT 0,
  penalty_zar REAL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_carbon_budget_registrations (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL,
  facility_name TEXT NOT NULL,
  sector TEXT NOT NULL CHECK(sector IN
    ('electricity','mining','manufacturing','transport','construction','waste','agriculture','other')),
  annual_threshold_tco2e REAL NOT NULL,
  reporting_year INTEGER NOT NULL,
  scope1_combustion_tco2e REAL,
  scope1_fugitive_tco2e REAL,
  scope1_process_tco2e REAL,
  scope2_grid_tco2e REAL,
  total_gross_tco2e REAL,
  combustion_offset_allowance_pct REAL DEFAULT 15.0,
  fugitive_process_offset_allowance_pct REAL DEFAULT 10.0,
  max_offset_allowance_tco2e REAL,
  credits_applied_tco2e REAL DEFAULT 0,
  tax_liability_zar REAL,
  tax_after_offset_zar REAL,
  filing_deadline TEXT,
  chain_status TEXT NOT NULL DEFAULT 'draft'
    CHECK(chain_status IN
      ('draft','data_entered','scope_calculated','allowance_computed','credits_selected',
       'coas_submitted','credits_retired','sars_prepared','efiling_ready',
       'sars_submitted','accepted','queried','responded','final','appeal')),
  cbt_account_ref TEXT,
  coas_retirement_refs TEXT,
  efiling_ready INTEGER DEFAULT 0,
  sla_deadline TEXT,
  sla_breached INTEGER DEFAULT 0,
  regulator_notified INTEGER DEFAULT 0,
  actor_id TEXT,
  reason TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
, cb_tier TEXT CHECK(cb_tier IN ('small','medium','large','major')));

CREATE TABLE oe_carbon_credit_rating (
  id                                                  TEXT PRIMARY KEY,
  rating_number                                       TEXT UNIQUE NOT NULL,

  project_id                                          TEXT NOT NULL,
  project_name                                        TEXT,
  issuer_id                                           TEXT NOT NULL,
  issuer_name                                         TEXT,
  rater_id                                            TEXT NOT NULL,
  rater_name                                          TEXT,
  buyer_id                                            TEXT,
  buyer_name                                          TEXT,

  registration_chain_ref                              TEXT,
  mrv_chain_ref                                       TEXT,
  reversal_chain_ref                                  TEXT,

  credit_vintage_year                                 INTEGER NOT NULL DEFAULT 0,
  multi_vintage                                       INTEGER NOT NULL DEFAULT 0,
  scope_scale_tonnes                                  REAL NOT NULL DEFAULT 0,
  methodology_id                                      TEXT,
  methodology_name                                    TEXT,
  registry_name                                       TEXT,

  methodology_score                                   REAL,
  additionality_score                                 REAL,
  permanence_score                                    REAL,
  leakage_score                                       REAL,
  cobenefit_score                                     REAL,
  composite_score                                     REAL,
  rating_band                                         TEXT CHECK (rating_band IN (
    'AAA','AA','A','BBB','BB','B','CCC','D'
  )),
  prior_composite_score                               REAL,
  prior_rating_band                                   TEXT,
  composite_drop_pct                                  REAL NOT NULL DEFAULT 0,
  icroa_aligned                                       INTEGER NOT NULL DEFAULT 0,

  afolu_high_reversal_risk                            INTEGER NOT NULL DEFAULT 0,
  methodology_under_review                            INTEGER NOT NULL DEFAULT 0,
  external_credit_red_flag                            INTEGER NOT NULL DEFAULT 0,
  ccp_aligned_project                                 INTEGER NOT NULL DEFAULT 0,
  article_6_authorised                                INTEGER NOT NULL DEFAULT 0,
  institutional_buyer                                 INTEGER NOT NULL DEFAULT 0,
  issuer_disputed                                     INTEGER NOT NULL DEFAULT 0,

  current_tier                                        TEXT NOT NULL CHECK (current_tier IN (
    'basic','standard','premium','institutional'
  )),
  authority_required                                  TEXT CHECK (authority_required IN (
    'junior_analyst','senior_analyst','ratings_committee_chair','board_rating_committee'
  )),
  urgency_band                                        TEXT,
  rating_completeness_index                           INTEGER NOT NULL DEFAULT 0,
  rerating_count_30d                                  INTEGER NOT NULL DEFAULT 0,
  monitoring_freshness_days                           INTEGER,
  monitoring_data_stale                               INTEGER NOT NULL DEFAULT 0,
  vintage_age_years                                   INTEGER NOT NULL DEFAULT 0,
  last_monitoring_data_at                             TEXT,

  title                                               TEXT,
  narrative                                           TEXT,
  reason_code                                         TEXT,
  withdraw_reason                                     TEXT,
  downgrade_reason                                    TEXT,
  integrity_reason                                    TEXT,
  remediation_narrative                               TEXT,

  current_ball_in_court_party                         TEXT,
  last_responder_party                                TEXT,

  is_reportable                                       INTEGER NOT NULL DEFAULT 0,
  regulator_relevant                                  INTEGER NOT NULL DEFAULT 0,
  regulator_reason_text                               TEXT,

  chain_status                                        TEXT NOT NULL CHECK (chain_status IN (
    'rating_requested','desk_review','methodology_score','additionality_score',
    'permanence_score','leakage_score','cobenefit_score','composite_score',
    'published','monitoring','re_rating_triggered','re_rated',
    'downgraded','withdrawn','escalated_to_integrity'
  )),
  rating_requested_at                                 TEXT,
  desk_review_at                                      TEXT,
  methodology_score_at                                TEXT,
  additionality_score_at                              TEXT,
  permanence_score_at                                 TEXT,
  leakage_score_at                                    TEXT,
  cobenefit_score_at                                  TEXT,
  composite_score_at                                  TEXT,
  published_at                                        TEXT,
  monitoring_at                                       TEXT,
  re_rating_triggered_at                              TEXT,
  re_rated_at                                         TEXT,
  downgraded_at                                       TEXT,
  withdrawn_at                                        TEXT,
  escalated_to_integrity_at                           TEXT,

  regulator_crossed_at                                TEXT,
  regulator_inbox_ref                                 TEXT,
  regulator_ref                                       TEXT,
  sla_target_hours                                    INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                                     TEXT,
  last_sla_breach_at                                  TEXT,
  sla_breached                                        INTEGER NOT NULL DEFAULT 0,
  escalation_level                                    INTEGER NOT NULL DEFAULT 0,

  tenant_id                                           TEXT,
  created_by                                          TEXT NOT NULL,
  created_at                                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_carbon_credit_rating_events (
  id                  TEXT PRIMARY KEY,
  rating_id           TEXT NOT NULL,
  event_type          TEXT NOT NULL,
  from_status         TEXT,
  to_status           TEXT,
  actor_id            TEXT,
  actor_party         TEXT,
  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_carbon_erpas (
  id                       TEXT PRIMARY KEY,
  erpa_number              TEXT UNIQUE NOT NULL,

  -- Provenance
  source_event             TEXT,
  source_entity_type       TEXT,
  source_entity_id         TEXT,
  source_wave              TEXT,

  -- Project + standard + counterparties
  project_id               TEXT NOT NULL,
  project_name             TEXT NOT NULL,
  registry_standard        TEXT NOT NULL CHECK (registry_standard IN (
    'verra_vcs','gold_standard','article_6_4','cdm'
  )),
  methodology_id           TEXT,
  seller_party_id          TEXT NOT NULL,
  seller_party_name        TEXT NOT NULL,
  buyer_party_id           TEXT NOT NULL,
  buyer_party_name         TEXT NOT NULL,

  -- Commercial descriptors
  transfer_type            TEXT NOT NULL CHECK (transfer_type IN (
    'article6','voluntary','compliance'
  )),
  volume_tier              TEXT NOT NULL CHECK (volume_tier IN (
    'minor','moderate','material','major','mega'
  )),
  contracted_volume_tco2e  REAL,               -- total contracted forward volume
  delivered_volume_tco2e   REAL,               -- cumulative delivered so far
  shortfall_volume_tco2e   REAL,               -- contracted - delivered when short
  price_per_tco2e          REAL,
  contract_currency        TEXT,               -- ZAR / USD / EUR
  contract_value           REAL,               -- price * volume
  vintage_year             INTEGER,            -- credit vintage delivered
  host_country             TEXT,               -- NDC host (corresponding-adjustment)
  corresponding_adjustment_required INTEGER NOT NULL DEFAULT 0,
  corresponding_adjustment_ref      TEXT,      -- the CA authorisation reference
  delivery_window_start    TEXT,
  delivery_window_end      TEXT,

  -- Refs
  erpa_ref                 TEXT,
  delivery_ref             TEXT,
  verification_ref         TEXT,
  settlement_ref           TEXT,
  dispute_ref              TEXT,

  -- Narrative
  execution_basis          TEXT,
  schedule_basis           TEXT,
  delivery_basis           TEXT,
  verification_basis       TEXT,
  shortfall_basis          TEXT,
  make_good_basis          TEXT,
  settlement_basis         TEXT,
  dispute_basis            TEXT,
  termination_basis        TEXT,
  reason_code              TEXT,
  erpa_summary             TEXT,

  -- State + lifecycle
  chain_status             TEXT NOT NULL CHECK (chain_status IN (
    'erpa_drafted','erpa_executed','delivery_scheduled','delivery_initiated',
    'delivery_verified','shortfall_flagged','make_good_pending','settled',
    'completed','disputed','terminated','withdrawn'
  )),
  drafted_at               TEXT NOT NULL,
  executed_at              TEXT,
  delivery_scheduled_at    TEXT,
  delivery_initiated_at    TEXT,
  delivery_verified_at     TEXT,
  shortfall_flagged_at     TEXT,
  make_good_pending_at     TEXT,
  settled_at               TEXT,
  completed_at             TEXT,
  disputed_at              TEXT,
  terminated_at            TEXT,
  withdrawn_at             TEXT,

  delivery_round           INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at          TEXT,
  last_sla_breach_at       TEXT,
  is_reportable            INTEGER NOT NULL DEFAULT 0,
  escalation_level         INTEGER NOT NULL DEFAULT 0,

  created_by               TEXT NOT NULL,
  created_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_carbon_erpas_events (
  id              TEXT PRIMARY KEY,
  erpa_id         TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
