  methodology             TEXT,           -- e.g. VM0007, ACM0002, GS TPDDTEC
  province                TEXT,
  host_country            TEXT NOT NULL DEFAULT 'ZA',

  -- Crediting economics (estimated)
  crediting_years         INTEGER,
  estimated_annual_tco2e  REAL,
  estimated_total_tco2e   REAL,
  registered_serial_block TEXT,

  -- Refs
  pin_ref                 TEXT,
  pdd_ref                 TEXT,
  validation_ref          TEXT,
  car_ref                 TEXT,
  consultation_ref        TEXT,
  dna_authorization_ref   TEXT,
  registration_ref        TEXT,
  rejection_ref           TEXT,

  -- Narrative
  validation_basis        TEXT,
  corrections_basis       TEXT,
  consultation_basis      TEXT,
  dna_basis               TEXT,
  registration_basis      TEXT,
  rejection_basis         TEXT,
  withdrawal_basis        TEXT,
  reason_code             TEXT,
  rod_notes               TEXT,

  -- State + lifecycle
  chain_status            TEXT NOT NULL CHECK (chain_status IN (
    'pin_submitted','pdd_drafted','validation_underway','corrections_required',
    'public_consultation','dna_authorization','registration_requested',
    'registered','crediting_active','rejected','withdrawn'
  )),
  pin_submitted_at         TEXT NOT NULL,
  pdd_drafted_at           TEXT,
  validation_underway_at   TEXT,
  corrections_required_at  TEXT,
  public_consultation_at   TEXT,
  dna_authorization_at     TEXT,
  registration_requested_at TEXT,
  registered_at            TEXT,
  crediting_active_at      TEXT,
  rejected_at              TEXT,
  withdrawn_at             TEXT,

  car_round                INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at          TEXT,
  last_sla_breach_at       TEXT,
  escalation_level         INTEGER NOT NULL DEFAULT 0,

  created_by              TEXT NOT NULL,
  created_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_carbon_registration_events (
  id              TEXT PRIMARY KEY,
  project_id      TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_carbon_registry_transfers (
  id                      TEXT PRIMARY KEY,
  participant_id          TEXT NOT NULL,   -- transferor
  counterparty_id         TEXT,            -- transferee (if on platform)
  transfer_type           TEXT NOT NULL CHECK(transfer_type IN ('domestic','international_art6','corsia','voluntary_crossregistry')),

  -- Credit details
  serial_range_start      TEXT,
  serial_range_end        TEXT,
  quantity_tco2e          REAL NOT NULL,
  vintage_year            INTEGER,
  project_id              TEXT,            -- linked carbon project
  methodology             TEXT,

  -- Registry details
  source_registry         TEXT,            -- 'verra', 'gold_standard', 'isimangaliso', 'dffe'
  destination_registry    TEXT,
  source_account          TEXT,
  destination_account     TEXT,

  -- AML/KYC
  aml_check_ref           TEXT,
  aml_check_passed_at     TEXT,
  aml_rejection_reason    TEXT,

  -- Registry authorization
  registry_auth_ref       TEXT,
  authorized_at           TEXT,
  registry_rejection_reason TEXT,

  -- Transfer tracking
  transfer_initiated_at   TEXT,
  receipt_confirmed_at    TEXT,
  transfer_certificate_ref TEXT,

  -- Corresponding adjustment (Art 6.2)
  ca_required             INTEGER DEFAULT 0,  -- 1 if international_art6 or corsia
  unfccc_notification_ref TEXT,
  dna_notification_ref    TEXT,
  ca_notified_at          TEXT,

  chain_status            TEXT NOT NULL DEFAULT 'transfer_requested' CHECK(chain_status IN (
    'transfer_requested','aml_kyc_check','aml_kyc_passed','registry_review',
    'authorized','transfer_in_flight','destination_receipt','ca_notation_required',
    'ca_notified','completed','aml_rejected','registry_rejected','cancelled'
  )),
  sla_deadline            TEXT NOT NULL,
  sla_breached            INTEGER NOT NULL DEFAULT 0,
  regulator_notified      INTEGER NOT NULL DEFAULT 0,

  actor_id                TEXT,
  reason                  TEXT,
  created_at              TEXT NOT NULL,
  updated_at              TEXT NOT NULL
);

CREATE TABLE oe_carbon_reversals (
  id                            TEXT PRIMARY KEY,
  reversal_number               TEXT UNIQUE NOT NULL,

  -- Provenance (the registered / crediting project the reversal hit)
  source_event                  TEXT,
  source_entity_type            TEXT,
  source_entity_id              TEXT,
  source_wave                   TEXT,

  -- Carbon project identity
  project_party_id              TEXT NOT NULL,
  project_party_name            TEXT NOT NULL,
  vvb_name                      TEXT,
  project_name                  TEXT NOT NULL,
  project_tier                  TEXT,              -- afolu_redd / large_scale / small_scale
  standard                      TEXT,              -- verra_vcs / gold_standard / article6
  methodology                   TEXT,
  province                      TEXT,
  host_country                  TEXT,
  registered_project_ref        TEXT,              -- the W37 registry id / project number
  credit_serial_block           TEXT,              -- issued serial block affected

  -- Reversal characterisation
  reversal_cause                TEXT,              -- wildfire / drought / pest_disease / illegal_logging / project_failure / non_compliance
  reversal_type                 TEXT NOT NULL CHECK (reversal_type IN (
    'unintentional', 'intentional'
  )),
  reversal_tier                 TEXT NOT NULL CHECK (reversal_tier IN (
    'catastrophic', 'significant', 'minor'
  )),
  reversed_tco2e                INTEGER NOT NULL DEFAULT 0,   -- magnitude of the loss
  buffer_cancelled_tco2e        INTEGER NOT NULL DEFAULT 0,   -- buffer credits cancelled (buffer path)
  replacement_tco2e             INTEGER NOT NULL DEFAULT 0,   -- credits replaced (replacement path)

  -- Refs
  buffer_pool_ref               TEXT,              -- shared buffer-pool ledger ref
  replacement_serial_block      TEXT,              -- serial block of replacement credits
  reversal_ref                  TEXT,              -- registry reversal-event id
  regulator_ref                 TEXT,              -- regulator notification ref

  -- Narrative
  reversal_summary              TEXT,
  assessment_basis              TEXT,
  quantification_basis          TEXT,
  buffer_basis                  TEXT,
  remediation_basis             TEXT,
  replacement_basis             TEXT,
  verification_basis            TEXT,
  reason_code                   TEXT,
  closure_notes                 TEXT,

  -- State + lifecycle
  chain_status                  TEXT NOT NULL CHECK (chain_status IN (
    'reversal_reported','under_assessment','loss_quantified',
    'buffer_cancellation_proposed','buffer_cancelled','remediation_verified',
    'replacement_required','replacement_submitted','replacement_verified',
    'closed','escalated','false_alarm'
  )),
  reversal_reported_at          TEXT NOT NULL,
  under_assessment_at           TEXT,
  loss_quantified_at            TEXT,
  buffer_cancellation_proposed_at TEXT,
  buffer_cancelled_at           TEXT,
  remediation_verified_at       TEXT,
  replacement_required_at       TEXT,
  replacement_submitted_at      TEXT,
  replacement_verified_at       TEXT,
  closed_at                     TEXT,
  escalated_at                  TEXT,
  false_alarm_at                TEXT,

  is_reportable                 INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at               TEXT,
  last_sla_breach_at            TEXT,
  escalation_level              INTEGER NOT NULL DEFAULT 0,

  created_by                    TEXT NOT NULL,
  created_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_carbon_reversals_events (
  id              TEXT PRIMARY KEY,
  reversal_id     TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_carbon_scope3_disclosures (
  id                          TEXT PRIMARY KEY,
  participant_id              TEXT NOT NULL,   -- carbon fund / reporting entity

  -- Classification
  s3_tier                     TEXT NOT NULL CHECK(s3_tier IN (
    'micro','standard','comprehensive','full_chain'
  )),
  reporting_year              INTEGER NOT NULL,
  entity_name                 TEXT,
  reporting_framework         TEXT CHECK(reporting_framework IN (
    'ghg_protocol','issb_ifrs_s2','cdp','tcfd','king_iv','integrated',NULL
  )),

  -- Category scope
  category_count              INTEGER,        -- number of Scope 3 categories in scope
  category_list               TEXT,           -- comma-separated cat numbers 1–15

  -- Data collection
  primary_data_coverage_pct   REAL,           -- % of spend/activity covered by primary data
  spend_based_pct             REAL,
  supplier_responses          INTEGER,        -- number of supplier data responses

  -- Calculated totals (tCO2e)
  scope3_total_tco2e          REAL,
  cat1_purchased_goods_tco2e  REAL,
  cat3_fuel_energy_tco2e      REAL,
  cat11_use_of_products_tco2e REAL,
  cat12_eol_treatment_tco2e   REAL,

  -- Assurance
  assurance_provider          TEXT,
  assurance_standard          TEXT,           -- AA1000AS, ISO 14064-3, ISAE 3000
  assurance_type              TEXT CHECK(assurance_type IN (
    'limited','reasonable','none',NULL
  )),
  assurance_completed_at      TEXT,
  qualified_opinion_reason    TEXT,

  -- Filing
  filing_platform             TEXT,           -- CDP, JSE, ISSB registry, SA Climate Registry
  filing_ref                  TEXT,
  filing_submitted_at         TEXT,

  -- Timeline
  categories_set_at           TEXT,
  data_collection_opened_at   TEXT,
  data_collection_closed_at   TEXT,
  calculations_completed_at   TEXT,
  review_completed_at         TEXT,

  chain_status                TEXT NOT NULL DEFAULT 'scope3_initiated' CHECK(chain_status IN (
    'scope3_initiated','category_boundaries_set','data_collection_open',
    'data_collection_complete','emission_calculations','calculations_reviewed',
    'assurance_submitted','limited_assurance_complete','reasonable_assurance_complete',
    'disclosure_filed','assurance_qualified','withdrawn'
  )),
  sla_deadline                TEXT NOT NULL,
  sla_breached                INTEGER NOT NULL DEFAULT 0,
  regulator_notified          INTEGER NOT NULL DEFAULT 0,

  actor_id                    TEXT,
  reason                      TEXT,
  created_at                  TEXT NOT NULL,
  updated_at                  TEXT NOT NULL
);

CREATE TABLE oe_carbon_tax_returns (
  id                    TEXT PRIMARY KEY,
  chain_status          TEXT NOT NULL DEFAULT 'period_open',
  sla_deadline          TEXT,
  sla_breached          INTEGER NOT NULL DEFAULT 0,
  regulator_notified    INTEGER NOT NULL DEFAULT 0,
  actor_id              TEXT,
  reason                TEXT,
  created_at            TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at            TEXT NOT NULL DEFAULT (datetime('now')),

  -- Taxpayer context
  participant_id        TEXT NOT NULL,
  tax_class             TEXT NOT NULL DEFAULT 'standard'
                          CHECK (tax_class IN ('micro','standard','large','major')),
  tax_period            TEXT NOT NULL,       -- 'Q1-2025', 'Q2-2025', etc.
  fiscal_year           INTEGER NOT NULL,

  -- Emissions data
  scope1_tco2e          REAL NOT NULL DEFAULT 0,
  scope2_tco2e          REAL NOT NULL DEFAULT 0,
  process_emissions_tco2e REAL NOT NULL DEFAULT 0,
  total_emissions_tco2e REAL NOT NULL DEFAULT 0,

  -- Allowances (Carbon Tax Act Schedule 2)
  basic_allowance_pct   REAL NOT NULL DEFAULT 0,
  offset_allowance_pct  REAL NOT NULL DEFAULT 0,   -- max 10% Annex 2 / 5% general
  total_allowance_pct   REAL NOT NULL DEFAULT 0,

  -- Financial
  tax_rate_per_tco2     REAL NOT NULL DEFAULT 190,  -- 2025 rate (ZAR)
  gross_tax_liability   REAL,
  allowances_value      REAL,
  net_tax_payable       REAL,
  payment_reference     TEXT,
  paid_amount           REAL,
  paid_at               TEXT,

  -- SARS tracking
  sars_submission_ref   TEXT,
  sars_assessment_ref   TEXT,
  assessment_amount     REAL,
  dispute_reason        TEXT
);

CREATE TABLE oe_carbon_verifications (
  id                  TEXT PRIMARY KEY,
  monitoring_id       TEXT NOT NULL,
  doe_id              TEXT NOT NULL,             -- verification body
  verification_type   TEXT NOT NULL,             -- initial | periodic | final
  status              TEXT NOT NULL DEFAULT 'engaged',
                                                  -- engaged | site_visit_done |
                                                  -- draft_opinion | final_opinion | issued
  site_visit_at       TEXT,
  draft_opinion_at    TEXT,
  final_opinion_at    TEXT,
  opinion_r2_key      TEXT,
  fee_zar             REAL,
  created_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_cascade_rule_audit (
  id TEXT PRIMARY KEY,
  rule_id TEXT NOT NULL,
  source_event TEXT NOT NULL,
  source_entity_type TEXT,
  source_entity_id TEXT,
  mode TEXT,                                 -- drive | block
  outcome TEXT NOT NULL CHECK(outcome IN ('ran','skipped','blocked','error')),
  detail TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_cbt_sed_reports (
  id TEXT PRIMARY KEY,
  ipp_id TEXT NOT NULL,                          -- IPP / generator (ipp_developer user id)
  project_name TEXT NOT NULL,                    -- REIPPPP project name
  reipppp_bid_window TEXT NOT NULL,              -- e.g. BW1, BW2, BW3, BW4, BW5, BW6
  reporting_year INTEGER NOT NULL,               -- calendar year being reported
  cbt_disbursement_tier TEXT NOT NULL CHECK(cbt_disbursement_tier IN (
    'micro', 'small', 'medium', 'major'
  )),

  -- CBT trust details
  trust_registration_number TEXT,               -- Master of the High Court trust registration
  beneficiary_community TEXT,                   -- community name / municipal ward
  beneficiary_count INTEGER,                    -- number of registered beneficiaries
  cbt_equity_percentage REAL,                   -- % equity held by CBT in the project SPV

  -- Financial reporting (ZAR)
  annual_cbt_disbursement_zar REAL,             -- CBT disbursement for the reporting year
  cumulative_cbt_disbursement_zar REAL,         -- total disbursements since project COD
  sed_spend_zar REAL,                           -- SED expenditure for the reporting year
  sed_spend_percentage REAL,                    -- sed_spend as % of project revenue
  local_content_percentage REAL,                -- % local content in procurement

  -- Documentary trail
  report_ref TEXT,                              -- DMRE submission reference number
  queries_ref TEXT,                             -- DMRE query/information-request reference
  remediation_plan_ref TEXT,                    -- remediation plan document reference
  non_compliance_reason TEXT,                   -- DMRE grounds for non-compliance finding
  escalation_reason TEXT,
  cancellation_reason TEXT,

  -- Chain state
  chain_status TEXT NOT NULL DEFAULT 'reporting_period_open'
    CHECK(chain_status IN (
      'reporting_period_open',   -- DMRE reporting window opened; IPP must begin data collection
      'data_collection',         -- IPP gathering disbursement and SED expenditure data
      'report_drafted',          -- annual CBT/SED report draft complete; awaiting IPP sign-off
      'submitted',               -- submitted to DMRE; SLA clock starts
      'under_review',            -- DMRE conducting initial review of the submission
      'queries_issued',          -- DMRE issued information requests / clarifications to IPP
      'response_submitted',      -- IPP submitted responses to DMRE queries
      'approved',                -- DMRE approved the annual CBT/SED report; terminal
      'non_compliant',           -- DMRE found the report / disbursements non-compliant
      'remediation_submitted',   -- IPP submitted a remediation plan to address non-compliance
      'cancelled',               -- report voided before submission; terminal
      'escalated'                -- escalated to DMRE Enforcement and/or BBBEE Commission; terminal
    )),

  -- SLA
  sla_deadline TEXT,
  sla_breached INTEGER DEFAULT 0,
  regulator_notified INTEGER DEFAULT 0,
  actor_id TEXT,
  reason TEXT,

  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_ccp_assessments (
  id                                  TEXT PRIMARY KEY,
  assessment_number                   TEXT UNIQUE NOT NULL,

  -- Provenance (the W37 registration / W11 MRV that produced this proponent's request)
  source_event                        TEXT,
  source_entity_type                  TEXT,
  source_entity_id                    TEXT,
  source_wave                         TEXT,

  -- Project identity
  project_id                          TEXT NOT NULL,
  project_name                        TEXT,
  registry_standard                   TEXT,
  methodology_id                      TEXT,
  methodology_version                 TEXT,
  proponent_party_id                  TEXT,
  proponent_party_name                TEXT,
  vvb_name                            TEXT,
  quality_assessor_name               TEXT,
  host_country                        TEXT,

  -- Classification
  sector                              TEXT NOT NULL CHECK (sector IN (
    'redd_plus','jurisdictional','avoidance',
    'arr','improved_forest_mgmt','cookstove','renewable_energy',
    'methane','industrial_gas','engineered_removal','soil_carbon','blue_carbon'
  )),
  assessment_tier                     TEXT NOT NULL CHECK (assessment_tier IN (
    'minor','moderate','major','mega'
  )),
  assessed_annual_tco2e               REAL NOT NULL DEFAULT 0,
  high_integrity_risk_flag            INTEGER NOT NULL DEFAULT 0,

  -- 10 CCP criteria scores (0-100); NULL = not yet scored
  effective_governance_score          REAL,
  tracking_system_score               REAL,
  transparency_score                  REAL,
  robust_quantification_score         REAL,
  no_double_counting_score            REAL,
  permanence_score                    REAL,
  additionality_score                 REAL,
  sustainable_development_score       REAL,
  transition_to_net_zero_score        REAL,
  safeguards_score                    REAL,

  -- Derived label class + grant conditions
  label_class                         TEXT CHECK (label_class IN (
    'ccp_eligible','ccp_conditional','ccp_not_eligible'
  )),
  ccp_aggregate_score                 REAL,
  gap_count                           INTEGER DEFAULT 0,
  weakest_criterion                   TEXT,
  weakest_score                       REAL,
  integrity_floor_cross_flag          INTEGER NOT NULL DEFAULT 0,
  conditional_grant_flag              INTEGER NOT NULL DEFAULT 0,
  corsia_phase2_eligible_flag         INTEGER NOT NULL DEFAULT 0,
  sylvera_grade_equivalent            TEXT,
  premium_pricing_uplift_pct          REAL DEFAULT 0,
  predicted_assessment_days           INTEGER DEFAULT 0,

  -- Gates
  screened_flag                       INTEGER NOT NULL DEFAULT 0,
  eligibility_check_ok_flag           INTEGER NOT NULL DEFAULT 0,
  assessment_complete_flag            INTEGER NOT NULL DEFAULT 0,
  vvb_review_complete_flag            INTEGER NOT NULL DEFAULT 0,
  decision_made_flag                  INTEGER NOT NULL DEFAULT 0,

  -- Refs
  request_ref                         TEXT,
  screening_ref                       TEXT,
  eligibility_check_ref               TEXT,
  assessment_ref                      TEXT,
  vvb_review_ref                      TEXT,
  decision_ref                        TEXT,
  grant_ref                           TEXT,
  denial_ref                          TEXT,
  hold_ref                            TEXT,
  return_ref                          TEXT,
  dispute_ref                         TEXT,
  withdrawal_ref                      TEXT,
  regulator_ref                       TEXT,
  corsia_eligibility_ref              TEXT,

  -- Narrative
  request_basis                       TEXT,
  screening_basis                     TEXT,
  eligibility_check_basis             TEXT,
  assessment_basis                    TEXT,
  vvb_review_basis                    TEXT,
  decision_basis                      TEXT,
  grant_basis                         TEXT,
  denial_basis                        TEXT,
  hold_basis                          TEXT,
  return_basis                        TEXT,
  dispute_basis                       TEXT,
  withdrawal_basis                    TEXT,
  reason_code                         TEXT,
  conditional_grant_conditions        TEXT,
  assessment_summary                  TEXT,

  -- State + lifecycle
  chain_status                        TEXT NOT NULL CHECK (chain_status IN (
    'requested','screening','eligibility_check','assessment_in_progress','vvb_review',
    'ccp_decision_pending','ccp_label_granted','on_hold','returned','disputed',
    'ccp_label_denied','withdrawn'
  )),
  requested_at                        TEXT NOT NULL,
  screening_at                        TEXT,
  eligibility_check_at                TEXT,
  assessment_in_progress_at           TEXT,
  vvb_review_at                       TEXT,
  ccp_decision_pending_at             TEXT,
  ccp_label_granted_at                TEXT,
  on_hold_at                          TEXT,
  returned_at                         TEXT,
  disputed_at                         TEXT,
  ccp_label_denied_at                 TEXT,
  withdrawn_at                        TEXT,

  is_reportable                       INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                     TEXT,
  last_sla_breach_at                  TEXT,
  escalation_level                    INTEGER NOT NULL DEFAULT 0,

  created_by                          TEXT NOT NULL,
  created_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_ccp_assessments_events (
  id              TEXT PRIMARY KEY,
