    ('ghg_protocol_scope2','re100','sbti','cdp','iso14064','jse_esg','tcfd','issb_ifrs_s2','gbcsa')),
  certificate_number TEXT UNIQUE,
  issued_at TEXT,
  expiry_date TEXT,
  pdf_r2_key TEXT,
  sla_deadline TEXT,
