  fund_id           TEXT NOT NULL,
  participant_id    TEXT NOT NULL,
  amount_zar        REAL NOT NULL,
  contributed_at    TEXT NOT NULL DEFAULT (datetime('now')),
  refunded_at       TEXT,
  refund_amount_zar REAL,
  status            TEXT NOT NULL DEFAULT 'held'   -- held | partially_used | exhausted |
                                                  -- refunded
);

CREATE TABLE oe_clearing_fund (
  id                TEXT PRIMARY KEY,
  fund_year         INTEGER NOT NULL,
  total_size_zar    REAL NOT NULL,
  initial_contribution_pct REAL NOT NULL,
  variable_assessment_basis TEXT,                  -- 'avg_daily_var' | 'avg_volume'
  status            TEXT NOT NULL DEFAULT 'active',
  established_at    TEXT NOT NULL DEFAULT (datetime('now')),
  closed_at         TEXT
);

CREATE TABLE oe_clearing_loss_events (
  id                TEXT PRIMARY KEY,
  default_event_id  TEXT NOT NULL,
  fund_id           TEXT NOT NULL,
  loss_amount_zar   REAL NOT NULL,
  defaulter_margin_used_zar  REAL,                -- step 1 of waterfall
  defaulter_default_fund_used_zar REAL,           -- step 2
  clearing_house_capital_used_zar REAL,           -- step 3 ("skin in the game")
  mutualised_amount_zar REAL,                     -- step 4 — across non-defaulters
  status            TEXT NOT NULL DEFAULT 'open',
                                                  -- open | waterfall_executing |
                                                  -- mutualised | resolved
  resolved_at       TEXT,
  notes             TEXT,
  created_at        TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_cod_chain (
  id                   TEXT PRIMARY KEY,
  cod_number           TEXT UNIQUE NOT NULL,
  project_id           TEXT,
  participant_id       TEXT NOT NULL,
  project_name         TEXT NOT NULL,
  epc_contract_id      TEXT,
  epc_contractor_name  TEXT,
  capacity_mw          REAL NOT NULL DEFAULT 0,
  capacity_tier        TEXT NOT NULL DEFAULT 'small',  -- large | medium | small
  chain_status         TEXT NOT NULL DEFAULT 'draft',
  target_cod_date      TEXT,
  actual_cod_date      TEXT,
  epc_signed_at        TEXT,
  ntp_issued_at        TEXT,
  mobilization_at      TEXT,
  mechanical_complete_at TEXT,
  cold_comm_at         TEXT,
  grid_sync_at         TEXT,
  reliability_run_at   TEXT,
  cod_certified_at     TEXT,
  ie_certifier         TEXT,                          -- Independent Engineer firm
  ie_cert_doc_ref      TEXT,                          -- IE certificate document ref
  nersa_scada_ref      TEXT,                          -- NERSA SCADA registration ref
  cancellation_reason  TEXT,
  construction_notes   TEXT,
  sla_deadline_at      TEXT,
  last_sla_breach_at   TEXT,
  escalation_level     INTEGER NOT NULL DEFAULT 0,
  created_by           TEXT NOT NULL,
  created_at           TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at           TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_cod_chain_events (
  id          TEXT PRIMARY KEY,
  cod_id      TEXT NOT NULL,
  event_type  TEXT NOT NULL,    -- epc_signed | ntp_issued | mobilized |
                                -- mechanical_complete | cold_commissioned |
                                -- grid_synchronized | reliability_started |
                                -- cod_certified | cancelled | sla_breached
  from_status TEXT,
  to_status   TEXT,
  actor_id    TEXT,
  notes       TEXT,
  payload     TEXT,              -- JSON
  created_at  TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_collateral_postings (
  id              TEXT PRIMARY KEY,
  margin_call_id  TEXT,                          -- nullable for initial margin
  participant_id  TEXT NOT NULL,
  asset_type      TEXT NOT NULL,                 -- zar_cash | govt_bond | bank_guarantee |
                                                  -- letter_of_credit
  asset_ref       TEXT,                          -- bond ISIN / LC reference
  haircut_pct     REAL NOT NULL DEFAULT 0,
  face_value_zar  REAL NOT NULL,
  collateral_value_zar REAL NOT NULL,            -- face × (1 - haircut)
  posted_at       TEXT NOT NULL DEFAULT (datetime('now')),
  released_at     TEXT,
  substituted_by  TEXT                           -- id of replacement posting
);

CREATE TABLE oe_compliance_audits (
  id              TEXT PRIMARY KEY,
  licensee_id     TEXT NOT NULL,
  audit_type      TEXT NOT NULL,                 -- routine | targeted | post_incident
  scope           TEXT,
  started_at      TEXT NOT NULL DEFAULT (datetime('now')),
  concluded_at    TEXT,
  lead_auditor    TEXT,
  status          TEXT NOT NULL DEFAULT 'open',
                                                  -- open | site_visited | report_drafted |
                                                  -- report_issued | closed
  findings_count  INTEGER NOT NULL DEFAULT 0,
  penalty_zar     REAL DEFAULT 0,
  report_r2_key   TEXT,
  notes           TEXT
);

CREATE TABLE oe_compliance_inspections (
  id                       TEXT PRIMARY KEY,
  inspection_number        TEXT UNIQUE NOT NULL,

  -- Provenance
  source_event             TEXT,
  source_entity_type       TEXT,
  source_entity_id         TEXT,
  source_wave              TEXT,

  -- Regulator (NERSA officer / inspectorate)
  officer_party_id         TEXT NOT NULL,
  officer_party_name       TEXT NOT NULL,

  -- Respondent (licensee under inspection)
  respondent_party_id      TEXT NOT NULL,
  respondent_party_name    TEXT NOT NULL,

  -- Inspection descriptors
  licence_ref              TEXT,
  facility_name            TEXT NOT NULL,
  inspection_trigger       TEXT,             -- routine / complaint / incident / thematic
  contravention_tier       TEXT NOT NULL CHECK (contravention_tier IN (
    'critical', 'serious', 'minor'
  )),
  licence_condition_ref    TEXT,             -- breached condition (e.g. ERA s10(g))

  -- Enforcement arithmetic
  penalty_amount_zar       REAL,             -- imposed financial penalty / sanction
  daily_penalty_zar        REAL,             -- per-day continuing-contravention penalty
  remediation_cost_zar     REAL,             -- respondent's estimated remediation cost

  -- Refs
  findings_ref             TEXT,
  directive_ref            TEXT,
  penalty_ref              TEXT,
  appeal_ref               TEXT,
  tribunal_ref             TEXT,

  -- Narrative
  inspection_basis         TEXT,
  findings_basis           TEXT,
  directive_basis          TEXT,
  remediation_basis        TEXT,
  penalty_basis            TEXT,
  appeal_basis             TEXT,
  reason_code              TEXT,
  rod_notes                TEXT,

  -- State + lifecycle
  chain_status             TEXT NOT NULL CHECK (chain_status IN (
    'inspection_scheduled','inspection_in_progress','findings_drafted',
    'findings_issued','directive_issued','remediation_underway',
    'remediation_verified','penalty_imposed','appealed',
    'compliant_closed','enforcement_closed','withdrawn'
  )),
  inspection_scheduled_at   TEXT NOT NULL,
  inspection_in_progress_at TEXT,
  findings_drafted_at       TEXT,
  findings_issued_at        TEXT,
  directive_issued_at       TEXT,
  remediation_underway_at   TEXT,
  remediation_verified_at   TEXT,
  penalty_imposed_at        TEXT,
  appealed_at               TEXT,
  compliant_closed_at       TEXT,
  enforcement_closed_at     TEXT,
  withdrawn_at              TEXT,

  is_reportable            INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at          TEXT,
  last_sla_breach_at       TEXT,
  escalation_level         INTEGER NOT NULL DEFAULT 0,

  created_by              TEXT NOT NULL,
  created_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_compliance_inspections_events (
  id              TEXT PRIMARY KEY,
  inspection_id   TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_compliance_notices (
  id                  TEXT PRIMARY KEY,
  licensee_user_id    TEXT NOT NULL,          -- the participant who must respond
  source_case_id      TEXT,                   -- regulator_enforcement_cases.id
  source_inbox_id     TEXT,                   -- oe_regulator_inbox.id
  notice_type         TEXT NOT NULL
    CHECK (notice_type IN ('remediation','warning','penalty','suspension','revocation','information_request')),
  title               TEXT NOT NULL,
  body                TEXT NOT NULL,
  remedy_deadline_at  TEXT,                   -- ISO ts; cron flags overdue
  status              TEXT NOT NULL DEFAULT 'issued'
    CHECK (status IN ('issued','acknowledged','satisfied','overdue','escalated','withdrawn')),
  acknowledged_at     TEXT,
  satisfied_at        TEXT,
  satisfied_evidence  TEXT,                   -- regulator-side note or URL
  overdue_flagged_at  TEXT,
  issued_by           TEXT NOT NULL,
  created_at          TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_connection_energization (
  id                       TEXT PRIMARY KEY,
  energization_number      TEXT UNIQUE NOT NULL,

  -- Provenance (W75 follows W28 GCA / W58 capacity allocation)
  source_event             TEXT,
  source_entity_type       TEXT,
  source_entity_id         TEXT,
  source_wave              TEXT,
  gca_ref                  TEXT,              -- W28 Grid Connection Agreement
  capacity_allocation_ref  TEXT,              -- W58 capacity allocation

  -- Connected facility (the IPP being energized)
  facility_id              TEXT NOT NULL,
  facility_name            TEXT NOT NULL,
  connection_point         TEXT,              -- substation / busbar name
  network_operator         TEXT,              -- NTCSA / municipal DNO

  -- Classification
  technology               TEXT,              -- solar_pv / wind / battery / chp / hydro
  connection_capacity_mw   REAL NOT NULL,     -- MW at the connection point — drives the tier
  voltage_kv               REAL,              -- connection voltage
  connection_tier          TEXT NOT NULL CHECK (connection_tier IN (
    'embedded','distribution','sub_transmission','transmission','bulk'
  )),

  -- Commercial Operation
  cod_certificate_no       TEXT,
  cod_date                 TEXT,

  -- Refs
  program_ref              TEXT,
  inspection_ref           TEXT,
  energization_ref         TEXT,
  synchronization_ref      TEXT,
  compliance_test_ref      TEXT,
  suspension_ref           TEXT,
  withdrawal_ref           TEXT,

  -- Narrative
  program_basis            TEXT,
  approval_basis           TEXT,
  inspection_basis         TEXT,
  energization_basis       TEXT,
  cold_commissioning_basis TEXT,
  synchronization_basis    TEXT,
  trial_operation_basis    TEXT,
  compliance_test_basis    TEXT,
  cod_basis                TEXT,
  suspension_basis         TEXT,
  resumption_basis         TEXT,
  withdrawal_basis         TEXT,
  reason_code              TEXT,

  -- State + lifecycle
  chain_status             TEXT NOT NULL CHECK (chain_status IN (
    'connection_ready','program_review','program_approved','pre_energization_inspection',
    'energization_authorized','cold_commissioning','synchronized','trial_operation',
    'compliance_testing','commercial_operation','commissioning_suspended','connection_withdrawn'
  )),
  connection_ready_at            TEXT NOT NULL,
  program_review_at              TEXT,
  program_approved_at            TEXT,
  pre_energization_inspection_at TEXT,
  energization_authorized_at     TEXT,
  cold_commissioning_at          TEXT,
  synchronized_at                TEXT,
  trial_operation_at             TEXT,
  compliance_testing_at          TEXT,
  commercial_operation_at        TEXT,
  commissioning_suspended_at     TEXT,
  connection_withdrawn_at        TEXT,

  sla_deadline_at          TEXT,
  last_sla_breach_at       TEXT,
  is_reportable            INTEGER NOT NULL DEFAULT 0,
  escalation_level         INTEGER NOT NULL DEFAULT 0,

  created_by               TEXT NOT NULL,
  created_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_connection_energization_events (
  id              TEXT PRIMARY KEY,
  energization_id TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_consent_records (
  id                 TEXT PRIMARY KEY,
  participant_id     TEXT,                        -- NULL for pre-auth cookie consent
  session_id         TEXT,                        -- shared id for anonymous tracking
  consent_type       TEXT NOT NULL,               -- cookies_necessary | cookies_analytics |
                                                   -- cookies_marketing | terms_of_service |
                                                   -- privacy_policy | aml_disclosure
  version            TEXT NOT NULL,               -- policy version string
  accepted           INTEGER NOT NULL,            -- 0/1
  ip                 TEXT,
  user_agent         TEXT,
  created_at         TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_construction_cost_reports (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL,
  lender_id TEXT NOT NULL,
  ipp_id TEXT NOT NULL,
  report_month TEXT NOT NULL,                -- YYYY-MM format
  budget_tier TEXT NOT NULL CHECK(budget_tier IN ('small','medium','large','mega')),

  -- Financial metrics
  total_project_budget_zar REAL,             -- original approved budget
  actual_spend_to_date_zar REAL,             -- cumulative certified spend
  cost_to_complete_estimate_zar REAL,        -- IE estimate to finish
  projected_final_cost_zar REAL,             -- actual_spend + cost_to_complete
  contingency_budget_zar REAL,
  contingency_spent_zar REAL,

  -- Progress
  physical_completion_percentage REAL,       -- 0–100
  scheduled_completion_date TEXT,            -- ISO date from contract
  revised_completion_date TEXT,              -- lender-acknowledged revision

  -- IE certification
  ie_name TEXT,                              -- IE firm name
  ie_certification_ref TEXT,                 -- IE report reference number
  ie_certified_at TEXT,                      -- datetime of IE certification

  -- Overrun tracking
  overrun_zar REAL,                          -- projected_final − budget
  overrun_percentage REAL,                   -- overrun / budget * 100
  equity_injection_required_zar REAL,        -- equity cure required
  standby_facility_amount_zar REAL,          -- drawn from standby facility

  -- State machine
  chain_status TEXT NOT NULL DEFAULT 'monitoring_period_open' CHECK(chain_status IN (
    'monitoring_period_open',
    'report_requested',
    'report_submitted',
    'ie_review',
    'ie_certified',
    'budget_compliant',
    'cost_overrun_risk',
    'equity_injection_required',
    'standby_drawdown',
    'resolved',
    'default_triggered',
    'cancelled'
  )),
  sla_deadline TEXT,
  sla_breached INTEGER DEFAULT 0,
  regulator_notified INTEGER DEFAULT 0,
  actor_id TEXT,
  reason TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_consultation_notices (
  id                              TEXT PRIMARY KEY,
  notice_number                   TEXT UNIQUE NOT NULL,

  -- Provenance (the upstream wave that triggered the consultation — typically W43
  -- tariff determination, W33 licence renewal or a generic NERSA rulemaking)
  source_event                    TEXT,
  source_entity_type              TEXT,
  source_entity_id                TEXT,
  source_wave                     TEXT,

  -- Notice identity
  notice_title                    TEXT NOT NULL,
  era_section                     TEXT,                       -- e.g. 's.10', 'sch2'
  gazette_number                  TEXT,
  gazette_publication_at          TEXT,

  -- Classification
  consultation_kind               TEXT NOT NULL CHECK (consultation_kind IN (
    'rulemaking','methodology','licence_condition','code_amendment','policy','rates_decision'
  )),
  consultation_class              TEXT NOT NULL CHECK (consultation_class IN (
    'binding','guidance','consultative'
  )),
  consultation_tier               TEXT NOT NULL CHECK (consultation_tier IN (
    'minor','standard','material','landmark'
  )),
  affected_parties_estimate       INTEGER NOT NULL DEFAULT 0,   -- drives the tier
  is_binding_class                INTEGER NOT NULL DEFAULT 0,   -- mirrors consultation_class='binding'

  -- Comment period
  comment_period_start_at         TEXT,
  comment_period_end_at           TEXT,
  comment_period_minimum_days     INTEGER DEFAULT 30,           -- statutory floor
  extension_count                 INTEGER NOT NULL DEFAULT 0,
  comments_received_count         INTEGER NOT NULL DEFAULT 0,

  -- Stakeholder balance + coverage (input metrics — battery is derived live)
  industry_comments_count         INTEGER NOT NULL DEFAULT 0,
  consumer_comments_count         INTEGER NOT NULL DEFAULT 0,
  civil_society_comments_count    INTEGER NOT NULL DEFAULT 0,
  ipp_comments_count              INTEGER NOT NULL DEFAULT 0,
  government_comments_count       INTEGER NOT NULL DEFAULT 0,
  provinces_represented           INTEGER NOT NULL DEFAULT 0,
  sectors_represented             INTEGER NOT NULL DEFAULT 0,
  questions_total                 INTEGER NOT NULL DEFAULT 0,
  questions_answered              INTEGER NOT NULL DEFAULT 0,

  -- Hearing
  hearing_scheduled_at            TEXT,
  hearing_held_at                 TEXT,
  hearing_venue                   TEXT,
  presiding_member_name           TEXT,

  -- Response + adoption
  response_document_ref           TEXT,
  decision_reasons                TEXT,
  adopted_decision_ref            TEXT,

  -- Live battery snapshots (decorated live by route too, but persisted for audit)
  procedural_validity_flag        INTEGER NOT NULL DEFAULT 0,
  judicial_review_risk_score      INTEGER NOT NULL DEFAULT 0,
  predicted_consultation_days     INTEGER DEFAULT 0,

  -- Gates
  published_flag                  INTEGER NOT NULL DEFAULT 0,
  comment_period_opened_flag      INTEGER NOT NULL DEFAULT 0,
  comment_period_closed_flag      INTEGER NOT NULL DEFAULT 0,
  hearing_held_flag               INTEGER NOT NULL DEFAULT 0,
  response_drafted_flag           INTEGER NOT NULL DEFAULT 0,
  adopted_flag                    INTEGER NOT NULL DEFAULT 0,

  -- Refs
  draft_ref                       TEXT,
  publish_ref                     TEXT,
  open_ref                        TEXT,
  extension_ref                   TEXT,
  close_ref                       TEXT,
  reopen_ref                      TEXT,
  hearing_schedule_ref            TEXT,
  hearing_ref                     TEXT,
  analysis_ref                    TEXT,
  response_ref                    TEXT,
  adoption_ref                    TEXT,
  hold_ref                        TEXT,
  withdrawal_ref                  TEXT,
  cancellation_ref                TEXT,
  regulator_ref                   TEXT,

  -- Narrative
  draft_basis                     TEXT,
  publish_basis                   TEXT,
  open_basis                      TEXT,
  extension_basis                 TEXT,
  close_basis                     TEXT,
  hearing_basis                   TEXT,
  analysis_basis                  TEXT,
  response_basis                  TEXT,
  adoption_basis                  TEXT,
  hold_basis                      TEXT,
  withdrawal_basis                TEXT,
  cancellation_basis              TEXT,
  reason_code                     TEXT,
  consultation_summary            TEXT,

  -- State + lifecycle
  chain_status                    TEXT NOT NULL CHECK (chain_status IN (
    'drafted','published','open_for_comment','comment_period_closed',
    'hearing_scheduled','hearing_held','analysis','response_drafted',
    'adopted','on_hold','withdrawn','cancelled'
  )),
  drafted_at                      TEXT NOT NULL,
  published_at                    TEXT,
  open_for_comment_at             TEXT,
  comment_period_closed_at        TEXT,
  hearing_scheduled_at_status     TEXT,
  hearing_held_at_status          TEXT,
  analysis_at                     TEXT,
  response_drafted_at             TEXT,
  adopted_at                      TEXT,
  on_hold_at                      TEXT,
  withdrawn_at                    TEXT,
  cancelled_at                    TEXT,

  is_reportable                   INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                 TEXT,
  last_sla_breach_at              TEXT,
  escalation_level                INTEGER NOT NULL DEFAULT 0,

  created_by                      TEXT NOT NULL,
  created_at                      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_consultation_notices_events (
  id                 TEXT PRIMARY KEY,
  notice_id          TEXT NOT NULL,
  event_type         TEXT NOT NULL,
  from_status        TEXT,
  to_status          TEXT,
  actor_id           TEXT,
  actor_party        TEXT,
  notes              TEXT,
  payload            TEXT,
  created_at         TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_control_environment_audit (
  id                                          TEXT PRIMARY KEY,
  control_number                              TEXT UNIQUE NOT NULL,
  control_classification                      TEXT NOT NULL CHECK (control_classification IN (
    'preventive','detective','corrective','directive','governance'
  )),
  control_framework                           TEXT,
  framework_control_ref                       TEXT,
  period_label                                TEXT NOT NULL,
  period_start                                TEXT,
  period_end                                  TEXT,

  -- 8 cross-chain bridges (W118 mandatory + W119/W120 + W113/W114/W115/W116/W117)
  w113_evm_ref                                TEXT,
  w114_doc_control_ref                        TEXT,
  w115_submittal_ref                          TEXT,
  w116_rfi_ref                                TEXT,
  w117_change_order_ref                       TEXT,
  w118_block_height_range_low                 INTEGER,
  w118_block_height_range_high                INTEGER,
  w119_export_pack_ref                        TEXT,
  w120_attestation_ref                        TEXT,
  parent_control_id                           TEXT,

  -- 5 floor flags (FLOOR-AT-DIRECTIVE 1+ / FLOOR-AT-GOVERNANCE 2+)
  material_weakness_suspected                 INTEGER NOT NULL DEFAULT 0,
  regulator_audit_in_progress                 INTEGER NOT NULL DEFAULT 0,
  soc2_type2_period_open                      INTEGER NOT NULL DEFAULT 0,
  iso27001_surveillance_audit_due             INTEGER NOT NULL DEFAULT 0,
  sox_404_attestation_pending                 INTEGER NOT NULL DEFAULT 0,

  -- Design documentation (COSO + SOC 2 + ISO 27001)
  control_description                         INTEGER NOT NULL DEFAULT 0,
  control_objective                           INTEGER NOT NULL DEFAULT 0,
  responsible_party                           INTEGER NOT NULL DEFAULT 0,
  frequency_documented                        INTEGER NOT NULL DEFAULT 0,
  inputs_documented                           INTEGER NOT NULL DEFAULT 0,
  outputs_documented                          INTEGER NOT NULL DEFAULT 0,
  ipe_documented                              INTEGER NOT NULL DEFAULT 0,
  manual_or_automated                         INTEGER NOT NULL DEFAULT 0,
  coso_principle_mapped                       INTEGER NOT NULL DEFAULT 0,
  iso27001_control_mapped                     INTEGER NOT NULL DEFAULT 0,
  soc2_criteria_mapped                        INTEGER NOT NULL DEFAULT 0,
  walkthrough_evidence                        INTEGER NOT NULL DEFAULT 0,
  soa_linked                                  INTEGER NOT NULL DEFAULT 0,

  -- ToD (Test of Design) - test_plan/evidence/executed derived from timestamps
  tod_sample_size                             INTEGER NOT NULL DEFAULT 0,
  tod_reviewer_signoff                        INTEGER NOT NULL DEFAULT 0,
  tod_pass_rate_pct                           INTEGER NOT NULL DEFAULT 0,
  tod_exceptions_logged                       INTEGER NOT NULL DEFAULT 0,
  tod_passed                                  INTEGER NOT NULL DEFAULT 0,

  -- ToOE (Test of Operating Effectiveness) - test_plan/evidence/executed derived from timestamps
  tooe_sample_size                            INTEGER NOT NULL DEFAULT 0,
  tooe_reviewer_signoff                       INTEGER NOT NULL DEFAULT 0,
  tooe_pass_rate_pct                          INTEGER NOT NULL DEFAULT 0,
  tooe_exceptions_logged                      INTEGER NOT NULL DEFAULT 0,
  tooe_passed                                 INTEGER NOT NULL DEFAULT 0,

  -- Deficiency + remediation
  deficiency_severity                         TEXT,
  remediation_progress_pct                    INTEGER NOT NULL DEFAULT 0,
  external_auditor_sign_off                   INTEGER NOT NULL DEFAULT 0,

  -- Composite indexes + bands
  current_tier                                TEXT NOT NULL CHECK (current_tier IN (
    'preventive','detective','corrective','directive','governance'
  )),
  authority_required                          TEXT CHECK (authority_required IN (
    'control_owner','process_owner','CISO','audit_committee_chair'
  )),
  urgency_band                                TEXT,
  control_health_band                         TEXT,
  design_documentation_completeness_index     INTEGER NOT NULL DEFAULT 0,
  tod_test_completeness_index                 INTEGER NOT NULL DEFAULT 0,
  tooe_test_completeness_index                INTEGER NOT NULL DEFAULT 0,
  evidence_coverage_index                     INTEGER NOT NULL DEFAULT 0,
  audit_window_hours                          INTEGER NOT NULL DEFAULT 0,
  days_to_quarterly_cutoff                    INTEGER NOT NULL DEFAULT 0,
  days_to_annual_audit                        INTEGER NOT NULL DEFAULT 0,

  -- Narrative + reason codes
  title                                       TEXT,
  reason_code                                 TEXT,
  deficient_reason                            TEXT,
  exception_reason                            TEXT,
  suspend_reason                              TEXT,

  is_reportable_flag                          INTEGER NOT NULL DEFAULT 0,
  regulator_relevant                          INTEGER NOT NULL DEFAULT 0,
  regulator_reason_text                       TEXT,

  -- External-auditor (signed JWT)
  external_auditor_firm                       TEXT,
  external_auditor_engagement_ref             TEXT,
  external_auditor_jwt_jti                    TEXT,

  -- 12 forward + 4 branch lifecycle timestamps
  chain_status                                TEXT NOT NULL CHECK (chain_status IN (
    'control_defined','design_documented','walkthrough_completed',
    'tod_test_planned','tod_evidence_collected','tod_test_executed',
    'tooe_test_planned','tooe_evidence_collected','tooe_test_executed',
    'deficiency_assessed','remediation_completed','archived',
    'deficient','excepted','suspended','remediated_re_test'
  )),
  control_defined_at                          TEXT,
  design_documented_at                        TEXT,
  walkthrough_completed_at                    TEXT,
  tod_test_planned_at                         TEXT,
  tod_evidence_collected_at                   TEXT,
  tod_test_executed_at                        TEXT,
  tooe_test_planned_at                        TEXT,
  tooe_evidence_collected_at                  TEXT,
  tooe_test_executed_at                       TEXT,
  deficiency_assessed_at                      TEXT,
  remediation_completed_at                    TEXT,
  archived_at                                 TEXT,
  deficient_at                                TEXT,
  excepted_at                                 TEXT,
  suspended_at                                TEXT,
  remediated_re_test_at                       TEXT,

  -- Regulator crossing
  regulator_crossed_at                        TEXT,
  regulator_inbox_ref                         TEXT,
  regulator_ref                               TEXT,

  -- SLA (HOURS, INVERTED polarity)
  sla_target_hours                            INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                             TEXT,
  sla_breached                                INTEGER NOT NULL DEFAULT 0,
  escalation_level                            INTEGER NOT NULL DEFAULT 0,

  tenant_id                                   TEXT,
  created_by                                  TEXT NOT NULL,
  created_at                                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_control_environment_audit_events (
  id                  TEXT PRIMARY KEY,
  control_id          TEXT NOT NULL,
  event_type          TEXT NOT NULL,
  from_status         TEXT,
  to_status           TEXT,
  from_tier           TEXT,
  to_tier             TEXT,
  actor_id            TEXT,
  actor_party         TEXT,
  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_counterparty_margin (
  id                          TEXT PRIMARY KEY,
  case_number                 TEXT UNIQUE NOT NULL,

  -- Provenance
  source_event                TEXT,
  source_entity_type          TEXT,
  source_entity_id            TEXT,
  source_wave                 TEXT,

  -- Counterparty / clearing member
  counterparty_id             TEXT NOT NULL,
  counterparty_name           TEXT NOT NULL,
  member_code                 TEXT,
  account_type                TEXT CHECK (account_type IN (
    'house','client','omnibus'
  )),
  systemically_important      INTEGER NOT NULL DEFAULT 0,

  -- Exposure / collateral descriptors
  product_class               TEXT CHECK (product_class IN (
    'power_forward','power_spot','carbon','financial_derivative','repo','mixed'
  )),
  exposure_zar                REAL,            -- mark-to-market exposure at risk
  collateral_held_zar         REAL,
  margin_call_zar             REAL,
  collateral_posted_zar       REAL,
  shortfall_zar               REAL,
  default_fund_draw_zar       REAL,
  recovery_zar                REAL,
  write_off_zar               REAL,
  utilisation_pct             REAL,            -- exposure / limit
  severity_tier               TEXT NOT NULL CHECK (severity_tier IN (
    'minor','moderate','material','major','systemic'
  )),

  -- Parties
  clearing_party_id           TEXT,
  clearing_party_name         TEXT,
  member_party_id             TEXT,
  member_party_name           TEXT,

  -- Refs
  warning_ref                 TEXT,
  margin_call_ref             TEXT,
  collateral_ref              TEXT,
  restriction_ref             TEXT,
  cure_ref                    TEXT,
  default_ref                 TEXT,
  close_out_ref               TEXT,
  default_fund_ref            TEXT,

  -- Narrative
  warning_basis               TEXT,
  margin_call_basis           TEXT,
  collateral_basis            TEXT,
  restriction_basis           TEXT,
  cure_basis                  TEXT,
  default_basis               TEXT,
  close_out_basis             TEXT,
  default_fund_basis          TEXT,
  recovery_basis              TEXT,
  write_off_basis             TEXT,
  reason_code                 TEXT,
  resolution_summary          TEXT,

  -- State + lifecycle
  chain_status                TEXT NOT NULL CHECK (chain_status IN (
    'limit_active','exposure_warning','margin_call_issued','collateral_received',
    'position_restriction','cure_period','default_declared','close_out',
    'default_fund_draw','recovered','written_off','withdrawn'
  )),
  limit_active_at             TEXT NOT NULL,
  exposure_warning_at         TEXT,
  margin_call_issued_at       TEXT,
  collateral_received_at      TEXT,
  position_restriction_at     TEXT,
  cure_period_at              TEXT,
  default_declared_at         TEXT,
  close_out_at                TEXT,
  default_fund_draw_at        TEXT,
  recovered_at                TEXT,
  written_off_at              TEXT,
  withdrawn_at                TEXT,

  cure_round                  INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at             TEXT,
  last_sla_breach_at          TEXT,
  is_reportable               INTEGER NOT NULL DEFAULT 0,
  escalation_level            INTEGER NOT NULL DEFAULT 0,

  created_by                  TEXT NOT NULL,
  created_at                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_counterparty_margin_events (
  id              TEXT PRIMARY KEY,
  margin_id       TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_counterparty_offers (
  id                    TEXT PRIMARY KEY,
  offeror_participant_id TEXT NOT NULL,
  offeror_role          TEXT NOT NULL,   -- carbon_fund | lender | ipp_developer | offtaker ...
  target_role           TEXT NOT NULL,   -- role this offer is aimed at (ipp_developer ...)
  offer_kind            TEXT NOT NULL,   -- carbon_rec | carbon_voluntary | carbon_involuntary | funding_debt | funding_mezz | funding_equity | energy_supply
  registry_standard     TEXT,            -- carbon offers only: gold_standard | verra_vcs | pure_earth | i_rec | article_6_4 | cdm
  headline              TEXT NOT NULL,
  terms_json            TEXT NOT NULL DEFAULT '{}',  -- kind-specific commercial terms
  match_json            TEXT,            -- optional eligibility filter (min_capacity_mw, technology[])
  status                TEXT NOT NULL DEFAULT 'active',  -- active | paused | withdrawn
  tenant_id             TEXT NOT NULL DEFAULT 'default',
  created_at            TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at            TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_country_routing (
  country_iso          TEXT PRIMARY KEY,           -- ISO 3166-1 alpha-3 (ZAF, GBR, …)
  country_name         TEXT NOT NULL,
  ndc_authority        TEXT,                       -- e.g. 'Department of Forestry, Fisheries and the Environment'
  ndc_authority_email  TEXT,
  article_6_track      TEXT NOT NULL DEFAULT 'unknown'
    CHECK (article_6_track IN ('6.2','6.4','paris_only','non_party','unknown')),
  registry_url_pattern TEXT,                       -- e.g. 'https://verra.org/project/{proj}/vintage/{year}/serial/{serial}'
  active               INTEGER NOT NULL DEFAULT 1,
  notes                TEXT,
  updated_at           TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_covenant_certificate_events (
  id              TEXT PRIMARY KEY,
  certificate_id  TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_covenant_certificates (
  id                      TEXT PRIMARY KEY,
  certificate_number      TEXT UNIQUE NOT NULL,

  -- Provenance
  source_event            TEXT,
  source_entity_type      TEXT,
  source_entity_id        TEXT,
  source_wave             TEXT,

  -- Borrower (project company / SPV)
  borrower_party_id       TEXT NOT NULL,
  borrower_party_name     TEXT NOT NULL,

  -- Facility agent + lender of record
  facility_agent_name     TEXT,
  lender_name             TEXT,

  -- Facility descriptors
  facility_name           TEXT NOT NULL,
  facility_tier           TEXT NOT NULL CHECK (facility_tier IN (
    'senior_secured', 'mezzanine', 'subordinated'
  )),
  facility_limit          REAL,            -- committed facility size (ZAR)
  outstanding_principal   REAL,            -- drawn + outstanding (ZAR)
  test_period             TEXT,            -- e.g. 2026-Q1 / 2025-H2
  test_period_end         TEXT,            -- period-end date (ISO)

  -- Measured covenant ratios + thresholds (snapshot for this certificate)
  dscr_actual             REAL,
  dscr_threshold          REAL,
  llcr_actual             REAL,
  llcr_threshold          REAL,
  gearing_actual          REAL,            -- debt / (debt+equity), as a ratio
  gearing_threshold       REAL,
  breached_covenants      TEXT,            -- comma list e.g. 'DSCR,GEARING'

  -- Refs
  certificate_ref         TEXT,
  review_ref              TEXT,
  breach_ref              TEXT,
  waiver_ref              TEXT,
  cure_ref                TEXT,
  acceleration_ref        TEXT,

  -- Narrative
  submission_basis        TEXT,
  review_basis            TEXT,
  breach_basis            TEXT,
  waiver_basis            TEXT,
  cure_basis              TEXT,
  acceleration_basis      TEXT,
  reason_code             TEXT,
  rod_notes               TEXT,

  -- State + lifecycle
  chain_status            TEXT NOT NULL CHECK (chain_status IN (
    'certificate_due','certificate_submitted','under_review','ratios_verified',
    'compliant','breach_identified','waiver_requested','waiver_granted',
    'cure_period','cured','accelerated'
  )),
  certificate_due_at        TEXT NOT NULL,
  certificate_submitted_at  TEXT,
  under_review_at           TEXT,
  ratios_verified_at        TEXT,
  compliant_at              TEXT,
  breach_identified_at      TEXT,
  waiver_requested_at       TEXT,
  waiver_granted_at         TEXT,
  cure_period_at            TEXT,
  cured_at                  TEXT,
  accelerated_at            TEXT,

  waiver_round             INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at          TEXT,
  last_sla_breach_at       TEXT,
  escalation_level         INTEGER NOT NULL DEFAULT 0,

  created_by              TEXT NOT NULL,
  created_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_cp_clearances (
  id                        TEXT PRIMARY KEY,
  participant_id            TEXT NOT NULL,   -- lender originating the CP register

  -- Classification
  cp_tier                   TEXT NOT NULL CHECK(cp_tier IN (
    'minor','standard','major','systemic'
  )),
  facility_ref              TEXT,            -- W53 credit facility application
  project_ref               TEXT,            -- underlying project / W1 IPP-PM ref
  borrower_name             TEXT,

  -- CP counts (tracked for KPI dashboard)
  cp_count_total            INTEGER,
  cp_count_satisfied        INTEGER DEFAULT 0,
  cp_count_waived           INTEGER DEFAULT 0,
  cp_count_failed           INTEGER DEFAULT 0,

  -- Timeline
  register_submitted_at     TEXT,
  register_agreed_at        TEXT,
  satisfaction_commenced_at TEXT,
  evidence_submitted_at     TEXT,
  review_commenced_at       TEXT,
  cps_cleared_at            TEXT,
  drawdown_authorized_at    TEXT,
  closing_deadline          TEXT,            -- long-stop date negotiated in term sheet

  -- Default / failure
  cp_failed_reason          TEXT,
  cp_failed_at              TEXT,

  chain_status              TEXT NOT NULL DEFAULT 'cp_register_draft' CHECK(chain_status IN (
    'cp_register_draft','cp_register_submitted','cp_register_agreed',
    'satisfying_cps','cps_submitted','under_lender_review',
    'cps_satisfied','cps_partially_waived',
    'drawdown_authorized','cp_defaulted','withdrawn','expired'
  )),
  sla_deadline              TEXT NOT NULL,
  sla_breached              INTEGER NOT NULL DEFAULT 0,
  regulator_notified        INTEGER NOT NULL DEFAULT 0,

  actor_id                  TEXT,
  reason                    TEXT,
  created_at                TEXT NOT NULL,
  updated_at                TEXT NOT NULL
);

CREATE TABLE oe_cp_tracker (
  id                   TEXT PRIMARY KEY,
  cp_title             TEXT NOT NULL,
  cp_tier              TEXT NOT NULL CHECK (cp_tier IN ('operational', 'commercial', 'financial', 'regulatory', 'strategic')),
  project_ref          TEXT,
  lender_ref           TEXT,
  gate_ref             TEXT,
  description          TEXT,
  chain_status         TEXT NOT NULL DEFAULT 'identified' CHECK (chain_status IN (
                         'identified', 'documented', 'submitted', 'under_verification',
                         'conditional_pass', 'outstanding', 'notice_served', 'cure_underway',
                         'satisfied', 'waived', 'lapsed', 'rejected'
                       )),
  sla_deadline         TEXT,
  sla_breached         INTEGER NOT NULL DEFAULT 0,
  regulator_notified   INTEGER NOT NULL DEFAULT 0,
  actor_id             TEXT,
  reason               TEXT,
  created_at           TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at           TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_credit_facility_applications (
  id                            TEXT PRIMARY KEY,
  application_number            TEXT UNIQUE NOT NULL,

  -- Provenance (pipeline / origination source)
  source_event                  TEXT,
  source_entity_type            TEXT,
  source_entity_id              TEXT,
  source_wave                   TEXT,

  -- Parties (two-party write)
  applicant_party_id            TEXT NOT NULL,     -- the borrower / project company
  applicant_party_name          TEXT NOT NULL,
  lender_name                   TEXT,              -- lender of record
  sponsor_name                  TEXT,              -- project sponsor

  -- Facility identity
  facility_tier                 TEXT NOT NULL CHECK (facility_tier IN (
    'small','medium','large','major','systemic'
  )),
  facility_name                 TEXT NOT NULL,
  facility_type                 TEXT,              -- term_loan / revolving / bridge / mezzanine / construction / refinance
  facility_purpose              TEXT,
  facility_limit_zar_m          REAL,              -- facility limit in millions ZAR (drives the tier)
  tenor_months                  INTEGER,
  margin_bps                    REAL,
  pricing_basis                 TEXT,              -- jibar_plus / fixed / prime_linked
  project_id                    TEXT,
  project_name                  TEXT,
  sector                        TEXT,              -- solar_pv / wind / bess / chp / grid / hydro

  -- Credit metrics
  credit_rating                 TEXT,              -- internal grade
  ltv_pct                       REAL,
  dscr_base                     REAL,
  gearing_pct                   REAL,
  pd_pct                        REAL,              -- probability of default
  lgd_pct                       REAL,              -- loss given default
  ead_zar_m                     REAL,              -- exposure at default
  approved_amount_zar_m         REAL,
  conditions_count              INTEGER,
  cp_count                      INTEGER,

  -- Refs (per stage)
  screening_ref                 TEXT,
  assessment_ref                TEXT,
  committee_ref                 TEXT,
  approval_ref                  TEXT,
  agreement_ref                 TEXT,
  cp_ref                        TEXT,
  activation_ref                TEXT,
  decline_ref                   TEXT,
  regulator_ref                 TEXT,

  -- Narrative
  screening_basis               TEXT,
  assessment_basis              TEXT,
  committee_basis               TEXT,
  approval_basis                TEXT,
  conditions_basis              TEXT,
  cp_basis                      TEXT,
  activation_basis              TEXT,
  decline_basis                 TEXT,
  reason_code                   TEXT,
  decision_notes                TEXT,
  notes                         TEXT,

  referral_round                INTEGER NOT NULL DEFAULT 0,

  -- State + lifecycle
  chain_status                  TEXT NOT NULL CHECK (chain_status IN (
    'application_received','screening','credit_assessment','committee_review',
    'referred_back','conditions_pending','approved','agreement_issued',
    'cp_satisfied','facility_available','declined','withdrawn'
  )),
  application_received_at       TEXT NOT NULL,
  screening_at                  TEXT,
  credit_assessment_at          TEXT,
  committee_review_at           TEXT,
  referred_back_at              TEXT,
  conditions_pending_at         TEXT,
  approved_at                   TEXT,
  agreement_issued_at           TEXT,
  cp_satisfied_at               TEXT,
  facility_available_at         TEXT,
  declined_at                   TEXT,
  withdrawn_at                  TEXT,

  is_reportable                 INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at               TEXT,
  last_sla_breach_at            TEXT,
  escalation_level              INTEGER NOT NULL DEFAULT 0,

  created_by                    TEXT NOT NULL,
  created_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_credit_facility_applications_events (
  id                 TEXT PRIMARY KEY,
  application_id     TEXT NOT NULL,
  event_type         TEXT NOT NULL,
  from_status        TEXT,
  to_status          TEXT,
  actor_id           TEXT,
  actor_party        TEXT,
  notes              TEXT,
  payload            TEXT,
  created_at         TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_credit_insurance (
  id                        TEXT PRIMARY KEY,
  participant_id            TEXT NOT NULL,   -- IPP / project developer

  -- Policy classification
  insurance_tier            TEXT NOT NULL CHECK(insurance_tier IN (
    'short_term','medium_term','long_term','project_finance'
  )),
  insurance_type            TEXT CHECK(insurance_type IN (
    'political_risk','credit_risk','comprehensive','miga_guarantee',
    'ecic_cover','atidi_cover','lloyds_syndicate',NULL
  )),
  insurer_name              TEXT,
  policy_ref                TEXT,

  -- Underlying exposure
  project_ref               TEXT,           -- link to W20 project
  ppa_ref                   TEXT,           -- link to W22 PPA contract
  facility_ref              TEXT,           -- link to W53 credit facility

  -- Financial terms
  cover_amount_zar          REAL,
  premium_rate_pct          REAL,
  annual_premium_zar        REAL,
  policy_inception          TEXT,
  policy_expiry             TEXT,
  cover_period_years        REAL,

  -- Underwriting
  underwriting_started_at   TEXT,
  terms_issued_at           TEXT,
  terms_ref                 TEXT,
  negotiation_started_at    TEXT,
  bound_at                  TEXT,

  -- Renewal
  renewal_due_date          TEXT,
  renewed_at                TEXT,

  -- Claim
  claim_event               TEXT,           -- triggering event description
  claim_amount_zar          REAL,
  claim_lodged_at           TEXT,
  claim_assessed_at         TEXT,
  claim_paid_at             TEXT,
  claim_paid_amount_zar     REAL,
  claim_decline_reason      TEXT,

  chain_status              TEXT NOT NULL DEFAULT 'application' CHECK(chain_status IN (
    'application','underwriting','terms_issued','negotiation','bound','active',
    'renewal_due','claim_lodged','claim_assessed','claim_paid','lapsed','cancelled','declined'
  )),
  sla_deadline              TEXT NOT NULL,
  sla_breached              INTEGER NOT NULL DEFAULT 0,
  regulator_notified        INTEGER NOT NULL DEFAULT 0,

  actor_id                  TEXT,
  reason                    TEXT,
  created_at                TEXT NOT NULL,
  updated_at                TEXT NOT NULL
);

CREATE TABLE oe_crediting_period_renewals (
  id                       TEXT PRIMARY KEY,
  renewal_number           TEXT UNIQUE NOT NULL,

  -- Provenance
  source_event             TEXT,
  source_entity_type       TEXT,
  source_entity_id         TEXT,
  source_wave              TEXT,

  -- Project + standard + VVB
  project_id               TEXT NOT NULL,
  project_name             TEXT NOT NULL,
  registry_standard        TEXT NOT NULL CHECK (registry_standard IN (
    'verra_vcs','gold_standard','article_6_4','cdm'
  )),
  methodology_id           TEXT,
  vvb_name                 TEXT,
  proponent_party_id       TEXT NOT NULL,
  proponent_party_name     TEXT NOT NULL,

  -- Crediting-period descriptors
  issuance_tier            TEXT NOT NULL CHECK (issuance_tier IN (
    'minor','moderate','material','major','mega'
  )),
  annual_issuance_tco2e    REAL,
  crediting_period_number  INTEGER,            -- which renewal (1st/2nd/3rd…)
  current_period_start     TEXT,
  current_period_end       TEXT,               -- the expiring period (lapse driver)
  renewed_period_start     TEXT,
  renewed_period_end       TEXT,

  -- Baseline reassessment
  original_baseline_tco2e  REAL,               -- baseline of the expiring period
  revised_baseline_tco2e   REAL,               -- reassessed baseline for renewal
  baseline_reduction_pct   REAL,               -- (orig - revised)/orig * 100, clamped >=0
  additionality_outcome    TEXT,               -- additional / not_additional / conditional

  -- Refs
  application_ref          TEXT,
  completeness_ref         TEXT,
  vvb_report_ref           TEXT,
  decision_ref             TEXT,
  refusal_ref              TEXT,

  -- Narrative
  submission_basis         TEXT,
  completeness_basis       TEXT,
  revision_basis           TEXT,
  baseline_basis           TEXT,
  additionality_basis      TEXT,
  validation_basis         TEXT,
  decision_basis           TEXT,
  refusal_basis            TEXT,
  reason_code              TEXT,
  renewal_summary          TEXT,

  -- State + lifecycle
  chain_status             TEXT NOT NULL CHECK (chain_status IN (
    'renewal_due','application_submitted','completeness_check','revision_requested',
    'baseline_reassessment','additionality_retest','vvb_validation','standard_review',
    'renewed','refused','withdrawn','lapsed'
  )),
  renewal_due_at            TEXT NOT NULL,
  application_submitted_at  TEXT,
  completeness_check_at     TEXT,
  revision_requested_at     TEXT,
  baseline_reassessment_at  TEXT,
  additionality_retest_at   TEXT,
  vvb_validation_at         TEXT,
  standard_review_at        TEXT,
  renewed_at                TEXT,
  refused_at                TEXT,
  withdrawn_at              TEXT,
  lapsed_at                 TEXT,

  revision_round           INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at          TEXT,
  last_sla_breach_at       TEXT,
  is_reportable            INTEGER NOT NULL DEFAULT 0,
  escalation_level         INTEGER NOT NULL DEFAULT 0,

  created_by               TEXT NOT NULL,
  created_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_crediting_period_renewals_events (
  id              TEXT PRIMARY KEY,
  renewal_id      TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_cross_border_trades (
  id                        TEXT PRIMARY KEY,
  participant_id            TEXT NOT NULL,   -- trader submitting for pre-approval

  -- Transaction classification
  cbt_tier                  TEXT NOT NULL CHECK(cbt_tier IN (
    'small','standard','large','systemic'
  )),
  counterparty_jurisdiction TEXT,            -- ISO 3166 country code
  counterparty_type         TEXT CHECK(counterparty_type IN (
    'non_resident_firm','foreign_gov','multilateral','sadc_member','eu_firm','other',NULL
  )),
  trade_type                TEXT CHECK(trade_type IN (
    'spot_energy','forward_contract','option','swap','emissions_credit',NULL
  )),
  notional_zar              REAL,
  notional_currency         TEXT DEFAULT 'ZAR',

  -- Underlying references
  underlying_trade_ref      TEXT,            -- linked trade from W44
  algo_cert_ref             TEXT,            -- W60 algo certification if algorithmic

  -- FSCA approval
  fsca_application_ref      TEXT,
  fsca_submitted_at         TEXT,
  fsca_review_started_at    TEXT,
  fsca_approval_ref         TEXT,
  fsca_approved_at          TEXT,
  fsca_rejection_reason     TEXT,

  -- SARB ExCon approval
  sarb_application_ref      TEXT,
  sarb_submitted_at         TEXT,
  sarb_review_started_at    TEXT,
  sarb_approval_ref         TEXT,
  sarb_approved_at          TEXT,
  sarb_rejection_reason     TEXT,

  -- Execution
  trade_executed_at         TEXT,
  trade_settlement_date     TEXT,

  chain_status              TEXT NOT NULL DEFAULT 'pre_approval_required' CHECK(chain_status IN (
    'pre_approval_required','fsca_application','sarb_excon_application',
    'fsca_under_review','sarb_under_review','fsca_approved','fully_approved',
    'trade_executed','fsca_rejected','sarb_rejected','withdrawn','expired'
  )),
  sla_deadline              TEXT NOT NULL,
  sla_breached              INTEGER NOT NULL DEFAULT 0,
  regulator_notified        INTEGER NOT NULL DEFAULT 0,

  actor_id                  TEXT,
  reason                    TEXT,
  created_at                TEXT NOT NULL,
  updated_at                TEXT NOT NULL
);

CREATE TABLE oe_csat_records (
  id                      TEXT PRIMARY KEY,
  participant_id          TEXT NOT NULL,   -- support requestor / customer
  ticket_id               TEXT,            -- reference to oe_support_tickets (W14)
  support_tier            TEXT NOT NULL CHECK(support_tier IN ('p1_critical','p2_high','p3_medium','p4_low')),
  resolved_at             TEXT,            -- when the ticket was resolved

  -- Survey
  survey_sent_at          TEXT,
  survey_expires_at       TEXT,
  survey_responded_at     TEXT,
  csat_score              INTEGER CHECK(csat_score BETWEEN 1 AND 5 OR csat_score IS NULL),
  csat_comment            TEXT,

  -- Follow-up
  follow_up_reason        TEXT,            -- why follow-up was needed
  follow_up_sent_at       TEXT,
  follow_up_responded_at  TEXT,
  follow_up_score         INTEGER CHECK(follow_up_score BETWEEN 1 AND 5 OR follow_up_score IS NULL),

  -- Escalation
  escalation_reason       TEXT,
  escalated_at            TEXT,
  escalation_resolved_at  TEXT,
  escalation_resolution   TEXT,

  -- Aggregate
  resolution_time_minutes INTEGER,        -- actual resolution time
  sla_target_minutes      INTEGER,        -- SLA target for this tier
  sla_met                 INTEGER,        -- 0/1

  chain_status            TEXT NOT NULL DEFAULT 'survey_pending' CHECK(chain_status IN (
    'survey_pending','survey_sent','survey_completed','score_analysis',
    'follow_up_sent','follow_up_received','escalated',
    'closed_satisfied','closed_escalated','no_response'
  )),
  sla_deadline            TEXT NOT NULL,
  sla_breached            INTEGER NOT NULL DEFAULT 0,
  regulator_notified      INTEGER NOT NULL DEFAULT 0,

  actor_id                TEXT,
  reason                  TEXT,
  created_at              TEXT NOT NULL,
  updated_at              TEXT NOT NULL
);

CREATE TABLE oe_curtailment_claims (
  id                      TEXT PRIMARY KEY,
  claim_number            TEXT UNIQUE NOT NULL,

  -- Provenance
  source_event            TEXT,
  source_entity_type      TEXT,
  source_entity_id        TEXT,
  source_wave             TEXT,

  -- Seller (IPP / generator) + buyer (offtaker)
  seller_party_id         TEXT NOT NULL,
  seller_party_name       TEXT NOT NULL,
  buyer_party_name        TEXT,
  arbiter_name            TEXT,

  -- PPA / facility descriptors
  ppa_ref                 TEXT,            -- the W22 PPA contract this settles against
  facility_name           TEXT NOT NULL,
  facility_tier           TEXT NOT NULL CHECK (facility_tier IN (
    'utility_scale', 'commercial', 'embedded'
  )),
  contracted_capacity_mw  REAL,            -- nameplate / contracted MW
  tariff_per_mwh          REAL,            -- PPA tariff (post-W39 escalation) ZAR/MWh

  -- Curtailment / deemed-energy descriptors
  curtailment_type        TEXT,            -- economic / system_security / grid_constraint / network_outage
  curtailment_event       TEXT,            -- short label of the triggering event
  curtailment_hours       REAL,            -- duration of the curtailment instruction
  deemed_energy_mwh       REAL,            -- claimed avoided generation (MWh)
  claimed_amount          REAL,            -- seller's claim (ZAR)
  proposed_amount         REAL,            -- buyer's proposed quantum (ZAR)
  agreed_amount           REAL,            -- agreed quantum (ZAR)
  settled_amount          REAL,            -- paid (ZAR)

  -- Refs
  log_ref                 TEXT,
  classification_ref      TEXT,
  claim_ref               TEXT,
  validation_ref          TEXT,
  quantum_ref             TEXT,
  settlement_ref          TEXT,
  dispute_ref             TEXT,
  arbitration_ref         TEXT,

  -- Narrative
  log_basis               TEXT,
  classification_basis    TEXT,
  claim_basis             TEXT,
  validation_basis        TEXT,
  quantum_basis           TEXT,
  settlement_basis        TEXT,
  dispute_basis           TEXT,
  arbitration_basis       TEXT,
  reason_code             TEXT,
  rod_notes               TEXT,

  -- State + lifecycle
  chain_status            TEXT NOT NULL CHECK (chain_status IN (
    'curtailment_logged','classification_review','claim_prepared','claim_submitted',
    'validation_underway','quantum_proposed','quantum_agreed','compensation_settled',
    'disputed','arbitrated','non_compensable','withdrawn'
  )),
  curtailment_logged_at     TEXT NOT NULL,
  classification_review_at  TEXT,
  claim_prepared_at         TEXT,
  claim_submitted_at        TEXT,
  validation_underway_at    TEXT,
