CREATE TABLE oe_cyber_incidents (
  id                              TEXT PRIMARY KEY,
  case_number                     TEXT NOT NULL UNIQUE,
  asset_scope                     TEXT NOT NULL,    -- e.g. "trading-vpn" | "settlement-api" | "broker-dashboard" | "dr-storage"
  affected_system                 TEXT NOT NULL,    -- system name / cluster
  project_id                      TEXT,             -- optional IPP link
  detected_at                     TEXT NOT NULL,
  reported_at                     TEXT NOT NULL,
  reported_by                     TEXT NOT NULL,
  incident_type                   TEXT NOT NULL,    -- 'unauthorised_access' | 'data_exfiltration' | 'ransomware' | 'phishing' | 'ddos' | 'insider_threat' | 'config_drift' | 'credential_compromise'
  incident_tier                   TEXT NOT NULL,    -- catastrophic|major|personal_data|operational|low
  threat_vector                   TEXT NOT NULL,    -- e.g. "spear-phishing", "exploited 0-day", "supply chain"
  records_affected                INTEGER NOT NULL DEFAULT 0,
  data_categories                 TEXT,             -- 'PII;banking;biometrics' semicolon-separated tags
  containment_summary             TEXT,
  rca_summary                     TEXT,
  remediation_plan                TEXT,
  linked_wo_id                    TEXT,             -- W16 work order if remediation dispatched as WO
  regulator_notified              INTEGER NOT NULL DEFAULT 0,
  regulator_authority             TEXT,             -- 'IR' (POPIA s22) | 'SAPS_CYBERCRIME' (Cybercrimes Act s54) | 'IR;SAPS_CYBERCRIME'
  regulator_ref                   TEXT,             -- IR / SAPS reference number(s)
  subjects_notified               INTEGER NOT NULL DEFAULT 0,
  subjects_notified_count         INTEGER NOT NULL DEFAULT 0,
  chain_status                    TEXT NOT NULL,    -- detected|triaged|contained|notified_regulator|notified_subjects|investigating|remediation_planned|remediation_executing|verified|closed|escalated|false_alarm
  triaged_at                      TEXT,
  contained_at                    TEXT,
  notified_regulator_at           TEXT,
  notified_subjects_at            TEXT,
  investigating_at                TEXT,
  remediation_planned_at          TEXT,
  remediation_executing_at        TEXT,
  verified_at                     TEXT,
  escalated_at                    TEXT,
  false_alarm_at                  TEXT,
  closed_at                       TEXT,
  closure_notes                   TEXT,
  sla_deadline_at                 TEXT,
  last_sla_breach_at              TEXT,
  escalation_level                INTEGER NOT NULL DEFAULT 0,
  created_by                      TEXT NOT NULL,
  created_at                      TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at                      TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_data_export_requests (
  id                 TEXT PRIMARY KEY,
  participant_id     TEXT NOT NULL,
  status             TEXT NOT NULL DEFAULT 'queued',
                                                  -- queued | processing | ready | downloaded |
                                                  -- expired | failed
  r2_key             TEXT,                        -- zip in R2 once ready
  byte_size          INTEGER,
  requested_at       TEXT NOT NULL DEFAULT (datetime('now')),
  completed_at       TEXT,
  downloaded_at      TEXT,
  expires_at         TEXT,                        -- 7 days after ready
  error              TEXT
);

CREATE TABLE oe_data_subject_requests (
  id TEXT PRIMARY KEY,
  tenant_id TEXT NOT NULL,
  -- Request metadata
  requester_name TEXT NOT NULL,
  requester_email TEXT NOT NULL,
  requester_id_number TEXT,          -- SA ID or passport (POPIA §26 verification)
  relationship TEXT NOT NULL CHECK (relationship IN ('data_subject','authorised_representative','guardian')),
  -- Request classification
  request_type TEXT NOT NULL CHECK (request_type IN ('access','correction','deletion','objection','portability','restriction')),
  -- Tier drives SLA (MIXED by type, stored as snapshot)
  sla_days INTEGER NOT NULL,         -- computed from request_type at creation
  -- Subject matter
  data_categories TEXT,              -- JSON array: personal_info, financial, health, etc.
  systems_involved TEXT,             -- JSON array: D1 tables / KV namespaces
  -- Processing chain
  chain_status TEXT NOT NULL DEFAULT 'received' CHECK (chain_status IN (
    'received','acknowledged','identity_verified','data_mapped','legal_assessment',
    'response_drafted','fulfilled','partial_disclosure','refused',
    'erasure_completed','objection_upheld','withdrawn'
  )),
  -- Outcome tracking
  legal_ground_for_refusal TEXT,     -- POPIA §11 / PAIA exemption
  partial_disclosure_rationale TEXT,
  response_ref TEXT,                  -- reference number issued to subject
  -- Regulator notification
  ir_notified INTEGER NOT NULL DEFAULT 0,   -- Information Regulator notified?
  ir_notification_ref TEXT,
  -- SLA
  sla_deadline TEXT NOT NULL,
  -- Audit
  actor_id TEXT,
  reason_code TEXT,
  reason_detail TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_deal_links (
