  id                TEXT PRIMARY KEY,
  owner_id          TEXT NOT NULL,    -- subscriber who runs the generation
  owner_role        TEXT NOT NULL,    -- carbon_fund | lender | ipp_developer ...
  subject_type      TEXT NOT NULL,    -- ipp_projects | oe_carbon_projects | fund_facility
  subject_id        TEXT NOT NULL,
  subject_label     TEXT,
  doc_type          TEXT NOT NULL,    -- pdd | mrv | validation_report | rec_issuance_request | term_sheet | info_memo
  registry_standard TEXT,             -- gold_standard | verra_vcs | pure_earth | i_rec | article_6_4 | cdm
  status            TEXT NOT NULL DEFAULT 'generated',  -- generated | in_review | submitted | accepted | rejected
  title             TEXT NOT NULL,
  content_md        TEXT NOT NULL DEFAULT '',   -- rendered submission-format body (markdown)
  meta_json         TEXT NOT NULL DEFAULT '{}', -- source refs + computed figures
  r2_key            TEXT,             -- set when persisted to vault
  tenant_id         TEXT NOT NULL DEFAULT 'default',
  created_at        TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at        TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_document_envelopes (
  id              TEXT PRIMARY KEY,
  template_id     TEXT NOT NULL REFERENCES oe_document_templates(id),
  raised_by       TEXT NOT NULL,
  raised_at       TEXT NOT NULL DEFAULT (datetime('now')),
  variables_json  TEXT NOT NULL,                       -- filled values
  body_rendered   TEXT NOT NULL,                       -- snapshot of rendered text
  signatories_json TEXT NOT NULL,                      -- [{ participant_id, role, label, signed_at? }]
  status          TEXT NOT NULL DEFAULT 'sent',        -- sent|in_progress|completed|cancelled|expired
  completed_at    TEXT,
  cancelled_at    TEXT,
  cancellation_reason TEXT,
  r2_signed_key   TEXT,                                -- final PDF/MD location
  document_hash   TEXT                                  -- SHA-256 of body_rendered, used as the signing payload
);

CREATE TABLE oe_document_templates (
  id              TEXT PRIMARY KEY,
  template_key    TEXT UNIQUE NOT NULL,                -- e.g. 'ppa.standard.v3'
  display_name    TEXT NOT NULL,
  category        TEXT NOT NULL,                       -- ppa|nda|epc|amendment|consent|other
  body_md         TEXT NOT NULL,                       -- markdown with {{vars}}
  variables_json  TEXT NOT NULL,                       -- declared vars + descriptions
  required_signatories_json TEXT NOT NULL,             -- ordered [{ role, label }]
  jurisdiction    TEXT,                                -- ZA-NERSA, JSE-SRL, REIPPPP, etc.
  version         INTEGER NOT NULL DEFAULT 1,
  status          TEXT NOT NULL DEFAULT 'draft',       -- draft|published|deprecated
  created_by      TEXT,
  created_at      TEXT NOT NULL DEFAULT (datetime('now')),
  published_at    TEXT,
  deprecated_at   TEXT
);

CREATE TABLE oe_drawdown_chain (
  id                   TEXT PRIMARY KEY,
  drawdown_number      TEXT UNIQUE NOT NULL,
  facility_id          TEXT,
  project_id           TEXT,
  participant_id       TEXT NOT NULL,                   -- IPP requesting
  lender_id            TEXT NOT NULL,                   -- lender extending
  project_name         TEXT NOT NULL,
  facility_name        TEXT,
  tranche_label        TEXT NOT NULL DEFAULT 'tranche_1',
  amount_zar           REAL NOT NULL DEFAULT 0,
  tranche_tier         TEXT NOT NULL DEFAULT 'equity',  -- senior | mezz | equity
  chain_status         TEXT NOT NULL DEFAULT 'requested',
  requested_at         TEXT,
  documents_at         TEXT,
  ie_review_at         TEXT,
  cp_started_at        TEXT,
  on_hold_at           TEXT,
  approved_at          TEXT,
  funded_at            TEXT,
  closed_at            TEXT,
  ie_certifier         TEXT,                            -- Independent Engineer firm
  ie_cert_doc_ref      TEXT,                            -- IE cert ref
  cp_evidence_ref      TEXT,                            -- CP evidence bundle ref
  sarb_disclosure_ref  TEXT,                            -- SARB exposure disclosure ref (senior only)
  query_notes          TEXT,
  rejection_reason     TEXT,
  cancellation_reason  TEXT,
  funding_account_ref  TEXT,                            -- treasury wire ref once funded
  drawdown_notes       TEXT,
  sla_deadline_at      TEXT,
  last_sla_breach_at   TEXT,
  escalation_level     INTEGER NOT NULL DEFAULT 0,
  created_by           TEXT NOT NULL,
  created_at           TEXT NOT NULL DEFAULT (datetime('now')),
