);

CREATE TABLE oe_drawdown_chain_events (
  id          TEXT PRIMARY KEY,
  drawdown_id TEXT NOT NULL,
  event_type  TEXT NOT NULL,    -- documents_submitted | ie_review_started |
                                -- cp_passed | queried | resumed |
                                -- approved | funded | closed |
                                -- rejected | cancelled | sla_breached
  from_status TEXT,
  to_status   TEXT,
  actor_id    TEXT,
  notes       TEXT,
  payload     TEXT,              -- JSON
  created_at  TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_dscr_monitoring (
  id                              TEXT PRIMARY KEY,
  monitoring_number               TEXT UNIQUE NOT NULL,

  source_event                    TEXT,
  source_entity_type              TEXT,
  source_entity_id                TEXT,
  source_wave                     TEXT,

  facility_id                     TEXT NOT NULL,
  facility_name                   TEXT NOT NULL,
  project_id                      TEXT NOT NULL,
  project_name                    TEXT NOT NULL,
  borrower_id                     TEXT NOT NULL,
  borrower_name                   TEXT NOT NULL,
  lender_agent_id                 TEXT NOT NULL,
  lender_agent_name               TEXT NOT NULL,

  test_period_label               TEXT NOT NULL,
  test_period_start               TEXT NOT NULL,
  test_period_end                 TEXT NOT NULL,
  test_date                       TEXT NOT NULL,

  -- Threshold matrix (from the facility agreement)
  pass_threshold                  REAL NOT NULL DEFAULT 1.30,
  lockup_threshold                REAL NOT NULL DEFAULT 1.20,
  default_floor                   REAL NOT NULL DEFAULT 1.00,
  equity_cure_cap_multiple        REAL NOT NULL DEFAULT 1.0,

  -- Measured ratios
  current_dscr                    REAL,
  forward_dscr_p12m               REAL,
  backward_dscr_12m               REAL,
  llcr_value                      REAL,
  plcr_value                      REAL,

  -- Cash-flow inputs (ZAR)
  cfads_period_zar                REAL NOT NULL DEFAULT 0,
  debt_service_period_zar         REAL NOT NULL DEFAULT 0,
  shortfall_zar                   REAL NOT NULL DEFAULT 0,
  outstanding_debt_zar            REAL NOT NULL DEFAULT 0,
  npv_loan_life_zar               REAL NOT NULL DEFAULT 0,
  npv_project_life_zar            REAL NOT NULL DEFAULT 0,

  -- Cure inputs
  equity_cure_available_zar       REAL NOT NULL DEFAULT 0,
  dsra_balance_zar                REAL NOT NULL DEFAULT 0,
  proposed_cure_amount_zar        REAL NOT NULL DEFAULT 0,
  executed_cure_amount_zar        REAL NOT NULL DEFAULT 0,

  -- Sister-loan + cross-default
  sister_loan_id                  TEXT,
  sister_loan_dscr                REAL,

  -- Tier (RE-DERIVED)
  dscr_tier                       TEXT NOT NULL CHECK (dscr_tier IN ('minor','standard','material','severe')),
  is_systemic_carrier             INTEGER NOT NULL DEFAULT 0,

  -- Trend (annualised; negative = deteriorating)
  annual_trend                    REAL NOT NULL DEFAULT 0,

  -- Lifecycle flags
  watch_flag                      INTEGER NOT NULL DEFAULT 0,
  breach_flag                     INTEGER NOT NULL DEFAULT 0,
  lock_up_flag                    INTEGER NOT NULL DEFAULT 0,
  cure_proposed_flag              INTEGER NOT NULL DEFAULT 0,
  cure_executing_flag             INTEGER NOT NULL DEFAULT 0,
  cure_validated_flag             INTEGER NOT NULL DEFAULT 0,
  accelerated_flag                INTEGER NOT NULL DEFAULT 0,
  waived_flag                     INTEGER NOT NULL DEFAULT 0,

  -- Refs
  last_action_ref                 TEXT,
  regulator_ref                   TEXT,
  chain_basis                     TEXT,
  reason_code                     TEXT,
  monitoring_summary              TEXT,

  -- State machine
  chain_status                    TEXT NOT NULL CHECK (chain_status IN (
    'period_open','data_collected','computed','certified_clean',
    'watch','breach_recorded','cure_proposed','cure_in_progress',
    'cure_validated','lock_up','accelerated','waived'
  )),
  period_open_at                  TEXT NOT NULL,
  data_collected_at               TEXT,
  computed_at                     TEXT,
  certified_clean_at              TEXT,
  watch_at                        TEXT,
  breach_recorded_at              TEXT,
  cure_proposed_at                TEXT,
  cure_in_progress_at             TEXT,
  cure_validated_at               TEXT,
  lock_up_at                      TEXT,
  accelerated_at                  TEXT,
  waived_at                       TEXT,

  -- Audit / SLA
  is_reportable                   INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                 TEXT,
  last_sla_breach_at              TEXT,
  escalation_level                INTEGER NOT NULL DEFAULT 0,

  created_by                      TEXT NOT NULL,
  created_at                      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_dscr_monitoring_events (
  id                 TEXT PRIMARY KEY,
  monitoring_id      TEXT NOT NULL,
  event_type         TEXT NOT NULL,
  from_status        TEXT,
  to_status          TEXT,
  actor_id           TEXT,
  actor_party        TEXT,
  notes              TEXT,
  payload            TEXT,
  created_at         TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_dscr_reports (
  id                        TEXT PRIMARY KEY,
  participant_id            TEXT NOT NULL,   -- IPP developer

  -- Report identity
  dscr_tier                 TEXT NOT NULL CHECK(dscr_tier IN (
    'emerging','standard','large','systemically_important'
  )),
  reporting_period          TEXT NOT NULL,   -- e.g. "2025-Q1" or "2025-H1"
  report_date               TEXT,            -- date of actual report
  dfi_name                  TEXT,            -- primary DFI (IDC/DBSA/Nedbank/etc.)
  dfi_reference             TEXT,            -- DFI loan reference

  -- DSCR inputs
  net_revenue_zar           REAL,
  operating_costs_zar       REAL,
  debt_service_zar          REAL,            -- principal + interest
  dscr_value                REAL,            -- net_revenue / debt_service (after O&M)
  minimum_dscr_covenant     REAL DEFAULT 1.20,
  dscr_cushion              REAL,            -- dscr_value - minimum_dscr_covenant

  -- IE certification
  ie_name                   TEXT,
  ie_certification_ref      TEXT,
  ie_certified_at           TEXT,
  ie_comments               TEXT,

  -- DFI submission and queries
  dfi_submitted_at          TEXT,
  dfi_query_details         TEXT,
  dfi_query_raised_at       TEXT,
  ipp_response_summary      TEXT,
  ipp_responded_at          TEXT,
  dfi_accepted_at           TEXT,

  -- Breach
  breach_dscr               REAL,
  breach_type               TEXT CHECK(breach_type IN ('historical','projected','both',NULL)),
  cure_period_days          INTEGER,
  covenant_breach_at        TEXT,

  chain_status              TEXT NOT NULL DEFAULT 'data_gathering' CHECK(chain_status IN (
    'data_gathering','calculation','ie_review','ie_certified',
    'dfi_submitted','dfi_queries','queries_responded',
    'accepted','covenant_breach','withdrawn'
  )),
  sla_deadline              TEXT NOT NULL,
  sla_breached              INTEGER NOT NULL DEFAULT 0,
  regulator_notified        INTEGER NOT NULL DEFAULT 0,

  actor_id                  TEXT,
  reason                    TEXT,
  created_at                TEXT NOT NULL,
  updated_at                TEXT NOT NULL
);

CREATE TABLE oe_ed_commitment_events (
  id            TEXT PRIMARY KEY,
  commitment_id TEXT NOT NULL,
  event_type    TEXT NOT NULL,
  from_status   TEXT,
  to_status     TEXT,
  actor_id      TEXT,
  notes         TEXT,
  payload       TEXT,
  created_at    TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_ed_commitments (
  id                              TEXT PRIMARY KEY,
  case_number                     TEXT NOT NULL UNIQUE,
  project_id                      TEXT NOT NULL,
  project_name                    TEXT NOT NULL,
  bid_window                      TEXT NOT NULL,    -- e.g. 'BW5', 'BW6', 'RMIPPPP'
  commitment_type                 TEXT NOT NULL,    -- ownership|local_content|jobs|skills|enterprise_dev|socio_economic|community_trust
  commitment_label                TEXT NOT NULL,    -- human label e.g. "Black ownership %", "Local content %", "FTE jobs"
  baseline_value                  REAL NOT NULL,    -- contractual commitment (e.g. 30 for 30%, or 450 for 450 FTE)
  baseline_unit                   TEXT NOT NULL,    -- 'percent' | 'fte' | 'zar' | 'count'
  reporting_period                TEXT NOT NULL,    -- 'YYYY-Qn' or 'YYYY' for the most recent reporting cycle
  current_value                   REAL,             -- latest reported value
  variance_pct                    REAL,             -- (current - baseline) / baseline * 100 — negative = under
  variance_threshold_pct          REAL NOT NULL DEFAULT -5.0, -- below this fires variance_flagged
  cure_plan_summary               TEXT,
  cure_plan_filed_at              TEXT,
  cure_plan_approved_at           TEXT,
  remediation_summary             TEXT,
  linked_wo_id                    TEXT,             -- W16 work order if remediation dispatched as WO
  penalty_amount_zar              REAL,
  penalty_ref                     TEXT,
  regulator_authority             TEXT,             -- 'IPPO' | 'DMRE' | 'DTI' | combined
  regulator_ref                   TEXT,             -- IPPO/DMRE/DTI reference number(s)
  chain_status                    TEXT NOT NULL,    -- 9 states + escalated + false_alarm
  baseline_locked_at              TEXT NOT NULL,
  monitoring_at                   TEXT,
  variance_flagged_at             TEXT,
  cure_plan_required_at           TEXT,
  cure_plan_submitted_at          TEXT,
  cure_executing_at               TEXT,
  verified_compliant_at           TEXT,
  penalty_issued_at               TEXT,
  escalated_at                    TEXT,
  false_alarm_at                  TEXT,
  closed_at                       TEXT,
  closure_notes                   TEXT,
  sla_deadline_at                 TEXT,
  last_sla_breach_at              TEXT,
  escalation_level                INTEGER NOT NULL DEFAULT 0,
  created_by                      TEXT NOT NULL,
  created_at                      TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at                      TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_email_outbox (
  id          TEXT PRIMARY KEY,
  to_addr     TEXT NOT NULL,
  template    TEXT NOT NULL,
  payload     TEXT NOT NULL DEFAULT '{}',  -- JSON of the template data
