CREATE TABLE oe_enforcement_action_events (
  id                  TEXT PRIMARY KEY,
  action_id           TEXT NOT NULL,
  event_type          TEXT NOT NULL,
  from_status         TEXT,
  to_status           TEXT,
  actor_id            TEXT,
  actor_party         TEXT,
  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_enforcement_actions (
  id                                  TEXT PRIMARY KEY,
  case_number                         TEXT UNIQUE NOT NULL,

  -- Provenance — upstream chain that triggered the case
  source_event                        TEXT,
  source_entity_type                  TEXT,
  source_entity_id                    TEXT,
  source_wave                         TEXT,
  trigger_kind                        TEXT CHECK (trigger_kind IN (
    'compliance_inspection','consumer_complaint','consultation_breach',
    'tariff_audit','market_surveillance','self_report','periodic_review',
    'whistleblower','regulator_initiated'
  )),

  -- Respondent identity
  respondent_party_id                 TEXT NOT NULL,
  respondent_party_name               TEXT,
  respondent_licence_no               TEXT,
  respondent_persona                  TEXT,
  respondent_contact                  TEXT,

  -- Allegation classification
  allegation_class                    TEXT NOT NULL CHECK (allegation_class IN (
    'tariff_non_compliance','metering_failure','reporting_failure',
    'licence_condition_breach','grid_code_breach','consumer_protection',
    'safety_violation','environmental_breach','market_abuse',
    'unlicensed_operation','repeat_offender','systemic_market_abuse'
  )),
  allegation_summary                  TEXT,
  era_section_cited                   TEXT,
  offence_count                       INTEGER NOT NULL DEFAULT 1,
  contravention_period_start          TEXT,
  contravention_period_end            TEXT,

  -- Tier + authority (RE-DERIVED on every transition)
  penalty_tier                        TEXT NOT NULL CHECK (penalty_tier IN (
    'minor','standard','material','severe'
  )),
  authority_required                  TEXT CHECK (authority_required IN (
    'enforcement_officer','panel_chair','council_subcommittee','full_council'
  )),

  -- Penalty quantum (ERA s35 cap R1m per offence; can stack)
  proposed_penalty_per_offence_zar    REAL NOT NULL DEFAULT 0,
  proposed_penalty_total_zar          REAL NOT NULL DEFAULT 0,
  imposed_penalty_zar                 REAL,
  recovered_zar                       REAL NOT NULL DEFAULT 0,
  accrued_interest_zar                REAL NOT NULL DEFAULT 0,

  -- Audi (representations period) tracking
  representations_opened_at           TEXT,
  representations_closed_at           TEXT,
  representations_received_flag       INTEGER NOT NULL DEFAULT 0,
  representations_summary             TEXT,
  hearing_requested_flag              INTEGER NOT NULL DEFAULT 0,
  hearing_held_flag                   INTEGER NOT NULL DEFAULT 0,
  reasoned_refusal_flag               INTEGER NOT NULL DEFAULT 0,
  procedural_irregularity_flag        INTEGER NOT NULL DEFAULT 0,

  -- Council determination
  determination_liable_flag           INTEGER,
  determination_basis                 TEXT,
  determination_date                  TEXT,

  -- Recovery / enforcement
  enforcement_step                    TEXT CHECK (enforcement_step IN (
    'none','demand_letter','writ_issued','sheriff_attachment',
    'garnishee','contempt_application'
  )),
  enforcement_step_at                 TEXT,
  payment_due_date                    TEXT,
  days_overdue                        INTEGER NOT NULL DEFAULT 0,

  -- Appeal
  appeal_filed_at                     TEXT,
  appeal_forum                        TEXT,
  appeal_outcome                      TEXT,

  -- Repeat-offender history (denormalised for live battery)
  prior_penalty_count                 INTEGER NOT NULL DEFAULT 0,
  days_since_last_penalty             INTEGER,

  -- Refs
  serve_ref                           TEXT,
  hearing_ref                         TEXT,
  determination_ref                   TEXT,
  penalty_ref                         TEXT,
  payment_ref                         TEXT,
  appeal_ref                          TEXT,
  enforcement_ref                     TEXT,
  regulator_ref                       TEXT,

  -- Narrative
  allegations_basis                   TEXT,
  determination_summary               TEXT,
  penalty_basis                       TEXT,
  appeal_basis                        TEXT,
  enforcement_basis                   TEXT,
  reason_code                         TEXT,

  -- State + lifecycle (12 status states + cancelled handled via withdrawn)
  chain_status                        TEXT NOT NULL CHECK (chain_status IN (
    'case_opened','allegations_drafted','allegations_served',
    'representations_period','hearing_held','determination',
    'penalty_imposed','paid','appealed','enforced_via_court',
    'dismissed','withdrawn'
  )),
  case_opened_at                      TEXT NOT NULL,
  allegations_drafted_at              TEXT,
  allegations_served_at               TEXT,
  representations_period_at           TEXT,
  hearing_held_at                     TEXT,
  determination_at                    TEXT,
  penalty_imposed_at                  TEXT,
  paid_at                             TEXT,
  appealed_at                         TEXT,
  enforced_via_court_at               TEXT,
  dismissed_at                        TEXT,
  withdrawn_at                        TEXT,

  is_reportable                       INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                     TEXT,
  last_sla_breach_at                  TEXT,
  escalation_level                    INTEGER NOT NULL DEFAULT 0,

  created_by                          TEXT NOT NULL,
  created_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_enforcement_actions_events (
  id            TEXT PRIMARY KEY,
  case_id       TEXT NOT NULL,
  event_type    TEXT NOT NULL,
  from_status   TEXT,
  to_status     TEXT,
  actor_id      TEXT,
  actor_party   TEXT,
  notes         TEXT,
  payload       TEXT,
  created_at    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_eop_activations (
  id                        TEXT PRIMARY KEY,
  participant_id            TEXT NOT NULL,   -- grid operator / SO

  -- Event classification
  eop_tier                  TEXT NOT NULL CHECK(eop_tier IN (
    'n1_minor','n1_significant','n2_double','black_start'
  )),
  contingency_type          TEXT CHECK(contingency_type IN (
    'line_trip','generator_trip','transformer_fault','busbar_fault',
    'under_frequency','voltage_collapse','protection_failure','external','other',NULL
  )),
  contingency_description   TEXT NOT NULL,
  affected_mw               REAL,            -- MW affected / load shed
  affected_region           TEXT,            -- geographic region
  load_shedding_stage       INTEGER,         -- Eskom stage 1–8 if applicable

  -- Event timeline
  contingency_at            TEXT NOT NULL,   -- when fault/event occurred
  eop_activated_at          TEXT,
  operations_centre_alerted_at TEXT,
  load_shedding_started_at  TEXT,
  restoration_started_at    TEXT,
  normal_ops_restored_at    TEXT,
  total_outage_duration_min INTEGER,         -- minutes

  -- Post-Event Review
  per_initiated_at          TEXT,
  per_completed_at          TEXT,
  per_lead_name             TEXT,
  root_cause                TEXT,
  contributing_factors      TEXT,
  lessons_learned           TEXT,
  action_items              TEXT,            -- JSON array of follow-up items

  -- Escalation
  nersa_notification_ref    TEXT,
  escalation_reason         TEXT,

  -- NTCSA / SO references
  ntcsa_incident_ref        TEXT,
  so_incident_ref           TEXT,
  protection_relay_refs     TEXT,            -- CSV of relay references triggered

  chain_status              TEXT NOT NULL DEFAULT 'contingency_detected' CHECK(chain_status IN (
    'contingency_detected','eop_activated','operations_centre_alerted',
    'load_shedding_assessed','restoration_in_progress','normal_operations_restored',
    'post_event_review','per_completed','per_outstanding','escalated_to_regulator','withdrawn'
  )),
  sla_deadline              TEXT NOT NULL,
  sla_breached              INTEGER NOT NULL DEFAULT 0,
  regulator_notified        INTEGER NOT NULL DEFAULT 0,

  actor_id                  TEXT,
  reason                    TEXT,
  created_at                TEXT NOT NULL,
  updated_at                TEXT NOT NULL
);

CREATE TABLE oe_esap_compliance (
  id                     TEXT PRIMARY KEY,
  chain_status           TEXT NOT NULL DEFAULT 'monitoring_period_open',
  sla_deadline           TEXT,
  sla_breached           INTEGER NOT NULL DEFAULT 0,
  regulator_notified     INTEGER NOT NULL DEFAULT 0,
  actor_id               TEXT,
  reason                 TEXT,
  -- Business fields
  project_id             TEXT NOT NULL,
  reporting_period       TEXT NOT NULL,
  commitment_tier        TEXT NOT NULL CHECK (commitment_tier IN ('systemic','major','significant','minor','routine')),
  es_monitor_id          TEXT,
  finding_count_minor    INTEGER NOT NULL DEFAULT 0,
  finding_count_major    INTEGER NOT NULL DEFAULT 0,
  remediation_deadline   TEXT,
  breach_basis           TEXT,
  -- Timestamps
  created_at             TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at             TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_esap_monitoring (
  id                       TEXT PRIMARY KEY,
  participant_id           TEXT NOT NULL,   -- lender / project finance institution

  -- Project references
  project_ref              TEXT,            -- link to W20 construction/COD project
  facility_ref             TEXT,            -- link to W53 credit facility application
  loan_ref                 TEXT,            -- loan agreement reference

  -- ESAP classification
  esap_tier                TEXT NOT NULL CHECK(esap_tier IN (
    'category_c','category_b','category_a','critical_ps'
  )),
  ep_category              TEXT CHECK(ep_category IN ('A','B','C',NULL)),  -- Equator Category
  ps_triggers              TEXT,            -- JSON array of IFC PS triggered e.g. ["PS1","PS6","PS7"]

  -- Monitoring details
  monitoring_cycle         TEXT,            -- e.g. "Annual 2025", "Semi-annual H1-2025"
  site_name                TEXT,
  site_location            TEXT,
  auditor_name             TEXT,
  auditor_firm             TEXT,
  visit_scheduled_date     TEXT,
  visit_completed_date     TEXT,

  -- Findings
  findings_summary         TEXT,
  finding_count_major      INTEGER DEFAULT 0,
  finding_count_minor      INTEGER DEFAULT 0,
  ps1_labour_compliant     INTEGER,         -- 0/1 per PS
  ps2_labour_compliant     INTEGER,
  ps3_resource_compliant   INTEGER,
  ps4_community_compliant  INTEGER,
  ps6_biodiversity_compliant INTEGER,
  ps7_indigenous_compliant INTEGER,

  -- CAP / Remediation
  cap_submitted_at         TEXT,
  cap_due_date             TEXT,
  cap_reference            TEXT,
  remediation_started_at   TEXT,
  remediation_completed_at TEXT,

  -- Third-party review
  tpa_firm                 TEXT,
  tpa_ref                  TEXT,
  tpa_completed_at         TEXT,
  tpa_outcome              TEXT CHECK(tpa_outcome IN ('satisfactory','conditional','unsatisfactory',NULL)),

  -- Closure
  closed_at                TEXT,
  escalation_reason        TEXT,
  non_compliance_ref       TEXT,

  chain_status             TEXT NOT NULL DEFAULT 'esap_issued' CHECK(chain_status IN (
    'esap_issued','site_visit_scheduled','site_visit_completed','action_identified',
    'corrective_action_plan','remediation_in_progress','third_party_review',
    'partial_close','closed_satisfactory','closed_escalated','non_compliant','withdrawn'
  )),
  sla_deadline             TEXT NOT NULL,
  sla_breached             INTEGER NOT NULL DEFAULT 0,
  regulator_notified       INTEGER NOT NULL DEFAULT 0,

  actor_id                 TEXT,
  reason                   TEXT,
  created_at               TEXT NOT NULL,
  updated_at               TEXT NOT NULL
);

CREATE TABLE oe_esg_disclosure (
  id                                  TEXT PRIMARY KEY,
  disclosure_number                   TEXT UNIQUE NOT NULL,

  source_event                        TEXT,
  source_entity_type                  TEXT,
  source_entity_id                    TEXT,
  source_wave                         TEXT,

  reporting_entity_id                 TEXT NOT NULL,
  reporting_entity_name               TEXT,
  reporting_entity_lei                TEXT,
  ticker                              TEXT,
  financial_year_label                TEXT,
  financial_year_end_at               TEXT,
  period_opened_at                    TEXT,

  disclosure_scope                    TEXT NOT NULL DEFAULT 'entity_only' CHECK (disclosure_scope IN (
    'entity_only','entity_plus_subsidiaries','group_consolidated'
  )),
  climate_risk_exposure               TEXT NOT NULL DEFAULT 'low' CHECK (climate_risk_exposure IN (
    'low','medium','high'
  )),
  assurance_level                     TEXT NOT NULL DEFAULT 'none' CHECK (assurance_level IN (
    'none','limited','reasonable'
  )),
