  external_auditor_party_id           TEXT,

  jse_listed_strict                   INTEGER NOT NULL DEFAULT 0,
  scope3_inclusive_15cat              INTEGER NOT NULL DEFAULT 0,
  climate_scenario_required           INTEGER NOT NULL DEFAULT 0,
  material_topics_count               INTEGER NOT NULL DEFAULT 0,
  sbti_committed_strict               INTEGER NOT NULL DEFAULT 0,
  year_had_listed_disclosure          INTEGER NOT NULL DEFAULT 0,

  scope1_tco2e                        REAL,
  scope2_market_tco2e                 REAL,
  scope2_location_tco2e               REAL,
  scope3_total_tco2e                  REAL,
  baseline_year                       INTEGER,
  baseline_total_tco2e                REAL,
  reduction_pct_vs_baseline           REAL,
  sbti_alignment_score                REAL,

  tcfd_completeness_pct               REAL,
  gri_completeness_pct                REAL,
  cdp_score                           REAL,
  cdp_score_band                      TEXT,
  jse_srl_completeness_pct            REAL,
  king_iv_completeness_pct            REAL,
  issb_s1_s2_completeness_pct         REAL,
  assurance_confidence_level          TEXT,
  esg_disclosure_index                REAL,
  regulator_filing_window_days        INTEGER,
  urgency_band                        TEXT CHECK (urgency_band IN (
    'critical','high','medium','low'
  )),

  current_tier                        TEXT NOT NULL CHECK (current_tier IN (
    'minor','standard','material','strategic'
  )),
  effective_tier                      TEXT CHECK (effective_tier IN (
    'minor','standard','material','strategic'
  )),
  authority_required                  TEXT CHECK (authority_required IN (
    'esg_analyst','sustainability_director','audit_committee_chair','board_chair'
  )),

  dispute_count                       INTEGER NOT NULL DEFAULT 0,
  restate_count                       INTEGER NOT NULL DEFAULT 0,
  cancel_count                        INTEGER NOT NULL DEFAULT 0,

  parent_disclosure_id                TEXT,
  prior_disclosure_id                 TEXT,
  regulator_ref                       TEXT,
  jse_sens_ref                        TEXT,
  cipc_ref                            TEXT,
  dffe_ref                            TEXT,
  sars_ref                            TEXT,

  title                               TEXT,
  narrative                           TEXT,
  result_text                         TEXT,
  disputed_reason                     TEXT,
  cancelled_reason                    TEXT,
  restated_reason                     TEXT,
  reason_code                         TEXT,

  current_ball_in_court_party         TEXT,
  last_responder_party                TEXT,
  analyst_party                       TEXT,
  director_party                      TEXT,
  audit_committee_party               TEXT,
  board_party                         TEXT,

  chain_status                        TEXT NOT NULL CHECK (chain_status IN (
    'period_open','data_collected','boundary_verified','metrics_computed',
    'draft_compiled','internal_review','assurance_engaged',
    'assurance_in_progress','assured','published','filed','archived',
    'disputed','cancelled'
  )),
  period_open_at                      TEXT,
  data_collected_at                   TEXT,
  boundary_verified_at                TEXT,
  metrics_computed_at                 TEXT,
  draft_compiled_at                   TEXT,
  internal_review_at                  TEXT,
  assurance_engaged_at                TEXT,
  assurance_in_progress_at            TEXT,
  assured_at                          TEXT,
  published_at                        TEXT,
  filed_at                            TEXT,
  archived_at                         TEXT,
  disputed_at                         TEXT,
  cancelled_at                        TEXT,

  is_reportable                       INTEGER NOT NULL DEFAULT 0,
  regulator_crossed_at                TEXT,
  regulator_inbox_ref                 TEXT,
  sla_deadline_at                     TEXT,
  last_sla_breach_at                  TEXT,
  escalation_level                    INTEGER NOT NULL DEFAULT 0,

  created_by                          TEXT NOT NULL,
  created_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_esg_disclosure_events (
  id                  TEXT PRIMARY KEY,
  disclosure_id       TEXT NOT NULL,
  event_type          TEXT NOT NULL,
  from_status         TEXT,
  to_status           TEXT,
  actor_id            TEXT,
  actor_party         TEXT,
  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_export_curtailments (
  id                        TEXT PRIMARY KEY,
  participant_id            TEXT NOT NULL,   -- Esums plant operator

  -- Curtailment classification
  curtailment_tier          TEXT NOT NULL CHECK(curtailment_tier IN (
    'minor','moderate','significant','systemic'
  )),
  curtailment_type          TEXT CHECK(curtailment_type IN (
    'network_congestion','load_management','emergency_curtailment',
    'planned_maintenance','frequency_deviation','voltage_violation',NULL
  )),

  -- Asset references
  site_id                   TEXT,            -- Esums site
  meter_id                  TEXT,            -- metering point
  so_curtailment_ref        TEXT,            -- System Operator curtailment reference
  ppa_ref                   TEXT,            -- PPA under which compensation due (W22)

  -- Curtailment event
  curtailment_start         TEXT,
  curtailment_end           TEXT,
  curtailment_duration_h    REAL,            -- hours of curtailment
  available_capacity_mw     REAL,            -- installed capacity available at curtailment
  actual_generation_mwh     REAL,            -- actual generation during period
  deemed_energy_mwh         REAL,            -- lost generation (deemed MWh)
  irradiance_ghi_kwh_m2     REAL,           -- measured irradiance for solar verification

  -- Claim financials
  tariff_rate_per_mwh       REAL,
  claim_amount_zar          REAL,
  compensation_paid_zar     REAL,
  settlement_ref            TEXT,

  -- Dispute
  dispute_grounds           TEXT,
  arbitration_ref           TEXT,
  rejection_reason          TEXT,

  chain_status              TEXT NOT NULL DEFAULT 'curtailment_detected' CHECK(chain_status IN (
    'curtailment_detected','notification_logged','energy_calculation','claim_prepared',
    'claim_submitted','under_review','disputed','arbitration',
    'settled','rejected','withdrawn','cancelled'
  )),
  sla_deadline              TEXT NOT NULL,
  sla_breached              INTEGER NOT NULL DEFAULT 0,
  regulator_notified        INTEGER NOT NULL DEFAULT 0,

  actor_id                  TEXT,
  reason                    TEXT,
  created_at                TEXT NOT NULL,
  updated_at                TEXT NOT NULL
);

CREATE TABLE oe_facility_amendments (
  id                     TEXT PRIMARY KEY,
  facility_id            TEXT NOT NULL,
  amendment_ref          TEXT,
  amendment_class        TEXT NOT NULL CHECK (amendment_class IN (
                           'unanimous_consent', 'majority_consent',
                           'technical_amendment', 'administrative_amendment',
                           'clerical_correction'
                         )),
  amendment_type         TEXT,
  majority_threshold_pct REAL,
  unanimous_required     INTEGER NOT NULL DEFAULT 0,
  consent_deadline       TEXT,
  effective_date         TEXT,
  security_variation     INTEGER NOT NULL DEFAULT 0,
  pricing_change_bps     REAL,
  description            TEXT,
  chain_status           TEXT NOT NULL DEFAULT 'amendment_requested' CHECK (chain_status IN (
                           'amendment_requested', 'eligibility_assessed',
                           'lender_circulated', 'majority_response',
                           'unanimous_required', 'consent_obtained',
                           'documentation_prepared', 'execution_signed',
                           'effective', 'refused', 'lapsed', 'withdrawn'
                         )),
  sla_deadline           TEXT,
  sla_breached           INTEGER NOT NULL DEFAULT 0,
  regulator_notified     INTEGER NOT NULL DEFAULT 0,
  actor_id               TEXT,
  reason                 TEXT,
  created_at             TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at             TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_fault_fingerprint_ml (
  id                                      TEXT PRIMARY KEY,
  model_number                            TEXT UNIQUE NOT NULL,
  model_family                            TEXT NOT NULL CHECK (model_family IN (
    'xgboost','random_forest','gradient_boosting','cnn_1d','lightgbm','catboost','baseline_physics'
  )),
  model_version                           TEXT,
  training_dataset_hash                   TEXT,
  feature_count                           INTEGER,
  asset_class                             TEXT NOT NULL CHECK (asset_class IN (
    'wind_turbine','pv_inverter','battery_storage','transformer','transmission_line',
    'substation','hydrogen_electrolyser','grid_scada','smart_meter','generic'
  )),
  assets_covered                          INTEGER,
  jurisdiction_count                      INTEGER,
  safety_critical                         INTEGER NOT NULL DEFAULT 0,
  training_examples_count                 INTEGER,
  validation_examples_count               INTEGER,
  hyperparameter_set_hash                 TEXT,
  champion_model_id                       TEXT,
  challenger_model_id                     TEXT,
  retrain_due_at                          TEXT,
  model_card_expiry_at                    TEXT,

  -- 5 cross-chain bridges (W71 NOT NULL + W118 mandatory + W15 + W41 + W63)
  w71_asset_prognostics_ref               TEXT NOT NULL,
  w15_warranty_claim_ref                  TEXT,
  w41_problem_management_ref              TEXT,
  w63_warranty_recovery_ref               TEXT,
  w118_block_ref                          TEXT,

  -- 5 floor flags (FLOOR-AT-LARGE-FLEET >=1 / FLOOR-AT-FLEET-SYSTEMIC >=3)
  safety_critical_fault_class             INTEGER NOT NULL DEFAULT 0,
  regulator_reportable_misclass           INTEGER NOT NULL DEFAULT 0,
  nerc_cip_audit_in_scope                 INTEGER NOT NULL DEFAULT 0,
  sox_ml_governance_required              INTEGER NOT NULL DEFAULT 0,
  iso_42001_required                      INTEGER NOT NULL DEFAULT 0,

  -- Multi-class specifics
  class_count                             INTEGER,
  class_label_set_hash                    TEXT,
  class_distribution_payload              TEXT,
  confusion_matrix                        TEXT,
  min_samples_per_class                   INTEGER,

  -- Multi-class 11 LIVE metric fields
  macro_f1                                REAL,
  micro_f1                                REAL,
  weighted_recall                         REAL,
  top_3_accuracy                          REAL,
  log_loss                                REAL,
  roc_auc_macro                           REAL,
  confusion_matrix_density                REAL,
  class_imbalance_ratio                   REAL,
  calibration_brier                       REAL,
  class_drift_psi                         REAL,
  novel_class_detection_rate              REAL,

  -- Governance / performance components (0-130 composite)
  reconciliation_with_w71_physics_pct     REAL,
  ntt_baseline_comparison_pct             REAL,
  inference_latency_p50_ms                REAL,
  inference_latency_p99_ms                REAL,
  model_card_status                       TEXT CHECK (model_card_status IN (
    'draft','approved','published','expired'
  )),
  iso27001_controls_ok                    INTEGER NOT NULL DEFAULT 0,
  soc2_type2_controls_ok                  INTEGER NOT NULL DEFAULT 0,
  iso_42001_compliance_score              INTEGER,
  control_effectiveness_index             INTEGER,

  -- Composite indexes + bands
  current_tier                            TEXT NOT NULL CHECK (current_tier IN (
    'single_asset','small_fleet','large_fleet','multi_jurisdiction_fleet','fleet_systemic'
  )),
  authority_required                      TEXT,
  urgency_band                            TEXT,
  model_health_band                       TEXT,

  -- Narrative + reason codes
  title                                   TEXT,
  reason_code                             TEXT,

  is_reportable                           INTEGER NOT NULL DEFAULT 0,
  regulator_relevant                      INTEGER NOT NULL DEFAULT 0,
  regulator_reason_text                   TEXT,
  regulator_ref                           TEXT,
  regulator_inbox_ref                     TEXT,

  -- 12 forward + 4 branch lifecycle timestamps
  chain_status                            TEXT NOT NULL CHECK (chain_status IN (
    'model_proposed','labeled_dataset_bound','class_imbalance_resolved','features_engineered',
    'train_test_split','multiclass_model_trained','confusion_matrix_validated','calibrated',
    'shadow_deployed','live_ab_active','champion_promoted','retrained','archived',
    'class_drift_detected','rolled_back','recalled','failover_to_physics_baseline'
  )),
  model_proposed_at                       TEXT,
  labeled_dataset_bound_at                TEXT,
  class_imbalance_resolved_at             TEXT,
  features_engineered_at                  TEXT,
  train_test_split_at                     TEXT,
  multiclass_model_trained_at             TEXT,
  confusion_matrix_validated_at           TEXT,
  calibrated_at                           TEXT,
  shadow_deployed_at                      TEXT,
  live_ab_active_at                       TEXT,
  champion_promoted_at                    TEXT,
  retrained_at                            TEXT,
  archived_at                             TEXT,
  class_drift_detected_at                 TEXT,
  rolled_back_at                          TEXT,
  recalled_at                             TEXT,
  failover_to_physics_baseline_at         TEXT,

  -- Regulator crossing
  regulator_crossed_at                    TEXT,

  -- SLA (HOURS, INVERTED polarity)
  sla_target_hours                        INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                         TEXT,
  sla_breached                            INTEGER NOT NULL DEFAULT 0,
  last_sla_breach_at                      TEXT,
  escalation_level                        INTEGER NOT NULL DEFAULT 0,
  days_to_retrain_due                     INTEGER,
  days_to_model_card_expiry               INTEGER,

  tenant_id                               TEXT,
  created_by                              TEXT NOT NULL,
  created_at                              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_fault_fingerprint_ml_events (
  id                  TEXT PRIMARY KEY,
  model_id            TEXT NOT NULL,
  event_type          TEXT NOT NULL,
  from_status         TEXT,
  to_status           TEXT,
  from_tier           TEXT,
  to_tier             TEXT,
  actor_id            TEXT,
  actor_party         TEXT,
  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_feature_entitlements (
  participant_id TEXT NOT NULL,
  feature        TEXT NOT NULL,   -- e.g. 'doc_generation'
  status         TEXT NOT NULL DEFAULT 'active',
  tier           TEXT,            -- starter | professional | enterprise (informational)
  activated_at   TEXT NOT NULL DEFAULT (datetime('now')),
  tenant_id      TEXT NOT NULL DEFAULT 'default',
  PRIMARY KEY (participant_id, feature)
);

CREATE TABLE oe_feature_flags (
  key             TEXT PRIMARY KEY,
  description     TEXT,
  default_enabled INTEGER NOT NULL DEFAULT 0,
  rollout_pct     REAL NOT NULL DEFAULT 0,    -- 0..100
  role_overrides  TEXT,                       -- JSON {admin: 100, trader: 50, ...}
  participant_allowlist TEXT,                 -- JSON array
  participant_blocklist TEXT,                 -- JSON array
  killed          INTEGER NOT NULL DEFAULT 0, -- emergency disable
  updated_at      TEXT NOT NULL DEFAULT (datetime('now')),
  updated_by      TEXT
);

CREATE TABLE oe_fee_schedule (
  id TEXT PRIMARY KEY,
  trigger_event TEXT NOT NULL UNIQUE,        -- the PlatformEvent that bills (e.g. ppa_evt_activated)
  fee_type TEXT NOT NULL CHECK(fee_type IN ('bps','flat_zar','pct')),
  rate REAL NOT NULL DEFAULT 0,              -- bps: basis points; flat_zar: ZAR; pct: 0..1
  min_fee_zar REAL DEFAULT 0,
  max_fee_zar REAL,                          -- NULL = uncapped
  applicable_tiers TEXT DEFAULT '[]',        -- JSON array of tier strings; [] = all
  payer_role TEXT,                           -- explicit payer when resolution=initiator override
  payer_resolution TEXT NOT NULL DEFAULT 'initiator'
    CHECK(payer_resolution IN ('initiator','beneficiary','split','platform')),
  is_enabled INTEGER NOT NULL DEFAULT 0,     -- ALL FREE at launch
  description TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
, split_config TEXT);

CREATE TABLE oe_frequency_events (
  id                  TEXT PRIMARY KEY,
  detected_at         TEXT NOT NULL,
  duration_seconds    REAL,
  min_frequency_hz    REAL,
  max_deviation_mhz   REAL,                       -- |49.95-50.00|*1000 = 50 mHz
  recovery_seconds    REAL,
  rocof_hz_per_s      REAL,                       -- Rate of change of frequency
  response_participants TEXT,                     -- JSON list of participants who reacted
  classification      TEXT,                       -- under_frequency | over_frequency |
                                                  -- transient | sustained
  severity            TEXT NOT NULL,              -- info | minor | major | critical
  notes               TEXT,
  created_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_fsca_compliance_reports (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL,
  fsp_licence_number  TEXT,
  fsp_class           TEXT NOT NULL DEFAULT 'standard'
                        CHECK (fsp_class IN ('micro','standard','large','systemic')),
  report_year         INTEGER NOT NULL,
  reporting_period_start TEXT NOT NULL,
  reporting_period_end   TEXT NOT NULL,
  chain_status        TEXT NOT NULL DEFAULT 'report_scheduled'
                        CHECK (chain_status IN (
                          'report_scheduled','data_gathering','drafting',
                          'internal_review','co_sign_off','submitted',
                          'under_review','queries_received','queries_responded',
                          'filed','deficiency_found','remediation','refiled','revocation_risk'
                        )),
  -- Compliance officer
  compliance_officer_id   TEXT,
  compliance_officer_name TEXT,
  co_signed_at            TEXT,
  -- Submission tracking
  fsca_reference          TEXT,
  submitted_at            TEXT,
  filed_at                TEXT,
  refiled_at              TEXT,
  -- Queries
  query_count             INTEGER NOT NULL DEFAULT 0,
  last_query_at           TEXT,
  last_response_at        TEXT,
  -- Deficiency / remediation
  deficiency_description  TEXT,
  remediation_plan        TEXT,
  remediation_deadline    TEXT,
  -- Risk flag
  revocation_risk_reason  TEXT,
  -- SLA
  sla_deadline            TEXT NOT NULL,
  sla_breached            INTEGER NOT NULL DEFAULT 0,
  regulator_notified      INTEGER NOT NULL DEFAULT 0,
  actor_id                TEXT NOT NULL,
  reason                  TEXT,
  created_at              TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at              TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_fsca_conduct_reports (
  id                       TEXT PRIMARY KEY,
  participant_id           TEXT NOT NULL,   -- trading participant

  -- Report classification
  report_tier              TEXT NOT NULL CHECK(report_tier IN (
    'retail','professional','market_maker','systemic'
  )),
  reporting_period         TEXT NOT NULL,   -- e.g. 'Q4-2025', 'Annual-2025'
  reporting_year           INTEGER NOT NULL,
  is_annual                INTEGER NOT NULL DEFAULT 0,  -- 0=quarterly, 1=annual

  -- Business metrics
  total_notional_zar       REAL,
  client_count             INTEGER,
  complaint_count          INTEGER,
  complaint_upheld_count   INTEGER,
  best_ex_exceptions       INTEGER DEFAULT 0,
  algo_incidents           INTEGER DEFAULT 0,
  conduct_breaches         INTEGER DEFAULT 0,

  -- Review process
  compliance_officer       TEXT,
  board_sign_off_date      TEXT,
  board_signatory          TEXT,

  -- Submission
  fsca_submission_ref      TEXT,
  submitted_at             TEXT,
  fsca_acknowledgement_ref TEXT,

  -- Queries
  query_summary            TEXT,
  query_raised_at          TEXT,
  query_responded_at       TEXT,
  query_response_ref       TEXT,

  -- Outcome
  accepted_at              TEXT,
  rejected_at              TEXT,
  rejection_reason         TEXT,
  escalation_reason        TEXT,

  chain_status             TEXT NOT NULL DEFAULT 'draft' CHECK(chain_status IN (
    'draft','internal_review','board_approved','submitted_to_fsca',
    'fsca_queries','queries_responded','accepted','rejected','escalated','withdrawn'
  )),
  sla_deadline             TEXT NOT NULL,
  sla_breached             INTEGER NOT NULL DEFAULT 0,
  regulator_notified       INTEGER NOT NULL DEFAULT 0,

  actor_id                 TEXT,
  reason                   TEXT,
  created_at               TEXT NOT NULL,
  updated_at               TEXT NOT NULL
);

CREATE TABLE oe_gca_connections (
  id                              TEXT PRIMARY KEY,
  case_number                     TEXT NOT NULL UNIQUE,
  project_id                      TEXT NOT NULL,
  project_name                    TEXT NOT NULL,
  ipp_party                       TEXT NOT NULL,
  network_party                   TEXT NOT NULL,    -- 'Eskom_Transmission' | 'Eskom_Distribution' | municipal name
  connection_tier                 TEXT NOT NULL,    -- transmission | distribution | embedded
  voltage_kv                      REAL NOT NULL,
  poc_substation                  TEXT NOT NULL,    -- point of connection substation
