CREATE TABLE oe_green_bond_reports (
  id                    TEXT PRIMARY KEY,
  participant_id        TEXT NOT NULL,
  bond_isin             TEXT,
  bond_class            TEXT NOT NULL DEFAULT 'project'
                          CHECK (bond_class IN ('project','corporate','sovereign','securitised')),
  report_year           INTEGER NOT NULL,
  issuance_size_zar     REAL NOT NULL DEFAULT 0,
  reporting_period_start TEXT NOT NULL,
  reporting_period_end   TEXT NOT NULL,
  chain_status          TEXT NOT NULL DEFAULT 'period_open'
                          CHECK (chain_status IN (
                            'period_open','data_gathering','impact_calculation',
                            'external_review','board_approval','submitted_jse',
                            'under_review','queries_raised','queries_responded',
                            'approved','published','deficiency_noted','remediation','rejected'
                          )),
  -- Impact metrics
  kwh_generated         REAL,
  carbon_avoided_tco2e  REAL,
  green_capex_deployed_zar REAL,
  eligible_projects_count INTEGER,
  -- External review
  external_reviewer      TEXT,
  review_type            TEXT CHECK (review_type IN ('second_party','certification','verification','rating')),
  review_completed_at    TEXT,
  review_ref             TEXT,
  -- Board
  board_approved_at      TEXT,
  board_resolution_ref   TEXT,
  -- JSE tracking
  jse_submission_ref     TEXT,
  jse_approved_at        TEXT,
  published_at           TEXT,
  -- Queries
  query_count            INTEGER NOT NULL DEFAULT 0,
  last_query_at          TEXT,
  last_response_at       TEXT,
  -- Deficiency
  deficiency_description TEXT,
  rejection_reason       TEXT,
  -- SLA
  sla_deadline           TEXT NOT NULL,
  sla_breached           INTEGER NOT NULL DEFAULT 0,
  regulator_notified     INTEGER NOT NULL DEFAULT 0,
  actor_id               TEXT NOT NULL,
  reason                 TEXT,
  created_at             TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at             TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_green_tariff_disclosures (
  id                       TEXT PRIMARY KEY,
  participant_id           TEXT NOT NULL,   -- offtaker

  -- PPA / tariff reference
  ppa_ref                  TEXT,            -- link to W22 PPA contract
  tariff_contract_number   TEXT,
  green_tariff_class       TEXT NOT NULL CHECK(green_tariff_class IN (
    'voluntary','corporate_ppa','utility_green_tariff','sbti_aligned'
  )),

  -- Consumption period
  disclosure_period        TEXT NOT NULL,   -- e.g. "2025-Q4" or "2025"
  consumption_mwh          REAL,
  contracted_green_mwh     REAL,
  matched_rec_mwh          REAL,
  match_percentage         REAL,            -- matched_rec_mwh / consumption_mwh * 100

  -- Attribute matching details
  rec_serial_from          TEXT,
  rec_serial_to            TEXT,
  irec_registry            TEXT,            -- I-REC, SAREC, GO, etc.
  generation_technology    TEXT,            -- solar, wind, hydro, etc.
  generation_country       TEXT DEFAULT 'ZA',
  additionality_claim      INTEGER DEFAULT 0,  -- 0/1 — new capacity

  -- Independent review
  reviewer_name            TEXT,
  reviewer_ref             TEXT,
  review_approved_at       TEXT,
  review_report_url        TEXT,

  -- Label
  label_issued_at          TEXT,
  label_certificate_number TEXT,
  label_valid_until        TEXT,

  -- CDP/SBTi submission
  cdp_submission_ref       TEXT,
  sbti_target_ref          TEXT,
  cdp_submitted_at         TEXT,
  disclosure_date          TEXT,

  -- Rejection
  rejection_reason         TEXT,

  chain_status             TEXT NOT NULL DEFAULT 'application_received' CHECK(chain_status IN (
    'application_received','eligibility_check','attribute_matching',
    'independent_review','review_approved','label_issued',
    'cdp_submitted','disclosed','rejected','withdrawn'
  )),
  sla_deadline             TEXT NOT NULL,
  sla_breached             INTEGER NOT NULL DEFAULT 0,
  regulator_notified       INTEGER NOT NULL DEFAULT 0,

  actor_id                 TEXT,
  reason                   TEXT,
  created_at               TEXT NOT NULL,
  updated_at               TEXT NOT NULL
);

CREATE TABLE oe_grid_capacity_allocations (
  id                            TEXT PRIMARY KEY,
  allocation_number             TEXT UNIQUE NOT NULL,

  -- Provenance (e.g. a licence/registration or IRP allocation that triggered it)
  source_event                  TEXT,
  source_entity_type            TEXT,
  source_entity_id              TEXT,
  source_wave                   TEXT,

  -- Parties (two-party split: applicant developer + network operator)
  applicant_party_id            TEXT NOT NULL,
  applicant_party_name          TEXT NOT NULL,
  operator_party_id             TEXT NOT NULL,
  operator_party_name           TEXT NOT NULL,

  -- Allocation identity
  capacity_tier                 TEXT NOT NULL CHECK (capacity_tier IN (
    'minor', 'small', 'medium', 'large', 'strategic'
  )),
  connection_type               TEXT NOT NULL,     -- generation / load / storage / hybrid
  technology                    TEXT,              -- solar_pv / wind / battery / gas / hydro / chp
  network_level                 TEXT,              -- transmission / distribution
  project_name                  TEXT NOT NULL,
  project_location              TEXT,              -- province / supply area
  requested_capacity_mw         REAL NOT NULL,     -- requested connection capacity (MW) — drives tier
  granted_capacity_mw           REAL,              -- firmly allocated capacity (MW)
  queue_rank                    INTEGER,           -- position in the capacity queue
  priority_date                 TEXT,              -- queue priority / ranking date
  substation                    TEXT,              -- connection substation / supply point
  supply_area                   TEXT,              -- network supply area / grid zone
  estimated_capex_zar_m         REAL,              -- estimated connection capex (R millions)
  gca_ref                       TEXT,              -- W28 Grid Connection Agreement ref (handoff)

  -- Refs
  application_ref               TEXT,
  screening_ref                 TEXT,
  info_request_ref              TEXT,
  assessment_ref                TEXT,              -- network / system-impact study ref
  queue_ref                     TEXT,              -- queue-position notice ref
  offer_ref                     TEXT,              -- capacity-allocation offer ref
  reservation_ref               TEXT,              -- capacity-reservation agreement ref
  allocation_ref                TEXT,              -- firm capacity-allocation certificate ref
  regulator_ref                 TEXT,              -- NERSA grid-access oversight ref

  -- Narrative
  application_basis             TEXT,
  screening_basis               TEXT,
  info_request_basis            TEXT,
  assessment_basis              TEXT,
  queue_basis                   TEXT,
  offer_basis                   TEXT,
  reservation_basis             TEXT,
  allocation_basis              TEXT,
  rejection_basis               TEXT,
  relinquish_basis              TEXT,
  reason_code                   TEXT,
  decision_notes                TEXT,

  info_request_round            INTEGER NOT NULL DEFAULT 0,

  -- State + lifecycle
  chain_status                  TEXT NOT NULL CHECK (chain_status IN (
    'application_received','completeness_screening','information_requested',
    'capacity_assessment','queue_positioned','offer_issued','capacity_reserved',
    'capacity_allocated','rejected','lapsed','relinquished','withdrawn'
  )),
  application_received_at       TEXT NOT NULL,
  completeness_screening_at     TEXT,
  information_requested_at      TEXT,
  capacity_assessment_at        TEXT,
  queue_positioned_at           TEXT,
  offer_issued_at               TEXT,
  capacity_reserved_at          TEXT,
  capacity_allocated_at         TEXT,
  rejected_at                   TEXT,
  lapsed_at                     TEXT,
  relinquished_at               TEXT,
  withdrawn_at                  TEXT,

  is_reportable                 INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at               TEXT,
  last_sla_breach_at            TEXT,
  escalation_level              INTEGER NOT NULL DEFAULT 0,

  created_by                    TEXT NOT NULL,
  created_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_grid_capacity_allocations_events (
  id                 TEXT PRIMARY KEY,
  allocation_id      TEXT NOT NULL,
  event_type         TEXT NOT NULL,
  from_status        TEXT,
  to_status          TEXT,
  actor_id           TEXT,
