CREATE TABLE oe_grid_wheeling_charges (
  id                    TEXT PRIMARY KEY,
  agreement_id          TEXT NOT NULL,                              -- oe_wheeling_agreements.id
  period_month          TEXT NOT NULL,                              -- YYYY-MM
  issued_by             TEXT NOT NULL,                              -- grid_operator user id
  issued_at             TEXT NOT NULL DEFAULT (datetime('now')),
  transmission_mwh      REAL NOT NULL DEFAULT 0,                    -- delivered transmission for the month
  tariff_zar_per_mwh    REAL NOT NULL DEFAULT 0,                    -- snapshot of agreement tariff at issue
  loss_factor_pct       REAL NOT NULL DEFAULT 0,                    -- snapshot of agreement loss factor
  loss_mwh              REAL NOT NULL DEFAULT 0,                    -- transmission_mwh × loss_factor_pct / 100
  gross_zar             REAL NOT NULL DEFAULT 0,                    -- transmission_mwh × tariff
  loss_zar              REAL NOT NULL DEFAULT 0,                    -- loss_mwh × tariff
  ancillaries_zar       REAL NOT NULL DEFAULT 0,                    -- reactive power, balancing services
  total_zar             REAL NOT NULL DEFAULT 0,                    -- gross + loss + ancillaries
  status                TEXT NOT NULL DEFAULT 'open'
                        CHECK (status IN ('open','disputed','reconciled','paid','escalated')),
  dispute_deadline_at   TEXT,                                       -- ISO; issued_at + dispute_window_days
  paid_at               TEXT,
  paid_by               TEXT,
  paid_amount_zar       REAL,
  escalated_at          TEXT,
  escalated_to          TEXT,                                       -- 'regulator'
  notes                 TEXT,
  created_at            TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at            TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_grid_wheeling_disputes (
  id                       TEXT PRIMARY KEY,
  charge_id                TEXT NOT NULL,                           -- oe_grid_wheeling_charges.id
  agreement_id             TEXT NOT NULL,
  raised_by                TEXT NOT NULL,                           -- offtaker / admin user id
  raised_at                TEXT NOT NULL DEFAULT (datetime('now')),
  dispute_reason           TEXT NOT NULL,
  claimed_amount_zar       REAL,                                    -- amount the offtaker thinks is correct
  status                   TEXT NOT NULL DEFAULT 'open'
                           CHECK (status IN ('open','resolved','escalated')),
  resolved_by              TEXT,
  resolved_at              TEXT,
  resolution_amount_zar    REAL,                                    -- final settled amount
  resolution_notes         TEXT,
  evidence_r2_key          TEXT,
  created_at               TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_gtia (
  id                          TEXT PRIMARY KEY,
  participant_id              TEXT NOT NULL,   -- IPP submitting the GTIA

  -- Classification
  gtia_tier                   TEXT NOT NULL CHECK(gtia_tier IN (
    'small','medium','large','bulk'
  )),
  project_ref                 TEXT,            -- W1 IPP-PM project reference
  gca_ref                     TEXT,            -- W28 grid connection agreement ref
  capacity_ref                TEXT,            -- W58 capacity allocation ref
  installed_capacity_mw       REAL,
  connection_voltage_kv       REAL,
  connection_type             TEXT CHECK(connection_type IN (
    'transmission','sub_transmission','distribution','embedded',NULL
  )),
  network_operator_name       TEXT,            -- SO or DSO name

  -- Technical interface details
  protection_relay_type       TEXT,
  protection_settings_ref     TEXT,            -- approved protection settings document
  scada_protocol              TEXT CHECK(scada_protocol IN (
    'iec61850','dnp3','modbus','iec104','proprietary',NULL
  )),
  scada_point_list_ref        TEXT,
  metering_class              TEXT,
  metering_standards_ref      TEXT,

  -- Timeline
  queries_raised_at           TEXT,
  queries_responded_at        TEXT,
  ipp_approved_at             TEXT,
  so_review_commenced_at      TEXT,
  protection_agreed_at        TEXT,
  scada_agreed_at             TEXT,
  gtia_executed_at            TEXT,

  -- Rejection
  rejection_party             TEXT CHECK(rejection_party IN ('ipp','so',NULL)),
  rejection_reason            TEXT,
  rejected_at                 TEXT,

  chain_status                TEXT NOT NULL DEFAULT 'gtia_initiated' CHECK(chain_status IN (
    'gtia_initiated','ipp_under_review','queries_raised','queries_responded',
    'ipp_approved','so_under_review','protection_settings_agreed',
    'scada_interface_agreed','gtia_executed',
    'ipp_rejected','so_rejected','withdrawn'
  )),
  sla_deadline                TEXT NOT NULL,
  sla_breached                INTEGER NOT NULL DEFAULT 0,
  regulator_notified          INTEGER NOT NULL DEFAULT 0,

  actor_id                    TEXT,
  reason                      TEXT,
  created_at                  TEXT NOT NULL,
  updated_at                  TEXT NOT NULL
);

