  priced_at                                           TEXT,
  invoice_acknowledged_at                             TEXT,
  dispute_window_opened_at                            TEXT,
  disputed_at                                         TEXT,
  resolved_dispute_at                                 TEXT,
  invoice_revised_at                                  TEXT,
  payment_pending_at                                  TEXT,
  settled_at                                          TEXT,
  archived_at                                         TEXT,
  cancelled_at                                        TEXT,

