CREATE TABLE oe_ipp_env_monitoring (
  -- Core
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL,
  project_name TEXT,
  monitoring_ref TEXT,
  chain_status TEXT NOT NULL DEFAULT 'scheduled',
  monitoring_title TEXT NOT NULL,

  -- Classification
  monitoring_category TEXT,    -- air_quality / water_quality / noise / dust / waste / land / biodiversity / stormwater / groundwater / visual
  monitoring_tier TEXT,        -- critical / regular / routine / baseline (drives URGENT SLA)
  eia_condition_ref TEXT,      -- EIA approval condition number
  sampling_location TEXT,      -- GPS coordinates or site description
  monitoring_frequency TEXT,   -- continuous / daily / weekly / monthly / quarterly / annual

  -- Measurement fields
  parameter_name TEXT,         -- e.g. "PM10", "pH", "Laeq(1h)", "COD"
  measured_value REAL,         -- the measurement result
  measurement_unit TEXT,       -- mg/m³, pH units, dB(A), mg/L etc.
  permit_limit_min REAL,       -- lower limit (optional)
  permit_limit_max REAL,       -- upper limit
  exceedance_magnitude REAL,   -- how far over the limit
  exceedance_pct REAL,         -- percentage over limit

  -- Context
  is_near_sensitive_receptor INTEGER NOT NULL DEFAULT 0, -- school/hospital/community within 500m (SIGNATURE driver)
  lab_accredited INTEGER NOT NULL DEFAULT 0,             -- SANAS-accredited lab used
  lab_name TEXT,
  lab_sample_ref TEXT,
  sampled_at TEXT,             -- ISO timestamp of sampling
  results_received_at TEXT,    -- when lab results came back

  -- Content
  sampling_methodology TEXT,
  findings TEXT,
  exceedance_cause TEXT,
  corrective_actions TEXT,
  corrective_action_deadline TEXT,
  report_title TEXT,
  report_submitted_to TEXT,    -- authority name (DFFE, NEAS, municipality)
  complaint_description TEXT,

  -- Floor flags (5)
  floor_nema_s30_notification INTEGER NOT NULL DEFAULT 0, -- NEMA s30 incident notification required
  floor_dffe_report_required INTEGER NOT NULL DEFAULT 0,  -- Formal DFFE report required
  floor_public_notice_required INTEGER NOT NULL DEFAULT 0, -- Public/community notification required
  floor_lender_report_required INTEGER NOT NULL DEFAULT 0, -- Lender environmental report required
  floor_eia_condition_breach INTEGER NOT NULL DEFAULT 0,   -- EIA condition has been breached

  -- SLA fields
  sla_target_hours INTEGER,
  sla_deadline_at TEXT,
  sla_breached INTEGER NOT NULL DEFAULT 0,
  sla_breach_count INTEGER NOT NULL DEFAULT 0,

  -- Regulator
  is_reportable INTEGER NOT NULL DEFAULT 0,
  regulator_ref TEXT,

  -- Cross-references
  ncr_ref TEXT,
  hse_incident_ref TEXT,
  ms_ref TEXT,
  stage_gate_ref TEXT,

  -- State timestamps (12)
  scheduled_at TEXT,
  sampling_at TEXT,
  sample_submitted_at TEXT,
  compliance_assessed_at TEXT,
  report_drafted_at TEXT,
  report_submitted_at TEXT,
  closed_at TEXT,
  exceedance_flagged_at TEXT,
  corrective_action_at TEXT,
  under_investigation_at TEXT,
  cancelled_at TEXT,

  -- Meta
  created_by TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_ipp_equity_transfers (
  id TEXT PRIMARY KEY,
  project_ref TEXT NOT NULL,
  transfer_type TEXT NOT NULL CHECK(transfer_type IN ('secondary_sale','community_equity','dfi_exit','sponsor_reorg','debt_equity_swap')),
  transferor_name TEXT,
  transferee_name TEXT,
  equity_quantum_zar REAL NOT NULL,
  equity_pct REAL,
  equity_tier TEXT NOT NULL CHECK(equity_tier IN ('micro','small','medium','large','flagship')),
  chain_status TEXT NOT NULL DEFAULT 'transfer_initiated' CHECK(chain_status IN (
    'transfer_initiated','due_diligence','regulatory_notification',
    'lender_consent_requested','offtaker_notification','nersa_review',
    'regulatory_clearance_issued','conditions_precedent_tracking',
    'cp_documentation_submitted','transfer_completed','transfer_rejected','transfer_lapsed'
  )),
  sla_due_date TEXT,
  sla_breached INTEGER DEFAULT 0,
  is_reportable INTEGER DEFAULT 0,
  actor_party TEXT,
  reason TEXT,
  notes TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE oe_ipp_esmr (
  id                  TEXT    PRIMARY KEY,
  project_ref         TEXT    NOT NULL,
  reporting_period    TEXT    NOT NULL,
  loan_size_zar       REAL    NOT NULL,
  loan_tier           TEXT    NOT NULL
                              CHECK(loan_tier IN ('small','medium','large','major','flagship')),
  dfi_names           TEXT,
  lender_ta_ref       TEXT,
  breach_category     TEXT
                              CHECK(breach_category IN (
                                'ps1_assessment','ps2_labour','ps3_pollution',
                                'ps4_community_health','ps5_land_acquisition',
                                'ps6_biodiversity','ps7_indigenous','ps8_cultural'
                              ) OR breach_category IS NULL),
  chain_status        TEXT    NOT NULL DEFAULT 'reporting_period_open'
                              CHECK(chain_status IN (
                                'reporting_period_open','data_collection',
                                'monitoring_compilation','lender_ta_review',
                                'ta_report_preparation','report_submitted',
                                'lender_review','clarification_requested',
                                'clarification_submitted','certificate_issued',
                                'certificate_withheld','material_breach_declared'
                              )),
  sla_due_date        TEXT,
  sla_breached        INTEGER NOT NULL DEFAULT 0,
  is_reportable       INTEGER NOT NULL DEFAULT 0,
  actor_party         TEXT,
  reason              TEXT,
  notes               TEXT,
  created_at          TEXT    NOT NULL DEFAULT (datetime('now')),
  updated_at          TEXT    NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_ipp_evm (
  id                                          TEXT PRIMARY KEY,
  evm_number                                  TEXT UNIQUE NOT NULL,

  -- Project linkage
  project_id                                  TEXT NOT NULL,
  project_name                                TEXT,
  project_capacity_mw                         REAL NOT NULL DEFAULT 0,
  project_type                                TEXT,
  cost_book_period                            TEXT,

  -- Cross-chain bridges (W112 schedule + W21 drawdown + W30 disb +
  -- W77 reserve-account)
  schedule_ref                                TEXT,
  drawdown_ref                                TEXT,
  disbursement_ref                            TEXT,
  reserve_account_ref                         TEXT,

  -- Budget (BAC + contingency + management reserve)
  total_budget_zar                            REAL NOT NULL DEFAULT 0,
  contingency_initial_zar                     REAL NOT NULL DEFAULT 0,
  contingency_drawn_zar                       REAL NOT NULL DEFAULT 0,
  contingency_remaining_pct                   REAL NOT NULL DEFAULT 0,
  management_reserve_initial_zar              REAL NOT NULL DEFAULT 0,
  management_reserve_drawn_zar                REAL NOT NULL DEFAULT 0,
  management_reserve_remaining_pct            REAL NOT NULL DEFAULT 0,
  currency_code                               TEXT NOT NULL DEFAULT 'ZAR',
  forex_component_pct                         REAL NOT NULL DEFAULT 0,

  -- Cost ledger
  committed_cost_zar                          REAL NOT NULL DEFAULT 0,
  incurred_cost_zar                           REAL NOT NULL DEFAULT 0,
  invoiced_cost_zar                           REAL NOT NULL DEFAULT 0,
  paid_cost_zar                               REAL NOT NULL DEFAULT 0,
  last_cost_update_at                         TEXT,

  -- EVM (Earned Value Management) 12-field block
  planned_value_zar                           REAL NOT NULL DEFAULT 0,
  earned_value_zar                            REAL NOT NULL DEFAULT 0,
  actual_cost_zar                             REAL NOT NULL DEFAULT 0,
  budget_at_completion_zar                    REAL NOT NULL DEFAULT 0,
  estimate_at_completion_zar                  REAL NOT NULL DEFAULT 0,
  estimate_to_complete_zar                    REAL NOT NULL DEFAULT 0,
  variance_at_completion_zar                  REAL NOT NULL DEFAULT 0,
  cpi                                         REAL NOT NULL DEFAULT 0,
  spi                                         REAL NOT NULL DEFAULT 0,
  tcpi                                        REAL NOT NULL DEFAULT 0,
  cost_variance_zar                           REAL NOT NULL DEFAULT 0,
  schedule_variance_zar                       REAL NOT NULL DEFAULT 0,

  -- Variance + reforecast + CR tracking
  variance_count                              INTEGER NOT NULL DEFAULT 0,
  reforecast_count                            INTEGER NOT NULL DEFAULT 0,
  cr_count                                    INTEGER NOT NULL DEFAULT 0,
  cr_value_zar                                REAL NOT NULL DEFAULT 0,
  last_variance_at                            TEXT,
  last_reforecast_at                          TEXT,
  last_cr_at                                  TEXT,
  variance_reason                             TEXT,
  reforecast_reason                           TEXT,
  reforecast_rejection_reason                 TEXT,
  cr_summary                                  TEXT,

  -- 5 floor flags
  cpi_below_pct_85                            INTEGER NOT NULL DEFAULT 0,
  contingency_consumed_pct_75                 INTEGER NOT NULL DEFAULT 0,
  management_reserve_drawn                    INTEGER NOT NULL DEFAULT 0,
  forex_variance_above_pct_10                 INTEGER NOT NULL DEFAULT 0,
  multi_currency_book                         INTEGER NOT NULL DEFAULT 0,

  -- Tier + authority + completeness battery
  current_tier                                TEXT NOT NULL CHECK (current_tier IN (
    'small','medium','large','mega'
  )),
  authority_required                          TEXT CHECK (authority_required IN (
    'cost_engineer','PM','finance_director','CFO'
  )),
  urgency_band                                TEXT,
  evm_health_band                             TEXT,
  evm_completeness_index                      INTEGER NOT NULL DEFAULT 0,

  -- Narrative
  title                                       TEXT,
  narrative                                   TEXT,
  reason_code                                 TEXT,
  cancel_reason                               TEXT,

  current_ball_in_court_party                 TEXT,
  last_responder_party                        TEXT,

  is_reportable                               INTEGER NOT NULL DEFAULT 0,
  regulator_relevant                          INTEGER NOT NULL DEFAULT 0,
  regulator_reason_text                       TEXT,

  -- 11 lifecycle + 3 branch status timestamps
  chain_status                                TEXT NOT NULL CHECK (chain_status IN (
    'budget_set','committed','incurred','measured','variance_detected',
    'reforecast_drafted','CR_logged','CR_approved','reforecast_published',
    'reconciled','closed','cancelled','reforecast_rejected','contingency_drawn'
  )),
  budget_set_at                               TEXT,
  committed_at                                TEXT,
  incurred_at                                 TEXT,
  measured_at                                 TEXT,
  variance_detected_at                        TEXT,
  reforecast_drafted_at                       TEXT,
  cr_logged_at                                TEXT,
  cr_approved_at                              TEXT,
  reforecast_published_at                     TEXT,
  reconciled_at                               TEXT,
  closed_at                                   TEXT,
  cancelled_at                                TEXT,
  reforecast_rejected_at                      TEXT,
  contingency_drawn_at                        TEXT,
  signoff_at                                  TEXT,

  -- Regulator crossing
  regulator_crossed_at                        TEXT,
  regulator_inbox_ref                         TEXT,
  regulator_ref                               TEXT,

  -- SLA
  sla_target_hours                            INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                             TEXT,
  last_sla_breach_at                          TEXT,
  sla_breached                                INTEGER NOT NULL DEFAULT 0,
  escalation_level                            INTEGER NOT NULL DEFAULT 0,

  tenant_id                                   TEXT,
  created_by                                  TEXT NOT NULL,
  created_at                                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_ipp_evm_events (
