  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_ipp_risk_events (
  id          TEXT PRIMARY KEY,
  risk_id     TEXT NOT NULL REFERENCES oe_ipp_risks(id),
  event_type  TEXT NOT NULL,
  actor_id    TEXT,
  from_status TEXT,
  to_status   TEXT,
  payload     TEXT,
  created_at  TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_ipp_risks (
  id                          TEXT PRIMARY KEY,
  project_id                  TEXT NOT NULL,
  project_name                TEXT,

  -- Risk identification
  title                       TEXT NOT NULL,
  description                 TEXT,
  risk_category               TEXT NOT NULL DEFAULT 'technical'
                              CHECK (risk_category IN (
                                'construction','technical','financial','regulatory',
                                'environmental','safety','geopolitical','commercial',
                                'force_majeure','legal'
                              )),

  -- Risk tier (INVERTED SLA: catastrophic gets most time for response planning)
  risk_tier                   TEXT NOT NULL DEFAULT 'medium_impact'
                              CHECK (risk_tier IN (
                                'low_impact','medium_impact','high_impact',
                                'critical_impact','catastrophic'
                              )),

  -- Chain state
  chain_status                TEXT NOT NULL DEFAULT 'identified'
                              CHECK (chain_status IN (
                                'identified','assessed','quantified','response_planned',
                                'owner_assigned','monitoring','triggered','responding',
                                'outcome_recorded','closed','archived',
                                'escalated','deferred','cancelled','overdue_flagged'
                              )),

  -- Probability × Impact matrix (1–5 scale, PMBOK 7 Table 11-3)
  probability_score           INTEGER CHECK (probability_score BETWEEN 1 AND 5),
  impact_score                INTEGER CHECK (impact_score BETWEEN 1 AND 5),
  risk_score                  INTEGER,   -- probability_score × impact_score (1–25)
  residual_probability_score  INTEGER CHECK (residual_probability_score BETWEEN 1 AND 5),
  residual_impact_score       INTEGER CHECK (residual_impact_score BETWEEN 1 AND 5),
  residual_risk_score         INTEGER,   -- after mitigation

  -- Response strategy
  response_strategy           TEXT CHECK (response_strategy IN (
                                'avoid','mitigate','transfer','accept','escalate'
                              )),
  response_plan               TEXT,
  contingency_reserve_zar     REAL,
  risk_trigger_description    TEXT,   -- what happened when risk materialised
  treatment_outcome           TEXT,   -- result after response
  lessons_learned             TEXT,
  evidence_ref                TEXT,

  -- Ownership
  risk_owner                  TEXT,
  assigned_to                 TEXT,

  -- SLA (INVERTED: catastrophic 2160h > critical 1440h > high 720h > medium 336h > low 168h)
  sla_target_hours            INTEGER,
  sla_deadline_at             TEXT,
  sla_breached                INTEGER NOT NULL DEFAULT 0,
  last_sla_breach_at          TEXT,
  escalation_level            INTEGER NOT NULL DEFAULT 0,

  -- Regulator crossing fields (SIGNATURE)
  is_reportable               INTEGER NOT NULL DEFAULT 0,
  regulator_relevant          INTEGER NOT NULL DEFAULT 0,
  regulator_ref               TEXT,
  regulator_crossed_at        TEXT,

  -- Context flags
  is_safety                   INTEGER NOT NULL DEFAULT 0,
  is_regulatory               INTEGER NOT NULL DEFAULT 0,

  -- Floor flags (INVERTED SLA drivers — caller-supplied)
  floor_board_notify          INTEGER NOT NULL DEFAULT 0,  -- ≥20 risk_score OR safety critical
  floor_ep4_action_required   INTEGER NOT NULL DEFAULT 0,  -- Equator Principles IV action plan
  floor_lender_notifiable     INTEGER NOT NULL DEFAULT 0,  -- lender covenant trigger
  floor_nersa_notifiable      INTEGER NOT NULL DEFAULT 0,  -- regulatory notification
  floor_insurance_applicable  INTEGER NOT NULL DEFAULT 0,  -- insurance claim applicable

  -- Bridge references
  issue_ref                   TEXT,   -- W132 linked issue (when triggered)
  stage_gate_ref              TEXT,   -- W131 gate-blocking risk
  procurement_ref             TEXT,   -- W19 procurement risk
  hse_incident_ref            TEXT,   -- W25 safety risk
  w118_block_ref              TEXT,   -- W118 MANDATORY at outcome_recorded

  -- Live bridge flags
  bridges_to_issue_live       INTEGER NOT NULL DEFAULT 0,
  bridges_to_sg_live          INTEGER NOT NULL DEFAULT 0,
  bridges_to_w118_live        INTEGER NOT NULL DEFAULT 0,

  -- State timestamps
  identified_at               TEXT,
  assessed_at                 TEXT,
  quantified_at               TEXT,
  response_planned_at         TEXT,
  owner_assigned_at           TEXT,
  monitoring_at               TEXT,
  triggered_at                TEXT,
  responding_at               TEXT,
  outcome_recorded_at         TEXT,
  closed_at                   TEXT,
  archived_at                 TEXT,
  escalated_at                TEXT,
  deferred_at                 TEXT,
  cancelled_at                TEXT,
  overdue_flagged_at          TEXT,

  -- Audit
  created_by                  TEXT,
  created_at                  TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at                  TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_ipp_schedule (
  id                                          TEXT PRIMARY KEY,
  schedule_number                             TEXT UNIQUE NOT NULL,

  -- Project linkage
  project_id                                  TEXT NOT NULL,
  project_name                                TEXT,
  project_capacity_mw                         REAL NOT NULL DEFAULT 0,
  project_type                                TEXT,

  -- Cross-chain bridges (W19 / W20 / W23 / W25)
  procurement_ref                             TEXT,
  cod_ref                                     TEXT,
  insurance_claim_ref                         TEXT,
  hse_incident_ref                            TEXT,

  -- Baseline + dates
  baseline_label                              TEXT,
  baseline_set_at                             TEXT,
  baseline_total_tasks                        INTEGER NOT NULL DEFAULT 0,
  baseline_total_duration_days                INTEGER NOT NULL DEFAULT 0,
  baseline_planned_start                      TEXT,
  baseline_planned_finish                     TEXT,
  current_planned_finish                      TEXT,
  contractual_final_milestone_date            TEXT,

  -- Progress
  percent_complete                            REAL NOT NULL DEFAULT 0,
  tasks_completed                             INTEGER NOT NULL DEFAULT 0,
  tasks_in_progress                           INTEGER NOT NULL DEFAULT 0,
  tasks_not_started                           INTEGER NOT NULL DEFAULT 0,
  last_progress_update_at                     TEXT,

  -- EVM (Earned Value Management)
  planned_value_zar                           REAL NOT NULL DEFAULT 0,
  earned_value_zar                            REAL NOT NULL DEFAULT 0,
  actual_cost_zar                             REAL NOT NULL DEFAULT 0,
  budget_at_completion_zar                    REAL NOT NULL DEFAULT 0,
  cpi                                         REAL NOT NULL DEFAULT 0,
  spi                                         REAL NOT NULL DEFAULT 0,
  spi_t                                       REAL NOT NULL DEFAULT 0,
  schedule_variance_zar                       REAL NOT NULL DEFAULT 0,
  cost_variance_zar                           REAL NOT NULL DEFAULT 0,
  schedule_variance_pct                       REAL NOT NULL DEFAULT 0,
  cost_variance_pct                           REAL NOT NULL DEFAULT 0,

  -- Critical path
  critical_path_total_float_days              REAL NOT NULL DEFAULT 0,
  critical_tasks_count                        INTEGER NOT NULL DEFAULT 0,
  longest_path_duration_days                  INTEGER NOT NULL DEFAULT 0,

  -- Variance + rebaseline tracking
  variance_count                              INTEGER NOT NULL DEFAULT 0,
  rebaseline_count                            INTEGER NOT NULL DEFAULT 0,
  last_variance_at                            TEXT,
  last_rebaseline_at                          TEXT,
  variance_reason                             TEXT,
  rebaseline_reason                           TEXT,
  recovery_plan_summary                       TEXT,

  -- 5 floor flags
  critical_path_breach                        INTEGER NOT NULL DEFAULT 0,
  resource_constrained_over_pct_25            INTEGER NOT NULL DEFAULT 0,
  weather_window_at_risk                      INTEGER NOT NULL DEFAULT 0,
  community_disruption_threshold_breached     INTEGER NOT NULL DEFAULT 0,
  EPC_subcontractor_milestone_at_risk         INTEGER NOT NULL DEFAULT 0,

  -- Tier + authority + completeness battery
  current_tier                                TEXT NOT NULL CHECK (current_tier IN (
    'small','medium','large','mega'
  )),
  authority_required                          TEXT CHECK (authority_required IN (
    'scheduler','project_manager','portfolio_director','IPP_CEO'
  )),
  urgency_band                                TEXT,
  schedule_health_band                        TEXT,
  schedule_completeness_index                 INTEGER NOT NULL DEFAULT 0,

  -- Narrative
  title                                       TEXT,
  narrative                                   TEXT,
  reason_code                                 TEXT,
  suspend_reason                              TEXT,
  cancel_reason                               TEXT,
  late_finish_reason                          TEXT,

  current_ball_in_court_party                 TEXT,
  last_responder_party                        TEXT,

  is_reportable                               INTEGER NOT NULL DEFAULT 0,
  regulator_relevant                          INTEGER NOT NULL DEFAULT 0,
  regulator_reason_text                       TEXT,

  -- 9 lifecycle + 3 branch status timestamps
  chain_status                                TEXT NOT NULL CHECK (chain_status IN (
    'wbs_drafted','baseline_set','in_progress','status_updated',
    'variance_detected','impact_assessed','rebaselined','recovered',
    'completed','suspended','cancelled','late_finish'
  )),
  wbs_drafted_at                              TEXT,
  in_progress_at                              TEXT,
  status_updated_at                           TEXT,
  variance_detected_at                        TEXT,
  impact_assessed_at                          TEXT,
  rebaselined_at                              TEXT,
  recovered_at                                TEXT,
  completed_at                                TEXT,
  suspended_at                                TEXT,
  cancelled_at                                TEXT,
  late_finish_at                              TEXT,
  signoff_at                                  TEXT,

  -- Regulator crossing
  regulator_crossed_at                        TEXT,
  regulator_inbox_ref                         TEXT,
  regulator_ref                               TEXT,

  -- SLA
  sla_target_hours                            INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                             TEXT,
  last_sla_breach_at                          TEXT,
  sla_breached                                INTEGER NOT NULL DEFAULT 0,
  escalation_level                            INTEGER NOT NULL DEFAULT 0,

  tenant_id                                   TEXT,
  created_by                                  TEXT NOT NULL,
  created_at                                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

