  last_sla_breach_at                  TEXT,
  escalation_level                    INTEGER NOT NULL DEFAULT 0,

  created_by                          TEXT NOT NULL,
  created_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_itp_inspection_events (
  id                  TEXT PRIMARY KEY,
  itp_id              TEXT NOT NULL,
  event_type          TEXT NOT NULL,
  from_status         TEXT,
  to_status           TEXT,
  actor_id            TEXT,
  actor_party         TEXT,
  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_kyc_beneficial_owners (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,                  -- the corporate entity
  full_name       TEXT NOT NULL,
  id_number       TEXT,
  date_of_birth   TEXT,
  ownership_pct   REAL,
  is_pep          INTEGER NOT NULL DEFAULT 0,
  declared_at     TEXT NOT NULL DEFAULT (datetime('now')),
  verified_at     TEXT,
  verified_by     TEXT,
  source_of_funds TEXT
);

CREATE TABLE oe_kyc_risk_scores (
  participant_id           TEXT PRIMARY KEY,
  geographic_risk          REAL NOT NULL DEFAULT 0,   -- 0..100
  occupation_risk          REAL NOT NULL DEFAULT 0,
  product_risk             REAL NOT NULL DEFAULT 0,
  transaction_pattern_risk REAL NOT NULL DEFAULT 0,
  total_score              REAL NOT NULL DEFAULT 0,
  risk_tier                TEXT NOT NULL DEFAULT 'low',  -- low | medium | high
  inputs_json              TEXT,                          -- audit trail of inputs
  last_assessed_at         TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_kyc_screenings (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  screening_type  TEXT NOT NULL,                 -- pep | sanctions | adverse_media
  list_source     TEXT NOT NULL,                 -- un_consolidated | ofac_sdn | eu_consolidated | uk_hmt | sa_dwc_pep
  match_count     INTEGER NOT NULL DEFAULT 0,
  matches_json    TEXT,                          -- JSON of match details
  max_match_score REAL,                          -- 0..1 highest similarity
  status          TEXT NOT NULL DEFAULT 'pending_review',
                                                  -- pending_review | cleared | confirmed_match |
                                                  -- escalated | false_positive
  reviewer_id     TEXT,
  reviewed_at     TEXT,
  notes           TEXT,
  screened_at     TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_kyc_submissions (
  id                 TEXT PRIMARY KEY,
  participant_id     TEXT NOT NULL,
  document_type      TEXT NOT NULL,              -- id_document | proof_of_address |
                                                  -- company_registration | tax_clearance |
                                                  -- bank_confirmation | nersa_licence
  r2_key             TEXT NOT NULL,
  file_name          TEXT,
  mime_type          TEXT,
  size_bytes         INTEGER,
  status             TEXT NOT NULL DEFAULT 'pending',
                                                  -- pending | approved | rejected | expired
  reviewer_id        TEXT,
  reviewed_at        TEXT,
  notes              TEXT,
  expires_at         TEXT,                       -- e.g. 12 months for proof of address
  submitted_at       TEXT NOT NULL DEFAULT (datetime('now'))
, tenant_id TEXT, reason_code TEXT);

CREATE TABLE oe_kyc_tiers (
  participant_id           TEXT PRIMARY KEY,
  current_tier             INTEGER NOT NULL DEFAULT 0,   -- 0..3
  per_trade_limit_zar      REAL NOT NULL DEFAULT 0,
  monthly_volume_limit_zar REAL NOT NULL DEFAULT 0,
  evidence_status          TEXT,                          -- JSON {tier1:'approved', ...}
  upgraded_by              TEXT,
  upgraded_at              TEXT,
  updated_at               TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_kyc_verifications (
  id                   TEXT PRIMARY KEY,
  chain_status         TEXT NOT NULL DEFAULT 'pending_submission',
  sla_deadline         TEXT,
  sla_breached         INTEGER NOT NULL DEFAULT 0,
  regulator_notified   INTEGER NOT NULL DEFAULT 0,
  actor_id             TEXT,
  reason               TEXT,
  created_at           TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at           TEXT NOT NULL DEFAULT (datetime('now')),

  -- Subject
  participant_id       TEXT NOT NULL,
  entity_type          TEXT NOT NULL DEFAULT 'company'
                         CHECK (entity_type IN ('individual','company','trust','fund','foreign_entity')),
  risk_level           TEXT NOT NULL DEFAULT 'standard'
                         CHECK (risk_level IN ('standard','medium','high_risk','pep')),

  -- Document refs (R2 vault keys)
  id_document_ref      TEXT,
  proof_of_address_ref TEXT,
  company_docs_ref     TEXT,
  beneficial_owner_ref TEXT,
  edd_report_ref       TEXT,

  -- Screening outcomes
  pep_match            INTEGER NOT NULL DEFAULT 0,
  sanctions_match      INTEGER NOT NULL DEFAULT 0,
  adverse_media_match  INTEGER NOT NULL DEFAULT 0,

  -- Conditions (conditionally_approved)
  conditions_text      TEXT,
  conditions_met_at    TEXT,
  verified_at          TEXT
);

CREATE TABLE oe_late_payment_fees (
  id              TEXT PRIMARY KEY,
  invoice_id      TEXT NOT NULL REFERENCES invoices(id),
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  invoice_total   REAL NOT NULL,
  days_overdue    INTEGER NOT NULL,
  annual_rate_pct REAL NOT NULL,                   -- prime + 1% snapshot
  fee_zar         REAL NOT NULL,
  computed_at     TEXT NOT NULL DEFAULT (datetime('now')),
  status          TEXT NOT NULL DEFAULT 'pending', -- pending|waived|charged|settled
  waived_by       TEXT,
  waiver_reason   TEXT
);

CREATE TABLE oe_lender_dunning_notices (
  id                     TEXT PRIMARY KEY,
  watchlist_id           TEXT,                       -- nullable for standalone notices
  facility_id            TEXT NOT NULL,
  borrower_id            TEXT NOT NULL,              -- the participant id of the borrower
  cycle                  INTEGER NOT NULL DEFAULT 1, -- 1=info, 2=formal warning, 3=default notice
  trigger_signal         TEXT NOT NULL,              -- covenant_breach | covenant_warn |
                                                      -- payment_delay | dscr_warning |
                                                      -- rating_downgrade | manual
  title                  TEXT NOT NULL,
  body_json              TEXT NOT NULL,              -- arbitrary structured context
  status                 TEXT NOT NULL DEFAULT 'issued',
                                                      -- issued | acknowledged | cured |
                                                      -- overdue | withdrawn | escalated
  issued_at              TEXT NOT NULL DEFAULT (datetime('now')),
  issued_by              TEXT,
  cure_deadline_at       TEXT NOT NULL,
  acked_at               TEXT,
  acked_by               TEXT,
  cured_at               TEXT,
  cured_by               TEXT,
  cure_evidence_r2_key   TEXT,
  overdue_flagged_at     TEXT,
  withdrawn_at           TEXT,
  withdrawn_by           TEXT,
  escalated_at           TEXT,
  parent_notice_id       TEXT,                       -- prior cycle that triggered this one
  created_at             TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at             TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_lender_ecl_staging (
  id                      TEXT PRIMARY KEY,
  facility_id             TEXT NOT NULL,
  participant_id          TEXT NOT NULL,         -- the borrower
  stage                   INTEGER NOT NULL,      -- 1=performing | 2=under-perf | 3=non-perf
  stage_changed_at        TEXT,
  stage_change_reason     TEXT,
  exposure_zar            REAL NOT NULL,
  pd_12m                  REAL,                  -- 12-month probability of default
  pd_lifetime             REAL,                  -- lifetime PD
  lgd_pct                 REAL,                  -- loss given default
  ead_zar                 REAL,                  -- exposure at default
  ecl_amount_zar          REAL NOT NULL,         -- expected credit loss
  next_assessment_at      TEXT,
  notes                   TEXT,
  computed_at             TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_lender_intercreditor (
  id                         TEXT PRIMARY KEY,
  project_id                 TEXT NOT NULL,
  agent_lender_id            TEXT NOT NULL,
  total_facility_zar         REAL NOT NULL,
  senior_pct                 REAL NOT NULL,
  mezzanine_pct              REAL,
  subordinated_pct           REAL,
  cash_sweep_rule            TEXT,                -- JSON priority of payments
  voting_thresholds_json     TEXT,                -- {amend: 66, accelerate: 75, …}
  signed_at                  TEXT,
  created_at                 TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_lender_watchlist (
  id                     TEXT PRIMARY KEY,
  facility_id            TEXT NOT NULL,
  participant_id         TEXT NOT NULL,
  watchlist_tier         INTEGER NOT NULL,       -- 1=monitor, 2=concern, 3=critical
  trigger_signal         TEXT NOT NULL,          -- dscr_warning | covenant_breach |
                                                  -- payment_delay | rating_downgrade |
                                                  -- credit_deterioration
  trigger_value          REAL,
  action_plan            TEXT,
  added_at               TEXT NOT NULL DEFAULT (datetime('now')),
  reviewed_at            TEXT,
  next_review_at         TEXT,
  cleared_at             TEXT,
  added_by               TEXT
, cure_deadline_at    TEXT, dunning_cycle       INTEGER NOT NULL DEFAULT 0, auto_escalated_at   TEXT, borrower_acked_at   TEXT);

CREATE TABLE oe_lender_watchlist_events (
  id                  TEXT PRIMARY KEY,
  watchlist_id        TEXT NOT NULL,
  event_type          TEXT NOT NULL,                 -- added | tier_escalated | tier_decreased |
                                                      -- dunning_issued | dunning_cured |
                                                      -- dunning_overdue | cleared
  from_tier           INTEGER,
  to_tier             INTEGER,
  actor_id            TEXT,
  notes               TEXT,
  meta_json           TEXT,
  occurred_at         TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_licence_applications (
  id                            TEXT PRIMARY KEY,
  application_number            TEXT UNIQUE NOT NULL,

  -- Provenance (e.g. a connection agreement or procurement award that triggered it)
  source_event                  TEXT,
  source_entity_type            TEXT,
  source_entity_id              TEXT,
  source_wave                   TEXT,

  -- Parties (two-party split: applicant + NERSA officer)
  applicant_party_id            TEXT NOT NULL,
  applicant_party_name          TEXT NOT NULL,
  regulator_party_id            TEXT NOT NULL,
  regulator_party_name          TEXT NOT NULL,

  -- Application identity
  licence_class                 TEXT NOT NULL CHECK (licence_class IN (
    'major_licence', 'standard_licence', 'minor_licence'
  )),
  licence_type                  TEXT NOT NULL,     -- generation / transmission / distribution / trading / import_export
  technology                    TEXT,              -- solar_pv / wind / battery / gas / hydro / grid / na
  facility_name                 TEXT NOT NULL,
  facility_location             TEXT,              -- province / municipality
  capacity_mw                   REAL,              -- generation capacity / transfer capacity / notified max demand
  estimated_capex_zar_m         REAL,              -- estimated project capex (R millions)
  grid_connection_ref           TEXT,              -- W28 GCA ref where applicable
  reipppp_round                 TEXT,              -- procurement round where applicable

  -- Refs
  application_ref               TEXT,
  completeness_ref              TEXT,
  info_request_ref              TEXT,
  acceptance_ref                TEXT,
  participation_ref             TEXT,
  evaluation_ref                TEXT,
  council_ref                   TEXT,
  licence_ref                   TEXT,              -- issued licence number
  gazette_ref                   TEXT,              -- Government Gazette notice ref
  regulator_ref                 TEXT,              -- Council oversight / public register ref

  -- Narrative
  application_basis             TEXT,
  completeness_basis            TEXT,
  info_request_basis            TEXT,
  acceptance_basis              TEXT,
  participation_basis           TEXT,
  evaluation_basis              TEXT,
  council_basis                 TEXT,
  grant_basis                   TEXT,
  refusal_basis                 TEXT,
  reason_code                   TEXT,
  rod_notes                     TEXT,              -- record of decision

  info_request_round            INTEGER NOT NULL DEFAULT 0,

  -- State + lifecycle
  chain_status                  TEXT NOT NULL CHECK (chain_status IN (
    'application_received','completeness_review','additional_info_requested','accepted',
    'public_participation','technical_evaluation','council_decision','licence_granted',
    'licence_issued','refused','withdrawn','lapsed'
  )),
  application_received_at       TEXT NOT NULL,
  completeness_review_at        TEXT,
  additional_info_requested_at  TEXT,
  accepted_at                   TEXT,
  public_participation_at       TEXT,
  technical_evaluation_at       TEXT,
  council_decision_at           TEXT,
  licence_granted_at            TEXT,
  licence_issued_at             TEXT,
  refused_at                    TEXT,
  withdrawn_at                  TEXT,
  lapsed_at                     TEXT,

  is_reportable                 INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at               TEXT,
  last_sla_breach_at            TEXT,
  escalation_level              INTEGER NOT NULL DEFAULT 0,

  created_by                    TEXT NOT NULL,
  created_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_licence_applications_events (
  id                 TEXT PRIMARY KEY,
  application_id     TEXT NOT NULL,
  event_type         TEXT NOT NULL,
  from_status        TEXT,
  to_status          TEXT,
  actor_id           TEXT,
  actor_party        TEXT,
  notes              TEXT,
  payload            TEXT,
  created_at         TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_licence_obligations (
  id                    TEXT PRIMARY KEY,
  ipp_id                TEXT NOT NULL,
  licence_number        TEXT NOT NULL,
  obligation_ref        TEXT NOT NULL,
