                          'security_of_supply', 'environmental', 'financial',
                          'technical', 'administrative'
                        )),
  condition_description TEXT NOT NULL,
  compliance_period     TEXT NOT NULL,
  project_name          TEXT,
  chain_status          TEXT NOT NULL DEFAULT 'monitoring_active'
                          CHECK (chain_status IN (
                            'monitoring_active',
                            'assessment_due',
                            'evidence_gathered',
                            'evidence_submitted',
                            'under_review',
                            'query_raised',
                            'query_resolved',
                            'assessed_compliant',
                            'assessed_non_compliant',
                            'notice_issued',
                            'cure_active',
                            'cured',
                            'breached'
                          )),
  sla_deadline          TEXT,
  sla_breached          INTEGER NOT NULL DEFAULT 0,
  regulator_notified    INTEGER NOT NULL DEFAULT 0,
  actor_id              TEXT,
  reason                TEXT,
  created_at            TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at            TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_licence_renewal_events (
  id              TEXT PRIMARY KEY,
