CREATE TABLE oe_licence_renewals (
  id                          TEXT PRIMARY KEY,
  case_number                 TEXT NOT NULL UNIQUE,
  licence_id                  TEXT NOT NULL,
  licence_number              TEXT,
  licence_type                TEXT NOT NULL CHECK (licence_type IN ('generation','distribution','trading')),
  licence_class               TEXT NOT NULL CHECK (licence_class IN ('generation_utility','generation_embedded','generation_sseg','distribution','trading')),
  capacity_mw                 REAL,
  source_event                TEXT,
  source_entity_type          TEXT,
  source_entity_id            TEXT,
  source_wave                 TEXT,
  applicant_party_id          TEXT NOT NULL,
  applicant_party_name        TEXT NOT NULL,
  facility_name               TEXT,
  facility_province           TEXT,
  current_expiry_date         TEXT NOT NULL,
  requested_expiry_date       TEXT,
  granted_expiry_date         TEXT,
  application_pack_ref        TEXT,
  completeness_findings       TEXT,
  completeness_ref            TEXT,
  consultation_notice_ref     TEXT,
  consultation_responses_count INTEGER DEFAULT 0,
  technical_findings          TEXT,
  technical_evaluation_ref    TEXT,
  financial_findings          TEXT,
  financial_evaluation_ref    TEXT,
  decision_rod_ref            TEXT,
  council_meeting_ref         TEXT,
  council_vote_outcome        TEXT,
  conditions_attached         TEXT,
  amendment_summary           TEXT,
  refusal_grounds             TEXT,
  withdrawal_basis            TEXT,
  withdrawal_minute_ref       TEXT,
  appeal_filed                INTEGER NOT NULL DEFAULT 0,
  appeal_filing_ref           TEXT,
  tribunal_case_ref           TEXT,
  reason_code                 TEXT,
  rod_notes                   TEXT,
  chain_status                TEXT NOT NULL DEFAULT 'renewal_initiated',
  initiated_at                TEXT NOT NULL,
  application_filed_at        TEXT,
  completeness_checked_at     TEXT,
  consultation_opened_at      TEXT,
  evaluation_started_at       TEXT,
  decision_drafted_at         TEXT,
  council_voted_at            TEXT,
  granted_at                  TEXT,
  amended_at                  TEXT,
  refused_at                  TEXT,
  withdrawn_at                TEXT,
  sla_deadline_at             TEXT,
  last_sla_breach_at          TEXT,
  escalation_level            INTEGER NOT NULL DEFAULT 0,
  created_by                  TEXT NOT NULL,
  created_at                  TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at                  TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_load_curtailment (
  id                      TEXT PRIMARY KEY,
  case_number             TEXT UNIQUE NOT NULL,

  -- Provenance (W13 dispatch nominations + W18 emergency outages can initiate)
  source_event            TEXT,
  source_entity_type      TEXT,
  source_entity_id        TEXT,
  source_wave             TEXT,

  -- SO (system operator) party
  so_party_id             TEXT NOT NULL,
  so_party_name           TEXT NOT NULL,

  -- Customer / Distribution / IPP target party (curtailment respondent)
  customer_party_id       TEXT NOT NULL,
  customer_party_name     TEXT NOT NULL,
  customer_category       TEXT NOT NULL CHECK (customer_category IN (
    'distribution', 'large_industrial', 'embedded_generator', 'mining', 'metro'
  )),
  facility_name           TEXT,
  facility_province       TEXT,

  -- Stage + targets
  load_shed_stage         TEXT NOT NULL CHECK (load_shed_stage IN (
    'stage_1_2','stage_3_4','stage_5_6','stage_7_8'
  )),
  national_shed_gw        REAL NOT NULL,
  target_mw               REAL NOT NULL,
  actual_shed_mw          REAL,
  variance_pct            REAL,
  duration_hours          REAL NOT NULL,

  -- Refs
  grid_code_section       TEXT NOT NULL DEFAULT 'CSC-1',
  instruction_ref         TEXT,
  acknowledgement_ref     TEXT,
  metering_reconcile_ref  TEXT,
  post_mortem_ref         TEXT,
  refusal_ref             TEXT,
  partial_ref             TEXT,
  withdrawal_ref          TEXT,

  -- Penalty (only for refused + partial_compliance)
  penalty_zar             REAL,
  penalty_basis           TEXT,
  tribunal_case_ref       TEXT,

  -- Narrative + ROD
  refusal_grounds         TEXT,
  partial_basis           TEXT,
  withdrawal_basis        TEXT,
  post_mortem_findings    TEXT,
  reason_code             TEXT,
  rod_notes               TEXT,

  -- State + lifecycle
  chain_status            TEXT NOT NULL CHECK (chain_status IN (
    'instruction_issued','acknowledged','curtailment_started',
    'target_achieved','instruction_lifted','reconciled','post_mortem',
    'closed','refused','partial_compliance','withdrawn'
  )),
  instruction_issued_at   TEXT NOT NULL,
  acknowledged_at         TEXT,
  curtailment_started_at  TEXT,
  target_achieved_at      TEXT,
  partial_compliance_at   TEXT,
  instruction_lifted_at   TEXT,
  reconciled_at           TEXT,
  post_mortem_opened_at   TEXT,
  closed_at               TEXT,
  refused_at              TEXT,
  withdrawn_at            TEXT,

  sla_deadline_at         TEXT,
  last_sla_breach_at      TEXT,
  escalation_level        INTEGER NOT NULL DEFAULT 0,

  created_by              TEXT NOT NULL,
  created_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_load_curtailment_events (
  id              TEXT PRIMARY KEY,
  curtailment_id  TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_loan_defaults (
  id                      TEXT PRIMARY KEY,
  default_number          TEXT UNIQUE NOT NULL,

  -- Provenance
  source_event            TEXT,
  source_entity_type      TEXT,
  source_entity_id        TEXT,
  source_wave             TEXT,

  -- Borrower (project company / SPV)
  borrower_party_id       TEXT NOT NULL,
  borrower_party_name     TEXT NOT NULL,

  -- Lender of record + security agent (trustee)
  lender_name             TEXT,
  security_agent_name     TEXT,

  -- Facility descriptors
  facility_name           TEXT NOT NULL,
  facility_tier           TEXT NOT NULL CHECK (facility_tier IN (
    'senior_secured', 'mezzanine', 'subordinated'
  )),
  facility_limit          REAL,            -- committed facility size (ZAR)
  outstanding_principal   REAL,            -- drawn + outstanding at default (ZAR)
  accelerated_amount      REAL,            -- amount called on acceleration (ZAR)
  recovery_amount         REAL,            -- realised / recovered (ZAR)
  write_off_amount        REAL,            -- crystallised loss (ZAR)

  -- Default descriptors
  default_type            TEXT,            -- payment / covenant / insolvency / cross_default / moratorium
  default_event           TEXT,            -- short label of the triggering event
  days_past_due           INTEGER,         -- for payment defaults

  -- Refs
  flag_ref                TEXT,
  notice_ref              TEXT,
  cure_ref                TEXT,
  acceleration_ref        TEXT,
  standstill_ref          TEXT,
  enforcement_ref         TEXT,
  restructure_ref         TEXT,

  -- Narrative
  flag_basis              TEXT,
  review_basis            TEXT,
  notice_basis            TEXT,
  cure_basis              TEXT,
  acceleration_basis      TEXT,
  standstill_basis        TEXT,
  enforcement_basis       TEXT,
  restructure_basis       TEXT,
  reason_code             TEXT,
  rod_notes               TEXT,

  -- State + lifecycle
  chain_status            TEXT NOT NULL CHECK (chain_status IN (
    'default_flagged','under_review','reservation_of_rights','default_notice_issued',
    'cure_period','accelerated','standstill','enforcement_commenced',
    'cured','restructured','enforced_closed','written_off'
  )),
  default_flagged_at        TEXT NOT NULL,
  under_review_at           TEXT,
  reservation_of_rights_at  TEXT,
  default_notice_issued_at  TEXT,
  cure_period_at            TEXT,
  accelerated_at            TEXT,
  standstill_at             TEXT,
  enforcement_commenced_at  TEXT,
  cured_at                  TEXT,
  restructured_at           TEXT,
  enforced_closed_at        TEXT,
  written_off_at            TEXT,

  cure_deadline_at         TEXT,           -- contractual cure expiry
  sla_deadline_at          TEXT,
  last_sla_breach_at       TEXT,
  escalation_level         INTEGER NOT NULL DEFAULT 0,

  created_by              TEXT NOT NULL,
  created_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_loan_defaults_events (
  id              TEXT PRIMARY KEY,
  default_id      TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_loan_restructure (
  id                                                  TEXT PRIMARY KEY,
  restructure_number                                  TEXT UNIQUE NOT NULL,

  facility_id                                         TEXT NOT NULL,
  facility_name                                       TEXT,
  borrower_id                                         TEXT NOT NULL,
  borrower_name                                       TEXT,
  lender_agent_id                                     TEXT NOT NULL,
  lender_agent_name                                   TEXT,
  project_id                                          TEXT,
  project_name                                        TEXT,
  syndicate_size                                      INTEGER NOT NULL DEFAULT 1,

  facility_amount_zar                                 REAL NOT NULL DEFAULT 0,
  outstanding_debt_zar                                REAL NOT NULL DEFAULT 0,
  debt_service_per_month_zar                          REAL NOT NULL DEFAULT 0,

  trigger_reason_code                                 TEXT,
  trigger_narrative                                   TEXT,
  covenant_breach_ref                                 TEXT,
  dscr_shortfall_ref                                  TEXT,
  default_chain_ref                                   TEXT,

  forbearance_period_months                           INTEGER NOT NULL DEFAULT 0,
  principal_reschedule_zar                            REAL NOT NULL DEFAULT 0,
  principal_reschedule_pct                            REAL NOT NULL DEFAULT 0,
  maturity_extension_months                           INTEGER NOT NULL DEFAULT 0,
  equity_cure_quantum_zar                             REAL NOT NULL DEFAULT 0,
  proposed_relief_zar                                 REAL NOT NULL DEFAULT 0,

  consent_severity                                    TEXT CHECK (consent_severity IN (
    'simple_majority','special_majority','super_majority','unanimity'
  )),
  consent_threshold_pct                               REAL NOT NULL DEFAULT 50,
  consent_majority_pct                                REAL NOT NULL DEFAULT 0,
  syndicate_consented                                 INTEGER NOT NULL DEFAULT 0,
  consent_deadline_at                                 TEXT,
  consent_majority_passed                             INTEGER NOT NULL DEFAULT 0,

  cross_border_syndicate                              INTEGER NOT NULL DEFAULT 0,
  sustainability_linked_loan                          INTEGER NOT NULL DEFAULT 0,
  public_bondholder_consent_required                  INTEGER NOT NULL DEFAULT 0,
  ifrs9_stage_3_at_trigger                            INTEGER NOT NULL DEFAULT 0,
  sarb_large_exposure_threshold                       INTEGER NOT NULL DEFAULT 0,
  was_on_watch_at_trigger                             INTEGER NOT NULL DEFAULT 0,
  ifrs9_stage_at_trigger                              INTEGER NOT NULL DEFAULT 1,

  current_tier                                        TEXT NOT NULL CHECK (current_tier IN (
    'minor','standard','material','systemic'
  )),
  authority_required                                  TEXT CHECK (authority_required IN (
    'relationship_manager','credit_committee','portfolio_director','CRO','board_credit_subcommittee'
  )),
  board_escalation_required                           INTEGER NOT NULL DEFAULT 0,
  urgency_band                                        TEXT,
  restructure_completeness_index                      INTEGER NOT NULL DEFAULT 0,

  title                                               TEXT,
  narrative                                           TEXT,
  reason_code                                         TEXT,
  cancel_reason                                       TEXT,
  rejection_reason                                    TEXT,
  abandon_reason                                      TEXT,
  escalation_reason                                   TEXT,

  current_ball_in_court_party                         TEXT,
  last_responder_party                                TEXT,

  is_reportable                                       INTEGER NOT NULL DEFAULT 0,
  regulator_relevant                                  INTEGER NOT NULL DEFAULT 0,
  regulator_reason_text                               TEXT,

  chain_status                                        TEXT NOT NULL CHECK (chain_status IN (
    'trigger_event','preliminary_assessment','restructure_proposal_drafted',
    'lender_credit_committee_review','borrower_term_sheet_negotiation',
    'term_sheet_signed','legal_documentation_drafted','consent_solicitation',
    'signing','effective_date','monitoring_period','completed',
    'rejected_by_committee','abandoned','escalated_to_default'
  )),
  trigger_event_at                                    TEXT,
  preliminary_assessment_at                           TEXT,
  restructure_proposal_drafted_at                     TEXT,
  lender_credit_committee_review_at                   TEXT,
  borrower_term_sheet_negotiation_at                  TEXT,
  term_sheet_signed_at                                TEXT,
  legal_documentation_drafted_at                      TEXT,
  consent_solicitation_at                             TEXT,
  signing_at                                          TEXT,
  effective_date_at                                   TEXT,
  monitoring_period_at                                TEXT,
  completed_at                                        TEXT,
  rejected_by_committee_at                            TEXT,
  abandoned_at                                        TEXT,
  escalated_to_default_at                             TEXT,

  regulator_crossed_at                                TEXT,
  regulator_inbox_ref                                 TEXT,
  regulator_ref                                       TEXT,
  sla_target_hours                                    INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                                     TEXT,
  last_sla_breach_at                                  TEXT,
  sla_breached                                        INTEGER NOT NULL DEFAULT 0,
  escalation_level                                    INTEGER NOT NULL DEFAULT 0,

  tenant_id                                           TEXT,
  created_by                                          TEXT NOT NULL,
  created_at                                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_loan_restructure_events (
  id                  TEXT PRIMARY KEY,
  restructure_id      TEXT NOT NULL,
  event_type          TEXT NOT NULL,
  from_status         TEXT,
  to_status           TEXT,
  actor_id            TEXT,
  actor_party         TEXT,
  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_loan_transfers (
  id                            TEXT PRIMARY KEY,
  case_number                   TEXT UNIQUE NOT NULL,

  -- Provenance (the originated facility this participation derives from)
  source_event                  TEXT,
  source_entity_type            TEXT,
  source_entity_id              TEXT,
  source_wave                   TEXT,

  -- Parties (two-party split write: lender side + obligor)
  transferor_party_id           TEXT NOT NULL,
  transferor_party_name         TEXT NOT NULL,
  transferee_party_id           TEXT NOT NULL,
  transferee_party_name         TEXT NOT NULL,
  agent_party_id                TEXT NOT NULL,
  agent_party_name              TEXT NOT NULL,
  obligor_party_id              TEXT NOT NULL,
  obligor_party_name            TEXT NOT NULL,

  -- The facility / participation being transferred
  facility_code                 TEXT,              -- internal facility code
  facility_name                 TEXT NOT NULL,     -- human name of the facility
  transfer_type                 TEXT NOT NULL,     -- novation / assignment / sub_participation / funded_participation
  tranche                       TEXT,              -- term / revolving / dsra / bridge
  borrower_project              TEXT,              -- the underlying REIPPPP project
  facility_currency             TEXT,              -- ZAR / USD / EUR

  -- Transfer economics
  facility_total_zar_m          REAL,              -- total committed facility (ZAR millions)
  transfer_zar_m                REAL NOT NULL,     -- transferred participation (ZAR millions)
  transfer_price_pct            REAL,              -- price as pct of par
  settlement_zar_m              REAL,              -- cash settlement amount
  transfer_tier                 TEXT NOT NULL CHECK (transfer_tier IN (
    'minor','moderate','material','major','systemic'
  )),

  -- Residency of the incoming lender — drives the SARB exchange-control crossing
  transferee_residency          TEXT NOT NULL CHECK (transferee_residency IN (
    'resident','non_resident'
  )),
  transferee_epfi               INTEGER NOT NULL DEFAULT 0,  -- Equator Principles financial institution

  -- Screening / consent / approval gates
  kyc_cleared                   INTEGER NOT NULL DEFAULT 0,
  sanctions_cleared             INTEGER NOT NULL DEFAULT 0,
  obligor_consent_granted       INTEGER NOT NULL DEFAULT 0,
  sarb_approval_required         INTEGER NOT NULL DEFAULT 0,
  sarb_approval_obtained        INTEGER NOT NULL DEFAULT 0,
  certificate_signed            INTEGER NOT NULL DEFAULT 0,
  register_updated              INTEGER NOT NULL DEFAULT 0,

  -- Refs
  request_ref                   TEXT,
  screening_ref                 TEXT,
  remediation_ref               TEXT,
  consent_ref                   TEXT,
  regulatory_ref                TEXT,
  approval_ref                  TEXT,
  certificate_ref               TEXT,
  settlement_ref                TEXT,
  completion_ref                TEXT,
  rejection_ref                 TEXT,
  decline_ref                   TEXT,
  withdrawal_ref                TEXT,
  regulator_ref                 TEXT,

  -- Narrative
  request_basis                 TEXT,
  screening_basis               TEXT,
  remediation_basis             TEXT,
  consent_basis                 TEXT,
  regulatory_basis              TEXT,
  approval_basis                TEXT,
  certificate_basis             TEXT,
  settlement_basis              TEXT,
  rejection_basis               TEXT,
  decline_basis                 TEXT,
  withdrawal_basis              TEXT,
  reason_code                   TEXT,
  notes                         TEXT,

  remediation_round             INTEGER NOT NULL DEFAULT 0,

  -- State + lifecycle
  chain_status                  TEXT NOT NULL CHECK (chain_status IN (
    'transfer_requested','kyc_screening','screening_remediation',
    'consent_solicitation','regulatory_review','transfer_approved',
    'certificate_executed','settled','completed','declined','rejected','withdrawn'
  )),
  transfer_requested_at         TEXT NOT NULL,
  kyc_screening_at              TEXT,
  screening_remediation_at      TEXT,
  consent_solicitation_at       TEXT,
  regulatory_review_at          TEXT,
  transfer_approved_at          TEXT,
  certificate_executed_at       TEXT,
  settled_at                    TEXT,
  completed_at                  TEXT,
  declined_at                   TEXT,
  rejected_at                   TEXT,
  withdrawn_at                  TEXT,

  is_reportable                 INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at               TEXT,
  last_sla_breach_at            TEXT,
  escalation_level              INTEGER NOT NULL DEFAULT 0,

  created_by                    TEXT NOT NULL,
  created_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_loan_transfers_events (
  id                 TEXT PRIMARY KEY,
  transfer_id        TEXT NOT NULL,
  event_type         TEXT NOT NULL,
  from_status        TEXT,
  to_status          TEXT,
  actor_id           TEXT,
  actor_party        TEXT,
  notes              TEXT,
  payload            TEXT,
  created_at         TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_margin_calls (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL,
  triggered_by        TEXT NOT NULL,             -- mark_movement | limit_breach |
                                                  -- regulatory | manual
  required_amount_zar REAL NOT NULL,
  posted_amount_zar   REAL NOT NULL DEFAULT 0,
  deadline_at         TEXT NOT NULL,
  status              TEXT NOT NULL DEFAULT 'open',
                                                  -- open | partial | satisfied |
                                                  -- breached | escalated | substituted
  collateral_basket   TEXT,                      -- JSON acceptable collateral
  notes               TEXT,
  created_at          TEXT NOT NULL DEFAULT (datetime('now')),
  satisfied_at        TEXT
);

CREATE TABLE oe_market_abuse_cases (
  id                            TEXT PRIMARY KEY,
  case_number                   TEXT UNIQUE NOT NULL,

  -- Provenance (the surveillance signal / source that raised the alert)
  source_event                  TEXT,
  source_entity_type            TEXT,
  source_entity_id              TEXT,
  source_wave                   TEXT,

  -- Parties (single-party write; the subject is read-only)
  subject_party_id              TEXT NOT NULL,     -- the trader / member under surveillance
  subject_party_name            TEXT NOT NULL,
  surveillance_party_id         TEXT NOT NULL,     -- the exchange market-surveillance function
  surveillance_party_name       TEXT NOT NULL,

  -- Case identity
  abuse_tier                    TEXT NOT NULL CHECK (abuse_tier IN (
    'info_alert','low_risk','medium_risk','high_risk','critical_abuse'
  )),
  typology                      TEXT NOT NULL,     -- insider_trading / price_manipulation / spoofing / wash_trade / front_running / layering / false_reporting / quote_stuffing
  alert_source                  TEXT,              -- automated_surveillance / mm_report / whistleblower / regulator_referral / news_screening
  instrument                    TEXT,
  energy_type                   TEXT,
  product                       TEXT,
  venue                         TEXT,              -- order_book / otc / auction
  risk_score                    REAL,              -- 0-100 surveillance risk score (drives the tier)
  suspect_volume_mwh            REAL,
  suspect_value_zar_m           REAL,
  estimated_benefit_zar         REAL,              -- estimated illicit gain (R)
  penalty_zar                   REAL,              -- administrative penalty / sanction (R)

  -- Refs
  triage_ref                    TEXT,
  investigation_ref             TEXT,
  evidence_ref                  TEXT,
  analysis_ref                  TEXT,
  stor_ref                      TEXT,
  referral_ref                  TEXT,
  enforcement_ref               TEXT,
  sanction_ref                  TEXT,
  dispute_ref                   TEXT,
  regulator_ref                 TEXT,

  -- Narrative
  triage_basis                  TEXT,
  investigation_basis           TEXT,
  evidence_basis                TEXT,
  analysis_basis                TEXT,
  stor_basis                    TEXT,
  sanction_basis                TEXT,
  dispute_basis                 TEXT,
  reason_code                   TEXT,
  resolution_notes              TEXT,
  notes                         TEXT,

  dispute_round                 INTEGER NOT NULL DEFAULT 0,

  -- State + lifecycle
  chain_status                  TEXT NOT NULL CHECK (chain_status IN (
    'alert_raised','triaged','under_investigation','evidence_review',
    'analysis_complete','cleared','stor_filed','regulator_referred',
    'enforcement_action','sanctioned','disputed','dispute_resolved'
  )),
  alert_raised_at               TEXT NOT NULL,
  triaged_at                    TEXT,
  under_investigation_at        TEXT,
  evidence_review_at            TEXT,
  analysis_complete_at          TEXT,
  cleared_at                    TEXT,
  stor_filed_at                 TEXT,
  regulator_referred_at         TEXT,
  enforcement_action_at         TEXT,
  sanctioned_at                 TEXT,
  disputed_at                   TEXT,
  dispute_resolved_at           TEXT,

  is_reportable                 INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at               TEXT,
  last_sla_breach_at            TEXT,
  escalation_level              INTEGER NOT NULL DEFAULT 0,

  created_by                    TEXT NOT NULL,
  created_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_market_abuse_cases_events (
  id                 TEXT PRIMARY KEY,
  case_id            TEXT NOT NULL,
  event_type         TEXT NOT NULL,
  from_status        TEXT,
  to_status          TEXT,
  actor_id           TEXT,
