);

CREATE TABLE oe_market_conduct_exams (
  id                          TEXT PRIMARY KEY,
  participant_id              TEXT NOT NULL,   -- regulator conducting the examination

  -- Examination classification
  exam_tier                   TEXT NOT NULL CHECK(exam_tier IN (
    'routine','thematic','targeted','major_systemic'
  )),
  exam_type                   TEXT CHECK(exam_type IN (
    'pricing_conduct','transparency','consumer_protection','market_integrity',
    'cross_cutting','ad_hoc',NULL
  )),
  subject_participant_id      TEXT,            -- entity being examined
  subject_licence_class       TEXT,            -- licence class under examination
  examination_ref             TEXT,            -- internal NERSA/FSCA reference

  -- Notice & document request
  notice_issued_at            TEXT,
  notice_ref                  TEXT,
  document_request_ref        TEXT,
  document_deadline           TEXT,
  documents_received_at       TEXT,

  -- On-site review
  on_site_start_date          TEXT,
  on_site_end_date            TEXT,
  on_site_lead_examiner       TEXT,

  -- Findings
  preliminary_findings_ref    TEXT,
  preliminary_issued_at       TEXT,
  response_deadline           TEXT,
  subject_response_ref        TEXT,
  subject_response_at         TEXT,

  -- Final report
  final_report_ref            TEXT,
  final_report_issued_at      TEXT,
  findings_summary            TEXT,
  adverse_findings_count      INTEGER DEFAULT 0,

  -- Outcome
  remedial_action_ref         TEXT,
  remedial_action_deadline    TEXT,
  enforcement_ref             TEXT,            -- links to W40/W66 enforcement proceedings

  chain_status                TEXT NOT NULL DEFAULT 'examination_scheduled' CHECK(chain_status IN (
    'examination_scheduled','notice_issued','document_request','documents_submitted',
    'on_site_review','preliminary_findings','subject_response','final_report_draft',
    'report_issued','remedial_action_required','enforcement_action',
    'closed_satisfactory','withdrawn'
  )),
  sla_deadline                TEXT NOT NULL,
  sla_breached                INTEGER NOT NULL DEFAULT 0,
  regulator_notified          INTEGER NOT NULL DEFAULT 0,

  actor_id                    TEXT,
  reason                      TEXT,
  created_at                  TEXT NOT NULL,
  updated_at                  TEXT NOT NULL
);

CREATE TABLE oe_marketplace_reviews (
  id TEXT PRIMARY KEY,
  transaction_id TEXT NOT NULL REFERENCES oe_sustainability_transactions(id),
  reviewer_id TEXT NOT NULL,
  reviewee_id TEXT NOT NULL,
  rating INTEGER NOT NULL CHECK(rating BETWEEN 1 AND 5),
  comment TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_methodology_amendments (
  id                       TEXT PRIMARY KEY,
  participant_id           TEXT NOT NULL,   -- carbon fund / project developer

  -- Project references
  project_ref              TEXT,            -- link to W37 carbon project registration
  crediting_period_ref     TEXT,            -- link to W56 crediting period renewal
  methodology_id           TEXT NOT NULL,   -- e.g. VM0038, AMS-I.D., GS-SSC-EE
  methodology_version      TEXT,            -- version in use at time of deviation

  -- Deviation details
  amendment_tier           TEXT NOT NULL CHECK(amendment_tier IN (
    'minor_parameter','moderate_change','major_change','article6_itmo'
  )),
  deviation_type           TEXT CHECK(deviation_type IN (
    'emission_factor','additionality_condition','technology_change',
    'monitoring_parameter','baseline_revision','geographic_boundary',NULL
  )),
  deviation_description    TEXT NOT NULL,
  deviation_discovered_at  TEXT,
  estimated_impact_tco2e   REAL,           -- estimated change in ERs due to deviation

  -- Materiality
  materiality_rationale    TEXT,
  is_material              INTEGER,         -- 0/1 determined at materiality_assessment

  -- Amendment details
  amendment_description    TEXT,
  new_methodology_version  TEXT,
  amendment_submitted_at   TEXT,

  -- DNA / Article 6
  dna_name                 TEXT,            -- designated national authority
  dna_notification_ref     TEXT,
  dna_notified_at          TEXT,

  -- Validator
  validator_name           TEXT,
  validator_ref            TEXT,
  revalidation_started_at  TEXT,
  revalidation_completed_at TEXT,
  validator_findings       TEXT,

  -- Outcome
  approved_at              TEXT,
  rejected_at              TEXT,
  rejection_reason         TEXT,

  chain_status             TEXT NOT NULL DEFAULT 'deviation_identified' CHECK(chain_status IN (
    'deviation_identified','materiality_assessment','minor_deviation','major_deviation',
    'methodology_update','dna_notified','validator_assigned','revalidation',
    'amendment_approved','amendment_rejected','withdrawn'
  )),
  sla_deadline             TEXT NOT NULL,
  sla_breached             INTEGER NOT NULL DEFAULT 0,
  regulator_notified       INTEGER NOT NULL DEFAULT 0,

  actor_id                 TEXT,
  reason                   TEXT,
  created_at               TEXT NOT NULL,
  updated_at               TEXT NOT NULL
);

CREATE TABLE oe_metrics_daily (
  id TEXT PRIMARY KEY,
  metric_date TEXT NOT NULL,                 -- YYYY-MM-DD
  chain_key TEXT NOT NULL,
  events_count INTEGER NOT NULL DEFAULT 0,
  value_total_zar REAL NOT NULL DEFAULT 0,
  sla_breaches INTEGER NOT NULL DEFAULT 0,
  regulator_crossings INTEGER NOT NULL DEFAULT 0,
