  required              INTEGER NOT NULL DEFAULT 0,
  allowed_methods       TEXT NOT NULL DEFAULT '["totp"]',  -- JSON
  step_up_grace_seconds INTEGER NOT NULL DEFAULT 900,
  device_trust_days     INTEGER NOT NULL DEFAULT 30,
  updated_at            TEXT NOT NULL DEFAULT (datetime('now')),
  updated_by            TEXT
);

CREATE TABLE oe_mfa_recovery_codes (
  id                 TEXT PRIMARY KEY,
  participant_id     TEXT NOT NULL,
  code_hash          TEXT NOT NULL,              -- SHA-256 of single-use code
  used_at            TEXT,                       -- NULL = available
