CREATE TABLE oe_oem_field_change_orders (
  id                              TEXT PRIMARY KEY,
  campaign_number                 TEXT UNIQUE NOT NULL,

  source_event                    TEXT,
  source_entity_type              TEXT,
  source_entity_id                TEXT,
  source_wave                     TEXT,

  -- OEM + scope identity
  oem_id                          TEXT NOT NULL,
  oem_name                        TEXT NOT NULL,
  product_family                  TEXT NOT NULL,
  product_model                   TEXT NOT NULL,
  serial_range_start              TEXT,
  serial_range_end                TEXT,
  firmware_baseline               TEXT,

  -- Campaign metadata
  campaign_title                  TEXT NOT NULL,
  change_class                    TEXT NOT NULL CHECK (change_class IN (
    'mandatory_safety','mandatory_performance','recommended','optional'
  )),
  technical_summary               TEXT,
  regulatory_reference            TEXT,
  ecrb_decision_ref               TEXT,
  reason_code                     TEXT,

  -- Fleet population
  affected_units                  INTEGER NOT NULL DEFAULT 0,
  affected_capacity_mw            REAL NOT NULL DEFAULT 0,
  affected_owner_count            INTEGER NOT NULL DEFAULT 0,
  affected_site_count             INTEGER NOT NULL DEFAULT 0,
  acknowledged_units              INTEGER NOT NULL DEFAULT 0,
  scheduled_units                 INTEGER NOT NULL DEFAULT 0,
  completed_units                 INTEGER NOT NULL DEFAULT 0,
  warranty_covered_units          INTEGER NOT NULL DEFAULT 0,

  -- Economics
  retrofit_cost_per_unit_zar      REAL NOT NULL DEFAULT 0,
  total_campaign_capex_zar        REAL NOT NULL DEFAULT 0,
  warranty_coverage_pct           REAL NOT NULL DEFAULT 0,
  fleet_energy_at_risk_mw         REAL NOT NULL DEFAULT 0,
  mean_time_to_retrofit_hours     REAL NOT NULL DEFAULT 0,
  predicted_full_coverage_days    REAL,
  judicial_review_risk            INTEGER NOT NULL DEFAULT 0,

  -- Tier (RE-DERIVED)
  campaign_tier                   TEXT NOT NULL CHECK (campaign_tier IN (
    'mandatory_safety','mandatory_performance','recommended','optional'
  )),

  -- Lifecycle flags
  submitted_flag                  INTEGER NOT NULL DEFAULT 0,
  approved_flag                   INTEGER NOT NULL DEFAULT 0,
  population_flag                 INTEGER NOT NULL DEFAULT 0,
  notification_flag               INTEGER NOT NULL DEFAULT 0,
  acknowledged_flag               INTEGER NOT NULL DEFAULT 0,
  scheduling_flag                 INTEGER NOT NULL DEFAULT 0,
  in_progress_flag                INTEGER NOT NULL DEFAULT 0,
  completed_flag                  INTEGER NOT NULL DEFAULT 0,
  suspended_flag                  INTEGER NOT NULL DEFAULT 0,
  cancelled_flag                  INTEGER NOT NULL DEFAULT 0,
  withdrawn_flag                  INTEGER NOT NULL DEFAULT 0,

  -- Refs
  last_action_ref                 TEXT,
  regulator_ref                   TEXT,
  campaign_summary                TEXT,

  -- State machine
  chain_status                    TEXT NOT NULL CHECK (chain_status IN (
    'draft','under_review','approved','population_identified',
    'notification_sent','acknowledged','scheduling','in_progress',
    'completed','suspended','cancelled','withdrawn'
  )),
  draft_at                        TEXT NOT NULL,
  under_review_at                 TEXT,
  approved_at                     TEXT,
  population_identified_at        TEXT,
  notification_sent_at            TEXT,
  acknowledged_at                 TEXT,
  scheduling_at                   TEXT,
  in_progress_at                  TEXT,
  completed_at                    TEXT,
  suspended_at                    TEXT,
  cancelled_at                    TEXT,
  withdrawn_at                    TEXT,

  -- Audit / SLA
  is_reportable                   INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                 TEXT,
  last_sla_breach_at              TEXT,
  escalation_level                INTEGER NOT NULL DEFAULT 0,

  created_by                      TEXT NOT NULL,
  created_at                      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_offer_engagements (
  id                  TEXT PRIMARY KEY,
  offer_id            TEXT NOT NULL,
  offer_kind          TEXT NOT NULL,
  initiator_id        TEXT NOT NULL,     -- the role that selected the offer (e.g. the IPP)
  initiator_role      TEXT NOT NULL,
  offeror_id          TEXT NOT NULL,
  offeror_role        TEXT NOT NULL,
  entity_type         TEXT NOT NULL,     -- what the engagement is about (ipp_projects ...)
  entity_id           TEXT NOT NULL,
  entity_label        TEXT,
  status              TEXT NOT NULL DEFAULT 'requested',  -- requested | accepted | declined | withdrawn
  note                TEXT,
  tenant_id           TEXT NOT NULL DEFAULT 'default',
  created_at          TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_offtaker_delivery_verification (
  id                    TEXT PRIMARY KEY,
  obligation_id         TEXT NOT NULL,                           -- oe_offtaker_ppa_obligations.id
  ppa_id                TEXT NOT NULL,
  period_month          TEXT NOT NULL,
  reading_mwh           REAL NOT NULL,                           -- delta vs the prior reading; can be negative for corrections
  reading_window_start  TEXT,                                    -- ISO; optional
  reading_window_end    TEXT,                                    -- ISO; optional
  submitted_by          TEXT NOT NULL,                           -- IPP user id
  submitted_at          TEXT NOT NULL DEFAULT (datetime('now')),
  status                TEXT NOT NULL DEFAULT 'submitted'
                        CHECK (status IN ('submitted','verified','rejected','reversed')),
  verified_by           TEXT,                                    -- offtaker user id
  verified_at           TEXT,
  rejection_reason      TEXT,
  meter_evidence_r2_key TEXT,
  notes                 TEXT,
  created_at            TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_offtaker_ppa_obligations (
  id                     TEXT PRIMARY KEY,
  ppa_id                 TEXT NOT NULL,                          -- off_ppa_portfolio.id
  participant_id         TEXT NOT NULL,                          -- offtaker (the buyer)
  counterparty_id        TEXT,                                   -- IPP (the seller); informational
  period_month           TEXT NOT NULL,                          -- YYYY-MM
  contracted_mwh         REAL NOT NULL DEFAULT 0,
  delivered_mwh          REAL NOT NULL DEFAULT 0,                -- sum of verified readings for the period
  threshold_pct          REAL NOT NULL DEFAULT 95,               -- % of contracted that must be delivered to avoid take-or-pay
  cure_deadline_at       TEXT,                                   -- ISO; null until shortfall detected
  status                 TEXT NOT NULL DEFAULT 'pending'
                         CHECK (status IN ('pending','delivered','shortfall','cured','take_or_pay')),
  take_or_pay_amount_zar REAL DEFAULT 0,                         -- computed at cure expiry
  cured_at               TEXT,
  cured_by               TEXT,
  cure_evidence_r2_key   TEXT,
  escalated_at           TEXT,
  notes                  TEXT,
  created_at             TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at             TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_onboarding_provisioning_log (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  role            TEXT NOT NULL,
  kind            TEXT NOT NULL,   -- 'om_site' | 'ipp_project' | 'none'
  entity_type     TEXT,
  entity_id       TEXT,
  detail_json     TEXT,
  created_at      TEXT NOT NULL DEFAULT (datetime('now'))
, manifest TEXT DEFAULT '{}');

CREATE TABLE oe_onboarding_state (
  user_id         TEXT NOT NULL,
  step_key        TEXT NOT NULL,
  completed_at    TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (user_id, step_key)
);

CREATE TABLE oe_permit_to_work (
  id                            TEXT PRIMARY KEY,
  permit_number                 TEXT UNIQUE NOT NULL,

  -- Provenance (the W16 work order / W59 PM task the permit authorises)
  source_event                  TEXT,
  source_entity_type            TEXT,
  source_entity_id              TEXT,
  source_wave                   TEXT,

  -- Parties (single-party write; functional tagging only)
  holder_party_id               TEXT NOT NULL,     -- the working crew / contractor
  holder_party_name             TEXT NOT NULL,
  authority_party_id            TEXT NOT NULL,      -- issuing / responsible person
  authority_party_name          TEXT NOT NULL,
  isolating_authority_name      TEXT,              -- competent person who isolated

  -- The asset / location / work
  asset_name                    TEXT,              -- the plant / site
  equipment_tag                 TEXT,              -- specific equipment / circuit reference
  work_location                 TEXT,              -- where on site
  work_description              TEXT,
  work_class                    TEXT NOT NULL CHECK (work_class IN (
    'electrical_live','electrical_isolated','working_at_height',
    'confined_space','hot_work','lifting','excavation','general'
  )),
  method_statement_ref          TEXT,

  -- Hazard rating (the W64 signature)
  hazard_score                  REAL NOT NULL,     -- composite 0..100 (drives tier)
  hazard_tier                   TEXT NOT NULL CHECK (hazard_tier IN (
    'low','moderate','high','critical','catastrophic'
  )),
  live_work                     INTEGER NOT NULL DEFAULT 0,  -- energised-work authorisation
  energy_sources                TEXT,              -- electrical / mechanical / stored / chemical
  isolation_points              INTEGER,           -- number of isolation/lockout points
  permit_validity_hours         REAL,              -- authorised work-window duration

  -- Gates
  assessed_flag                 INTEGER NOT NULL DEFAULT 0,
  isolation_plan_approved       INTEGER NOT NULL DEFAULT 0,
  isolation_verified            INTEGER NOT NULL DEFAULT 0,
  permit_issued_flag            INTEGER NOT NULL DEFAULT 0,
  work_started_flag             INTEGER NOT NULL DEFAULT 0,
  work_completed_flag           INTEGER NOT NULL DEFAULT 0,
  closed_flag                   INTEGER NOT NULL DEFAULT 0,
  revoked_flag                  INTEGER NOT NULL DEFAULT 0,

  -- Refs
  request_ref                   TEXT,
  assessment_ref                TEXT,
  isolation_plan_ref            TEXT,
  isolation_cert_ref            TEXT,
  permit_ref                    TEXT,
  suspension_ref                TEXT,
  completion_ref                TEXT,
  closure_ref                   TEXT,
  rejection_ref                 TEXT,
  revocation_ref                TEXT,
  withdrawal_ref                TEXT,
  regulator_ref                 TEXT,

  -- Narrative
  request_basis                 TEXT,
  assessment_basis              TEXT,
  isolation_basis               TEXT,
  issue_basis                   TEXT,
  suspension_basis              TEXT,
  completion_basis              TEXT,
  closure_basis                 TEXT,
  rejection_basis               TEXT,
  revocation_basis              TEXT,
  withdrawal_basis              TEXT,
  reason_code                   TEXT,
  notes                         TEXT,

  suspend_count                 INTEGER NOT NULL DEFAULT 0,

  -- State + lifecycle
  chain_status                  TEXT NOT NULL CHECK (chain_status IN (
    'permit_requested','hazard_assessment','isolation_pending',
    'isolation_confirmed','permit_issued','work_in_progress','suspended',
    'work_complete','permit_closed','permit_rejected','permit_revoked','withdrawn'
  )),
  permit_requested_at           TEXT NOT NULL,
  hazard_assessment_at          TEXT,
  isolation_pending_at          TEXT,
  isolation_confirmed_at        TEXT,
  permit_issued_at              TEXT,
  work_in_progress_at           TEXT,
  suspended_at                  TEXT,
  work_complete_at              TEXT,
  permit_closed_at              TEXT,
  permit_rejected_at            TEXT,
  permit_revoked_at             TEXT,
  withdrawn_at                  TEXT,

  is_reportable                 INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at               TEXT,
  last_sla_breach_at            TEXT,
  escalation_level              INTEGER NOT NULL DEFAULT 0,

  created_by                    TEXT NOT NULL,
  created_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_permit_to_work_events (
