CREATE TABLE oe_ppa_nominations (
  id                              TEXT PRIMARY KEY,
  nomination_number               TEXT UNIQUE NOT NULL,

  source_event                    TEXT,
  source_entity_type              TEXT,
  source_entity_id                TEXT,
  source_wave                     TEXT,

  ppa_id                          TEXT NOT NULL,
  ppa_reference                   TEXT NOT NULL,
  offtaker_id                     TEXT NOT NULL,
  offtaker_name                   TEXT NOT NULL,
  seller_id                       TEXT NOT NULL,
  seller_name                     TEXT NOT NULL,
  facility_id                     TEXT NOT NULL,
  facility_name                   TEXT NOT NULL,
  system_operator_id              TEXT,
  system_operator_name            TEXT,
  meter_operator_id               TEXT,
  meter_operator_name             TEXT,

  -- Period
  delivery_period_label           TEXT NOT NULL,
  delivery_period_start           TEXT NOT NULL,
  delivery_period_end             TEXT NOT NULL,
  delivery_period_hours           INTEGER NOT NULL DEFAULT 744,
  installed_capacity_mw           REAL NOT NULL DEFAULT 0,

  -- Nomination + delivery
  da_nominated_mwh                REAL NOT NULL DEFAULT 0,
  id_revised_mwh                  REAL,
  effective_nominated_mwh         REAL NOT NULL DEFAULT 0,
  metered_mwh                     REAL,

  -- Deviation analytics
  signed_deviation_mwh            REAL NOT NULL DEFAULT 0,
  absolute_deviation_mwh          REAL NOT NULL DEFAULT 0,
  absolute_deviation_pct          REAL NOT NULL DEFAULT 0,
  weather_attributable_pct        REAL NOT NULL DEFAULT 0,
  prior_pct_1                     REAL,
  prior_pct_2                     REAL,
  prior_pct_3                     REAL,

  -- Tariffs (ZAR / MWh)
  ppa_tariff_zar_per_mwh          REAL NOT NULL DEFAULT 0,
  deviation_tariff_zar_per_mwh    REAL NOT NULL DEFAULT 0,
  penalty_tariff_zar_per_mwh      REAL NOT NULL DEFAULT 0,

  -- Settlement (ZAR)
  contract_value_zar              REAL NOT NULL DEFAULT 0,
  deviation_value_zar             REAL NOT NULL DEFAULT 0,
  predicted_penalty_zar           REAL NOT NULL DEFAULT 0,
  settled_amount_zar              REAL,

  -- Excuse / dispute
  excuse_reason                   TEXT,
  excuse_evidence_ref             TEXT,
  dispute_ground                  TEXT,
  dispute_resolution_ref          TEXT,
  id_revision_count               INTEGER NOT NULL DEFAULT 0,

  -- Tier (RE-DERIVED)
  deviation_tier                  TEXT NOT NULL CHECK (deviation_tier IN ('minor','standard','material','major')),

  -- Lifecycle flags
  da_nominated_flag               INTEGER NOT NULL DEFAULT 0,
  da_confirmed_flag               INTEGER NOT NULL DEFAULT 0,
  id_revised_flag                 INTEGER NOT NULL DEFAULT 0,
  delivery_in_progress_flag       INTEGER NOT NULL DEFAULT 0,
  delivery_complete_flag          INTEGER NOT NULL DEFAULT 0,
  meter_data_flag                 INTEGER NOT NULL DEFAULT 0,
  reconciled_flag                 INTEGER NOT NULL DEFAULT 0,
  dispute_flag                    INTEGER NOT NULL DEFAULT 0,
  settled_flag                    INTEGER NOT NULL DEFAULT 0,
  excused_flag                    INTEGER NOT NULL DEFAULT 0,
  cancelled_flag                  INTEGER NOT NULL DEFAULT 0,

  -- Refs
  last_action_ref                 TEXT,
  regulator_ref                   TEXT,
  chain_basis                     TEXT,
  reason_code                     TEXT,
  nomination_summary              TEXT,

  -- State machine
  chain_status                    TEXT NOT NULL CHECK (chain_status IN (
    'nomination_window_open','da_nominated','da_confirmed','id_revised',
    'delivery_in_progress','delivery_complete','meter_data_received','reconciled',
    'dispute_raised','deviation_settled','excused','cancelled'
  )),
  nomination_window_open_at       TEXT NOT NULL,
  da_nominated_at                 TEXT,
  da_confirmed_at                 TEXT,
  id_revised_at                   TEXT,
  delivery_in_progress_at         TEXT,
  delivery_complete_at            TEXT,
  meter_data_received_at          TEXT,
  reconciled_at                   TEXT,
  dispute_raised_at               TEXT,
  deviation_settled_at            TEXT,
  excused_at                      TEXT,
  cancelled_at                    TEXT,

  -- Audit / SLA
  is_reportable                   INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                 TEXT,
  last_sla_breach_at              TEXT,
  escalation_level                INTEGER NOT NULL DEFAULT 0,

  created_by                      TEXT NOT NULL,
  created_at                      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_ppa_payment_securities (
  id                            TEXT PRIMARY KEY,
  security_number               TEXT UNIQUE NOT NULL,

  -- Provenance (PPA / pipeline source)
  source_event                  TEXT,
  source_entity_type            TEXT,
  source_entity_id              TEXT,
  source_wave                   TEXT,

  -- Parties (two-party write)
  offtaker_party_id             TEXT NOT NULL,     -- the buyer who posts the security
  offtaker_party_name           TEXT NOT NULL,
  seller_party_name             TEXT,              -- IPP beneficiary of the security
  agent_name                    TEXT,              -- facility / security agent

  -- Instrument identity
  security_tier                 TEXT NOT NULL CHECK (security_tier IN (
    'minor','moderate','material','major','critical'
  )),
  instrument_name               TEXT NOT NULL,
  instrument_type               TEXT,              -- letter_of_credit / bank_guarantee / parent_guarantee / cash_deposit
  issuer_name                   TEXT,              -- issuing bank / guarantor
  issuer_rating                 TEXT,              -- issuer credit rating
  secured_amount_zar_m          REAL,              -- secured amount in millions ZAR (drives the tier)
  required_amount_zar_m         REAL,              -- contractually required cover
  cover_months                  REAL,              -- months of invoices covered
  ppa_id                        TEXT,
  ppa_reference                 TEXT,
  project_id                    TEXT,
  project_name                  TEXT,
  sector                        TEXT,              -- solar_pv / wind / bess / chp / hydro
  expiry_date                   TEXT,              -- instrument expiry (drives expiry_pending)

  -- Drawdown / replenishment metrics
  drawn_amount_zar_m            REAL,              -- amount called on the instrument
  outstanding_invoice_zar_m     REAL,              -- unpaid PPA invoice that triggered the call
  replenishment_due_zar_m       REAL,              -- amount required to restore the instrument
  adequacy_shortfall_zar_m      REAL,              -- shortfall vs required cover at adequacy review
  drawdown_count                INTEGER NOT NULL DEFAULT 0,

  -- Refs (per stage)
  submission_ref                TEXT,
  verification_ref              TEXT,
  activation_ref                TEXT,
  adequacy_ref                  TEXT,
  drawdown_ref                  TEXT,
  replenishment_ref             TEXT,
  expiry_ref                    TEXT,
  release_ref                   TEXT,
  forfeit_ref                   TEXT,
  reject_ref                    TEXT,
  regulator_ref                 TEXT,

  -- Narrative
  submission_basis              TEXT,
  verification_basis            TEXT,
  activation_basis              TEXT,
  adequacy_basis                TEXT,
  drawdown_basis                TEXT,
  replenishment_basis           TEXT,
  expiry_basis                  TEXT,
  release_basis                 TEXT,
  forfeit_basis                 TEXT,
  reason_code                   TEXT,
  decision_notes                TEXT,
  notes                         TEXT,

  -- State + lifecycle
  chain_status                  TEXT NOT NULL CHECK (chain_status IN (
    'security_required','instrument_submitted','under_verification','active',
    'adequacy_review','drawdown_initiated','replenishment_pending','expiry_pending',
    'substitution_pending','released','forfeited','rejected'
  )),
  security_required_at          TEXT NOT NULL,
  instrument_submitted_at       TEXT,
  under_verification_at         TEXT,
  active_at                     TEXT,
  adequacy_review_at            TEXT,
  drawdown_initiated_at         TEXT,
  replenishment_pending_at      TEXT,
  expiry_pending_at             TEXT,
  substitution_pending_at       TEXT,
  released_at                   TEXT,
  forfeited_at                  TEXT,
  rejected_at                   TEXT,

  is_reportable                 INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at               TEXT,
  last_sla_breach_at            TEXT,
  escalation_level              INTEGER NOT NULL DEFAULT 0,

  created_by                    TEXT NOT NULL,
  created_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_ppa_payment_securities_events (
  id                 TEXT PRIMARY KEY,
  security_id        TEXT NOT NULL,
  event_type         TEXT NOT NULL,
  from_status        TEXT,
