  counterparty_credit_grade_below_B                   INTEGER NOT NULL DEFAULT 0,
  concentration_above_25pct                           INTEGER NOT NULL DEFAULT 0,
  halted_underlying                                   INTEGER NOT NULL DEFAULT 0,
