  credit_line_checked_at                              TEXT,
  settlement_risk_assessed_at                         TEXT,
  concentration_checked_at                            TEXT,
  halt_status_verified_at                             TEXT,
  mark_age_validated_at                               TEXT,
  cleared_at                                          TEXT,
  archived_at                                         TEXT,
  rejected_at                                         TEXT,
