  bid_close_at        TEXT,
  delivery_due_at     TEXT,
  award_to            TEXT,                            -- vendor identifier
  award_name          TEXT,                            -- denormalized vendor name
  award_amount_zar    REAL,                            -- actual award value
  awarded_at          TEXT,
  contracted_at       TEXT,
  delivered_at        TEXT,
  rejection_reason    TEXT,
  dispute_notes       TEXT,
  evaluation_notes    TEXT,
  sla_deadline_at     TEXT,
  last_sla_breach_at  TEXT,
  escalation_level    INTEGER NOT NULL DEFAULT 0,
  created_by          TEXT NOT NULL,
  created_at          TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_project_change_order_events (
  id                  TEXT PRIMARY KEY,
  co_id               TEXT NOT NULL,
  event_type          TEXT NOT NULL,
  from_status         TEXT,
  to_status           TEXT,
  actor_id            TEXT,
  actor_party         TEXT,
  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_project_change_orders (
  id                          TEXT PRIMARY KEY,
  co_number                   TEXT UNIQUE NOT NULL,

  -- Provenance / scope
  source_event                TEXT,
  source_entity_type          TEXT,
  source_entity_id            TEXT,
  source_wave                 TEXT,
  project_id                  TEXT,
  project_name                TEXT NOT NULL,
  participant_id              TEXT,
  participant_name            TEXT,
  contractor_name             TEXT,                  -- EPC / contractor raising the variation

  -- Change definition
  change_type                 TEXT,                  -- site_condition / design_change / scope_addition / regulatory / client_request / force_majeure
  title                       TEXT NOT NULL,
  description                 TEXT,
  variation_tier              TEXT NOT NULL CHECK (variation_tier IN (
    'minor','moderate','major','critical'
  )),

  -- Cost / schedule impact of THIS variation
  cost_impact_zar             REAL NOT NULL DEFAULT 0,
  schedule_impact_days        INTEGER NOT NULL DEFAULT 0,

  -- Baseline + earned-value snapshot
  baseline_cost_zar           REAL,
  baseline_duration_days      INTEGER,
  contingency_zar             REAL,
  contingency_drawn_zar       REAL NOT NULL DEFAULT 0,
  earned_value_zar            REAL,                  -- EV
  planned_value_zar           REAL,                  -- PV
  actual_cost_zar             REAL,                  -- AC
  budget_at_completion_zar    REAL,                  -- BAC

  -- Cumulative position (for re-baseline + bid-envelope)
  cumulative_approved_variation_zar  REAL NOT NULL DEFAULT 0,
  cumulative_approved_days           INTEGER NOT NULL DEFAULT 0,
  bid_envelope_cost_pct       REAL,                  -- REIPPPP cost-overrun tolerance (pct)
  bid_envelope_schedule_days  INTEGER,               -- REIPPPP COD-slip tolerance (days)

  -- Approval
  approval_authority          TEXT,                  -- project_manager / sponsor / board / dmre_notify
  approved_by                 TEXT,
  raised_by_party             TEXT,                  -- functional party that raised it

  reason_code                 TEXT,
  rejection_reason            TEXT,
  dispute_reason              TEXT,

  -- Refs
  submission_ref              TEXT,
  screening_ref               TEXT,
  assessment_ref              TEXT,
  approval_ref                TEXT,
  incorporation_ref           TEXT,
  deferral_ref                TEXT,
  dispute_ref                 TEXT,
  rejection_ref               TEXT,
  regulator_ref               TEXT,
  evidence_ref                TEXT,

  -- Narrative
  submission_basis            TEXT,
  screening_basis             TEXT,
  assessment_basis            TEXT,
  approval_basis              TEXT,
  incorporation_basis         TEXT,
  deferral_basis              TEXT,
  dispute_basis               TEXT,
  rejection_basis             TEXT,
  notes                       TEXT,

  -- State + lifecycle
  chain_status                TEXT NOT NULL CHECK (chain_status IN (
    'draft','submitted','screening','impact_assessment','pending_approval','approved',
    'incorporated','deferred','disputed','rejected','withdrawn','cancelled'
  )),
  draft_at                    TEXT NOT NULL,
  submitted_at                TEXT,
  screening_at                TEXT,
  impact_assessment_at        TEXT,
  pending_approval_at         TEXT,
  approved_at                 TEXT,
  incorporated_at             TEXT,
  deferred_at                 TEXT,
  disputed_at                 TEXT,
  rejected_at                 TEXT,
  withdrawn_at                TEXT,
  cancelled_at                TEXT,

  sla_deadline_at             TEXT,
  last_sla_breach_at          TEXT,
  is_reportable               INTEGER NOT NULL DEFAULT 0,
  escalation_level            INTEGER NOT NULL DEFAULT 0,

  created_by                  TEXT NOT NULL,
  created_at                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_project_risks (
  id                                  TEXT PRIMARY KEY,
  risk_number                         TEXT UNIQUE NOT NULL,

  -- Provenance
  source_event                        TEXT,
  source_entity_type                  TEXT,
  source_entity_id                    TEXT,
  source_wave                         TEXT,

  -- Project identity
  project_id                          TEXT NOT NULL,
  project_name                        TEXT,
  reipppp_bid_window                  TEXT,
  facility_id                         TEXT,
  facility_name                       TEXT,
  risk_owner_party_id                 TEXT,
  risk_owner_party_name               TEXT,
  raised_by_party_id                  TEXT,
  raised_by_party_name                TEXT,

  -- Classification
  risk_class                          TEXT NOT NULL CHECK (risk_class IN (
    'cost_overrun','schedule_slip','resource_constraint','design_change',
    'procurement_lead_time','site_conditions','subcontractor_default',
    'safety','environmental','force_majeure','regulatory_change',
    'strategic','financial_market','technology'
  )),
  risk_category                       TEXT,
  risk_title                          TEXT,
  risk_description                    TEXT,
  risk_tier                           TEXT NOT NULL CHECK (risk_tier IN (
    'low','moderate','high','critical'
  )),
  authority_required                  TEXT CHECK (authority_required IN (
    'project_manager','risk_owner','sponsor','board','dmre_notify'
  )),

  -- Qualitative scoring (PMBOK 7 / ISO 31000) — 1-5 P x I matrix
  probability_pct                     REAL NOT NULL DEFAULT 0,
  probability_band                    INTEGER,
  worst_case_cost_impact_zar          REAL NOT NULL DEFAULT 0,
  worst_case_schedule_impact_days     INTEGER NOT NULL DEFAULT 0,
  impact_band                         INTEGER,

  -- Quantitative SRA inputs (triangular: optimistic / most-likely / pessimistic)
  cost_optimistic_zar                 REAL,
  cost_most_likely_zar                REAL,
  cost_pessimistic_zar                REAL,
  schedule_optimistic_days            INTEGER,
  schedule_most_likely_days           INTEGER,
  schedule_pessimistic_days           INTEGER,

  -- Stored derived (the rest — p50/p80/bid_envelope/contingency_drawdown — are
  -- LIVE on fetch from inputs; D1 100-col limit per table).
  emv_zar                             REAL,
  residual_emv_zar                    REAL,
  integrity_floor_applied_flag        INTEGER NOT NULL DEFAULT 0,

  -- Response (PMBOK strategies: avoid / transfer / mitigate / accept / exploit /
  -- share / enhance)
  response_strategy                   TEXT,
  response_action                     TEXT,
  response_effectiveness_pct          REAL,
  response_owner                      TEXT,
  response_due_at                     TEXT,
  response_complete_flag              INTEGER NOT NULL DEFAULT 0,

  -- Contingency / reserve linkage
  contingency_drawn_zar               REAL NOT NULL DEFAULT 0,
  total_contingency_zar               REAL NOT NULL DEFAULT 0,
  bid_envelope_zar                    REAL NOT NULL DEFAULT 0,

  -- Realization (when realize_risk fires)
  realized_flag                       INTEGER NOT NULL DEFAULT 0,
  realized_cost_zar                   REAL,
  realized_schedule_days              INTEGER,
  realized_basis                      TEXT,

  -- Gates
  assessed_flag                       INTEGER NOT NULL DEFAULT 0,
  quantified_flag                     INTEGER NOT NULL DEFAULT 0,
  response_planned_flag               INTEGER NOT NULL DEFAULT 0,
  monitoring_flag                     INTEGER NOT NULL DEFAULT 0,

  -- Refs
  assess_ref                          TEXT,
  quantify_ref                        TEXT,
  response_plan_ref                   TEXT,
  response_active_ref                 TEXT,
  monitor_ref                         TEXT,
  realize_ref                         TEXT,
  close_ref                           TEXT,
  accept_ref                          TEXT,
  escalate_ref                        TEXT,
  reanalyze_ref                       TEXT,
  withdraw_ref                        TEXT,
  regulator_ref                       TEXT,

  -- Narrative
  assess_basis                        TEXT,
  quantify_basis                      TEXT,
  response_plan_basis                 TEXT,
  response_active_basis               TEXT,
  close_basis                         TEXT,
  escalate_basis                      TEXT,
  reason_code                         TEXT,
  response_summary                    TEXT,

  -- State + lifecycle
  chain_status                        TEXT NOT NULL CHECK (chain_status IN (
    'identified','assessed','quantified','response_planned','response_active',
    'monitoring','realized','closed','accepted','escalated','withdrawn','cancelled'
  )),
  identified_at                       TEXT NOT NULL,
  assessed_at                         TEXT,
  quantified_at                       TEXT,
  response_planned_at                 TEXT,
  response_active_at                  TEXT,
  monitoring_at                       TEXT,
  realized_at                         TEXT,
  closed_at                           TEXT,
  accepted_at                         TEXT,
  escalated_at                        TEXT,
  withdrawn_at                        TEXT,
  cancelled_at                        TEXT,

  is_reportable                       INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                     TEXT,
  last_sla_breach_at                  TEXT,
  escalation_level                    INTEGER NOT NULL DEFAULT 0,

  created_by                          TEXT NOT NULL,
  created_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

