CREATE TABLE oe_reconciliation_attestation (
  id                                          TEXT PRIMARY KEY,
  attestation_number                          TEXT UNIQUE NOT NULL,
  cadence                                     TEXT NOT NULL CHECK (cadence IN (
    'daily_tactical','weekly_management','monthly_management','quarterly_attestation','annual_audit'
  )),
  period_label                                TEXT NOT NULL,
  period_start                                TEXT,
  period_end                                  TEXT,

  -- 7 cross-chain bridges (W118 + W119 mandatory + W113/W114/W115/W116/W117)
  w113_evm_ref                                TEXT,
  w114_doc_control_ref                        TEXT,
  w115_submittal_ref                          TEXT,
  w116_rfi_ref                                TEXT,
  w117_change_order_ref                       TEXT,
  w118_block_height_range_low                 INTEGER,
  w118_block_height_range_high                INTEGER,
  w119_export_pack_ref                        TEXT,
  parent_attestation_id                       TEXT,

  -- 5 floor flags (FLOOR-AT-QUARTERLY 1+ / FLOOR-AT-ANNUAL 2+)
  material_variance_unresolved                INTEGER NOT NULL DEFAULT 0,
  external_auditor_request_active             INTEGER NOT NULL DEFAULT 0,
  regulator_audit_in_progress                 INTEGER NOT NULL DEFAULT 0,
  cross_border_feed_break                     INTEGER NOT NULL DEFAULT 0,
  icfr_deficiency_suspected                   INTEGER NOT NULL DEFAULT 0,

  -- Feed inventory (counters; feed details in events payload)
  feeds_in_scope                              INTEGER NOT NULL DEFAULT 0,
  feeds_ingested_count                        INTEGER NOT NULL DEFAULT 0,
  feeds_paired_count                          INTEGER NOT NULL DEFAULT 0,
  feeds_paired_pct                            INTEGER NOT NULL DEFAULT 0,
  feed_sources_csv                            TEXT,

  -- Variance ledger (ZAR)
  total_variance_zar                          INTEGER NOT NULL DEFAULT 0,
  materiality_threshold_zar                   INTEGER NOT NULL DEFAULT 0,
  net_variance_explained_zar                  INTEGER NOT NULL DEFAULT 0,
  unresolved_variance_zar                     INTEGER NOT NULL DEFAULT 0,
  variance_explained_pct                      INTEGER NOT NULL DEFAULT 0,

  -- Break classification + root cause
  break_classification                        TEXT,
  break_classified_pct                        INTEGER NOT NULL DEFAULT 0,
  root_cause_taxonomy                         TEXT,

  -- ICFR controls (COSO + TSC)
  coso_components_tested                      INTEGER NOT NULL DEFAULT 0,
  tsc_categories_tested                       INTEGER NOT NULL DEFAULT 0,
  material_weakness_open                      INTEGER NOT NULL DEFAULT 0,

  -- Remediation
  remediation_progress_pct                    INTEGER NOT NULL DEFAULT 0,
  remediation_closed_pct                      INTEGER NOT NULL DEFAULT 0,
  action_plan_drafted                         INTEGER NOT NULL DEFAULT 0,
  owner_assigned                              INTEGER NOT NULL DEFAULT 0,
  target_date_set                             INTEGER NOT NULL DEFAULT 0,
  evidence_attached                           INTEGER NOT NULL DEFAULT 0,
  followup_test_passed                        INTEGER NOT NULL DEFAULT 0,

  -- Sign-offs
  counter_party_signed_off                    INTEGER NOT NULL DEFAULT 0,
  independent_review_passed                   INTEGER NOT NULL DEFAULT 0,
  cfo_attestation_signed                      INTEGER NOT NULL DEFAULT 0,
  audit_committee_briefed                     INTEGER NOT NULL DEFAULT 0,

  -- Composite indexes + bands
  current_tier                                TEXT NOT NULL CHECK (current_tier IN (
    'daily_tactical','weekly_management','monthly_management','quarterly_attestation','annual_audit'
  )),
  authority_required                          TEXT CHECK (authority_required IN (
    'reconciler','controller','CFO','audit_committee_chair'
  )),
  urgency_band                                TEXT,
  attestation_health_band                     TEXT,
  reconciliation_completeness_index           INTEGER NOT NULL DEFAULT 0,
  icfr_control_effectiveness_index            INTEGER NOT NULL DEFAULT 0,
  variance_score_index                        INTEGER NOT NULL DEFAULT 0,
  remediation_progress_index                  INTEGER NOT NULL DEFAULT 0,
  attestation_window_hours                    INTEGER NOT NULL DEFAULT 0,
  days_to_quarterly_attestation               INTEGER NOT NULL DEFAULT 0,

  -- Narrative + reason codes
  title                                       TEXT,
  reason_code                                 TEXT,
  reject_reason                               TEXT,
  suspend_reason                              TEXT,
  restate_reason                              TEXT,
  escalation_reason                           TEXT,

  is_reportable                               INTEGER NOT NULL DEFAULT 0,
  regulator_relevant                          INTEGER NOT NULL DEFAULT 0,
  regulator_reason_text                       TEXT,

  -- External-auditor (signed JWT)
  external_auditor_firm                       TEXT,
  external_auditor_engagement_ref             TEXT,
  external_auditor_jwt_jti                    TEXT,

  -- 12 forward + 4 branch lifecycle timestamps
  chain_status                                TEXT NOT NULL CHECK (chain_status IN (
    'attestation_proposed','scope_defined','feeds_ingested',
    'blocks_paired','variance_computed','break_classified',
    'root_cause_logged','remediation_proposed','counter_party_signoff',
    'independent_review','attestation_signed','archived',
    'rejected','suspended','restated','escalated_to_audit_committee'
  )),
  attestation_proposed_at                     TEXT,
  scope_defined_at                            TEXT,
  feeds_ingested_at                           TEXT,
  blocks_paired_at                            TEXT,
  variance_computed_at                        TEXT,
  break_classified_at                         TEXT,
  root_cause_logged_at                        TEXT,
  remediation_proposed_at                     TEXT,
  counter_party_signoff_at                    TEXT,
  independent_review_at                       TEXT,
  attestation_signed_at                       TEXT,
  archived_at                                 TEXT,
  rejected_at                                 TEXT,
  suspended_at                                TEXT,
  restated_at                                 TEXT,
  escalated_at                                TEXT,

  -- Regulator crossing
  regulator_crossed_at                        TEXT,
  regulator_inbox_ref                         TEXT,
  regulator_ref                               TEXT,

  -- SLA (HOURS, INVERTED polarity)
  sla_target_hours                            INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                             TEXT,
  last_sla_breach_at                          TEXT,
  sla_breached                                INTEGER NOT NULL DEFAULT 0,
  escalation_level                            INTEGER NOT NULL DEFAULT 0,

  tenant_id                                   TEXT,
  created_by                                  TEXT NOT NULL,
  created_at                                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_reconciliation_attestation_events (
  id                  TEXT PRIMARY KEY,
  attestation_id      TEXT NOT NULL,
  event_type          TEXT NOT NULL,
  from_status         TEXT,
  to_status           TEXT,
  from_tier           TEXT,
  to_tier             TEXT,
  actor_id            TEXT,
  actor_party         TEXT,
  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_regulator_complaints (
  id                       TEXT PRIMARY KEY,
  complaint_number         TEXT UNIQUE NOT NULL,

  -- Provenance
  source_event             TEXT,
  source_entity_type       TEXT,
  source_entity_id         TEXT,
  source_wave              TEXT,

  -- Parties
  complainant_id           TEXT NOT NULL,
  complainant_name         TEXT NOT NULL,
  complainant_type         TEXT NOT NULL CHECK (complainant_type IN (
    'customer','licensee','ipp','offtaker','municipality','other'
  )),
  respondent_id            TEXT NOT NULL,
  respondent_name          TEXT NOT NULL,
  respondent_licence_no    TEXT,

  -- Classification
  complaint_category       TEXT NOT NULL CHECK (complaint_category IN (
    'billing','supply_quality','connection','tariff','metering','service','market_conduct','other'
  )),
  complaint_tier           TEXT NOT NULL CHECK (complaint_tier IN (
    'minor','moderate','significant','major','systemic'
  )),
  affected_customers       INTEGER,           -- drives the tier
  jurisdiction_basis       TEXT,              -- statutory basis for NERSA jurisdiction

  -- Refs
  complaint_ref            TEXT,
  referral_ref             TEXT,
  investigation_ref        TEXT,
  mediation_ref            TEXT,
  hearing_ref              TEXT,
  ruling_ref               TEXT,
  appeal_ref               TEXT,

  -- Narrative
  lodgement_basis          TEXT,
  admissibility_basis      TEXT,
  referral_basis           TEXT,
  settlement_basis         TEXT,
  investigation_basis      TEXT,
  mediation_basis          TEXT,
  hearing_basis            TEXT,
  ruling_basis             TEXT,
  remedy_basis             TEXT,
  dismissal_basis          TEXT,
  appeal_basis             TEXT,
  reason_code              TEXT,
  complaint_summary        TEXT,
  remedy_directed          TEXT,

  -- State + lifecycle
  chain_status             TEXT NOT NULL CHECK (chain_status IN (
    'complaint_lodged','admissibility_review','referred_to_licensee','under_investigation',
    'mediation','adjudication_hearing','ruling_issued','remedy_monitoring',
    'resolved','dismissed','appealed','withdrawn'
  )),
  lodged_at                TEXT NOT NULL,
  admissibility_review_at  TEXT,
  referred_to_licensee_at  TEXT,
  under_investigation_at   TEXT,
  mediation_at             TEXT,
  adjudication_hearing_at  TEXT,
  ruling_issued_at         TEXT,
  remedy_monitoring_at     TEXT,
  resolved_at              TEXT,
  dismissed_at             TEXT,
  appealed_at              TEXT,
  withdrawn_at             TEXT,

  sla_deadline_at          TEXT,
  last_sla_breach_at       TEXT,
  is_reportable            INTEGER NOT NULL DEFAULT 0,
  escalation_level         INTEGER NOT NULL DEFAULT 0,

  created_by               TEXT NOT NULL,
  created_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_regulator_complaints_events (
  id              TEXT PRIMARY KEY,
  complaint_id    TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_regulator_decisions (
  id                  TEXT PRIMARY KEY,
  application_id      TEXT NOT NULL,
  decision_ref        TEXT NOT NULL UNIQUE,
  decision_type       TEXT NOT NULL,             -- granted | refused | modified | deferred
  approved_revenue_zar REAL,
  approved_tariff_zar_kwh REAL,
  effective_from      TEXT,
  effective_to        TEXT,
  reasons_body        TEXT,                      -- written reasons
  decision_doc_r2_key TEXT,
  decided_at          TEXT NOT NULL DEFAULT (datetime('now')),
  decided_by          TEXT NOT NULL,
  panel_signatories   TEXT,                      -- JSON
  published_at        TEXT,
  created_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_regulator_escalation_rules (
  id                  TEXT PRIMARY KEY,
  rule_code           TEXT NOT NULL UNIQUE,
  description         TEXT NOT NULL,
  event_pattern       TEXT NOT NULL,          -- glob-ish; matches against source_event
  severity_min        TEXT NOT NULL DEFAULT 'medium'
    CHECK (severity_min IN ('info','low','medium','high','critical')),
  sla_minutes         INTEGER NOT NULL,       -- minutes between created_at and sla_due_at
  on_breach           TEXT NOT NULL DEFAULT 'escalate'
    CHECK (on_breach IN ('escalate','open_case','notify_only')),
  enabled             INTEGER NOT NULL DEFAULT 1,
  created_at          TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_regulator_export_pack (
  id                                          TEXT PRIMARY KEY,
  pack_number                                 TEXT UNIQUE NOT NULL,
  pack_cadence                                TEXT NOT NULL CHECK (pack_cadence IN (
    'ad_hoc','monthly_return','quarterly_attestation','half_year','annual_audit'
  )),
  regulator_target                            TEXT NOT NULL CHECK (regulator_target IN (
    'nersa','ippo','sarb','dmre','fsca','dffe','dti','jse_srl','sars','cipc'
  )),

  -- 6 cross-chain bridges (W118 mandatory + W113/W114/W115/W116/W117)
  w113_evm_ref                                TEXT,
  w114_doc_control_ref                        TEXT,
  w115_submittal_ref                          TEXT,
  w116_rfi_ref                                TEXT,
  w117_change_order_ref                       TEXT,
  w118_block_height_range_low                 INTEGER,
  w118_block_height_range_high                INTEGER,
  parent_pack_id                              TEXT,

  -- 5 floor flags (FLOOR-AT-QUARTERLY 1+ / FLOOR-AT-ANNUAL 2+)
  cross_regulator_pack                        INTEGER NOT NULL DEFAULT 0,
  material_restatement                        INTEGER NOT NULL DEFAULT 0,
  esg_double_materiality_trigger              INTEGER NOT NULL DEFAULT 0,
  lender_distribution_required                INTEGER NOT NULL DEFAULT 0,
  regulator_audit_in_progress                 INTEGER NOT NULL DEFAULT 0,

  -- XBRL conformance (taxonomy elements + iXBRL/PDF-A3/ETSI/CMS sigs)
  taxonomy_version_set                        INTEGER NOT NULL DEFAULT 0,
  schema_well_formed                          INTEGER NOT NULL DEFAULT 0,
  required_element_assets                     INTEGER NOT NULL DEFAULT 0,
  required_element_liabilities                INTEGER NOT NULL DEFAULT 0,
  required_element_equity                     INTEGER NOT NULL DEFAULT 0,
  required_element_revenue                    INTEGER NOT NULL DEFAULT 0,
  required_element_profit_loss                INTEGER NOT NULL DEFAULT 0,
  required_element_cash_equivalents           INTEGER NOT NULL DEFAULT 0,
  required_element_segments_reported          INTEGER NOT NULL DEFAULT 0,
  ixbrl_inline_html_valid                     INTEGER NOT NULL DEFAULT 0,
  pdf_a3_archival_attached                    INTEGER NOT NULL DEFAULT 0,
  signing_policy_etsi_119312                  INTEGER NOT NULL DEFAULT 0,
  cms_signature_rfc5652                       INTEGER NOT NULL DEFAULT 0,
  xbrl_conformance_score                      INTEGER NOT NULL DEFAULT 0,

  -- ESG taxonomy coverage (GRI / SASB / TCFD / ISSB)
  gri_standards_attached                      INTEGER NOT NULL DEFAULT 0,
  sasb_standards_attached                     INTEGER NOT NULL DEFAULT 0,
  tcfd_recommendations_attached               INTEGER NOT NULL DEFAULT 0,
  issb_ifrs_s1_s2_attached                    INTEGER NOT NULL DEFAULT 0,
  esg_taxonomy_coverage_pct                   INTEGER NOT NULL DEFAULT 0,

  -- COSO + SOC2 TSC + management/auditor narratives
  coso_components_present                     INTEGER NOT NULL DEFAULT 0,
  tsc_trust_categories_present                INTEGER NOT NULL DEFAULT 0,
  management_assertion_signed                 INTEGER NOT NULL DEFAULT 0,
  auditor_opinion_attached                    INTEGER NOT NULL DEFAULT 0,
  bridge_letter_attached                      INTEGER NOT NULL DEFAULT 0,
  controls_narrative_completeness             INTEGER NOT NULL DEFAULT 0,

  -- Internal QA + counterparty sign-off + ACK
  internal_qa_passed                          INTEGER NOT NULL DEFAULT 0,
  counterparty_signoff_obtained               INTEGER NOT NULL DEFAULT 0,
  regulator_ack_received                      INTEGER NOT NULL DEFAULT 0,

  -- Composite indexes + bands
  current_tier                                TEXT NOT NULL CHECK (current_tier IN (
    'ad_hoc','monthly_return','quarterly_attestation','half_year','annual_audit'
  )),
  authority_required                          TEXT CHECK (authority_required IN (
    'preparer','controller','CFO','CEO'
  )),
  urgency_band                                TEXT,
  pack_health_band                            TEXT,
  pack_completeness_index                     INTEGER NOT NULL DEFAULT 0,
  integrity_index                             INTEGER NOT NULL DEFAULT 0,
  regulator_export_window_hours               INTEGER NOT NULL DEFAULT 0,
  days_to_quarterly_attestation               INTEGER NOT NULL DEFAULT 0,

  -- Narrative + reason codes
  title                                       TEXT,
  reason_code                                 TEXT,
  reject_reason                               TEXT,
  withdraw_reason                             TEXT,
  restate_reason                              TEXT,
  suspend_reason                              TEXT,

  is_reportable                               INTEGER NOT NULL DEFAULT 0,
  regulator_relevant                          INTEGER NOT NULL DEFAULT 0,
  regulator_reason_text                       TEXT,

  -- mTLS counterparty fingerprint + ack codes
  mtls_cert_fingerprint                       TEXT,
  regulator_ack_code                          TEXT,
  regulator_reject_code                       TEXT,

  -- 12 forward + 4 branch lifecycle timestamps
  chain_status                                TEXT NOT NULL CHECK (chain_status IN (
    'pack_proposed','blocks_selected','leaves_filtered',
    'xbrl_assembled','narratives_attached','internal_qa',
    'counterparty_signoff','packaged','countersigned',
    'lodged_via_api','acknowledged_by_regulator','archived',
    'rejected_by_regulator','withdrawn','restated','suspended'
  )),
  pack_proposed_at                            TEXT,
  blocks_selected_at                          TEXT,
  leaves_filtered_at                          TEXT,
  xbrl_assembled_at                           TEXT,
  narratives_attached_at                      TEXT,
  internal_qa_at                              TEXT,
  counterparty_signoff_at                     TEXT,
  packaged_at                                 TEXT,
  countersigned_at                            TEXT,
  lodged_via_api_at                           TEXT,
  acknowledged_by_regulator_at                TEXT,
  archived_at                                 TEXT,
  rejected_at                                 TEXT,
  withdrawn_at                                TEXT,
  restated_at                                 TEXT,
  suspended_at                                TEXT,

  -- Regulator crossing
  regulator_crossed_at                        TEXT,
  regulator_inbox_ref                         TEXT,
  regulator_ref                               TEXT,

  -- SLA (HOURS, INVERTED polarity)
  sla_target_hours                            INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                             TEXT,
  last_sla_breach_at                          TEXT,
  sla_breached                                INTEGER NOT NULL DEFAULT 0,
  escalation_level                            INTEGER NOT NULL DEFAULT 0,

  tenant_id                                   TEXT,
  created_by                                  TEXT NOT NULL,
  created_at                                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                                  TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_regulator_export_pack_events (
  id                  TEXT PRIMARY KEY,
  pack_id             TEXT NOT NULL,
  event_type          TEXT NOT NULL,
  from_status         TEXT,
  to_status           TEXT,
  from_tier           TEXT,
  to_tier             TEXT,
  actor_id            TEXT,
  actor_party         TEXT,
  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_regulator_inbox (
  id                  TEXT PRIMARY KEY,
  source_event        TEXT NOT NULL,          -- 'clearing.disclosure.published' etc.
  source_entity_type  TEXT NOT NULL,
  source_entity_id    TEXT NOT NULL,
  severity            TEXT NOT NULL DEFAULT 'info'
    CHECK (severity IN ('info','low','medium','high','critical')),
  title               TEXT NOT NULL,
  body_json           TEXT,                   -- JSON copy of cascade ctx.data
  ack_status          TEXT NOT NULL DEFAULT 'pending'
    CHECK (ack_status IN ('pending','acknowledged','escalated','dismissed')),
  assigned_to         TEXT,                   -- user_id of the regulator handler
  ack_by              TEXT,
  ack_at              TEXT,
  ack_note            TEXT,
  escalated_at        TEXT,
  escalated_to_case   TEXT,                   -- regulator_enforcement_cases.id
  sla_due_at          TEXT,                   -- computed at insert from severity
  created_at          TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_regulator_levies (
  id                       TEXT PRIMARY KEY,
  levy_number              TEXT UNIQUE NOT NULL,

  -- Provenance (a levy is regulator-originated; kept for cascade symmetry)
  source_event             TEXT,
  source_entity_type       TEXT,
  source_entity_id         TEXT,
  source_wave              TEXT,

  -- Licensee being levied
  licensee_id              TEXT NOT NULL,
  licensee_name            TEXT NOT NULL,
  licensee_licence_no      TEXT,

  -- Classification
  sector                   TEXT NOT NULL CHECK (sector IN (
    'electricity','piped_gas','petroleum_pipeline'
  )),
  levy_basis               TEXT NOT NULL CHECK (levy_basis IN (
    'turnover_based','volume_based','fixed'
  )),
  levy_tier                TEXT NOT NULL CHECK (levy_tier IN (
    'micro','small','medium','large','major'
  )),
  financial_year           TEXT NOT NULL,

  -- Financials
  declared_base            REAL,              -- declared turnover (ZAR) or throughput volume
  base_unit                TEXT,              -- ZAR / MWh / GJ / m3
  levy_rate                REAL,              -- fraction of turnover, ZAR per unit, or flat amount
  assessed_amount          REAL NOT NULL,     -- ZAR — drives the tier
  paid_to_date             REAL NOT NULL DEFAULT 0,
  outstanding_amount       REAL NOT NULL DEFAULT 0,
  due_date                 TEXT,

  -- Refs
  assessment_ref           TEXT,
  invoice_ref              TEXT,
  objection_ref            TEXT,
  final_demand_ref         TEXT,
  enforcement_ref          TEXT,
  settlement_ref           TEXT,
  writeoff_ref             TEXT,

  -- Narrative
  assessment_basis         TEXT,
  review_basis             TEXT,
  invoice_basis            TEXT,
  objection_basis          TEXT,
  payable_basis            TEXT,
  payment_basis            TEXT,
  arrears_basis            TEXT,
  final_demand_basis       TEXT,
  enforcement_basis        TEXT,
  settlement_basis         TEXT,
  writeoff_basis           TEXT,
  withdrawal_basis         TEXT,
  reason_code              TEXT,

  -- State + lifecycle
  chain_status             TEXT NOT NULL CHECK (chain_status IN (
    'levy_assessed','assessment_review','invoiced','objection_review',
    'payment_pending','partially_paid','in_arrears','final_demand','enforcement',
    'settled','written_off','withdrawn'
  )),
  assessed_at              TEXT NOT NULL,
  assessment_review_at     TEXT,
  invoiced_at              TEXT,
  objection_review_at      TEXT,
  payment_pending_at       TEXT,
  partially_paid_at        TEXT,
  in_arrears_at            TEXT,
  final_demand_at          TEXT,
  enforcement_at           TEXT,
  settled_at               TEXT,
  written_off_at           TEXT,
  withdrawn_at             TEXT,

  sla_deadline_at          TEXT,
  last_sla_breach_at       TEXT,
  is_reportable            INTEGER NOT NULL DEFAULT 0,
  escalation_level         INTEGER NOT NULL DEFAULT 0,

  created_by               TEXT NOT NULL,
  created_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_regulator_levies_events (
  id              TEXT PRIMARY KEY,
  levy_id         TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_report_submissions (
  id                          TEXT PRIMARY KEY,
  report_kind                 TEXT NOT NULL,        -- nersa_quarterly | sars_vat201 | sars_irp6 | sars_carbon_tax
  report_id                   TEXT NOT NULL,        -- ref to oe_nersa_reports.id or oe_sars_reports.id
  submitted_to                TEXT NOT NULL,        -- e.g. 'NERSA' | 'SARS_efiling'
  submitted_by                TEXT,
  submission_envelope_r2_key  TEXT,                 -- XML envelope archived
  acknowledgment_id           TEXT,                 -- regulator-assigned id
  acknowledgment_received_at  TEXT,
  status                      TEXT NOT NULL DEFAULT 'queued',
                                                     -- queued | submitted | acknowledged |
                                                     -- accepted | rejected | resubmitted
  rejection_reason            TEXT,
  resubmission_of_id          TEXT,                 -- if this is a re-submit
  submitted_at                TEXT,
  created_at                  TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_reserve_account_chain (
  id                       TEXT PRIMARY KEY,
  reserve_number           TEXT UNIQUE NOT NULL,

  -- Provenance (a reserve obligation is established by a facility at financial close)
  source_event             TEXT,
  source_entity_type       TEXT,
  source_entity_id         TEXT,
  source_wave              TEXT,
  facility_ref             TEXT,              -- originating credit facility
  project_id               TEXT,              -- financed project / SPV
  loan_agreement_ref       TEXT,

  -- Parties
  lender_name              TEXT NOT NULL,     -- agent / facility agent
  borrower_name            TEXT NOT NULL,     -- project company / SPV
  account_bank             TEXT,              -- account bank holding the controlled account

  -- Classification
  reserve_type             TEXT,              -- dsra / mra / om_reserve / tax_reserve
  funding_mode             TEXT,              -- cash / letter_of_credit / hybrid
  target_basis             TEXT,              -- e.g. next_6m_debt_service
  account_number           TEXT,
  currency                 TEXT,              -- ZAR / USD
  target_amount_zar        REAL NOT NULL,     -- required balance — drives the tier
  current_balance_zar      REAL,              -- current funded balance
  drawn_amount_zar         REAL,              -- amount drawn (authorised use)
  shortfall_amount_zar     REAL,              -- balance gap at the last test
  reserve_tier             TEXT NOT NULL CHECK (reserve_tier IN (
    'small','medium','large','major','systemic'
  )),

  -- Dates
  next_test_date           TEXT,
  cure_deadline            TEXT,
  release_due_date         TEXT,
  shortfall_reason_code    TEXT,              -- lc_lapse / fx_move / missed_sweep / dscr_dip

  -- Refs
  funding_ref              TEXT,
  shortfall_ref            TEXT,
  cure_ref                 TEXT,
  drawdown_ref             TEXT,
  replenishment_ref        TEXT,
  waiver_ref               TEXT,
  release_ref              TEXT,
  breach_ref               TEXT,
  cancel_ref               TEXT,

  -- Narrative
  funding_basis            TEXT,
  shortfall_basis          TEXT,
  cure_basis               TEXT,
  drawdown_basis           TEXT,
  replenishment_basis      TEXT,
  waiver_basis             TEXT,
  release_basis            TEXT,
  breach_basis             TEXT,
  cancel_basis             TEXT,
  reason_code              TEXT,

  -- State + lifecycle
  chain_status             TEXT NOT NULL CHECK (chain_status IN (
    'reserve_required','funding_scheduled','funding_in_progress','funded',
    'shortfall_flagged','cure_pending','drawdown_authorized','drawn',
    'release_requested','released','breached','cancelled'
  )),
  reserve_required_at        TEXT NOT NULL,
  funding_scheduled_at       TEXT,
  funding_in_progress_at     TEXT,
  funded_at                  TEXT,
  shortfall_flagged_at       TEXT,
  cure_pending_at            TEXT,
  drawdown_authorized_at     TEXT,
  drawn_at                   TEXT,
  release_requested_at       TEXT,
  released_at                TEXT,
  breached_at                TEXT,
  cancelled_at               TEXT,

  sla_deadline_at          TEXT,
  last_sla_breach_at       TEXT,
  is_reportable            INTEGER NOT NULL DEFAULT 0,
  escalation_level         INTEGER NOT NULL DEFAULT 0,

  created_by               TEXT NOT NULL,
  created_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_reserve_account_chain_events (
  id                 TEXT PRIMARY KEY,
  reserve_account_id TEXT NOT NULL,
  event_type         TEXT NOT NULL,
  from_status        TEXT,
  to_status          TEXT,
  actor_id           TEXT,
  actor_party        TEXT,
  notes              TEXT,
  payload            TEXT,
  created_at         TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_reserve_activations (
  id                            TEXT PRIMARY KEY,
  activation_number             TEXT UNIQUE NOT NULL,

  -- Provenance (e.g. a frequency event, contingency, or dispatch shortfall)
  source_event                  TEXT,
  source_entity_type            TEXT,
  source_entity_id              TEXT,
  source_wave                   TEXT,

  -- Parties (two-party split: System Operator + reserve provider)
  so_party_id                   TEXT NOT NULL,
  so_party_name                 TEXT NOT NULL,
  provider_party_id             TEXT NOT NULL,
  provider_party_name           TEXT NOT NULL,

  -- Activation identity
  reserve_tier                  TEXT NOT NULL CHECK (reserve_tier IN (
    'instantaneous_reserve','regulating_reserve','ten_minute_reserve',
    'supplemental_reserve','emergency_reserve'
  )),
  provider_type                 TEXT NOT NULL,     -- generator / pumped_storage / demand_response / battery_storage / interconnector
  service_name                  TEXT NOT NULL,
  contract_ref                  TEXT,              -- ancillary-services contract
  trigger_type                  TEXT,              -- frequency_drop / contingency / voltage / dispatch_shortfall / planned_test
  instructed_mw                 REAL,              -- MW the SO instructed
  delivered_mw                  REAL,              -- MW actually delivered (set at review)
  response_time_seconds         REAL,              -- contracted full-response time (drives tier)
  actual_response_seconds       REAL,              -- measured response time
  frequency_hz_at_event         REAL,              -- grid frequency that triggered the activation
  availability_payment_zar      REAL,              -- standing availability payment (R)
  utilisation_payment_zar       REAL,              -- delivered-energy utilisation payment (R)
  penalty_zar                   REAL,              -- non-performance penalty / clawback (R)

  -- Refs
  instruction_ref               TEXT,
  acknowledgement_ref           TEXT,
  ramp_ref                       TEXT,
  delivery_ref                  TEXT,
  release_ref                   TEXT,
  review_ref                     TEXT,
  verification_ref              TEXT,
  settlement_ref                TEXT,
  dispute_ref                    TEXT,
  regulator_ref                 TEXT,

  -- Narrative
  instruction_basis             TEXT,
  response_basis                TEXT,
  performance_basis             TEXT,
  settlement_basis              TEXT,
  non_performance_basis         TEXT,
  dispute_basis                 TEXT,
  reason_code                   TEXT,
  notes                          TEXT,

  dispute_round                 INTEGER NOT NULL DEFAULT 0,

  -- State + lifecycle
  chain_status                  TEXT NOT NULL CHECK (chain_status IN (
    'activation_issued','acknowledged','ramping','sustaining','released',
    'performance_review','verified','settled','non_performance','disputed',
    'dispute_resolved','withdrawn'
  )),
  activation_issued_at          TEXT NOT NULL,
  acknowledged_at               TEXT,
  ramping_at                    TEXT,
  sustaining_at                 TEXT,
  released_at                   TEXT,
  performance_review_at         TEXT,
  verified_at                   TEXT,
  settled_at                    TEXT,
  non_performance_at            TEXT,
  disputed_at                   TEXT,
  dispute_resolved_at           TEXT,
  withdrawn_at                  TEXT,

  is_reportable                 INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at               TEXT,
  last_sla_breach_at            TEXT,
  escalation_level              INTEGER NOT NULL DEFAULT 0,

  created_by                    TEXT NOT NULL,
  created_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_reserve_activations_events (
  id                 TEXT PRIMARY KEY,
  activation_id      TEXT NOT NULL,
  event_type         TEXT NOT NULL,
  from_status        TEXT,
  to_status          TEXT,
  actor_id           TEXT,
