                                                  -- queued | submitted | confirmed |
                                                  -- failed | reversed
  submitted_at        TEXT,
  confirmed_at        TEXT,
  bank_confirmation   TEXT,
  failure_reason      TEXT,
  created_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_settlement_net_legs (
  id                  TEXT PRIMARY KEY,
  cycle_id            TEXT NOT NULL,
  from_participant_id TEXT NOT NULL,
  to_participant_id   TEXT NOT NULL,
  energy_type         TEXT NOT NULL,
  net_volume_mwh      REAL NOT NULL,
  net_value_zar       REAL NOT NULL,
  status              TEXT NOT NULL DEFAULT 'pending',
                                                  -- pending | novated | settled | failed
  novated_at          TEXT,
  settled_at          TEXT
);

CREATE TABLE oe_signatures (
  id              TEXT PRIMARY KEY,
  document_kind   TEXT NOT NULL,            -- contract | regulator_pack | nersa_submission |
                                            -- audit_export | wheeling_agreement | rfq_award
  document_ref    TEXT NOT NULL,            -- id of underlying record
  document_hash   TEXT NOT NULL,            -- SHA-256 of canonical document bytes
  signer_id       TEXT NOT NULL,
  signer_role     TEXT,                     -- 'buyer' | 'seller' | 'witness' | 'attestor'
  signature_b64   TEXT NOT NULL,            -- Ed25519 signature
  public_key_b64  TEXT NOT NULL,            -- signer's published verification key
  signed_at       TEXT NOT NULL DEFAULT (datetime('now')),
  ip              TEXT,
  user_agent      TEXT,
  signing_method  TEXT NOT NULL DEFAULT 'platform_key',
                                            -- platform_key | external_pki | id_doc_visual
  verified_at     TEXT,
  notes           TEXT
);

CREATE TABLE oe_site_commissioning_events (
  id TEXT PRIMARY KEY,
  site_id TEXT NOT NULL REFERENCES om_sites(id),
  event_type TEXT NOT NULL CHECK (event_type IN (
    'planned','site_registered','devices_registered','ingestion_wired',
    'first_telemetry_ok','energised','in_om',
    'commissioning_failed','decommissioned',
    'sla_breached','note'
  )),
  from_status TEXT,
  to_status TEXT NOT NULL,
  actor_id TEXT NOT NULL,
  notes TEXT,
  evidence_r2_key TEXT,
  body_json TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_sla_performance_reports (
  id                       TEXT PRIMARY KEY,
  participant_id           TEXT NOT NULL,   -- support / OEM operator

  -- Report scope
  report_tier              TEXT NOT NULL CHECK(report_tier IN (
    'standard','enhanced','critical','enterprise'
  )),
  reporting_period         TEXT NOT NULL,   -- e.g. 'Dec-2025', 'W50-2025'
  period_start             TEXT NOT NULL,
  period_end               TEXT NOT NULL,

  -- SLA metrics
  total_incidents          INTEGER DEFAULT 0,
  p1_count                 INTEGER DEFAULT 0,
  p2_count                 INTEGER DEFAULT 0,
  p3_count                 INTEGER DEFAULT 0,
  p4_count                 INTEGER DEFAULT 0,
  p1_sla_met               INTEGER DEFAULT 0,
  p2_sla_met               INTEGER DEFAULT 0,
  p3_sla_met               INTEGER DEFAULT 0,
  p4_sla_met               INTEGER DEFAULT 0,
  p1_sla_pct               REAL,            -- % of P1s resolved within SLA
  p2_sla_pct               REAL,
  p3_sla_pct               REAL,
  p4_sla_pct               REAL,
  overall_sla_pct          REAL,
  target_sla_pct           REAL NOT NULL DEFAULT 95.0,

  -- RCA
  rca_triggered            INTEGER DEFAULT 0,  -- 0/1 any misses warranting RCA
  rca_lead                 TEXT,
  rca_findings             TEXT,
  rca_completed_at         TEXT,
  root_causes              TEXT,            -- JSON array
  remediation_actions      TEXT,            -- JSON array

  -- Review
  reviewer_name            TEXT,
  review_completed_at      TEXT,
  remediation_plan_ref     TEXT,

  chain_status             TEXT NOT NULL DEFAULT 'data_collection' CHECK(chain_status IN (
    'data_collection','metrics_calculated','rca_in_progress','rca_complete',
    'management_review','approved','disputed','remediation_plan','withdrawn'
  )),
  sla_deadline             TEXT NOT NULL,
  sla_breached             INTEGER NOT NULL DEFAULT 0,
  regulator_notified       INTEGER NOT NULL DEFAULT 0,

  actor_id                 TEXT,
  reason                   TEXT,
  created_at               TEXT NOT NULL,
  updated_at               TEXT NOT NULL
);

CREATE TABLE oe_slb_kpi_ratchets (
  id                      TEXT PRIMARY KEY,
  participant_id          TEXT NOT NULL,
  ppa_ref                 TEXT,          -- reference to oe_ppa_contracts or W22
  slb_tier                TEXT NOT NULL CHECK(slb_tier IN ('voluntary','green_finance','listed','regulatory')),
  kpi_period              TEXT NOT NULL, -- e.g. "2026-Q2"
  period_start            TEXT NOT NULL,
  period_end              TEXT NOT NULL,

  -- KPI targets
  kpi_name                TEXT,          -- e.g. "RE percentage" or "Carbon intensity gCO2/kWh"
  kpi_target_value        REAL,
  kpi_unit                TEXT,          -- "%", "gCO2/kWh", "MWh"

  -- Actuals
  kpi_actual_value        REAL,
  kpi_data_source         TEXT,          -- "solax_api", "metering", "manual"
  kpi_measured_at         TEXT,

  -- Verification
  verifier_name           TEXT,
  verifier_report_ref     TEXT,
  verified_at             TEXT,
  kpi_met                 INTEGER,       -- 0/1/null

  -- Ratchet quantum
  ratchet_basis_points    REAL,          -- coupon step in bps
  ratchet_zar             REAL,          -- or ZAR equivalent
  ratchet_direction       TEXT CHECK(ratchet_direction IN ('step_up','step_down','neutral') OR ratchet_direction IS NULL),

  -- Dispute / arbitration
  dispute_ref             TEXT,
  arbitration_ref         TEXT,
  arbitration_outcome     TEXT,

  -- Disagreement
  dispute_description     TEXT,

  chain_status            TEXT NOT NULL DEFAULT 'kpi_pending' CHECK(chain_status IN (
    'kpi_pending','kpi_measurement','kpi_verification','kpi_certified',
    'ratchet_calculation','ratchet_agreed','ratchet_disputed','arbitration',
    'ratchet_applied','ratchet_waived','kpi_missed','withdrawn'
  )),
  sla_deadline            TEXT NOT NULL,
  sla_breached            INTEGER NOT NULL DEFAULT 0,
  regulator_notified      INTEGER NOT NULL DEFAULT 0,

  actor_id                TEXT,
  reason                  TEXT,
  created_at              TEXT NOT NULL,
  updated_at              TEXT NOT NULL
);

CREATE TABLE oe_sll_kpi_compliance (
  id                                  TEXT PRIMARY KEY,
  compliance_number                   TEXT UNIQUE NOT NULL,

  -- Provenance — upstream chain that triggered the case
  source_event                        TEXT,
  source_entity_type                  TEXT,
  source_entity_id                    TEXT,
  source_wave                         TEXT,
  trigger_kind                        TEXT CHECK (trigger_kind IN (
    'annual_period_open','semiannual_period_open','quarterly_period_open',
    'one_off_attestation','restatement_request','external_audit_trigger',
    'sarb_cps_audit','sa_green_taxonomy_audit'
  )),

  -- Borrower / loan identity
  borrower_party_id                   TEXT NOT NULL,
  borrower_party_name                 TEXT,
  borrower_persona                    TEXT,
  facility_id                         TEXT,
  facility_name                       TEXT,
  outstanding_zar                     REAL NOT NULL DEFAULT 0,
  remaining_tenor_days                INTEGER NOT NULL DEFAULT 0,
  base_margin_bps                     REAL NOT NULL DEFAULT 0,

  -- KPI classification
  materiality_class                   TEXT NOT NULL CHECK (materiality_class IN (
    'general_kpi','climate_kpi','safety_kpi','mandatory_disclosure_kpi',
    'governance_kpi','supply_chain_kpi'
  )),
  kpi_code                            TEXT NOT NULL,
  kpi_name                            TEXT,
  kpi_unit                            TEXT,
  kpi_period_label                    TEXT,
  kpi_period_year                     INTEGER,

  -- Tier + authority (RE-DERIVED on every transition)
  compliance_tier                     TEXT NOT NULL CHECK (compliance_tier IN (
    'minor','standard','material','severe'
  )),
  authority_required                  TEXT CHECK (authority_required IN (
    'esg_analyst','sustainability_officer','credit_committee',
    'board_sustainability_committee'
  )),

  -- KPI variance + measurement
  kpi_baseline_value                  REAL,
  kpi_target_value                    REAL,
  kpi_measured_value                  REAL,
  kpi_forecast_value                  REAL,
  measured_variance_pct               REAL,
  forecast_variance_pct               REAL,
  effective_variance_pct              REAL,

  -- Margin ratchet (bps, cumulative)
  ratchet_bps_this_period             REAL,
  cumulative_ratchet_bps              REAL NOT NULL DEFAULT 0,
  effective_margin_bps                REAL,
  cumulative_ratchet_zar              REAL,
  cure_failed_penalty_bps             REAL,

  -- ESG completeness battery
  tcfd_pillars_covered                INTEGER NOT NULL DEFAULT 0,
  tcfd_completeness_pct               REAL,
  attestation_fields_present          INTEGER NOT NULL DEFAULT 0,
  attestation_fields_required         INTEGER NOT NULL DEFAULT 0,
  attestation_completeness_pct        REAL,
  sbti_pathway                        TEXT CHECK (sbti_pathway IN (
    '1_5C','well_below_2C','2C','not_aligned'
  )),
  emissions_reduction_pct_per_year    REAL,
  taxonomy_eligible_zar               REAL,
  total_financing_zar                 REAL,
  taxonomy_alignment_pct              REAL,
  verifier_slug                       TEXT,
  verification_provenance_band        TEXT CHECK (verification_provenance_band IN (
    'big4','iso14065_accredited','industry_specialist','inadequate'
  )),

  -- Cure tracking
  cure_target_at                      TEXT,
  cure_actual_at                      TEXT,
  cure_basis                          TEXT,
  restatement_basis                   TEXT,

  -- Refs (regulator / hand-off)
  baseline_ref                        TEXT,
  measurement_ref                     TEXT,
  verification_ref                    TEXT,
  attestation_ref                     TEXT,
  ratchet_ref                         TEXT,
  amendment_ref                       TEXT,
  breach_ref                          TEXT,
  cure_ref                            TEXT,
  restatement_ref                     TEXT,
  regulator_ref                       TEXT,
  facility_ref                        TEXT,
  sustainability_event_ref            TEXT,

  -- Narrative
  baseline_basis                      TEXT,
  attestation_basis                   TEXT,
  breach_basis                        TEXT,
  fail_basis                          TEXT,
  cancellation_basis                  TEXT,
  reason_code                         TEXT,

  -- State + lifecycle (13 statuses)
  chain_status                        TEXT NOT NULL CHECK (chain_status IN (
    'kpi_period_open','baseline_set','measurement_collected',
    'independent_verification','kpi_attested','ratchet_computed',
    'margin_amended','breach_recorded','cure_period','cure_failed',
    'restatement','cancelled','sustainability_event'
  )),
  kpi_period_open_at                  TEXT NOT NULL,
  baseline_set_at                     TEXT,
  measurement_collected_at            TEXT,
  independent_verification_at         TEXT,
  kpi_attested_at                     TEXT,
  ratchet_computed_at                 TEXT,
  margin_amended_at                   TEXT,
  breach_recorded_at                  TEXT,
  cure_period_at                      TEXT,
  cure_failed_at                      TEXT,
  restatement_at                      TEXT,
  cancelled_at                        TEXT,
  sustainability_event_at             TEXT,
  kpi_due_at                          TEXT,

  is_reportable                       INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                     TEXT,
  last_sla_breach_at                  TEXT,
  escalation_level                    INTEGER NOT NULL DEFAULT 0,

  created_by                          TEXT NOT NULL,
  created_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

