CREATE TABLE oe_strate_swift_connector (
  id                                  TEXT PRIMARY KEY,
  connector_number                    TEXT UNIQUE NOT NULL,
  peer_id                             TEXT NOT NULL,
  counterparty_name                   TEXT,
  bic                                 TEXT,
  protocol                            TEXT NOT NULL CHECK (protocol IN (
    'iso_20022_xml','swift_mt','swift_mx','strate_proprietary',
    'samos_rtgs','sadc_rtgs','eft_ach','pcc_eb'
  )),
  iso20022_schema_version             TEXT,
  swift_user_key_fingerprint          TEXT,
  swift_user_key_expiry_at            TEXT,
  reconciliation_account_id           TEXT,
  endpoint_url                        TEXT,
  settlement_value_zar_per_cycle      REAL,

  -- 5 cross-chain bridges (W118 mandatory + W120 mandatory + W68/W3/W21)
  w120_reconciliation_attestation_ref TEXT,
  w68_counterparty_margin_ref         TEXT,
  w3_settlement_p6_ref                TEXT,
  w21_drawdown_ref                    TEXT,
  w118_block_ref                      TEXT,

  -- 5 floor flags (FLOOR-AT-SAMOS >=1 / FLOOR-AT-SWIFT-GLOBAL >=3)
  cross_border_payment                          INTEGER NOT NULL DEFAULT 0,
  sarb_excon_authorization_required             INTEGER NOT NULL DEFAULT 0,
  fic_act_high_risk_jurisdiction                INTEGER NOT NULL DEFAULT 0,
  basel_lcr_tier1_collateral                    INTEGER NOT NULL DEFAULT 0,
  cpmi_iosco_pfmi_principle9_systemic           INTEGER NOT NULL DEFAULT 0,

  -- Settlement quality components (0-130 composite)
  settlement_messages_per_minute      INTEGER,
  successful_settlement_count_24h     INTEGER,
  failed_settlement_count_24h         INTEGER,
  failure_rate_pct                    REAL,
  settlement_value_zar_last_24h       REAL,
  average_settlement_latency_ms       REAL,
  reconciliation_break_count          INTEGER,
  reconciliation_break_zar            REAL,
  lcr_contribution_pct                REAL,
  nsfr_contribution_pct               REAL,
  excon_authorization_status          TEXT CHECK (excon_authorization_status IN (
    'none','pending','authorized','expired'
  )),
  fic_act_kyc_status                  TEXT CHECK (fic_act_kyc_status IN (
    'clean','refresh_due','flagged'
  )),
  protocol_compliant                  INTEGER NOT NULL DEFAULT 0,
  iso27001_controls_ok                INTEGER NOT NULL DEFAULT 0,
  pci_dss_segmentation_ok             INTEGER NOT NULL DEFAULT 0,
  settlement_quality_index            INTEGER,

  -- Composite indexes + bands
  current_tier                        TEXT NOT NULL CHECK (current_tier IN (
    'domestic_eft','multi_bank_eft','strate_csd','samos_rtgs','swift_global'
  )),
  authority_required                  TEXT,
  urgency_band                        TEXT,
  connector_health_band               TEXT,

  -- Narrative + reason codes
  title                               TEXT,
  reason_code                         TEXT,

  is_reportable                       INTEGER NOT NULL DEFAULT 0,
  regulator_relevant                  INTEGER NOT NULL DEFAULT 0,
  regulator_reason_text               TEXT,
  regulator_ref                       TEXT,
  regulator_inbox_ref                 TEXT,

  -- 11 forward + 4 branch lifecycle timestamps
  chain_status                        TEXT NOT NULL CHECK (chain_status IN (
    'connector_proposed','bic_validated','bank_handshake_completed',
    'iso20022_schemas_loaded','messaging_session_established',
    'test_messages_validated','reconciliation_account_bound',
    'live_settlement_active','cycle_reconciled','archived',
    'disconnected','credential_revoked','suspended','failover_active'
  )),
  connector_proposed_at               TEXT,
  bic_validated_at                    TEXT,
  bank_handshake_completed_at         TEXT,
  iso20022_schemas_loaded_at          TEXT,
  messaging_session_established_at    TEXT,
  test_messages_validated_at          TEXT,
  reconciliation_account_bound_at     TEXT,
  live_settlement_active_at           TEXT,
  cycle_reconciled_at                 TEXT,
  archived_at                         TEXT,
  disconnected_at                     TEXT,
  suspended_at                        TEXT,
  credential_revoked_at               TEXT,
  failover_activated_at               TEXT,

  -- Regulator crossing
  regulator_crossed_at                TEXT,

  -- SLA (HOURS, INVERTED polarity)
  sla_target_hours                    INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at                     TEXT,
  sla_breached                        INTEGER NOT NULL DEFAULT 0,
  last_sla_breach_at                  TEXT,
  escalation_level                    INTEGER NOT NULL DEFAULT 0,
  days_to_key_renewal                 INTEGER,

  tenant_id                           TEXT,
  created_by                          TEXT NOT NULL,
  created_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_strate_swift_connector_events (
  id                  TEXT PRIMARY KEY,
  connector_id        TEXT NOT NULL,
  event_type          TEXT NOT NULL,
  from_status         TEXT,
  to_status           TEXT,
  from_tier           TEXT,
  to_tier             TEXT,
  actor_id            TEXT,
  actor_party         TEXT,
  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_submittal_rfi (
  id                                  TEXT PRIMARY KEY,
  submittal_rfi_number                TEXT UNIQUE NOT NULL,

  -- Provenance — upstream chain that triggered the case
  source_event                        TEXT,
  source_entity_type                  TEXT,
  source_entity_id                    TEXT,
  source_wave                         TEXT,

  -- Project / facility / parties
  project_id                          TEXT NOT NULL,
  project_name                        TEXT,
  facility_id                         TEXT,
  facility_name                       TEXT,
  contractor_id                       TEXT,
  contractor_name                     TEXT,
  designer_id                         TEXT,
  designer_name                       TEXT,
  vendor_id                           TEXT,
  vendor_name                         TEXT,
  owner_party_id                      TEXT,
  owner_party_name                    TEXT,

  -- Classification
  workflow_class                      TEXT NOT NULL CHECK (workflow_class IN (
    'submittal_design','submittal_product_data','submittal_mockup',
    'submittal_om_manuals','rfi_design_clarification','rfi_field_condition',
    'rfi_substitution_request','rfi_change_in_scope'
  )),
  priority_class                      TEXT NOT NULL CHECK (priority_class IN (
    'critical','high','standard','low'
  )),
  document_type                       TEXT,
  spec_section                        TEXT,
  csi_division                        TEXT,
  csi_section_code                    TEXT,
  uniclass_code                       TEXT,
  sans_section                        TEXT,
  transmittal_number                  TEXT,
  sequence_number                     INTEGER,

  -- Tier + authority (RE-DERIVED on every transition)
  current_tier                        TEXT NOT NULL CHECK (current_tier IN (
    'critical','high','standard','low'
  )),
  authority_required                  TEXT CHECK (authority_required IN (
    'construction_coordinator','lead_engineer','project_manager',
    'project_director'
  )),

  -- Coverage gates (drive tier floor + regulator crossings)
  affects_grid_code                   INTEGER NOT NULL DEFAULT 0,
  affects_life_safety                 INTEGER NOT NULL DEFAULT 0,
  affects_bid_envelope                INTEGER NOT NULL DEFAULT 0,
  holds_construction                  INTEGER NOT NULL DEFAULT 0,
  requires_designer_response          INTEGER NOT NULL DEFAULT 0,
  requires_ie_review                  INTEGER NOT NULL DEFAULT 0,
  requires_owner_review               INTEGER NOT NULL DEFAULT 0,

  -- Counts (live-wired against history)
  clarification_count                 INTEGER NOT NULL DEFAULT 0,
  revision_count                      INTEGER NOT NULL DEFAULT 0,
  rejection_count                     INTEGER NOT NULL DEFAULT 0,
  response_count                      INTEGER NOT NULL DEFAULT 0,

  -- Quantities (used in regulator crossing decisions + live battery)
  bid_envelope_drift_pct              REAL,
  grid_code_clauses_affected          INTEGER NOT NULL DEFAULT 0,
  estimated_cost_impact_zar           REAL,
  estimated_schedule_impact_days      INTEGER,

  -- Supersession / parent links
  parent_submittal_id                 TEXT,
  superseded_by_id                    TEXT,
  parent_rfi_id                       TEXT,

  -- Refs
  drawing_ref                         TEXT,
  attachments_json                    TEXT,
  spec_coverage_notes                 TEXT,
  regulator_ref                       TEXT,
  gca_ref                             TEXT,
  cod_ref                             TEXT,

  -- Narrative
  title                               TEXT,
  narrative                           TEXT,
  response_text                       TEXT,
  voided_reason                       TEXT,
  withdrawn_reason                    TEXT,
  reason_code                         TEXT,

  -- Party (current ball-in-court + history)
  current_ball_in_court_party         TEXT,
  last_responder_party                TEXT,
  requester_party                     TEXT,
  approver_party                      TEXT,

  -- State + lifecycle (13 statuses, listed; voided/withdrawn are exception
  -- terminals)
  chain_status                        TEXT NOT NULL CHECK (chain_status IN (
    'drafted','submitted','distributed','under_review',
    'clarification_requested','responded','approved',
    'returned_for_revision','revised','distributed_for_construction',
    'incorporated','closed_clean','voided','withdrawn'
  )),
  drafted_at                          TEXT NOT NULL,
  submitted_at                        TEXT,
  distributed_at                      TEXT,
  under_review_at                     TEXT,
  clarification_requested_at          TEXT,
  responded_at                        TEXT,
  approved_at                         TEXT,
  returned_for_revision_at            TEXT,
  revised_at                          TEXT,
  distributed_for_construction_at     TEXT,
  incorporated_at                     TEXT,
  closed_clean_at                     TEXT,
  voided_at                           TEXT,
  withdrawn_at                        TEXT,
  construction_hold_started_at        TEXT,

  -- Reportability + SLA
  is_reportable                       INTEGER NOT NULL DEFAULT 0,
  regulator_crossed_at                TEXT,
  regulator_inbox_ref                 TEXT,
  sla_deadline_at                     TEXT,
  response_due_at                     TEXT,
  last_sla_breach_at                  TEXT,
  escalation_level                    INTEGER NOT NULL DEFAULT 0,

  created_by                          TEXT NOT NULL,
  created_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_submittal_rfi_events (
  id                  TEXT PRIMARY KEY,
  submittal_rfi_id    TEXT NOT NULL,
  event_type          TEXT NOT NULL,
  from_status         TEXT,
  to_status           TEXT,
  actor_id            TEXT,
  actor_party         TEXT,
  notes               TEXT,
  payload             TEXT,
  created_at          TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_subscription_invoices (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL,          -- the billed participant (company)
  billing_period TEXT NOT NULL,          -- YYYY-MM (e.g. 2026-06)
  subscription_tier TEXT NOT NULL CHECK(subscription_tier IN ('starter','professional','enterprise')),

  -- Amounts
  amount_zar REAL NOT NULL,              -- gross invoice amount
  vat_zar REAL NOT NULL,                 -- 15% VAT
  total_zar REAL NOT NULL,               -- amount_zar + vat_zar
  discount_zar REAL DEFAULT 0,           -- negotiated discount if any
  net_payable_zar REAL NOT NULL,         -- total_zar - discount_zar

  -- Line items (JSON array of {description, qty, unit_price_zar})
  line_items TEXT NOT NULL DEFAULT '[]',

  -- Payment details
  payment_method TEXT CHECK(payment_method IN ('eft','debit_order','bank_wire','card','credit_note')),
  payment_ref TEXT,
  payment_date TEXT,
  payment_amount_zar REAL,
  bank_reference TEXT,

  -- Dunning state
  dunning_notices_sent INTEGER DEFAULT 0,  -- 0, 1 (dunning_1), 2 (dunning_2)
  suspension_reason TEXT,
  waiver_reason TEXT,
  write_off_reason TEXT,

  -- Chain state
  chain_status TEXT NOT NULL DEFAULT 'draft'
    CHECK(chain_status IN (
      'draft',           -- generated, not yet sent
      'issued',          -- sent to participant
      'payment_pending', -- acknowledged, awaiting payment
      'paid',            -- payment received; terminal
      'overdue',         -- past payment due date
      'dunning_1',       -- first dunning notice sent
      'dunning_2',       -- final dunning notice sent
      'suspended',       -- account suspended for non-payment; terminal
      'cancelled',       -- invoice voided before payment; terminal
      'waived',          -- debt forgiven by admin; terminal
      'written_off'      -- uncollectible, written off; terminal
    )),

  -- SLA
  sla_deadline TEXT,                     -- payment due date
  sla_breached INTEGER DEFAULT 0,
  regulator_notified INTEGER DEFAULT 0,
  actor_id TEXT,
  reason TEXT,

  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_substation_assets (
  id                       TEXT PRIMARY KEY,
  participant_id           TEXT NOT NULL,   -- grid operator (NTCSA/Eskom/MV distributor)

  -- Asset identity
  asset_number             TEXT NOT NULL UNIQUE,  -- utility asset tag
  asset_type               TEXT NOT NULL CHECK(asset_type IN (
    'power_transformer','auto_transformer','instrument_transformer',
    'circuit_breaker','disconnector','busbar','cable','overhead_line',
    'reactor','capacitor_bank','substation_battery','protection_relay'
  )),
  asset_tier               TEXT NOT NULL CHECK(asset_tier IN (
    'distribution','subtransmission','transmission','critical_node'
  )),
  name                     TEXT NOT NULL,
  location_name            TEXT,
  gps_latitude             REAL,
  gps_longitude            REAL,
  voltage_kv               REAL,
  rated_mva                REAL,
  manufacturer             TEXT,
  model                    TEXT,
  serial_number            TEXT,
  year_manufactured        INTEGER,

  -- Service history
  commissioned_at          TEXT,
  last_assessed_at         TEXT,
  condition_score          REAL CHECK(condition_score BETWEEN 0 AND 10 OR condition_score IS NULL),
  age_years                INTEGER,
  expected_life_years      INTEGER DEFAULT 40,
  remaining_life_years     INTEGER,

  -- Refurbishment
  refurbishment_type       TEXT,            -- minor/major/rewind/replacement
  refurbishment_cost_zar   REAL,
  refurbishment_started_at TEXT,
  refurbishment_completed_at TEXT,

  -- Decommission
  decommission_reason      TEXT CHECK(decommission_reason IN ('end_of_life','failure','replacement','stranded_asset',NULL)),
  decommissioned_at        TEXT,

  -- Failure
  failure_mode             TEXT,
  failure_reported_at      TEXT,
  failure_investigation_ref TEXT,

  chain_status             TEXT NOT NULL DEFAULT 'registered' CHECK(chain_status IN (
    'registered','commissioning','energised','condition_assessment',
    'assessment_complete','refurbishment_planned','out_of_service',
    'refurbishment','returned_to_service','decommission_decision',
    'decommissioned','failed'
  )),
  sla_deadline             TEXT NOT NULL,
  sla_breached             INTEGER NOT NULL DEFAULT 0,
  regulator_notified       INTEGER NOT NULL DEFAULT 0,

  actor_id                 TEXT,
  reason                   TEXT,
  created_at               TEXT NOT NULL,
  updated_at               TEXT NOT NULL
);

CREATE TABLE oe_support_ticket_events (
  id TEXT PRIMARY KEY,
  ticket_id TEXT NOT NULL,
  event_type TEXT NOT NULL CHECK (event_type IN (
    'opened','triaged','picked_up','wait_for_user',
    'user_responded','resolved','closed','reopened',
    'escalated','sla_breached','note'
  )),
  from_status TEXT,
  to_status TEXT,
  sla_window TEXT,
  actor_id TEXT,
  notes TEXT,
  payload_json TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_surveillance_alerts (
  id                TEXT PRIMARY KEY,
  alert_type        TEXT NOT NULL,                -- wash_trade | layering | spoofing |
                                                  -- marking_close | front_running |
                                                  -- mismatched_position | insider_pattern |
                                                  -- collusion | unusual_volume
  participant_id    TEXT NOT NULL,
  related_order_ids TEXT,                         -- JSON array
  related_fill_ids  TEXT,                         -- JSON array
  detected_at       TEXT NOT NULL DEFAULT (datetime('now')),
  severity          TEXT NOT NULL,                -- info | low | medium | high | critical
  score             REAL,                         -- 0..1 model confidence
  evidence_json     TEXT,                         -- relevant data points
  status            TEXT NOT NULL DEFAULT 'open',
                                                  -- open | under_review | escalated |
                                                  -- false_positive | confirmed | reported_to_fic
  reviewer_id       TEXT,
  reviewed_at       TEXT,
  reported_to       TEXT,                         -- 'FIC' / 'NERSA' / 'FSCA'
  reported_at       TEXT,
  notes             TEXT
);

CREATE TABLE oe_sustainability_listings (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL,                -- seller
  listing_type TEXT NOT NULL CHECK(listing_type IN ('rec','vcm','brokered_coa')),

  -- Source references (at least one required depending on type)
  rec_holding_id TEXT,    -- REFERENCES oe_rec_holdings(id)
  vcm_holding_id TEXT,    -- REFERENCES oe_vcm_holdings(id)

  -- Listing display details
  title TEXT NOT NULL,
  description TEXT,
  technology TEXT,
  vintage_year INTEGER,
  registry_standard TEXT,
  methodology TEXT,
  carbon_tax_eligible INTEGER DEFAULT 0,
  sustainability_framework TEXT,  -- re100, sbti, cdp, iso14064, jse_esg, gbcsa, ghg_protocol_scope2

  -- Pricing
  quantity_listed REAL NOT NULL,
  quantity_reserved REAL DEFAULT 0,
  quantity_sold REAL DEFAULT 0,
  unit TEXT NOT NULL CHECK(unit IN ('mwh','tco2e')),
  price_zar_per_unit REAL NOT NULL,
  min_purchase_qty REAL DEFAULT 1.0,

  -- Retirement options the seller allows
  allows_portfolio_hold INTEGER DEFAULT 1,
  allows_brokered_retirement INTEGER DEFAULT 1,

  -- Verification / provenance
  registry_cert_ids TEXT,           -- JSON array of cert IDs from issuing registry
  verified_by TEXT,
  verification_date TEXT,

  -- Chain state
  chain_status TEXT NOT NULL DEFAULT 'draft'
    CHECK(chain_status IN ('draft','active','partially_sold','sold_out','cancelled','expired')),

  listing_expiry TEXT,              -- ISO date; NULL = 90-day default
  sla_deadline TEXT,
  sla_breached INTEGER DEFAULT 0,
  regulator_notified INTEGER DEFAULT 0,
  actor_id TEXT,
  reason TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_sustainability_transactions (
  id TEXT PRIMARY KEY,
  listing_id TEXT NOT NULL REFERENCES oe_sustainability_listings(id),
  seller_id TEXT NOT NULL,
  buyer_id TEXT NOT NULL,
  listing_type TEXT NOT NULL CHECK(listing_type IN ('rec','vcm','brokered_coa')),

  -- What was purchased
  quantity_purchased REAL NOT NULL,
  unit TEXT NOT NULL CHECK(unit IN ('mwh','tco2e')),
  price_zar_per_unit REAL NOT NULL,
  total_zar REAL NOT NULL,
  platform_fee_zar REAL NOT NULL,     -- 1.5% of total_zar
  net_seller_zar REAL NOT NULL,        -- total_zar - platform_fee_zar

  -- Disposition: hold in portfolio or retire immediately
  disposition TEXT NOT NULL DEFAULT 'portfolio_hold'
    CHECK(disposition IN ('portfolio_hold','brokered_retirement')),

  -- Brokered retirement details (populated if disposition = brokered_retirement)
  retirement_beneficiary TEXT,
  retirement_purpose TEXT CHECK(retirement_purpose IN
    ('scope2_ghg_protocol','re100','sbti','cdp','iso14064','jse_esg','gbcsa_green_star',
     'carbon_tax_offset','supply_chain_scope3','other')),
  retirement_ref TEXT,                -- registry retirement serial / OE cert number

  -- Payment & settlement
  payment_method TEXT CHECK(payment_method IN
    ('platform_wallet','eft','instant_eft','card')),
  payment_ref TEXT,
  settlement_ref TEXT,

  -- Chain state
  chain_status TEXT NOT NULL DEFAULT 'pending'
    CHECK(chain_status IN
      ('pending','payment_processing','payment_confirmed',
       'settlement_pending','settled','failed','refunded','cancelled')),

  sla_deadline TEXT,
  sla_breached INTEGER DEFAULT 0,
  regulator_notified INTEGER DEFAULT 0,
  actor_id TEXT,
  reason TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_tariff_applications (
  id                  TEXT PRIMARY KEY,
  applicant_id        TEXT NOT NULL,
  application_ref     TEXT NOT NULL UNIQUE,
  application_type    TEXT NOT NULL,            -- mypd | annual_revision | special_review
  filing_date         TEXT NOT NULL,
  comment_period_ends TEXT NOT NULL,
  hearing_scheduled_at TEXT,
  status              TEXT NOT NULL DEFAULT 'filed',
                                                 -- filed | in_comment_period |
                                                 -- comment_period_closed | scheduled_for_hearing |
                                                 -- heard | decision_pending | decided |
                                                 -- on_appeal | withdrawn
  requested_revenue_zar REAL,
  current_revenue_zar  REAL,
  pct_change           REAL,
  documents_r2_prefix  TEXT,
  decision_id          TEXT,
  created_at           TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at           TEXT
);

CREATE TABLE oe_tariff_determinations (
  id                            TEXT PRIMARY KEY,
  determination_number          TEXT UNIQUE NOT NULL,

  -- Provenance (e.g. a renewal/licence the tariff attaches to)
  source_event                  TEXT,
  source_entity_type            TEXT,
  source_entity_id              TEXT,
  source_wave                   TEXT,

  -- Parties (two-party split: applicant licensee + NERSA officer)
  applicant_party_id            TEXT NOT NULL,
  applicant_party_name          TEXT NOT NULL,
  regulator_party_id            TEXT NOT NULL,
  regulator_party_name          TEXT NOT NULL,

  -- Determination identity
  licence_ref                   TEXT,
  tariff_entity                 TEXT NOT NULL,     -- the regulated entity/service the tariff covers
  tariff_segment                TEXT,              -- transmission / distribution / generation / retail / sseg
  determination_class           TEXT NOT NULL CHECK (determination_class IN (
    'multi_year', 'annual_tariff', 'sseg_feedin'
  )),
  mypd_period                   TEXT,              -- e.g. MYPD5 2025-2030
  price_year                    TEXT,              -- e.g. 2026/27

  -- Economic parameters (the heart of a price-control determination)
  requested_revenue_zar_m       REAL,              -- applicant's requested allowed revenue (R millions)
  allowed_revenue_zar_m         REAL,              -- determined allowed revenue (R millions)
  rab_zar_m                     REAL,              -- regulatory asset base (R millions)
  wacc_pre_tax                  REAL,              -- pre-tax real WACC (fraction, e.g. 0.0875)
  opex_zar_m                    REAL,              -- allowed operating expenditure (R millions)
  rca_balance_zar_m             REAL,              -- Regulatory Clearing Account true-up balance (R millions)
  requested_tariff_zar_kwh      REAL,              -- applicant's requested average tariff
  allowed_tariff_zar_kwh        REAL,              -- determined average tariff
  tariff_increase_pct           REAL,              -- headline determined increase (percent)
  x_factor                      REAL,              -- efficiency / X-factor

  -- Refs
  application_ref               TEXT,
  completeness_ref              TEXT,
  consultation_ref              TEXT,
  analysis_ref                  TEXT,
  draft_ref                     TEXT,
  determination_ref             TEXT,              -- determination document ref
  reconsideration_ref           TEXT,
  court_ref                     TEXT,              -- judicial-review case ref
  gazette_ref                   TEXT,              -- Government Gazette notice ref
  regulator_ref                 TEXT,              -- Council oversight / public register ref

  -- Narrative
  application_basis             TEXT,
  completeness_basis            TEXT,
  consultation_basis            TEXT,
  analysis_basis                TEXT,
  draft_basis                   TEXT,
  determination_basis           TEXT,
  reconsideration_basis         TEXT,
  remit_basis                   TEXT,
  reason_code                   TEXT,
  rod_notes                     TEXT,              -- record of decision

  -- State + lifecycle
  chain_status                  TEXT NOT NULL CHECK (chain_status IN (
    'application_received','completeness_review','public_consultation',
    'revenue_analysis','draft_determination','council_deliberation',
    'determination_issued','reconsideration_requested',
    'implemented','remitted','rejected','withdrawn'
  )),
  application_received_at       TEXT NOT NULL,
  completeness_review_at        TEXT,
  public_consultation_at        TEXT,
  revenue_analysis_at           TEXT,
  draft_determination_at        TEXT,
  council_deliberation_at       TEXT,
  determination_issued_at       TEXT,
  reconsideration_requested_at  TEXT,
  implemented_at                TEXT,
  remitted_at                   TEXT,
  rejected_at                   TEXT,
  withdrawn_at                  TEXT,

  is_reportable                 INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at               TEXT,
  last_sla_breach_at            TEXT,
  escalation_level              INTEGER NOT NULL DEFAULT 0,

  created_by                    TEXT NOT NULL,
  created_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_tariff_determinations_events (
  id                 TEXT PRIMARY KEY,
  determination_id   TEXT NOT NULL,
  event_type         TEXT NOT NULL,
  from_status        TEXT,
  to_status          TEXT,
  actor_id           TEXT,
  actor_party        TEXT,
  notes              TEXT,
  payload            TEXT,
  created_at         TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_tariff_indexation (
  id                      TEXT PRIMARY KEY,
  indexation_number       TEXT UNIQUE NOT NULL,

  -- Provenance
  source_event            TEXT,
  source_entity_type      TEXT,
  source_entity_id        TEXT,
  source_wave             TEXT,

  -- Seller (IPP / project company)
  seller_party_id         TEXT NOT NULL,
  seller_party_name       TEXT NOT NULL,

  -- Offtaker (buyer)
  offtaker_party_id       TEXT NOT NULL,
  offtaker_party_name     TEXT NOT NULL,

  -- Contract descriptors
  ppa_ref                 TEXT,
  project_name            TEXT NOT NULL,
  contract_tier           TEXT NOT NULL CHECK (contract_tier IN (
    'utility_scale', 'commercial', 'embedded'
  )),
  contract_year           INTEGER,          -- escalation anniversary (1..N)

  -- Indexation arithmetic
  base_tariff_zar_mwh     REAL,             -- tariff before this escalation
  index_type              TEXT,             -- CPI / PPI / CPI+forex
  index_reference_period  TEXT,             -- e.g. 2026-03 vs 2025-03
  index_value             REAL,             -- published index reading (%)
  escalation_factor       REAL,             -- multiplier applied to base
  proposed_tariff_zar_mwh REAL,             -- seller's proposed new tariff
  agreed_tariff_zar_mwh   REAL,             -- agreed / applied tariff
  annual_contract_value_zar REAL,           -- contract value at new tariff
  disputed_amount_zar     REAL,             -- value in dispute (delta)

  -- Refs
  index_ref               TEXT,
  notice_ref              TEXT,
  dispute_ref             TEXT,
  recalc_ref              TEXT,
  arbitration_ref         TEXT,

  -- Narrative
  calculation_basis       TEXT,
  notice_basis            TEXT,
  review_basis            TEXT,
  dispute_basis           TEXT,
  recalc_basis            TEXT,
  arbitration_basis       TEXT,
  reason_code             TEXT,
  rod_notes               TEXT,

  -- State + lifecycle
  chain_status            TEXT NOT NULL CHECK (chain_status IN (
    'indexation_due','index_published','escalation_calculated','notice_issued',
    'under_review','tariff_agreed','applied','disputed','recalculated',
    'arbitrated','withdrawn'
  )),
  indexation_due_at         TEXT NOT NULL,
  index_published_at        TEXT,
  escalation_calculated_at  TEXT,
  notice_issued_at          TEXT,
  under_review_at           TEXT,
  tariff_agreed_at          TEXT,
  applied_at                TEXT,
  disputed_at               TEXT,
  recalculated_at           TEXT,
  arbitrated_at             TEXT,
  withdrawn_at              TEXT,

  dispute_round            INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at          TEXT,
  last_sla_breach_at       TEXT,
  escalation_level         INTEGER NOT NULL DEFAULT 0,

  created_by              TEXT NOT NULL,
  created_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_tariff_indexation_events (
  id              TEXT PRIMARY KEY,
  indexation_id   TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_tenant_usage (
  participant_id       TEXT NOT NULL,
