CREATE TABLE oe_trade_allocation_events (
  id              TEXT PRIMARY KEY,
  allocation_id   TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_trade_allocations (
  id                       TEXT PRIMARY KEY,
  allocation_number        TEXT UNIQUE NOT NULL,

  -- Provenance (W76 follows execution on the venue)
  source_event             TEXT,
  source_entity_type       TEXT,
  source_entity_id         TEXT,
  source_wave              TEXT,
  trade_ref                TEXT,              -- executed block trade reference
  order_ref                TEXT,              -- originating order

  -- Counterparties / brokers
  executing_party          TEXT NOT NULL,     -- executing broker / desk
  clearing_party           TEXT,              -- clearing broker (give-up target)
  counterparty_name        TEXT NOT NULL,     -- client / fund affirming
  block_account            TEXT,              -- pre-allocation block account

  -- Classification
  instrument               TEXT,              -- energy_forward / rec / carbon / option
  energy_type              TEXT,              -- power / gas / carbon / rec
  side                     TEXT,              -- buy / sell
  quantity                 REAL,              -- contract quantity (MWh / units)
  price                    REAL,              -- execution price
  notional_zar             REAL NOT NULL,     -- trade notional — drives the tier
  allocation_legs          INTEGER,           -- number of sub-account legs
  notional_tier            TEXT NOT NULL CHECK (notional_tier IN (
    'micro','small','medium','large','block'
  )),

  -- Settlement
  settlement_date          TEXT,
  ssi_ref                  TEXT,              -- standing settlement instruction used
  csd_ref                  TEXT,              -- CSD / settlement reference
  break_reason_code        TEXT,              -- structured break classification

  -- Refs
  allocation_ref           TEXT,
  give_up_ref              TEXT,
  confirmation_ref         TEXT,
  affirmation_ref          TEXT,
  match_ref                TEXT,
  settlement_instruction_ref TEXT,
  break_ref                TEXT,
  cancel_ref               TEXT,

  -- Narrative
  allocation_basis         TEXT,
  give_up_basis            TEXT,
  confirmation_basis       TEXT,
  affirmation_basis        TEXT,
  match_basis              TEXT,
  settlement_basis         TEXT,
  break_basis              TEXT,
  resolution_basis         TEXT,
  cancel_basis             TEXT,
  reason_code              TEXT,

  -- State + lifecycle
  chain_status             TEXT NOT NULL CHECK (chain_status IN (
    'executed','allocation_pending','allocated','give_up_pending','give_up_accepted',
    'confirmation_issued','affirmed','matched','settlement_instructed','settled',
    'break_review','cancelled'
  )),
  executed_at                  TEXT NOT NULL,
  allocation_pending_at        TEXT,
  allocated_at                 TEXT,
  give_up_pending_at           TEXT,
  give_up_accepted_at          TEXT,
  confirmation_issued_at       TEXT,
  affirmed_at                  TEXT,
  matched_at                   TEXT,
  settlement_instructed_at     TEXT,
  settled_at                   TEXT,
  break_review_at              TEXT,
  cancelled_at                 TEXT,

  sla_deadline_at          TEXT,
  last_sla_breach_at       TEXT,
  is_reportable            INTEGER NOT NULL DEFAULT 0,
  escalation_level         INTEGER NOT NULL DEFAULT 0,

  created_by               TEXT NOT NULL,
  created_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_trade_reports (
  id                       TEXT PRIMARY KEY,
  report_number            TEXT UNIQUE NOT NULL,

  -- Provenance (the executed trade/match this report covers)
  source_event             TEXT,
  source_entity_type       TEXT,
  source_entity_id         TEXT,
  source_wave              TEXT,

  -- Firm / reporting identity
  desk_party_id            TEXT NOT NULL,
  desk_party_name          TEXT NOT NULL,
  trade_repository         TEXT,                 -- e.g. JSE Trade Repository

  -- Trade identity
  uti                      TEXT,                 -- Unique Transaction Identifier
  trade_ref                TEXT,                 -- internal trade/match ref
  counterparty_name        TEXT,
  counterparty_lei         TEXT,                 -- Legal Entity Identifier
  energy_type              TEXT,                 -- power / carbon / rec / gas
  product                  TEXT,                 -- forward / swap / option / spot / block
  report_class             TEXT NOT NULL CHECK (report_class IN (
    'otc_derivative', 'physical_forward', 'spot_physical'
  )),
  side                     TEXT,                 -- buy / sell
  trade_date               TEXT,
  value_date               TEXT,
  reporting_deadline       TEXT,                 -- the T+1 regulatory deadline

  -- Economics
  notional_zar_m           REAL,                 -- notional value (R millions)
  volume_mwh               REAL,
  price_zar_mwh            REAL,
  collateral_zar_m         REAL,

  -- Refs
  generation_ref           TEXT,
  submission_ref           TEXT,                 -- TR submission id
  acknowledgement_ref      TEXT,                 -- TR ack id
  reconciliation_ref       TEXT,
  break_ref                TEXT,
  rejection_ref            TEXT,                 -- TR NACK code/ref
  correction_ref           TEXT,
  exemption_ref            TEXT,                 -- intragroup/de-minimis exemption ref
  regulator_ref            TEXT,                 -- FSCA supervisory queue ref

  -- Narrative
  generation_basis         TEXT,
  submission_basis         TEXT,
  reconciliation_basis     TEXT,
  break_basis              TEXT,
  rejection_basis          TEXT,
  correction_basis         TEXT,
  exemption_basis          TEXT,
  reason_code              TEXT,
  resolution_notes         TEXT,

  -- State + lifecycle
  chain_status             TEXT NOT NULL CHECK (chain_status IN (
    'report_due','report_generated','submitted_to_tr','tr_acknowledged',
    'reconciled','break_identified','break_resolved','confirmed_complete',
    'tr_rejected','corrected','exempted','cancelled'
  )),
  report_due_at            TEXT NOT NULL,
  report_generated_at      TEXT,
  submitted_to_tr_at       TEXT,
  tr_acknowledged_at       TEXT,
  reconciled_at            TEXT,
  break_identified_at      TEXT,
  break_resolved_at        TEXT,
  confirmed_complete_at    TEXT,
  tr_rejected_at           TEXT,
  corrected_at             TEXT,
  exempted_at              TEXT,
  cancelled_at             TEXT,

  is_reportable            INTEGER NOT NULL DEFAULT 0,
  resubmission_count       INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at          TEXT,
  last_sla_breach_at       TEXT,
  escalation_level         INTEGER NOT NULL DEFAULT 0,

  created_by               TEXT NOT NULL,
  created_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at               TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_trade_reports_events (
  id            TEXT PRIMARY KEY,
  report_id     TEXT NOT NULL,
  event_type    TEXT NOT NULL,
  from_status   TEXT,
  to_status     TEXT,
  actor_id      TEXT,
  actor_party   TEXT,
