CREATE TABLE oe_vendor_escalation (
  id                      TEXT PRIMARY KEY,
  case_number             TEXT UNIQUE NOT NULL,

  -- Provenance (W15 warranty.systemic_defect + W24 pr.component_defect)
  source_event            TEXT,
  source_entity_type      TEXT,
  source_entity_id        TEXT,
  source_wave             TEXT,

  -- Operator (Esums O&M) party
  operator_party_id       TEXT NOT NULL,
  operator_party_name     TEXT NOT NULL,

  -- Vendor / supplier party
  vendor_party_id         TEXT NOT NULL,
  vendor_party_name       TEXT NOT NULL,

  -- OEM / manufacturer party (set when escalated)
  oem_party_id            TEXT,
  oem_party_name          TEXT,

  -- Affected component / fleet
  component_type          TEXT NOT NULL,
  component_model         TEXT,
  serial_range            TEXT,
  fleet_units_affected    INTEGER NOT NULL DEFAULT 0,
  fleet_units_total       INTEGER NOT NULL DEFAULT 0,
  fleet_fraction          REAL,
  site_name               TEXT,
  site_province           TEXT,

  -- Defect class + safety flag
  defect_class            TEXT NOT NULL CHECK (defect_class IN (
    'safety_recall', 'fleet_systemic', 'batch_defect', 'single_unit'
  )),
  safety_critical         INTEGER NOT NULL DEFAULT 0,

  -- Refs
  warranty_clause         TEXT,
  filing_ref              TEXT,
  vendor_decision_ref     TEXT,
  oem_decision_ref        TEXT,
  remediation_ref         TEXT,
  recall_ref              TEXT,
  arbitration_case_ref    TEXT,
  withdrawal_ref          TEXT,

  -- Liability / remedy economics
  claim_value_zar         REAL,
  liability_accepted      INTEGER,
  remedy_type             TEXT,
  remedy_cost_zar         REAL,

  -- Narrative
  defect_summary          TEXT,
  vendor_decision_basis   TEXT,
  oem_decision_basis      TEXT,
  remediation_plan        TEXT,
  recall_basis            TEXT,
  arbitration_basis       TEXT,
  withdrawal_basis        TEXT,
  reason_code             TEXT,
  rod_notes               TEXT,

  -- State + lifecycle
  chain_status            TEXT NOT NULL CHECK (chain_status IN (
    'filed','vendor_triage','vendor_decision','escalated_to_oem',
    'oem_field_investigation','oem_decision','remediation',
    'closed','recall_issued','arbitration','withdrawn'
  )),
  filed_at                TEXT NOT NULL,
  vendor_triage_at        TEXT,
  vendor_decision_at      TEXT,
  escalated_to_oem_at     TEXT,
  oem_investigation_at    TEXT,
  oem_decision_at         TEXT,
  remediation_at          TEXT,
  closed_at               TEXT,
  recall_issued_at        TEXT,
  arbitration_at          TEXT,
  withdrawn_at            TEXT,

  sla_deadline_at         TEXT,
  last_sla_breach_at      TEXT,
  escalation_level        INTEGER NOT NULL DEFAULT 0,

  created_by              TEXT NOT NULL,
  created_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at              TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_vendor_escalation_events (
  id              TEXT PRIMARY KEY,
  escalation_id   TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  actor_party     TEXT,
  notes           TEXT,
  payload         TEXT,
  created_at      TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE oe_virtual_ppa_settlements (
  id TEXT PRIMARY KEY,
  contract_ref TEXT NOT NULL,            -- underlying virtual/financial PPA (CfD) contract reference
  generator_id TEXT NOT NULL,            -- IPP / generator — receives the fixed strike price
  offtaker_id TEXT NOT NULL,             -- corporate buyer — receives the floating reference price
  settlement_period TEXT NOT NULL,       -- YYYY-MM
  reference_index TEXT NOT NULL CHECK(reference_index IN (
    'day_ahead_market', 'eskom_megaflex', 'ifrt_reference', 'wholesale_pool'
  )),

  -- Commercial terms for the period
  notional_mwh REAL NOT NULL,                   -- contracted notional volume for the period
  strike_price_zar_per_mwh REAL NOT NULL,       -- fixed/strike price agreed in the CfD
  reference_price_zar_per_mwh REAL,             -- floating reference/index price (NULL until published)

  -- Computed differential
  differential_zar_per_mwh REAL,
  settlement_amount_zar REAL,                   -- absolute value of the differential payable
  paying_party TEXT CHECK(paying_party IN ('generator', 'offtaker')),
  settlement_tier TEXT CHECK(settlement_tier IN ('minor', 'material', 'large', 'systemic')),

  -- Payment details
  payment_method TEXT CHECK(payment_method IN ('eft', 'bank_wire', 'clearing_house', 'netting')),
  payment_ref TEXT,
  payment_date TEXT,
  payment_amount_zar REAL,

  -- Dispute / recalculation / determination trail
  dispute_reason TEXT,
  recalculated_amount_zar REAL,
  isda_determination_ref TEXT,
  write_off_reason TEXT,
  cancellation_reason TEXT,

  -- Chain state
  chain_status TEXT NOT NULL DEFAULT 'reference_price_pending'
    CHECK(chain_status IN (
      'reference_price_pending', -- period opened; awaiting publication of the floating reference index
      'calculated',              -- differential computed (strike vs reference x notional)
      'statement_issued',        -- settlement statement issued to both counterparties
      'payment_pending',         -- acknowledged; payment due by sla_deadline
      'disputed',                -- a counterparty disputes the calculated differential
      'recalculating',           -- recalculation under way following dispute
      'isda_determination',      -- escalated to ISDA Calculation Agent for binding determination
      'partially_settled',       -- partial payment received; balance outstanding
      'overdue',                 -- sla_deadline passed without full settlement
      'settled',                 -- payment completed and confirmed; terminal
      'written_off',             -- uncollectible balance written off; terminal
      'cancelled'                -- statement voided before settlement (data correction); terminal
    )),

  -- SLA
  sla_deadline TEXT,
  sla_breached INTEGER DEFAULT 0,
  regulator_notified INTEGER DEFAULT 0,
  actor_id TEXT,
  reason TEXT,

  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_warranty_claim_events (
  id TEXT PRIMARY KEY,
  claim_id TEXT NOT NULL,
  event_type TEXT NOT NULL CHECK (event_type IN (
    'opened','triaged','submitted','acknowledged','review_started',
    'approved','denied','disputed','fulfilled','closed',
    'sla_breached','note'
  )),
  from_status TEXT,
  to_status TEXT,
  sla_window TEXT,
  actor_id TEXT,
  notes TEXT,
  payload_json TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_warranty_claims (
  id TEXT PRIMARY KEY,
  claim_number TEXT NOT NULL UNIQUE,
  tenant_id TEXT NOT NULL,
  asset_id TEXT,             -- om_devices.id when traceable
  asset_label TEXT NOT NULL, -- e.g. "Sungrow SG250HX serial SGN-1234"
  oem_id TEXT,               -- vendor/OEM participant id when known
  oem_name TEXT NOT NULL,
  site_id TEXT,              -- om_sites.id
  reported_by TEXT NOT NULL,
  subject TEXT NOT NULL,
  description TEXT,
  severity TEXT NOT NULL CHECK (severity IN ('safety','performance','cosmetic')),
  fault_code TEXT,
  failure_mode TEXT,
  warranty_ref TEXT,         -- OEM warranty contract reference
  rma_number TEXT,           -- OEM-issued RMA after acknowledge
  chain_status TEXT NOT NULL DEFAULT 'opened'
    CHECK (chain_status IN (
      'opened','triaged','submitted','acknowledged','under_review',
      'approved','denied','disputed','fulfilled','closed'
    )),
  -- Stage timestamps
  triaged_at TEXT,
  submitted_at TEXT,
  acknowledged_at TEXT,
  review_started_at TEXT,
  approved_at TEXT,
  denied_at TEXT,
  disputed_at TEXT,
  fulfilled_at TEXT,
  closed_at TEXT,
  -- Actor refs
  triaged_by TEXT,
  submitted_by TEXT,
  approved_by TEXT,
  denied_by TEXT,
  closed_by TEXT,
  -- SLA bookkeeping
  next_sla_due_at TEXT,
  next_sla_window TEXT
    CHECK (next_sla_window IS NULL OR next_sla_window IN ('triage','submit','ack','review','approve','fulfill')),
  last_sla_breach_at TEXT,
  sla_breach_count INTEGER NOT NULL DEFAULT 0,
  -- Resolution
  resolution TEXT,
  denial_reason TEXT,
  dispute_reason TEXT,
  recovery_zar REAL,         -- estimated cost recovery from OEM
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE oe_warranty_recoveries (
  id                            TEXT PRIMARY KEY,
  case_number                   TEXT UNIQUE NOT NULL,

  -- Provenance (the W15 RMA / W16 work order that generated the recoverable cost)
  source_event                  TEXT,
  source_entity_type            TEXT,
  source_entity_id              TEXT,
  source_wave                   TEXT,

  -- Parties (single-party write; functional tagging only)
  claimant_party_id             TEXT NOT NULL,     -- our O&M / asset side
  claimant_party_name           TEXT NOT NULL,
  oem_party_id                  TEXT NOT NULL,     -- the manufacturer / supplier
  oem_party_name                TEXT NOT NULL,
  assessor_party_id             TEXT,              -- independent / joint technical assessor
  assessor_party_name           TEXT,

  -- The defective asset / component
  asset_name                    TEXT,              -- the plant / site
  component_type                TEXT,              -- inverter / turbine / module / transformer / bms / scada
  oem_name                      TEXT,              -- OEM brand
  product_model                 TEXT,              -- model / part number
  serial_or_batch_ref           TEXT,              -- serial or manufacturing-batch reference
  warranty_ref                  TEXT,              -- supply-agreement warranty clause / number
  warranty_expiry               TEXT,              -- warranty expiry date

  -- Defect classification (the W63 signature)
  defect_class                  TEXT NOT NULL CHECK (defect_class IN (
    'isolated','batch','serial','safety','wear_out'
  )),
  defect_description            TEXT,
  failure_mode                  TEXT,
  units_affected                INTEGER,
  fleet_size                    INTEGER,

  -- Recovery economics (ZAR millions)
  repair_cost_zar_m             REAL,
  replacement_cost_zar_m        REAL,
  lost_generation_zar_m         REAL,
  claimed_zar_m                 REAL,              -- amount claimed against the OEM
  recovery_zar_m                REAL NOT NULL,     -- recovery amount (drives tier)
  recovered_zar_m               REAL,              -- amount actually recovered
  recovery_method               TEXT CHECK (recovery_method IS NULL OR recovery_method IN (
    'credit_note','replacement_in_kind','cash','repair_at_oem_cost'
  )),
  recovery_tier                 TEXT NOT NULL CHECK (recovery_tier IN (
    'minor','moderate','material','major','critical'
  )),

  -- Gates
  submitted_flag                INTEGER NOT NULL DEFAULT 0,
  acknowledged_flag             INTEGER NOT NULL DEFAULT 0,
  assessment_complete_flag      INTEGER NOT NULL DEFAULT 0,
  approved_flag                 INTEGER NOT NULL DEFAULT 0,
  dispute_raised                INTEGER NOT NULL DEFAULT 0,
  dispute_resolved              INTEGER NOT NULL DEFAULT 0,
  recovered_flag                INTEGER NOT NULL DEFAULT 0,

  -- Refs
  draft_ref                     TEXT,
  submission_ref                TEXT,
  acknowledgement_ref           TEXT,
  assessment_ref                TEXT,
  approval_ref                  TEXT,
  rejection_ref                 TEXT,
  dispute_ref                   TEXT,
  resolution_ref                TEXT,
  recovery_ref                  TEXT,
  confirmation_ref              TEXT,
  writeoff_ref                  TEXT,
  withdrawal_ref                TEXT,
  regulator_ref                 TEXT,

  -- Narrative
  draft_basis                   TEXT,
  submission_basis              TEXT,
  acknowledgement_basis         TEXT,
  assessment_basis              TEXT,
  approval_basis                TEXT,
  rejection_basis               TEXT,
  dispute_basis                 TEXT,
  resolution_basis              TEXT,
  recovery_basis                TEXT,
  writeoff_basis                TEXT,
  withdrawal_basis              TEXT,
  reason_code                   TEXT,
  notes                         TEXT,

  dispute_round                 INTEGER NOT NULL DEFAULT 0,

  -- State + lifecycle
  chain_status                  TEXT NOT NULL CHECK (chain_status IN (
    'claim_drafted','submitted_to_oem','oem_acknowledged','under_assessment',
    'assessment_complete','approved','disputed','recovery_pending',
    'recovered','rejected','withdrawn','written_off'
  )),
  claim_drafted_at              TEXT NOT NULL,
  submitted_to_oem_at           TEXT,
  oem_acknowledged_at           TEXT,
  under_assessment_at           TEXT,
  assessment_complete_at        TEXT,
  approved_at                   TEXT,
  disputed_at                   TEXT,
  recovery_pending_at           TEXT,
  recovered_at                  TEXT,
  rejected_at                   TEXT,
  withdrawn_at                  TEXT,
  written_off_at                TEXT,

  is_reportable                 INTEGER NOT NULL DEFAULT 0,
  sla_deadline_at               TEXT,
  last_sla_breach_at            TEXT,
  escalation_level              INTEGER NOT NULL DEFAULT 0,

  created_by                    TEXT NOT NULL,
  created_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at                    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

