CREATE TABLE oe_wheeling_agreements (
  id                  TEXT PRIMARY KEY,
  generator_id        TEXT NOT NULL,
  offtaker_id         TEXT NOT NULL,
  injection_point     TEXT NOT NULL,
  withdrawal_point    TEXT NOT NULL,
  contracted_mw       REAL NOT NULL,
  loss_factor_pct     REAL NOT NULL,
  wheeling_tariff_zar_per_mwh REAL NOT NULL,
  status              TEXT NOT NULL DEFAULT 'pending',
                                                  -- pending | approved | active |
                                                  -- terminated | rejected
  approved_by         TEXT,
  approved_at         TEXT,
  effective_from      TEXT,
  effective_to        TEXT,
  notes               TEXT,
  created_at          TEXT NOT NULL DEFAULT (datetime('now'))
, dispute_window_days INTEGER);

CREATE TABLE off_btm_designs (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  site_name       TEXT NOT NULL,
  rooftop_area_m2 REAL,
  proposed_kwp    REAL NOT NULL,
  inverter_kw     REAL,
  bess_kwh        REAL DEFAULT 0,
  expected_yield_kwh_yr REAL,
  capex_zar       REAL,
  estimated_payback_years REAL,
  self_consumption_pct REAL,
  scope2_reduction_tco2e_yr REAL,
  status          TEXT DEFAULT 'design' CHECK (status IN ('feasibility','design','approved','installed','commissioned','decommissioned')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE off_cfe_commitments (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  framework       TEXT NOT NULL,                     
  target_year     INTEGER NOT NULL,
  target_pct      REAL NOT NULL,                     
  pledge_date     TEXT,
  status          TEXT DEFAULT 'active' CHECK (status IN ('committed','active','achieved','off_track','revised','withdrawn')),
  current_pct     REAL,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE off_contract_redlines (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  contract_id     TEXT,
  version_no      TEXT NOT NULL,
  prepared_by     TEXT,
  changes_summary TEXT,
  document_r2_key TEXT,
  status          TEXT DEFAULT 'draft' CHECK (status IN ('draft','sent','received','accepted','rejected','superseded')),
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE off_energy_budgets (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  budget_year     INTEGER NOT NULL,
  category        TEXT NOT NULL,                     
  budget_zar      REAL NOT NULL,
  spent_zar       REAL DEFAULT 0,
  variance_zar    REAL,
  variance_pct    REAL,
  status          TEXT DEFAULT 'open' CHECK (status IN ('open','tracking','overspent','closed')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE off_ppa_portfolio (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  contract_ref    TEXT,
  counterparty_name TEXT NOT NULL,
  technology      TEXT,
  capacity_mw     REAL,
  ppa_term_years  INTEGER,
  ppa_start_date  TEXT,
  ppa_end_date    TEXT,
  price_zar_per_mwh REAL,
  indexation      TEXT,                              
  expected_p50_gwh_yr REAL,
  green_attributes TEXT,
  status          TEXT DEFAULT 'signed' CHECK (status IN ('negotiating','signed','active','expired','terminated')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
, cure_window_days INTEGER, take_or_pay_pct REAL);

CREATE TABLE off_scope2_reports (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  reporting_year  INTEGER NOT NULL,
  total_consumption_mwh REAL NOT NULL,
  location_factor_kg_kwh REAL,                       
  market_factor_kg_kwh REAL,
  location_tco2e  REAL,
  market_tco2e    REAL,
  recs_retired_mwh REAL DEFAULT 0,
  ppa_attributed_mwh REAL DEFAULT 0,
  renewable_pct   REAL,
  cfe_match_pct   REAL,
  status          TEXT DEFAULT 'draft' CHECK (status IN ('draft','published','assured','restated')),
  assured_by      TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now')),
  UNIQUE (participant_id, reporting_year)
);

CREATE TABLE off_tou_optimisations (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  analysis_month  TEXT NOT NULL,                     
  current_tariff_bucket TEXT,                        
  current_zar_per_kwh REAL,
  suggested_bucket TEXT,
  suggested_zar_per_kwh REAL,
  annual_savings_zar REAL,
  load_shift_required_pct REAL,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE offtaker_bills (
      id TEXT PRIMARY KEY,
      offtaker_id TEXT NOT NULL,
      source TEXT,
      meta_json TEXT,
      ai_result_json TEXT,
      created_at TEXT DEFAULT (datetime('now'))
    );

CREATE TABLE offtaker_budgets (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  site_group_id TEXT REFERENCES offtaker_site_groups(id),
  delivery_point_id TEXT REFERENCES offtaker_delivery_points(id),
  period TEXT NOT NULL,             -- '2026-04' or '2026-Q2'
  budgeted_kwh REAL,
  budgeted_zar REAL,
  cost_centre TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE offtaker_delivery_points (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL,
  name TEXT NOT NULL,
  location TEXT,
  meter_id TEXT,
  voltage_kv REAL,
  nmd_kva REAL,
  annual_kwh REAL,
  tariff_category TEXT,
  notes TEXT,
  status TEXT DEFAULT 'active',
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now')),
  FOREIGN KEY (participant_id) REFERENCES participants(id) ON DELETE CASCADE
);

CREATE TABLE offtaker_site_group_members (
  id TEXT PRIMARY KEY,
  group_id TEXT NOT NULL REFERENCES offtaker_site_groups(id) ON DELETE CASCADE,
  delivery_point_id TEXT NOT NULL REFERENCES offtaker_delivery_points(id),
  allocation_percentage REAL DEFAULT 100,
  added_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE (group_id, delivery_point_id)
);

CREATE TABLE offtaker_site_groups (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  group_name TEXT NOT NULL,
  group_type TEXT CHECK (group_type IN ('company','division','brand','region','other')),
  billing_entity TEXT,
  vat_number TEXT,
  consolidated_invoice BOOLEAN DEFAULT 1,
  cost_centre TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE om_alerts (
  id            TEXT PRIMARY KEY,
  rule_id       TEXT,               -- nullable for one-off alerts
  site_id       TEXT,
  device_id     TEXT,
  category      TEXT NOT NULL,      -- fault | sla | covenant | weather | revenue |
                                     -- maintenance | predictive
  severity      TEXT NOT NULL,
  title         TEXT NOT NULL,
  body          TEXT,
  channels      TEXT,               -- JSON ['push','sms','email','whatsapp']
  delivered_at  TEXT,
  acknowledged_at TEXT,
  created_at    TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE om_connections (
  id              TEXT PRIMARY KEY,
  site_id         TEXT NOT NULL,
  adapter         TEXT NOT NULL,      -- huawei | solaredge | sma | sungrow | enphase |
                                       -- fronius | goodwe | victron | deye | modbus |
                                       -- mqtt | csv_sftp | eskom_amr | landis_gyr |
                                       -- itron | cbi | carlo_gavazzi | solcast |
                                       -- open_meteo
  endpoint_url    TEXT,
  credentials_kv  TEXT,               -- KV namespace key (not the secret itself)
  polling_minutes INTEGER NOT NULL DEFAULT 5,
  last_poll_at    TEXT,
  last_status     TEXT,               -- ok | error | stale
  last_error      TEXT,
  enabled         INTEGER NOT NULL DEFAULT 1,
  created_at      TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE om_connector_runs (
  id              TEXT PRIMARY KEY,
  site_id         TEXT NOT NULL,
  source          TEXT NOT NULL,            -- 'api_push' | 'csv_upload' | 'modbus_poll' | 'sungrow_cloud' | …
  ingest_key_id   TEXT,                     -- null for authenticated uploads
  started_at      TEXT NOT NULL DEFAULT (datetime('now')),
  finished_at     TEXT,
  status          TEXT NOT NULL DEFAULT 'running',  -- running | ok | partial | failed
  rows_received   INTEGER NOT NULL DEFAULT 0,
  rows_written    INTEGER NOT NULL DEFAULT 0,
  rows_rejected   INTEGER NOT NULL DEFAULT 0,
  first_ts        TEXT,                     -- min(ts) of accepted rows
  last_ts         TEXT,                     -- max(ts) of accepted rows
  error_sample    TEXT,                     -- first error message if rejected > 0
  metadata        TEXT                      -- JSON: filename, sha256, user_agent, etc.
);

CREATE TABLE om_devices (
  id                    TEXT PRIMARY KEY,
  site_id               TEXT NOT NULL REFERENCES om_sites(id),
  device_type           TEXT NOT NULL,     -- inverter | string | meter |
                                            -- weather | battery | bms | transformer
  manufacturer          TEXT,              -- Huawei, SolarEdge, SMA, ...
  model                 TEXT,
  serial_number         TEXT,
  firmware_version      TEXT,
  installed_at          TEXT,              -- ISO date
  warranty_expiry       TEXT,              -- ISO date
  rated_kw              REAL,
  parent_device_id      TEXT,              -- string under an inverter
  status                TEXT NOT NULL DEFAULT 'online',
                                            -- online | offline | warning | fault
  last_seen_at          TEXT,
  location_in_plant     TEXT,              -- e.g. "Row 3, INV-7"
  created_at            TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE om_faults (
  id                    TEXT PRIMARY KEY,
  site_id               TEXT NOT NULL,
  device_id             TEXT,              -- nullable for site-level faults
  category              TEXT NOT NULL,     -- communication | inverter | string |
                                            -- panel | grid | weather | bos | unknown
  severity              TEXT NOT NULL,     -- critical | major | minor | info
  fault_code            TEXT,              -- OEM code
  description           TEXT,
  detected_at           TEXT NOT NULL,
  resolved_at           TEXT,
  status                TEXT NOT NULL DEFAULT 'open',
                                            -- open | acknowledged | in_progress |
                                            -- resolved | closed | false_positive
  root_cause            TEXT,
  -- Revenue Impact Engine fields
  hourly_loss_zar       REAL DEFAULT 0,    -- current bleed rate
  total_loss_zar        REAL DEFAULT 0,    -- accumulated since detection
  projected_loss_zar    REAL,              -- if unresolved by EOD
  dscr_impact           REAL,              -- change to monthly DSCR (e.g. -0.03)
  warranty_covered      INTEGER DEFAULT 0, -- 0/1 — within warranty period
  fault_history_count   INTEGER DEFAULT 0, -- prior occurrences of same fault on same device
  work_order_id         TEXT,
  weather_correlated    INTEGER DEFAULT 0, -- 1 if cloud / rain event coincided
  grid_correlated       INTEGER DEFAULT 0, -- 1 if grid frequency excursion
  created_at            TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at            TEXT
);

CREATE TABLE om_forecasts (
  id              TEXT PRIMARY KEY,
  site_id         TEXT NOT NULL,
  horizon         TEXT NOT NULL,      -- intraday | day_ahead | week_ahead | month_ahead
  forecast_for_ts TEXT NOT NULL,      -- the timestamp being forecasted
  generated_at    TEXT NOT NULL DEFAULT (datetime('now')),
  mwh_p50         REAL NOT NULL,
  mwh_p10         REAL,
  mwh_p90         REAL,
  revenue_p50_zar REAL,
  model_version   TEXT,
  confidence_pct  REAL
);

CREATE TABLE om_ingest_keys (
  id              TEXT PRIMARY KEY,
  site_id         TEXT NOT NULL,
  label           TEXT NOT NULL,
  token_hash      TEXT NOT NULL UNIQUE,    -- SHA-256 of the raw token, hex
  token_prefix    TEXT NOT NULL,           -- first 8 chars of raw, for UI list
  scope           TEXT NOT NULL DEFAULT 'write_telemetry',  -- write_telemetry | write_faults | full
  created_by      TEXT NOT NULL,
  created_at      TEXT NOT NULL DEFAULT (datetime('now')),
  last_used_at    TEXT,
  use_count       INTEGER NOT NULL DEFAULT 0,
  expires_at      TEXT,
  revoked         INTEGER NOT NULL DEFAULT 0
);

CREATE TABLE om_maintenance (
  id                  TEXT PRIMARY KEY,
  site_id             TEXT NOT NULL,
  device_id           TEXT,
  task_type           TEXT NOT NULL,   -- panel_cleaning | inverter_inspection |
                                        -- string_test | thermal_imaging |
                                        -- switchgear_inspection | transformer_service |
                                        -- vegetation_mgmt | meter_calibration |
                                        -- battery_health | generator_service
  frequency_days      INTEGER,         -- NULL for condition-based
  trigger_condition   TEXT,            -- JSON {metric, op, threshold}
  last_done_at        TEXT,
  next_due_at         TEXT NOT NULL,
  status              TEXT NOT NULL DEFAULT 'scheduled',
                                        -- scheduled | due | overdue | done | snoozed
  estimated_duration_minutes INTEGER,
  required_skill      TEXT,
  parts_required      TEXT,            -- JSON
  auto_create_wo_days INTEGER DEFAULT 7, -- days before due_at to auto-create
  created_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE om_part_movements (
  id          TEXT PRIMARY KEY,
  part_id     TEXT NOT NULL REFERENCES om_parts(id),
  movement    TEXT NOT NULL,          -- issued | received | adjusted | returned
  qty         INTEGER NOT NULL,
  wo_id       TEXT,
  technician_id TEXT,
  reason      TEXT,
  occurred_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE om_parts (
  id              TEXT PRIMARY KEY,
  part_number     TEXT NOT NULL UNIQUE,
  name            TEXT NOT NULL,
  manufacturer    TEXT,
  compatible_with TEXT,                  -- JSON [device_type / model patterns]
  unit_cost_zar   REAL DEFAULT 0,
  preferred_supplier TEXT,
  lead_time_days  INTEGER,
  min_stock_qty   INTEGER DEFAULT 0,
  current_stock   INTEGER NOT NULL DEFAULT 0,
  warehouse_id    TEXT DEFAULT 'main',
  created_at      TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE om_portal_tokens (
  id            TEXT PRIMARY KEY,
  token         TEXT NOT NULL UNIQUE,    -- random opaque token
  audience      TEXT NOT NULL,           -- lender | offtaker | insurer | contractor
  recipient_email TEXT,
  participant_id TEXT,                   -- the recipient's participant_id if known
  scope_site_ids TEXT,                   -- JSON array; NULL = portfolio access
  scope_project_ids TEXT,                -- JSON array
  expires_at    TEXT NOT NULL,
  last_used_at  TEXT,
  use_count     INTEGER NOT NULL DEFAULT 0,
  revoked       INTEGER NOT NULL DEFAULT 0,
  created_by    TEXT,
  created_at    TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE om_predictions (
  id                TEXT PRIMARY KEY,
  site_id           TEXT NOT NULL,
  device_id         TEXT,
  prediction_type   TEXT NOT NULL,    -- inverter_failure | string_degradation |
                                       -- panel_hotspot | battery_degradation |
                                       -- soiling_accumulation | transformer_risk
  confidence        REAL,             -- 0-1
  estimated_failure_at TEXT,
  recommended_action TEXT,
  estimated_loss_zar REAL,
  status            TEXT NOT NULL DEFAULT 'open',
                                        -- open | acted_on | dismissed | confirmed_true |
                                        -- confirmed_false
  generated_at      TEXT NOT NULL DEFAULT (datetime('now')),
  closed_at         TEXT
);

CREATE TABLE om_retention_policy (
  k                   TEXT PRIMARY KEY,
  raw_keep_days       INTEGER NOT NULL DEFAULT 14,    -- om_telemetry
  daily_keep_days     INTEGER NOT NULL DEFAULT 1825,  -- 5 years
  weekly_keep_days    INTEGER NOT NULL DEFAULT 3650,  -- 10 years
  updated_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE om_sites (
  id                    TEXT PRIMARY KEY,
  name                  TEXT NOT NULL,
  participant_id        TEXT,              -- owner (links to participants.id)
  project_id            TEXT,              -- optional link to ipp_projects.id
  technology            TEXT,              -- solar | wind | bess | hybrid
  capacity_mw           REAL NOT NULL DEFAULT 0,
  capacity_kwp          REAL,              -- for solar DC nameplate
  province              TEXT,
  latitude              REAL,
  longitude             REAL,
  commissioning_date    TEXT,              -- ISO date
  ppa_id                TEXT,              -- link to contract_documents.id
  ppa_tariff_zar_mwh    REAL,              -- blended PPA rate for revenue calc
  om_contractor_id      TEXT,              -- participant if outsourced
  lender_id             TEXT,
  status                TEXT NOT NULL DEFAULT 'operational',
                                            -- operational | construction |
                                            -- decommissioned | curtailed
  created_at            TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at            TEXT
, water_tariff_zar_kl REAL, commissioning_status TEXT NOT NULL DEFAULT 'planned', commissioning_due_at TEXT, commissioning_owner_id TEXT, commissioning_started_at TEXT, devices_registered_at TEXT, ingestion_wired_at TEXT, first_telemetry_at TEXT, energised_at TEXT, in_om_at TEXT, commissioning_failed_at TEXT, commissioning_failure_reason TEXT, last_commissioning_sla_breach_at TEXT);

CREATE TABLE om_technicians (
  id                    TEXT PRIMARY KEY,
  participant_id        TEXT,              -- optional link if user-backed
  name                  TEXT NOT NULL,
  phone                 TEXT,
  email                 TEXT,
  skills                TEXT,              -- JSON array of skill tags
  certifications        TEXT,              -- JSON array of certs
  home_base_lat         REAL,
  home_base_lon         REAL,
  current_lat           REAL,
  current_lon           REAL,
  status                TEXT NOT NULL DEFAULT 'available',
                                            -- available | en_route | on_site | off_duty
  active                INTEGER NOT NULL DEFAULT 1,
  contractor_id         TEXT,              -- if works for an O&M contractor
  created_at            TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE om_telemetry (
  id                    TEXT PRIMARY KEY,
  device_id             TEXT NOT NULL REFERENCES om_devices(id),
  site_id               TEXT NOT NULL,
  ts                    TEXT NOT NULL,     -- ISO timestamp UTC, 15-min aligned
  ac_kw                 REAL,
  dc_kw                 REAL,
  yield_kwh             REAL,              -- cumulative day yield
  interval_kwh          REAL,              -- this interval (15min) energy
  voltage_v             REAL,
  current_a             REAL,
  frequency_hz          REAL,
  temperature_c         REAL,
  irradiance_w_m2       REAL,
  status_code           TEXT,              -- OEM-specific status / fault code
  quality               TEXT DEFAULT 'valid',
                                            -- valid | interpolated | estimated |
                                            -- gap | suspect | manual
  created_at            TEXT NOT NULL DEFAULT (datetime('now'))
, flow_lps REAL, pressure_bar REAL, level_m REAL, treated_kl REAL, raw_kl REAL, pump_kw REAL);

CREATE TABLE om_telemetry_daily (
  device_id          TEXT NOT NULL,
  site_id            TEXT NOT NULL,
  day                TEXT NOT NULL,                  -- YYYY-MM-DD
  -- Energy
  kwh                REAL,
  ac_kw_avg          REAL,
  ac_kw_peak         REAL,
  -- Water
  flow_kl            REAL,
  pressure_bar_avg   REAL,
  level_m_end_of_day REAL,
  treated_kl         REAL,
  raw_kl             REAL,
  pump_kwh           REAL,
  -- Counts
  readings_n         INTEGER NOT NULL DEFAULT 0,
  -- Quality
  gap_minutes        INTEGER NOT NULL DEFAULT 0,
  -- Bookkeeping
  rolled_at          TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (device_id, day)
);

CREATE TABLE om_telemetry_weekly (
  site_id           TEXT NOT NULL,
  iso_week          TEXT NOT NULL,                   -- YYYY-WW
  kwh               REAL,
  flow_kl           REAL,
  treated_kl        REAL,
  raw_kl            REAL,
  pump_kwh          REAL,
  capacity_factor   REAL,
  rolled_at         TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (site_id, iso_week)
);

CREATE TABLE om_wo_chain_events (
  id              TEXT PRIMARY KEY,
  wo_id           TEXT NOT NULL,
  event_type      TEXT NOT NULL,         -- assigned | acknowledged | departed | arrived |
                                          -- diagnosed | repair_started | tested | completed |
                                          -- verified | closed | cancelled | sla_breached
  from_status     TEXT,
  to_status       TEXT,
  actor_id        TEXT,
  notes           TEXT,
  payload         TEXT,                  -- JSON
  created_at      TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE om_wo_events (
  id            TEXT PRIMARY KEY,
  wo_id         TEXT NOT NULL REFERENCES om_work_orders(id),
  event_type    TEXT NOT NULL,           -- created | assigned | acknowledged |
                                          -- en_route | on_site | photo | part_used |
                                          -- note | completed | verified | reopened
  actor_id      TEXT,
  payload       TEXT,                    -- JSON
  occurred_at   TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE om_work_orders (
  id                    TEXT PRIMARY KEY,
  wo_number             TEXT NOT NULL UNIQUE,
  site_id               TEXT NOT NULL,
  fault_id              TEXT,
  category              TEXT NOT NULL,     -- corrective | preventive | inspection |
                                            -- cleaning | installation | upgrade
  priority              TEXT NOT NULL,     -- critical | high | medium | low
  status                TEXT NOT NULL DEFAULT 'created',
                                            -- created | assigned | acknowledged |
                                            -- en_route | on_site | diagnosing |
                                            -- repairing | testing | completed |
                                            -- verified | closed | cancelled
  assigned_to           TEXT,              -- om_technicians.id
  contractor_id         TEXT,
  title                 TEXT,
  description           TEXT,
  -- SLA tracking
  sla_response_minutes  INTEGER,           -- target response (e.g. 240 = 4h)
  sla_resolve_hours     INTEGER,           -- target resolution (e.g. 24)
  sla_deadline          TEXT,              -- ISO timestamp
  sla_breached          INTEGER DEFAULT 0,
  -- Lifecycle timestamps
  created_at            TEXT NOT NULL DEFAULT (datetime('now')),
  assigned_at           TEXT,
  acknowledged_at       TEXT,
  en_route_at           TEXT,
  on_site_at            TEXT,
  completed_at          TEXT,
  verified_at           TEXT,
  closed_at             TEXT,
  -- Cost + outcome
  parts_used            TEXT,              -- JSON [{part_id, qty, cost}]
  parts_cost_zar        REAL DEFAULT 0,
  labour_hours          REAL DEFAULT 0,
  labour_cost_zar       REAL DEFAULT 0,
  travel_km             REAL DEFAULT 0,
  total_cost_zar        REAL DEFAULT 0,
  revenue_recovered_zar REAL DEFAULT 0,
  photos                TEXT,              -- JSON array of R2 keys
  resolution_notes      TEXT,
  difficulty_rating     INTEGER,           -- 1-5
  first_time_fix        INTEGER,           -- 1 if fault didn't recur in 7 days
  updated_at            TEXT
, chain_status TEXT NOT NULL DEFAULT 'created', last_sla_breach_at TEXT, escalation_level INTEGER NOT NULL DEFAULT 0);

CREATE TABLE ona_faults (
  id TEXT PRIMARY KEY,
  site_id TEXT NOT NULL REFERENCES ona_sites(id),
  fault_code TEXT,
  fault_description TEXT,
  severity TEXT DEFAULT 'medium' CHECK (severity IN ('low','medium','high','critical')),
  start_time TEXT NOT NULL,
  end_time TEXT,
  duration_minutes INTEGER,
  generation_lost_mwh REAL,
  estimated_revenue_impact REAL,
  status TEXT DEFAULT 'open' CHECK (status IN ('open','investigating','resolved','escalated')),
  resolution TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
, source TEXT DEFAULT 'manual');

CREATE TABLE ona_forecast_summary (
  id TEXT PRIMARY KEY,
  site_id TEXT NOT NULL,
  forecast_day TEXT NOT NULL,          -- YYYY-MM-DD the forecast is FOR
  day_ahead_mwh REAL,
  intra_day_mwh REAL,
  weekly_mwh REAL,
  actual_mwh REAL,
  variance_pct REAL,
  last_updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE (site_id, forecast_day)
);

CREATE TABLE ona_forecasts (
  id TEXT PRIMARY KEY,
  site_id TEXT NOT NULL REFERENCES ona_sites(id),
  forecast_date TEXT NOT NULL,
  forecast_type TEXT NOT NULL CHECK (forecast_type IN ('day_ahead','intra_day','weekly','monthly')),
  generation_mwh REAL,
  availability_percentage REAL,
  confidence_percentage REAL,
  synced_at TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ona_maintenance (
  id TEXT PRIMARY KEY,
  site_id TEXT NOT NULL REFERENCES ona_sites(id),
  maintenance_type TEXT NOT NULL CHECK (maintenance_type IN ('scheduled','unscheduled','inspection','upgrade')),
  start_time TEXT NOT NULL,
  end_time TEXT,
  duration_hours REAL,
  generation_impact_mwh REAL,
  description TEXT,
  status TEXT DEFAULT 'scheduled' CHECK (status IN ('scheduled','in_progress','completed','cancelled')),
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ona_nominations (
  id TEXT PRIMARY KEY,
  site_id TEXT NOT NULL REFERENCES ona_sites(id),
  nomination_date TEXT NOT NULL,
  nominated_mwh REAL,
  available_capacity_mw REAL,
  forecast_mwh REAL,
  actual_mwh REAL,
  variance_mwh REAL,
  status TEXT DEFAULT 'nomination' CHECK (status IN ('nomination','confirmed','actual','disputed')),
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ona_sites (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  site_name TEXT NOT NULL,
  ona_site_id TEXT UNIQUE,
  latitude REAL,
  longitude REAL,
  capacity_mw REAL,
  status TEXT DEFAULT 'active' CHECK (status IN ('active','inactive','maintenance')),
  last_sync_at TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE participant_preferences (
  participant_id TEXT PRIMARY KEY,
  notify_email_contracts INTEGER DEFAULT 1,
  notify_email_settlement INTEGER DEFAULT 1,
  notify_email_covenants INTEGER DEFAULT 1,
  notify_email_lois INTEGER DEFAULT 1,
  notify_in_app INTEGER DEFAULT 1,
  locale TEXT DEFAULT 'en-ZA',
  currency TEXT DEFAULT 'ZAR',
  timezone TEXT DEFAULT 'Africa/Johannesburg',
  date_format TEXT DEFAULT 'YYYY-MM-DD',
  dashboard_layout TEXT,
  updated_at TEXT DEFAULT (datetime('now')),
  FOREIGN KEY (participant_id) REFERENCES participants(id) ON DELETE CASCADE
);

CREATE TABLE "participants" (
  id                       TEXT PRIMARY KEY,
  email                    TEXT UNIQUE NOT NULL,
  password_hash            TEXT NOT NULL,
  name                     TEXT NOT NULL,
  company_name             TEXT,
  role                     TEXT NOT NULL CHECK (role IN (
    'admin','ipp_developer','trader','carbon_fund','offtaker',
    'lender','grid_operator','regulator','support','esco','epc_contractor'
  )),
  status                   TEXT DEFAULT 'pending' CHECK (status IN ('pending','active','suspended','rejected')),
  kyc_status               TEXT DEFAULT 'pending' CHECK (kyc_status IN ('pending','in_review','approved','rejected')),
  bbbee_level              INTEGER CHECK (bbbee_level BETWEEN 1 AND 8),
  subscription_tier        TEXT DEFAULT 'starter' CHECK (subscription_tier IN ('free','starter','professional','enterprise')),
  tenant_id                TEXT DEFAULT 'default',
  email_verified           INTEGER DEFAULT 0,
  otp_code                 TEXT,
  otp_expires_at           TEXT,
  last_login               TEXT,
  onboarding_completed     INTEGER DEFAULT 0,
  created_at               TEXT DEFAULT (datetime('now')),
  updated_at               TEXT DEFAULT (datetime('now')),
  -- columns added by later migrations (377, 378, 472) — preserved here
  phone                    TEXT,
  job_title                TEXT,
  org_website              TEXT,
  org_reg_num              TEXT,
  invited_by               TEXT,
  bio                      TEXT,
  avatar_r2                TEXT,
  onboarding_step          TEXT DEFAULT 'welcome',
  onboarding_data          TEXT DEFAULT '{}',
  onboarding_skipped       INTEGER DEFAULT 0,
  participant_market_access TEXT DEFAULT 'full_trading'
);

CREATE TABLE password_reset_tokens (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id) ON DELETE CASCADE,
  token_hash TEXT NOT NULL UNIQUE,
  expires_at TEXT NOT NULL,
  used_at TEXT,
  requested_ip TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE payments (
  id TEXT PRIMARY KEY,
  invoice_id TEXT NOT NULL REFERENCES invoices(id),
  payment_reference TEXT UNIQUE NOT NULL,
  amount REAL NOT NULL,
  currency TEXT DEFAULT 'ZAR',
  payment_method TEXT CHECK (payment_method IN ('eft','swift','rtgs','internal')),
  payment_date TEXT NOT NULL,
  bank_reference TEXT,
  reconciled INTEGER DEFAULT 0,
  reconciled_by TEXT,
  reconciled_at TEXT,
  notes TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE pcaf_asset_classes (
  code            TEXT PRIMARY KEY,
  name            TEXT NOT NULL,
  category        TEXT NOT NULL,   -- 'lending','investment','insurance'
  guidance_doc    TEXT,
  display_order   INTEGER DEFAULT 0
);

CREATE TABLE pcaf_facilitated_emissions (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL,
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  reporting_year      INTEGER NOT NULL,
  transaction_type    TEXT NOT NULL,                 -- 'equity_underwriting','debt_underwriting','syndicated_loan','green_bond'
  issuer_id           TEXT,
  issuer_name         TEXT,
  facilitation_zar    REAL NOT NULL,                 -- value placed
  issuer_sector       TEXT,
  issuer_evic_zar     REAL,
  issuer_scope1_tco2e REAL,
  issuer_scope2_tco2e REAL,
  issuer_scope3_tco2e REAL,
  weighting_factor    REAL DEFAULT 0.33,             -- PCAF default for facilitated emissions
  facilitated_tco2e   REAL,
  status              TEXT DEFAULT 'recorded',
  notes               TEXT,
  created_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE pcaf_financed_emissions (
  id                          TEXT PRIMARY KEY,
  participant_id              TEXT NOT NULL REFERENCES participants(id),  -- the bank / fund
  tenant_id                   TEXT DEFAULT 'default' NOT NULL,
  reporting_year              INTEGER NOT NULL,
  asset_class                 TEXT NOT NULL REFERENCES pcaf_asset_classes(code),

  -- Counterparty / asset
  counterparty_id             TEXT,                 -- participant if internal
  counterparty_name           TEXT NOT NULL,
  counterparty_country        TEXT,
  counterparty_sector_nace    TEXT,                 -- NACE/GICS sector code
  counterparty_revenue_zar    REAL,
  counterparty_evic_zar       REAL,                 -- enterprise value incl. cash
  property_address            TEXT,                  -- CRE / mortgage
  vehicle_make_model          TEXT,                  -- motor vehicle loans
  project_id                  TEXT,                  -- project finance

  -- Exposure
  outstanding_amount_zar      REAL NOT NULL,
  commitment_amount_zar       REAL,
  fx_rate                     REAL DEFAULT 1.0,
  attribution_method          TEXT DEFAULT 'evic'
                              CHECK (attribution_method IN ('evic','total_equity','property_value','vehicle_value','revenue','asset_value')),

  -- Counterparty emissions
  counterparty_scope1_tco2e   REAL,
  counterparty_scope2_tco2e   REAL,
  counterparty_scope3_tco2e   REAL,
  emissions_data_source       TEXT,                 -- 'CDP','reported','proxy','sector_average'
  pcaf_data_quality_score     INTEGER CHECK (pcaf_data_quality_score BETWEEN 1 AND 5),

  -- Computed (stored for audit re-creation)
  attribution_factor          REAL,                 -- outstanding / EVIC etc.
  financed_scope1_tco2e       REAL,
  financed_scope2_tco2e       REAL,
  financed_scope3_tco2e       REAL,
  financed_total_tco2e        REAL,
  emission_intensity          REAL,                 -- tCO2e per ZAR financed

  -- Lifecycle
  status                      TEXT DEFAULT 'recorded'
                              CHECK (status IN ('draft','recorded','assured','restated','retired')),
  notes                       TEXT,
  evidence_r2_key             TEXT,
  computed_at                 TEXT DEFAULT (datetime('now')),
  created_at                  TEXT DEFAULT (datetime('now'))
);

CREATE TABLE pcaf_insurance_emissions (
  id                            TEXT PRIMARY KEY,
  participant_id                TEXT NOT NULL REFERENCES participants(id),
  tenant_id                     TEXT DEFAULT 'default' NOT NULL,
  reporting_year                INTEGER NOT NULL,
  -- Insurance line of business per PCAF Part C
  line_of_business              TEXT NOT NULL CHECK (line_of_business IN (
                                  'commercial_lines','personal_motor','commercial_motor',
                                  'property','marine','aviation','energy','agriculture',
                                  'health','life','reinsurance'
                                )),
  -- Insured counterparty / asset
  insured_name                  TEXT NOT NULL,
  insured_country               TEXT,
  insured_sector_nace           TEXT,
  policy_reference              TEXT,
  premium_zar                   REAL NOT NULL,
  -- Attribution: PCAF Part C uses gross-written-premium / total-customer-revenue
  attribution_method            TEXT DEFAULT 'premium_to_revenue'
                                CHECK (attribution_method IN (
                                  'premium_to_revenue','premium_to_revenue_minus_claims',
                                  'activity_based','asset_value'
                                )),
  insured_revenue_zar           REAL,
  insured_scope1_tco2e          REAL,
  insured_scope2_tco2e          REAL,
  insured_scope3_tco2e          REAL,
  emissions_data_source         TEXT,
  pcaf_data_quality_score       INTEGER CHECK (pcaf_data_quality_score BETWEEN 1 AND 5),
  attribution_factor            REAL,
  insurance_associated_tco2e    REAL,
  status                        TEXT DEFAULT 'recorded'
                                CHECK (status IN ('draft','recorded','assured','restated','retired')),
  notes                         TEXT,
  created_at                    TEXT DEFAULT (datetime('now'))
);

CREATE TABLE pcaf_targets (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  framework       TEXT NOT NULL,                    -- 'NZBA','SBTi_FI','GFANZ'
  scope           TEXT NOT NULL,                    -- 'portfolio_wide','sector','asset_class'
  sector          TEXT,                              -- e.g. 'power','oil_gas','steel','aluminum','cement','aviation','shipping','real_estate'
  asset_class     TEXT,
  base_year       INTEGER NOT NULL,
  base_intensity  REAL,                              -- kgCO2e/MWh, kgCO2e/tonne, etc.
  target_year     INTEGER NOT NULL,
  target_intensity REAL,
  pathway_alignment TEXT,                            -- 'IEA NZE 2050','SDA','1.5C','well-below-2C'
  status          TEXT DEFAULT 'committed' CHECK (status IN ('committed','approved','on_track','off_track','revised','retired')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE permanence_monitoring (
  id              TEXT PRIMARY KEY,
  project_id      TEXT NOT NULL REFERENCES cdr_projects(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  observation_date TEXT NOT NULL,
  reporting_year  INTEGER NOT NULL,
  stored_tco2e    REAL NOT NULL,
  reversal_tco2e  REAL DEFAULT 0,
  reversal_cause  TEXT,                              -- 'fire','disease','natural','intentional','measurement_revision'
  monitoring_method TEXT,                            -- 'satellite','field_survey','sensors','self_reported'
  attestation     TEXT,
  evidence_r2_key TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE pipeline_activities (
  id TEXT PRIMARY KEY,
  deal_id TEXT NOT NULL REFERENCES pipeline_deals(id),
  activity_type TEXT NOT NULL,
  description TEXT,
  due_date TEXT,
  completed INTEGER DEFAULT 0,
  completed_at TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE pipeline_deals (
  id TEXT PRIMARY KEY,
  deal_name TEXT NOT NULL,
  client_participant_id TEXT NOT NULL REFERENCES participants(id),
  deal_type TEXT,
  estimated_value REAL,
  currency TEXT DEFAULT 'ZAR',
  probability_percentage INTEGER,
  stage TEXT DEFAULT 'identification' CHECK (stage IN ('identification','qualification','proposal','negotiation','contracting','closed')),
  status TEXT DEFAULT 'active' CHECK (status IN ('active','won','lost','cancelled')),
  submission_deadline TEXT,
  award_date TEXT,
  contract_value REAL,
  created_by TEXT NOT NULL REFERENCES participants(id),
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE platform_ai_logs (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL,
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  domain              TEXT NOT NULL CHECK (domain IN (
                        'esg','trade','contract','license','grid_alarm','ipp_milestone',
                        'invoice','counterparty','market_surveillance','generic'
                      )),
  input_text          TEXT NOT NULL,
  input_metadata_json TEXT,
  model_id            TEXT,
  output_label        TEXT,
  output_categories_json TEXT,
  confidence          REAL,
  reasoning           TEXT,
  user_accepted       INTEGER DEFAULT 0,
  user_override       TEXT,
  resolved_at         TEXT,
  created_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE platform_anomaly_flags (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL,
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  domain              TEXT NOT NULL CHECK (domain IN (
                        'trading','invoice','contract','grid_telemetry','metering',
                        'license_application','counterparty','ipp_milestone','esg'
                      )),
  entity_table        TEXT,                          -- which table the anomaly refers to
  entity_id           TEXT,                          -- record id (not FK to allow cross-module)
  rule                TEXT NOT NULL,                 -- 'price_spike','wash_trade','duplicate_invoice','factor_mismatch','telemetry_dropout','milestone_slip',…
  severity            TEXT DEFAULT 'medium' CHECK (severity IN ('low','medium','high','critical')),
  detail              TEXT,
  expected_value      REAL,
  observed_value      REAL,
  status              TEXT DEFAULT 'open' CHECK (status IN ('open','investigating','dismissed','resolved')),
  detected_at         TEXT DEFAULT (datetime('now')),
  resolved_at         TEXT,
  resolved_by         TEXT
);

CREATE TABLE platform_modules (
  participant_id TEXT NOT NULL REFERENCES participants(id),
  module_id TEXT NOT NULL,
  enabled INTEGER DEFAULT 1,
  granted_by TEXT REFERENCES participants(id),
  updated_at TEXT DEFAULT (datetime('now')),
  PRIMARY KEY (participant_id, module_id)
);

CREATE TABLE platform_scenario_runs (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL REFERENCES participants(id),
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  scenario_code       TEXT NOT NULL REFERENCES platform_scenarios(code),
  domain              TEXT NOT NULL,
  horizon_unit        TEXT NOT NULL CHECK (horizon_unit IN ('day','week','month','quarter','year')),
  horizon_value       INTEGER NOT NULL,
  -- Result metrics (domain-specific; nullable as appropriate)
  base_value_zar      REAL,
  shocked_value_zar   REAL,
  value_at_risk_zar   REAL,                          -- |shocked - base|
  pct_change          REAL,
  worst_entity        TEXT,                          -- worst-impacted contract / counterparty / project
  worst_entity_var_zar REAL,
  details_json        TEXT,                          -- per-row impact array
  status              TEXT DEFAULT 'complete' CHECK (status IN ('queued','running','complete','failed')),
  computed_at         TEXT DEFAULT (datetime('now')),
  notes               TEXT
);

CREATE TABLE platform_scenarios (
  code            TEXT PRIMARY KEY,
  domain          TEXT NOT NULL CHECK (domain IN (
                    'trading','grid','ipp_project','regulator_tariff',
                    'lender_credit','offtaker_demand','climate'
                  )),
  family          TEXT NOT NULL,                     -- 'price_shock','outage','irr_sensitivity','tariff_path'…
  name            TEXT NOT NULL,
  description     TEXT,
  parameters_json TEXT,                              -- default JSON parameter set
  severity        TEXT CHECK (severity IN ('mild','moderate','severe','extreme')),
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE popia_breaches (
  id TEXT PRIMARY KEY,
  discovered_at TEXT NOT NULL,
  reported_by TEXT REFERENCES participants(id),
  severity TEXT NOT NULL DEFAULT 'low' CHECK (severity IN ('low','medium','high','critical')),
  category TEXT NOT NULL, -- e.g. 'unauthorised_access', 'data_loss', 'malware', 'misdelivery', 'other'
  description TEXT NOT NULL,
  affected_subjects_count INTEGER DEFAULT 0,
  affected_data_categories TEXT, -- JSON array
  containment_actions TEXT,
  regulator_notified_at TEXT,
  subjects_notified_at TEXT,
  status TEXT NOT NULL DEFAULT 'open' CHECK (status IN ('open','contained','closed')),
  root_cause TEXT,
  lessons_learned TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE popia_consent_records (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  consent_type TEXT NOT NULL,
  granted INTEGER DEFAULT 1,
  consent_date TEXT,
  withdrawal_date TEXT,
  ip_address TEXT,
  user_agent TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE popia_consents (
  participant_id TEXT PRIMARY KEY REFERENCES participants(id),
  marketing INTEGER DEFAULT 0,
  data_sharing INTEGER DEFAULT 0,
  third_party INTEGER DEFAULT 0,
  analytics INTEGER DEFAULT 1,
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE popia_corrections (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  field_name TEXT NOT NULL,
  current_value TEXT,
  requested_value TEXT NOT NULL,
  reason TEXT,
  status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','applied','rejected','withdrawn')),
  processed_by TEXT REFERENCES participants(id),
  processed_at TEXT,
  resolution_notes TEXT,
  requested_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE popia_data_requests (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  request_type TEXT NOT NULL CHECK (request_type IN ('export','correction','erasure','objection','consent')),
  status TEXT DEFAULT 'pending' CHECK (status IN ('pending','processing','completed','rejected')),
  data_export_key TEXT,
  processed_at TEXT,
  processed_by TEXT,
  notes TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE popia_dsar_requests (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  scope TEXT,
  status TEXT DEFAULT 'pending' CHECK (status IN ('pending','in_review','completed','rejected')),
  export_r2_key TEXT,
  processed_by TEXT REFERENCES participants(id),
  processed_at TEXT,
  requested_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE popia_erasure_requests (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  reason TEXT,
  status TEXT DEFAULT 'pending' CHECK (status IN ('pending','in_review','completed','rejected')),
  processed_by TEXT REFERENCES participants(id),
  processed_at TEXT,
  resolution_notes TEXT,
  requested_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE popia_objections (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  processing_purpose TEXT NOT NULL,
  grounds TEXT,
  status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','upheld','rejected','withdrawn')),
  processed_by TEXT REFERENCES participants(id),
  processed_at TEXT,
  resolution_notes TEXT,
  requested_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE popia_pii_access_log (
  id TEXT PRIMARY KEY,
  actor_id TEXT NOT NULL REFERENCES participants(id),
  subject_id TEXT NOT NULL REFERENCES participants(id),
  access_type TEXT NOT NULL, -- 'dsar_export', 'impersonation', 'admin_view', 'support_view'
  justification TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE portfolio_temperature_alignment (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  reporting_year  INTEGER NOT NULL,
  sector          TEXT,                              -- 'power','oil_gas',… or 'portfolio'
  methodology     TEXT,                              -- 'SDA','GEVA','PACTA'
  temperature_c   REAL NOT NULL,                     -- implied temperature rise (°C)
  pathway         TEXT,                              -- 'IEA NZE','PRIMAP',…
  computed_at     TEXT DEFAULT (datetime('now')),
  notes           TEXT
);

CREATE TABLE ppa_marketplace_listings (
  id              TEXT PRIMARY KEY,
  seller_id       TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  listing_type    TEXT NOT NULL CHECK (listing_type IN ('sell','buy')),
  technology      TEXT NOT NULL,                     -- 'solar','wind','hybrid','bess','gas'
  capacity_mw     REAL NOT NULL,
  expected_p50_gwh_yr REAL,
  ppa_term_years  INTEGER NOT NULL,
  price_zar_per_mwh REAL,
  price_floor_zar REAL,
  price_ceiling_zar REAL,
  delivery_point  TEXT,
  delivery_grid_zone TEXT,
  start_date      TEXT,
  green_attributes TEXT,                             -- 'rec_bundled','rec_stripped','24_7_cfe'
  status          TEXT DEFAULT 'listed' CHECK (status IN ('listed','negotiating','signed','withdrawn','expired')),
  description     TEXT,
  evidence_r2_key TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE ppa_marketplace_offers (
  id              TEXT PRIMARY KEY,
  listing_id      TEXT NOT NULL REFERENCES ppa_marketplace_listings(id),
  bidder_id       TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  offered_price_zar_per_mwh REAL NOT NULL,
  offered_volume_gwh_yr REAL NOT NULL,
  offered_term_years INTEGER,
  conditions      TEXT,
  status          TEXT DEFAULT 'submitted' CHECK (status IN ('submitted','shortlisted','accepted','rejected','withdrawn')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE pre_trade_checks (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  intent_type     TEXT NOT NULL CHECK (intent_type IN ('order','block_bid','intraday','rec','carbon')),
  intent_payload  TEXT NOT NULL,                     -- JSON of proposed order
  outcome         TEXT NOT NULL CHECK (outcome IN ('allow','block','warn')),
  failed_checks   TEXT,                              -- JSON list of breached checks
  credit_used_pre REAL,
  credit_used_post REAL,
  credit_limit    REAL,
  checked_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE procurement_awards (
  id TEXT PRIMARY KEY,
  rfp_id TEXT NOT NULL REFERENCES procurement_rfps(id),
  winning_bid_id TEXT NOT NULL REFERENCES procurement_bids(id),
  award_value REAL,
  currency TEXT DEFAULT 'ZAR',
  contract_id TEXT,
  awarded_at TEXT,
  awarded_by TEXT NOT NULL REFERENCES participants(id),
  notes TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE procurement_bids (
  id TEXT PRIMARY KEY,
  rfp_id TEXT NOT NULL REFERENCES procurement_rfps(id),
  participant_id TEXT NOT NULL REFERENCES participants(id),
  technical_proposal_key TEXT,
  commercial_proposal_key TEXT,
  bid_amount REAL,
  currency TEXT DEFAULT 'ZAR',
  score REAL,
  rank INTEGER,
  status TEXT DEFAULT 'submitted' CHECK (status IN ('submitted','under_review','shortlisted','awarded','rejected')),
  submitted_at TEXT,
  created_at TEXT DEFAULT (datetime('now'))
, technical_score REAL, sustainability_score REAL, delivery_score REAL, overall_score REAL);

CREATE TABLE procurement_rfps (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  description TEXT,
  rfp_reference TEXT UNIQUE,
  created_by TEXT NOT NULL REFERENCES participants(id),
  closing_date TEXT,
  evaluation_date TEXT,
  budget REAL,
  currency TEXT DEFAULT 'ZAR',
  status TEXT DEFAULT 'draft' CHECK (status IN ('draft','published','evaluation','awarded','cancelled')),
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE product_carbon_footprints (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL,
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  product_code        TEXT NOT NULL,
  product_name        TEXT NOT NULL,
  functional_unit     TEXT NOT NULL,                -- '1 kg cement', '1 MWh electricity', '1 unit'
  reporting_year      INTEGER NOT NULL,
  methodology         TEXT,                          -- 'ISO 14067','PEFCR','PAS 2050','custom'
  -- Cradle-to-gate emissions split (modular per ISO 14067)
  upstream_tco2e_per_unit    REAL DEFAULT 0,
  manufacturing_tco2e_per_unit REAL DEFAULT 0,
  distribution_tco2e_per_unit REAL DEFAULT 0,
  use_phase_tco2e_per_unit   REAL DEFAULT 0,
  end_of_life_tco2e_per_unit REAL DEFAULT 0,
  total_tco2e_per_unit       REAL DEFAULT 0,
  units_sold                 REAL,
  total_lifecycle_tco2e      REAL,
  data_quality_score         REAL,                   -- 0..100
  assurance_status           TEXT,
  evidence_r2_key            TEXT,
  notes                      TEXT,
  created_at                 TEXT DEFAULT (datetime('now')),
  UNIQUE (participant_id, product_code, reporting_year)
);

CREATE TABLE project_activities (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL,
  parent_id TEXT,
  wbs_code TEXT NOT NULL,
  sort_order INTEGER NOT NULL,
  name TEXT NOT NULL,
  type TEXT NOT NULL CHECK (type IN ('summary','task','milestone')),
  duration_days REAL NOT NULL DEFAULT 0,
  planned_start TEXT,
  planned_finish TEXT,
  early_start TEXT,
  early_finish TEXT,
  late_start TEXT,
  late_finish TEXT,
  total_float REAL,
  free_float REAL,
  is_critical INTEGER DEFAULT 0,
  actual_start TEXT,
  actual_finish TEXT,
  percent_complete REAL DEFAULT 0,
  constraint_type TEXT CHECK (constraint_type IN ('ASAP','SNET','FNLT','MSO','MFO')),
  constraint_date TEXT,
  calendar_id TEXT,
  notes TEXT,
  version INTEGER NOT NULL DEFAULT 1,
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL,
  UNIQUE(project_id, wbs_code)
);

CREATE TABLE project_baselines (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL,
  name TEXT NOT NULL,
  is_current INTEGER NOT NULL DEFAULT 0,
  saved_by TEXT NOT NULL,
  saved_at TEXT NOT NULL,
  notes TEXT,
  UNIQUE(project_id, name)
);

CREATE TABLE project_calendars (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL,
  name TEXT NOT NULL,
  is_default INTEGER NOT NULL DEFAULT 0,
  workdays TEXT NOT NULL,                 -- JSON
  created_at TEXT NOT NULL
);

CREATE TABLE project_cp_readiness (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  cp_name TEXT NOT NULL,
  target_date TEXT NOT NULL,
  days_until_date INTEGER,
  status TEXT DEFAULT 'not_ready' CHECK (status IN ('not_ready','at_risk','on_track','achieved','waived')),
  readiness_notes TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE project_disbursements (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  disbursement_number TEXT UNIQUE NOT NULL,
  tranche TEXT NOT NULL,
  requested_amount REAL NOT NULL,
  approved_amount REAL,
  currency TEXT DEFAULT 'ZAR',
  status TEXT DEFAULT 'requested' CHECK (status IN ('requested','ie_review','ie_approved','lender_review','lender_approved','disbursed','cancelled')),
  requested_by TEXT NOT NULL REFERENCES participants(id),
  requested_at TEXT DEFAULT (datetime('now')),
  ie_reviewer_id TEXT,
  ie_reviewed_at TEXT,
  ie_approved INTEGER DEFAULT 0,
  lender_reviewer_id TEXT,
  lender_reviewed_at TEXT,
  lender_approved INTEGER DEFAULT 0,
  disbursed_at TEXT,
  bank_reference TEXT,
  notes TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE project_financials (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  equity_percentage REAL,
  debt_amount REAL,
  interest_rate REAL,
  tenor_years INTEGER,
  dsra_percentage REAL,
  projected_irr REAL,
  npv_usd REAL,
  debt_service_coverage_ratio REAL,
  loan_life_coverage_ratio REAL,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE project_generation (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  period_start TEXT NOT NULL,
  period_end TEXT NOT NULL,
  availability_percentage REAL,
  capacity_factor_percentage REAL,
  generation_mwh REAL,
  availability_adjustment REAL,
  efficiency_adjustment REAL,
  penalty_amount REAL,
  bonus_amount REAL,
  net_payment_due REAL,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE project_milestones (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  milestone_name TEXT NOT NULL,
  milestone_type TEXT NOT NULL CHECK (milestone_type IN ('financial_close','construction_start','construction_complete','commissioning','cod','operational','termination')),
  order_index INTEGER NOT NULL,
  target_date TEXT NOT NULL,
  satisfied_date TEXT,
  evidence_keys TEXT,
  status TEXT DEFAULT 'pending' CHECK (status IN ('pending','satisfied','waived','failed')),
  notes TEXT,
  created_at TEXT DEFAULT (datetime('now'))
, linked_activity_id TEXT);

CREATE TABLE project_resources (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL,
  name TEXT NOT NULL,
  resource_type TEXT NOT NULL CHECK (resource_type IN ('labor','equipment','material')),
  unit TEXT,
  max_units REAL NOT NULL DEFAULT 1,
  rate_per_unit REAL,
  calendar_id TEXT,
  created_at TEXT NOT NULL
);

CREATE TABLE project_schedule_state (
  project_id TEXT PRIMARY KEY,
  version INTEGER NOT NULL DEFAULT 1,
  status_date TEXT,
  last_computed_at TEXT,
  total_duration_days REAL,
  start_date TEXT,
  finish_date TEXT,
  has_cycles INTEGER DEFAULT 0
);

CREATE TABLE public_comments (
  id              TEXT PRIMARY KEY,
  consultation_id TEXT NOT NULL REFERENCES public_consultations(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  commenter_name  TEXT NOT NULL,
  commenter_org   TEXT,
  commenter_email TEXT,
  is_anonymous    INTEGER DEFAULT 0,
  comment_text    TEXT,
  attachment_r2_key TEXT,
  category        TEXT,                              -- 'oppose','support','technical','clarification'
  consolidated_into TEXT,                            -- a determination id if folded
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE public_consultations (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  consultation_ref TEXT NOT NULL UNIQUE,
  title           TEXT NOT NULL,
  scope           TEXT,                              -- 'tariff','licence','code','rule','policy'
  reference_doc_r2_key TEXT,
  opened_at       TEXT NOT NULL,
  closed_at       TEXT,
  status          TEXT DEFAULT 'open' CHECK (status IN ('draft','open','closed','consolidated','published')),
  written_comments_count INTEGER DEFAULT 0,
  hearings_held   INTEGER DEFAULT 0,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE public_hearings (
  id              TEXT PRIMARY KEY,
  consultation_id TEXT REFERENCES public_consultations(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  hearing_date    TEXT NOT NULL,
  venue           TEXT,
  panel_chair     TEXT,
  status          TEXT DEFAULT 'scheduled' CHECK (status IN ('scheduled','held','postponed','cancelled')),
  transcript_r2_key TEXT,
  attendee_count  INTEGER,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE rbac_invitations (
  id              TEXT PRIMARY KEY,
  token           TEXT UNIQUE NOT NULL,
  invited_by      TEXT NOT NULL REFERENCES participants(id),
  email           TEXT,                 -- pre-fill email on registration form; null = open link
  role            TEXT NOT NULL,        -- role the invitee will get on acceptance
  organization    TEXT,
  note            TEXT,
  status          TEXT NOT NULL DEFAULT 'pending'
                  CHECK (status IN ('pending','accepted','expired','revoked')),
  expires_at      TEXT NOT NULL,
  accepted_by     TEXT REFERENCES participants(id),
  accepted_at     TEXT,
  created_at      TEXT NOT NULL DEFAULT (datetime('now'))
, project_id TEXT, deal_terms TEXT);

CREATE TABLE rbac_permissions (
  key          TEXT PRIMARY KEY,   -- e.g. 'trading.write'
  domain       TEXT NOT NULL,      -- trading | settlement | carbon | ipp | lender | offtaker | grid | regulator | esums | documents | audit | users
  action       TEXT NOT NULL,      -- read | write | approve | export | invite
  display_name TEXT NOT NULL,
  description  TEXT
);

CREATE TABLE rbac_registrations (
  id              TEXT PRIMARY KEY,
  email           TEXT UNIQUE NOT NULL,
  password_hash   TEXT NOT NULL,
  full_name       TEXT NOT NULL,
  company_name    TEXT,
  requested_role  TEXT NOT NULL,
  organization_type TEXT,
  reg_number      TEXT,   -- company/CIPC reg number
  phone           TEXT,
  motivation      TEXT,   -- why they need this role
  status          TEXT NOT NULL DEFAULT 'pending'
                  CHECK (status IN ('pending','approved','rejected','converted')),
  reviewed_by     TEXT REFERENCES participants(id),
  reviewed_at     TEXT,
  rejection_reason TEXT,
  invitation_id   TEXT REFERENCES rbac_invitations(id),
  created_at      TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE rbac_role_permissions (
  role           TEXT NOT NULL,
  permission_key TEXT NOT NULL REFERENCES rbac_permissions(key),
  PRIMARY KEY (role, permission_key)
);

CREATE TABLE rec_certificates (
  id TEXT PRIMARY KEY,
  certificate_serial TEXT UNIQUE NOT NULL,
  generator_participant_id TEXT REFERENCES participants(id),
  project_id TEXT REFERENCES ipp_projects(id),
  generation_period_start TEXT NOT NULL,
  generation_period_end TEXT NOT NULL,
  mwh_represented REAL NOT NULL,
  technology TEXT,
  registry TEXT,                    -- 'I-REC','SAREC','TIGRs','custom'
  issuance_date TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'issued' CHECK (status IN ('issued','transferred','retired','cancelled')),
  owner_participant_id TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE rec_hourly_listings (
  id                  TEXT PRIMARY KEY,
  seller_id           TEXT NOT NULL REFERENCES participants(id),
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  technology          TEXT NOT NULL CHECK (technology IN ('solar','wind','hydro','nuclear','geothermal','battery')),
  grid_zone           TEXT NOT NULL,
  hour_utc            TEXT NOT NULL,                  -- ISO hour-truncated UTC
  available_kwh       REAL NOT NULL,
  remaining_kwh       REAL NOT NULL,
  price_zar_per_kwh   REAL NOT NULL,
  certificate_ref     TEXT,                            -- IRECs / GO / equivalent serial
  status              TEXT DEFAULT 'listed'
                       CHECK (status IN ('listed','partial','sold_out','withdrawn')),
  created_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE rec_hourly_trades (
  id                  TEXT PRIMARY KEY,
  listing_id          TEXT NOT NULL REFERENCES rec_hourly_listings(id),
  buyer_id            TEXT NOT NULL REFERENCES participants(id),
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  kwh                 REAL NOT NULL,
  price_zar_per_kwh   REAL NOT NULL,
  total_zar           REAL NOT NULL,
  hour_utc            TEXT NOT NULL,
  retired_at          TEXT,                            -- non-null once retired against a load hour
  retirement_purpose  TEXT,                            -- '24/7 CFE matching','annual scope 2','voluntary'
  created_at          TEXT DEFAULT (datetime('now'))
);

CREATE TABLE rec_retirements (
  id TEXT PRIMARY KEY,
  rec_certificate_id TEXT NOT NULL REFERENCES rec_certificates(id),
  retiring_participant_id TEXT NOT NULL REFERENCES participants(id),
  retirement_purpose TEXT NOT NULL CHECK (retirement_purpose IN (
    'scope_2','voluntary','compliance','customer_claim','greenhouse_trade'
  )),
  consumption_period_start TEXT,
  consumption_period_end TEXT,
  consumption_site_group_id TEXT REFERENCES offtaker_site_groups(id),
  consumption_mwh REAL,             -- how much consumption this cert is matched to
  beneficiary_name TEXT,
  beneficiary_statement TEXT,       -- text for public / scope 2 disclosure
  retirement_certificate_number TEXT UNIQUE NOT NULL,
  retired_at TEXT NOT NULL DEFAULT (datetime('now')),
  created_by TEXT REFERENCES participants(id)
);

CREATE TABLE reg_annual_reports (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  reporting_year  INTEGER NOT NULL UNIQUE,
  total_licensees INTEGER,
  licences_granted INTEGER DEFAULT 0,
  licences_refused INTEGER DEFAULT 0,
  determinations_issued INTEGER DEFAULT 0,
  consultations_completed INTEGER DEFAULT 0,
  complaints_received INTEGER DEFAULT 0,
  complaints_resolved INTEGER DEFAULT 0,
  inspections_conducted INTEGER DEFAULT 0,
  enforcement_actions INTEGER DEFAULT 0,
  document_r2_key TEXT,
  status          TEXT DEFAULT 'draft' CHECK (status IN ('draft','reviewed','published','tabled')),
  published_at    TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE reg_complaints (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  complaint_ref   TEXT NOT NULL UNIQUE,
  complainant_name TEXT NOT NULL,
  complainant_contact TEXT,
  against_licensee TEXT NOT NULL,
  category        TEXT,                              
  description     TEXT,
  received_at     TEXT NOT NULL,
  acknowledged_at TEXT,
  assigned_to     TEXT,
  resolution_due  TEXT,
  resolved_at     TEXT,
  outcome         TEXT,
  status          TEXT DEFAULT 'open' CHECK (status IN ('open','acknowledged','investigating','resolved','escalated','withdrawn')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE reg_compliance_monitoring (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  licensee_id     TEXT,
  licensee_name   TEXT NOT NULL,
  monitoring_period TEXT NOT NULL,
  obligation_summary TEXT,
  compliance_score REAL,                              
  open_findings_count INTEGER DEFAULT 0,
  enforcement_actions_count INTEGER DEFAULT 0,
  risk_rating     TEXT CHECK (risk_rating IN ('low','medium','high','very_high')),
  last_reviewed_at TEXT,
  next_review_due TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE reg_inspections (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  licensee_id     TEXT,
  licensee_name   TEXT NOT NULL,
  inspection_type TEXT NOT NULL CHECK (inspection_type IN ('routine','triggered','post_incident','complaint_driven','random')),
  inspector_name  TEXT,
  scheduled_at    TEXT,
  conducted_at    TEXT,
  scope           TEXT,
  findings        TEXT,                              
  outcome         TEXT CHECK (outcome IN ('compliant','non_compliant_minor','non_compliant_material','enforcement_referral')),
  follow_up_due   TEXT,
  status          TEXT DEFAULT 'scheduled' CHECK (status IN ('scheduled','conducted','reporting','closed','cancelled')),
  report_r2_key   TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE reg_licence_applications (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  application_ref TEXT NOT NULL UNIQUE,
  applicant_id    TEXT,
  applicant_name  TEXT NOT NULL,
  licence_category TEXT NOT NULL,                    
  capacity_mw     REAL,
  technology      TEXT,
  jurisdiction    TEXT,
  filed_at        TEXT NOT NULL,
  completeness_check_outcome TEXT,
  technical_evaluator TEXT,
  financial_evaluator TEXT,
  public_consultation_id TEXT,
  panel_decision_at TEXT,
  outcome         TEXT CHECK (outcome IN ('pending','granted','granted_with_conditions','refused','withdrawn')),
  conditions      TEXT,
  determination_id TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE reg_public_register (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  entry_type      TEXT NOT NULL CHECK (entry_type IN ('licensee','generator','distributor','trader','reseller','exempt_generator')),
  legal_name      TEXT NOT NULL,
  trading_name    TEXT,
  registration_no TEXT,
  jurisdiction    TEXT,
  licence_no      TEXT,
  capacity_mw     REAL,
  technology      TEXT,
  status          TEXT DEFAULT 'active' CHECK (status IN ('active','suspended','revoked','expired','dormant')),
  effective_from  TEXT,
  effective_to    TEXT,
  public_address  TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE reg_tariff_applications (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  application_ref TEXT NOT NULL UNIQUE,
  applicant_id    TEXT,
  applicant_name  TEXT NOT NULL,
  tariff_year     INTEGER NOT NULL,
  requested_increase_pct REAL NOT NULL,
  approved_increase_pct REAL,
  multi_year_path TEXT,                              
  hearing_id      TEXT,
  determination_id TEXT,
  status          TEXT DEFAULT 'filed' CHECK (status IN ('filed','consultation','hearing','determined','appealed','withdrawn')),
  decision_date   TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE regulator_case_assignments (
  id TEXT PRIMARY KEY,
  subject_type TEXT NOT NULL CHECK (subject_type IN (
    'licence','tariff_submission','enforcement_case','surveillance_alert'
  )),
  subject_id TEXT NOT NULL,
  assignee_id TEXT NOT NULL REFERENCES participants(id),
  assigned_by TEXT NOT NULL REFERENCES participants(id),
  assigned_at TEXT NOT NULL DEFAULT (datetime('now')),
  role TEXT DEFAULT 'lead',             -- 'lead','reviewer','observer'
  notes TEXT
);

CREATE TABLE regulator_determinations (
  id TEXT PRIMARY KEY,
  reference_number TEXT UNIQUE NOT NULL,
  title TEXT NOT NULL,
  category TEXT NOT NULL CHECK (category IN (
    'tariff','licence','rule','notice','enforcement','code_of_conduct','methodology'
  )),
  statutory_basis TEXT,                 -- e.g. 'ERA 2006 s.4'
  summary TEXT,
  body_md TEXT,
  publication_date TEXT NOT NULL,
  gazette_reference TEXT,
  document_r2_key TEXT,
  published_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE regulator_enforcement_case_events (
  id              TEXT PRIMARY KEY,
  case_id         TEXT NOT NULL,
  event_type      TEXT NOT NULL CHECK (event_type IN (
    'opened','evidence_filed','hearing_scheduled','hearing_held',
    'finding_issued','appeal_lodged','appeal_decided','closed'
  )),
  actor_id        TEXT NOT NULL,
  occurred_at     TEXT NOT NULL DEFAULT (datetime('now')),
  payload_json    TEXT,
  notes           TEXT
);

CREATE TABLE regulator_enforcement_cases (
  id TEXT PRIMARY KEY,
  case_number TEXT UNIQUE NOT NULL,
  respondent_participant_id TEXT REFERENCES participants(id),
  respondent_name TEXT NOT NULL,
  related_licence_id TEXT REFERENCES regulator_licences(id),
  alleged_contravention TEXT NOT NULL,
  statutory_provision TEXT,             -- e.g. 'ERA 2006 s.24(1)'
  severity TEXT NOT NULL DEFAULT 'medium' CHECK (severity IN ('low','medium','high','critical')),
  status TEXT NOT NULL DEFAULT 'open' CHECK (status IN (
    'open','investigating','hearing','finding','penalty_imposed','appealed','closed','withdrawn'
  )),
  opened_at TEXT NOT NULL DEFAULT (datetime('now')),
  lead_investigator_id TEXT REFERENCES participants(id),
  finding TEXT,
  finding_date TEXT,
  penalty_amount_zar REAL,
  penalty_description TEXT,
  appeal_filed_at TEXT,
  appeal_outcome TEXT,
  closed_at TEXT,
  created_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE regulator_enforcement_events (
  id TEXT PRIMARY KEY,
  case_id TEXT NOT NULL REFERENCES regulator_enforcement_cases(id) ON DELETE CASCADE,
  event_type TEXT NOT NULL,             -- 'complaint','hearing_notice','evidence_submitted','decision','appeal_filed'
  event_date TEXT NOT NULL,
  description TEXT,
  evidence_r2_key TEXT,
  actor_id TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE regulator_filings (
      id TEXT PRIMARY KEY,
      filing_type TEXT NOT NULL,
      reporting_period TEXT NOT NULL,
      filed_by TEXT NOT NULL,
      status TEXT DEFAULT 'draft',
      narrative TEXT,
      evidence_json TEXT,
      created_at TEXT DEFAULT (datetime('now'))
    );

CREATE TABLE regulator_licence_action_workflow (
  id                  TEXT PRIMARY KEY,
  licence_id          TEXT,
  application_id      TEXT,
  action_type         TEXT NOT NULL CHECK (action_type IN (
    'grant','vary','suspend','revoke','reinstate','renew'
  )),
  status              TEXT NOT NULL DEFAULT 'draft'
    CHECK (status IN ('draft','pending_hearing','decided','executed','appealed','reversed')),
  initiated_by        TEXT NOT NULL,
  initiated_at        TEXT NOT NULL DEFAULT (datetime('now')),
  decided_at          TEXT,
  decided_by          TEXT,
  decision_rationale  TEXT,
  appeal_deadline     TEXT,
  evidence_r2_key     TEXT,
  notes               TEXT,
  updated_at          TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE regulator_licence_conditions (
  id TEXT PRIMARY KEY,
  licence_id TEXT NOT NULL REFERENCES regulator_licences(id) ON DELETE CASCADE,
  condition_number TEXT NOT NULL,
  condition_text TEXT NOT NULL,
  category TEXT,                -- technical | financial | reporting | community | env
  compliance_status TEXT NOT NULL DEFAULT 'compliant' CHECK (compliance_status IN (
    'compliant','in_review','breached','waived'
  )),
  last_tested_at TEXT,
  evidence_ref TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE regulator_licence_events (
  id TEXT PRIMARY KEY,
  licence_id TEXT NOT NULL REFERENCES regulator_licences(id) ON DELETE CASCADE,
  event_type TEXT NOT NULL CHECK (event_type IN (
    'granted','varied','renewed','suspended','revoked','surrendered','expired','condition_breach'
  )),
  event_date TEXT NOT NULL,
  details TEXT,
  actor_id TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE regulator_licences (
  id TEXT PRIMARY KEY,
  licence_number TEXT UNIQUE NOT NULL,
  licensee_participant_id TEXT REFERENCES participants(id),
  licensee_name TEXT NOT NULL,
  licence_type TEXT NOT NULL CHECK (licence_type IN (
    'generation','distribution','trading','transmission','import','export','reticulation'
  )),
  technology TEXT,              -- solar_pv | wind | hydro | thermal | storage | hybrid | n/a
  capacity_mw REAL DEFAULT 0,
  location TEXT,                -- e.g. 'De Aar, NC' or 'ZA-GP-02'
  issue_date TEXT NOT NULL,
  effective_date TEXT,
  expiry_date TEXT,
  status TEXT NOT NULL DEFAULT 'active' CHECK (status IN (
    'pending','active','varied','suspended','revoked','expired','surrendered'
  )),
  notes TEXT,
  created_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE regulator_surveillance_alerts (
  id TEXT PRIMARY KEY,
  rule_id TEXT REFERENCES regulator_surveillance_rules(id),
  rule_code TEXT NOT NULL,              -- denormalised so alerts survive rule rename
  participant_id TEXT REFERENCES participants(id),
  entity_type TEXT,                     -- 'trade_orders' | 'trade_matches' | 'participants'
  entity_id TEXT,
  severity TEXT NOT NULL DEFAULT 'medium' CHECK (severity IN ('low','medium','high','critical')),
  details_json TEXT,                    -- evidence metrics (e.g. { matches: 12, volume: 400 })
  status TEXT NOT NULL DEFAULT 'open' CHECK (status IN (
    'open','investigating','escalated','false_positive','confirmed','resolved'
  )),
  escalated_case_id TEXT REFERENCES regulator_enforcement_cases(id),
  assigned_to TEXT REFERENCES participants(id),
  raised_at TEXT NOT NULL DEFAULT (datetime('now')),
  resolved_at TEXT,
  resolution_notes TEXT
);

CREATE TABLE regulator_surveillance_rules (
  id TEXT PRIMARY KEY,
  rule_code TEXT UNIQUE NOT NULL,
  rule_name TEXT NOT NULL,
  description TEXT,
  rule_type TEXT NOT NULL CHECK (rule_type IN (
    'wash_trade','layering','spoofing','concentration','price_manipulation',
    'circular_trade','front_running','market_abuse_generic'
  )),
  severity TEXT NOT NULL DEFAULT 'medium' CHECK (severity IN ('low','medium','high','critical')),
  parameters_json TEXT,                 -- window_hours, threshold_pct, etc.
  enabled BOOLEAN DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE regulator_surveillance_triage (
  id                  TEXT PRIMARY KEY,
  alert_id            TEXT NOT NULL,
  triaged_by          TEXT NOT NULL,
  triaged_at          TEXT NOT NULL DEFAULT (datetime('now')),
  decision            TEXT NOT NULL CHECK (decision IN (
    'false_positive','monitor','escalate_to_enforcement','contact_party','close_no_action'
  )),
  rationale           TEXT,
  enforcement_case_id TEXT,
  next_review_at      TEXT
);

CREATE TABLE regulator_tariff_decisions (
  id TEXT PRIMARY KEY,
  submission_id TEXT NOT NULL REFERENCES regulator_tariff_submissions(id),
  decision_number TEXT UNIQUE NOT NULL,
  decision_date TEXT NOT NULL,
  approved_revenue_zar REAL,
  approved_tariff_c_per_kwh REAL,
  variance_percentage REAL,             -- computed off requested vs approved
  reasons TEXT,                         -- reasons for determination (PAJA-compliant)
  effective_from TEXT NOT NULL,
  effective_to TEXT,
  published_in_gazette BOOLEAN DEFAULT 0,
  gazette_reference TEXT,
  created_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE regulator_tariff_submissions (
  id TEXT PRIMARY KEY,
  reference_number TEXT UNIQUE NOT NULL,
  licensee_participant_id TEXT NOT NULL REFERENCES participants(id),
  licence_id TEXT REFERENCES regulator_licences(id),
  submission_title TEXT NOT NULL,
  tariff_period_start TEXT NOT NULL,    -- e.g. '2026-04-01'
  tariff_period_end TEXT NOT NULL,
  requested_revenue_zar REAL,
  requested_tariff_c_per_kwh REAL,
  methodology TEXT,                     -- 'MYPD4' | 'bilateral' | 'wheeling' | ...
  supporting_docs_json TEXT,            -- R2 keys
  status TEXT NOT NULL DEFAULT 'submitted' CHECK (status IN (
    'draft','submitted','public_hearing','determined','withdrawn','rejected'
  )),
  public_hearing_date TEXT,
  submitted_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE regulatory_bodies (
  code            TEXT PRIMARY KEY,
  name            TEXT NOT NULL,
  jurisdiction    TEXT NOT NULL,                     -- 'ZA','EU','US','UK','GLB' etc.
  kind            TEXT NOT NULL CHECK (kind IN (
                    'financial','energy','environmental','tax','labour',
                    'info_regulator','consumer','health_safety','listings',
                    'competition','climate','other'
                  )),
  applies_to_roles TEXT,                             -- comma-separated role list
  frequency       TEXT,                              -- 'annual','quarterly','monthly','event'
  mandatory       INTEGER DEFAULT 1,
  description     TEXT,
  filing_doc_url  TEXT
);

CREATE TABLE regulatory_filings (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  body_code       TEXT NOT NULL REFERENCES regulatory_bodies(code),
  reporting_period TEXT NOT NULL,                    -- '2026-Q1' / '2026-01' / '2026' etc.
  due_date        TEXT,
  status          TEXT DEFAULT 'draft' CHECK (status IN (
                    'draft','queued','submitted','accepted','rejected','withdrawn','overdue'
                  )),
  submitted_at    TEXT,
  acknowledged_at TEXT,
  external_reference TEXT,
  filing_pack_r2_key TEXT,
  filed_by        TEXT,                              -- user id
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE report_catalog (
  code            TEXT PRIMARY KEY,
  role            TEXT NOT NULL,
  module          TEXT NOT NULL,
  name            TEXT NOT NULL,
  description     TEXT,
  framework       TEXT,
  default_period  TEXT NOT NULL DEFAULT 'monthly'    
);

CREATE TABLE reports_registry (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  module          TEXT NOT NULL,                    
  report_code     TEXT NOT NULL,                    
  report_name     TEXT NOT NULL,
  reporting_period_start TEXT,
  reporting_period_end   TEXT,
  framework       TEXT,                              
  params          TEXT,                              
  payload_json    TEXT,                              
  r2_payload_key  TEXT,                              
  row_count       INTEGER,
  total_value_zar REAL,
  status          TEXT DEFAULT 'generated'
                   CHECK (status IN ('queued','generating','generated','distributed','superseded','withdrawn')),
  superseded_by   TEXT REFERENCES reports_registry(id),
  distributed_to  TEXT,                              
  generated_at    TEXT DEFAULT (datetime('now')),
  distributed_at  TEXT
);

CREATE TABLE request_stats (
  id              TEXT PRIMARY KEY,
  bucket_start    TEXT NOT NULL,   -- ISO, floored to 15-minute boundaries
  route           TEXT NOT NULL,
  method          TEXT NOT NULL,
  status_class    TEXT NOT NULL,   -- '2xx' | '3xx' | '4xx' | '5xx'
  count           INTEGER NOT NULL DEFAULT 0,
  latency_ms_sum  INTEGER NOT NULL DEFAULT 0,
  latency_ms_max  INTEGER NOT NULL DEFAULT 0,
  slow_count      INTEGER NOT NULL DEFAULT 0  -- latency > 1000ms
);

CREATE TABLE reserve_accounts (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  reserve_type TEXT NOT NULL CHECK (reserve_type IN ('dsra','mra','om_reserve','tax_reserve','insurance','other')),
  target_amount_zar REAL NOT NULL,
  target_basis TEXT,                   -- 'next_6m_debt_service','next_12m_om','fixed'
  current_balance_zar REAL DEFAULT 0,
  custodian TEXT,
  account_number TEXT,
  status TEXT DEFAULT 'active' CHECK (status IN ('active','drawn_down','closed')),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE reserve_movements (
  id TEXT PRIMARY KEY,
  reserve_id TEXT NOT NULL REFERENCES reserve_accounts(id),
  movement_type TEXT NOT NULL CHECK (movement_type IN ('top_up','release','draw','interest','transfer_in','transfer_out')),
  amount_zar REAL NOT NULL,
  waterfall_run_id TEXT REFERENCES waterfall_runs(id),
  reason TEXT,
  created_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE resource_assignments (
  id TEXT PRIMARY KEY,
  activity_id TEXT NOT NULL,
  resource_id TEXT NOT NULL,
  units REAL NOT NULL DEFAULT 1,
  UNIQUE(activity_id, resource_id)
);

CREATE TABLE risk_factor_history (
  factor_id     TEXT NOT NULL,
  as_of_date    TEXT NOT NULL,
  value         REAL NOT NULL,
  source_run_id TEXT,
  created_at    TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (factor_id, as_of_date)
);

CREATE TABLE risk_factors (
  id            TEXT PRIMARY KEY,
  name          TEXT NOT NULL,
  factor_type   TEXT NOT NULL,          -- spot | fx | rates | fuel | index
  unit          TEXT NOT NULL,          -- ZAR/MWh, ZAR/USD, %, etc.
  source        TEXT,                   -- mark_prices, external_feed_xyz
  created_at    TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE risk_portfolios (
  id                 TEXT PRIMARY KEY,
  name               TEXT NOT NULL,
  owner_id           TEXT,
  basis_filter_json  TEXT NOT NULL DEFAULT '{}',
  is_system          INTEGER NOT NULL DEFAULT 0,
  created_at         TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at         TEXT
);

CREATE TABLE risk_scenario_results (
  id                TEXT PRIMARY KEY,
  scenario_id       TEXT NOT NULL,
  portfolio_id      TEXT NOT NULL,
  as_of_date        TEXT NOT NULL,
  pnl_impact_zar    REAL NOT NULL,         -- negative = loss
  breakdown_json    TEXT,                   -- per-factor contribution
  created_at        TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE risk_scenarios (
  id                  TEXT PRIMARY KEY,
  name                TEXT NOT NULL,
  description         TEXT,
  is_system           INTEGER NOT NULL DEFAULT 0,
  factor_shocks_json  TEXT NOT NULL,
  owner_id            TEXT,                -- null for system
  created_at          TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at          TEXT
);

CREATE TABLE risk_var_results (
  id                TEXT PRIMARY KEY,
  portfolio_id      TEXT NOT NULL,
  as_of_date        TEXT NOT NULL,
  methodology       TEXT NOT NULL DEFAULT 'historical_simulation',
  confidence        REAL NOT NULL,        -- 0.95 | 0.99
  horizon_days      INTEGER NOT NULL DEFAULT 1,
  var_amount_zar    REAL NOT NULL,        -- positive number (loss magnitude)
  es_amount_zar     REAL,                 -- expected shortfall, same convention
  components_json   TEXT,                  -- [{factor_id,name,contribution_zar,pct}]
  created_at        TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE scenario_runs (
  id                  TEXT PRIMARY KEY,
  participant_id      TEXT NOT NULL REFERENCES participants(id),
  tenant_id           TEXT DEFAULT 'default' NOT NULL,
  scenario_code       TEXT NOT NULL REFERENCES climate_scenarios(code),
  horizon_years       INTEGER NOT NULL,             -- 5 / 10 / 30 yrs
  base_year           INTEGER NOT NULL,
  -- Aggregated outputs
  portfolio_emissions_base_tco2e   REAL,
  portfolio_emissions_target_tco2e REAL,
  emissions_at_risk_tco2e          REAL,
  financial_value_at_risk_zar      REAL,
  -- Worst-affected sector
  worst_sector_nace                TEXT,
  worst_sector_var_zar             REAL,
  -- Output detail (JSON: per-sector impact array)
  sector_impacts_json              TEXT,
  status              TEXT DEFAULT 'complete' CHECK (status IN ('queued','running','complete','failed')),
  computed_at         TEXT DEFAULT (datetime('now')),
  notes               TEXT
);

CREATE TABLE scope2_disclosures (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  reporting_year INTEGER NOT NULL,
  total_consumption_mwh REAL NOT NULL,
  location_based_emissions_tco2e REAL,
  market_based_emissions_tco2e REAL,
  renewable_mwh_claimed REAL,
  renewable_percentage REAL,
  grid_factor_tco2e_per_mwh REAL,    -- SA national grid factor; NERSA-published
  audit_reference TEXT,
  status TEXT DEFAULT 'draft' CHECK (status IN ('draft','published','audited','revised')),
  published_at TEXT,
  created_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE sectoral_pathways (
  id              TEXT PRIMARY KEY,
  pathway_code    TEXT NOT NULL,                     -- 'IEA_NZE_2050','NGFS_NET_ZERO'
  sector          TEXT NOT NULL,                     -- 'power','steel','cement','aluminum','aviation','shipping','road_freight','oil_gas','buildings'
  year            INTEGER NOT NULL,
  intensity_value REAL NOT NULL,                     -- intensity at this year
  unit            TEXT NOT NULL,                     -- 'kgCO2e/kWh','tCO2e/t','gCO2e/pkm'
  notes           TEXT,
  UNIQUE (pathway_code, sector, year)
);

CREATE TABLE sensitive_rate_counters (
        bucket_key TEXT PRIMARY KEY,
        window_start INTEGER NOT NULL,
        count INTEGER NOT NULL,
        max_requests INTEGER NOT NULL,
        expires_at INTEGER NOT NULL
      );

CREATE TABLE servitudes (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  servitude_type TEXT NOT NULL CHECK (servitude_type IN ('powerline','access_road','water_pipeline','fibre','other')),
  parcel_number TEXT,
  grantor TEXT,
  consideration_zar REAL,
  registered_at_deeds BOOLEAN DEFAULT 0,
  registration_date TEXT,
  notes TEXT
);

CREATE TABLE sessions (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id) ON DELETE CASCADE,
  access_jti TEXT NOT NULL UNIQUE,
  refresh_token_hash TEXT NOT NULL UNIQUE,
  issued_at TEXT NOT NULL DEFAULT (datetime('now')),
  expires_at TEXT NOT NULL,
  refresh_expires_at TEXT NOT NULL,
  last_used_at TEXT,
  user_agent TEXT,
  ip TEXT,
  revoked_at TEXT,
  revoked_reason TEXT
);

CREATE TABLE settlement_breaks (
  id                   TEXT PRIMARY KEY,
  invoice_id           TEXT NOT NULL,
  break_type           TEXT NOT NULL CHECK (break_type IN (
    'quantity','price','timing','metering','tariff','fx','other'
  )),
  severity             TEXT NOT NULL DEFAULT 'medium'
    CHECK (severity IN ('low','medium','high','critical')),
  status               TEXT NOT NULL DEFAULT 'open'
    CHECK (status IN ('open','investigating','resolved','rejected')),
  reported_by          TEXT NOT NULL,
  reported_at          TEXT NOT NULL DEFAULT (datetime('now')),
  reason               TEXT NOT NULL,
  expected_value       REAL,
  actual_value         REAL,
  resolution_outcome   TEXT CHECK (resolution_outcome IN (
    'corrected','rebooked','waived','escalated','no_action'
  )),
  resolution_notes     TEXT,
  resolved_at          TEXT,
  resolved_by          TEXT,
  created_at           TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at           TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE settlement_calendar (
  id                 TEXT PRIMARY KEY,
  trading_day        TEXT NOT NULL,                  -- YYYY-MM-DD (T+0)
  market_zone        TEXT NOT NULL DEFAULT 'ZA',
  gate_close_at      TEXT NOT NULL,                  -- ISO; nominations cut-off
  metering_close_at  TEXT NOT NULL,                  -- ISO; metering cut-off (T+1)
  invoice_run_at     TEXT NOT NULL,                  -- ISO; settlement engine fires (T+1)
  payment_due_at     TEXT NOT NULL,                  -- ISO; cash clearing deadline (T+5)
  status             TEXT NOT NULL DEFAULT 'scheduled'
    CHECK (status IN ('scheduled','gate_closed','metering_closed','invoiced','settled','disputed','cancelled')),
  notes              TEXT,
  created_at         TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at         TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE (trading_day, market_zone)
);

CREATE TABLE settlement_disputes (
  id TEXT PRIMARY KEY,
  invoice_id TEXT NOT NULL REFERENCES invoices(id),
  filed_by TEXT NOT NULL REFERENCES participants(id),
  reason TEXT NOT NULL,
  evidence_keys TEXT,
  status TEXT DEFAULT 'open' CHECK (status IN ('open','under_review','resolved','rejected')),
  resolution TEXT,
  resolved_by TEXT,
  resolved_at TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE settlement_dlq (
  id TEXT PRIMARY KEY,
  run_id TEXT REFERENCES settlement_runs(id),
  contract_id TEXT,
  period_start TEXT,
  period_end TEXT,
  error_message TEXT NOT NULL,
  error_context_json TEXT,
  attempt_count INTEGER DEFAULT 1,
  status TEXT NOT NULL DEFAULT 'open' CHECK (status IN ('open','retrying','resolved','abandoned')),
  last_attempt_at TEXT,
  resolved_at TEXT,
  resolved_by TEXT REFERENCES participants(id),
  resolution_notes TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE settlement_dvp_locks (
  cycle_id          TEXT PRIMARY KEY,
  lock_status       TEXT NOT NULL DEFAULT 'open',
  cash_confirmed_at TEXT,
  cash_confirmed_by TEXT,
  cash_ref          TEXT,
  energy_confirmed_at TEXT,
  energy_confirmed_by TEXT,
  energy_ref        TEXT,
  locked_at         TEXT,
  released_at       TEXT,
  released_reason   TEXT,
  created_at        TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at        TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE settlement_fail_escalations (
  id                TEXT PRIMARY KEY,
  instruction_id    TEXT NOT NULL,
  escalation_tier   INTEGER NOT NULL DEFAULT 1,
  triggered_at      TEXT NOT NULL DEFAULT (datetime('now')),
  triggered_by      TEXT,
  resolution_status TEXT NOT NULL DEFAULT 'open',
  resolved_at       TEXT,
  resolved_by       TEXT,
  notes             TEXT
);

CREATE TABLE settlement_fees (
  id                  TEXT PRIMARY KEY,
  invoice_id          TEXT NOT NULL,
  fee_type            TEXT NOT NULL CHECK (fee_type IN (
    'dunning','late_payment','rebooking','admin','wheeling_uplift','imbalance_uplift'
  )),
  basis               TEXT NOT NULL,             -- "2% of outstanding", "R0.50/MWh", "flat R250", etc.
  amount_zar          REAL NOT NULL,
  reason              TEXT,
  calc_rule_version   TEXT NOT NULL,             -- bumped when the rule changes
  applied_after       TEXT,                      -- the precondition date (e.g. payment_due_at)
  calculated_at       TEXT NOT NULL DEFAULT (datetime('now')),
  applied_by          TEXT,                      -- system user id, or 'system' for engine
  UNIQUE (invoice_id, fee_type, calc_rule_version)
);

CREATE TABLE settlement_run_events (
  id TEXT PRIMARY KEY,
  run_id TEXT NOT NULL REFERENCES settlement_runs(id) ON DELETE CASCADE,
  event_type TEXT NOT NULL,             -- 'contract_processed','invoice_created','error','warning'
  entity_type TEXT,
  entity_id TEXT,
  message TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE settlement_runs (
  id TEXT PRIMARY KEY,
  run_type TEXT NOT NULL CHECK (run_type IN (
    'ppa_energy','wheeling','imbalance','ancillary','adhoc'
  )),
  period_start TEXT NOT NULL,
  period_end TEXT NOT NULL,
  initiated_by TEXT REFERENCES participants(id),
  started_at TEXT NOT NULL DEFAULT (datetime('now')),
  completed_at TEXT,
  status TEXT NOT NULL DEFAULT 'running' CHECK (status IN (
    'running','completed','failed','partial','cancelled'
  )),
  contracts_considered INTEGER DEFAULT 0,
  invoices_generated INTEGER DEFAULT 0,
  total_value_zar REAL DEFAULT 0,
  error_message TEXT,
  idempotency_key TEXT UNIQUE            -- prevents double-runs for the same period/type
);

CREATE TABLE siem_delivery_log (
  id TEXT PRIMARY KEY,
  forwarder_id TEXT NOT NULL REFERENCES siem_forwarders(id),
  stream TEXT NOT NULL,
  batch_size INTEGER,
  http_status INTEGER,
  response_body_snippet TEXT,
  attempted_at TEXT NOT NULL DEFAULT (datetime('now')),
  duration_ms INTEGER
);

CREATE TABLE siem_forwarder_cursors (
  forwarder_id TEXT NOT NULL REFERENCES siem_forwarders(id) ON DELETE CASCADE,
  stream TEXT NOT NULL,                        -- 'audit' | 'pii' | 'cascade_dlq' | 'cron_failure'
  last_cursor TEXT,                            -- ISO timestamp OR row id of last forwarded event
  last_forwarded_count INTEGER DEFAULT 0,
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (forwarder_id, stream)
);

CREATE TABLE siem_forwarders (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,                          -- human label
  vendor TEXT NOT NULL CHECK (vendor IN (
    'splunk_hec','elastic','datadog','sumo','generic_https'
  )),
  endpoint_url TEXT NOT NULL,
  secret_kv_key TEXT,                          -- KV key for HEC token / API key
  subscribe_json TEXT NOT NULL,                -- JSON: {"events":["audit","pii","cron_failure","cascade_dlq"], "min_severity":"info"}
  enabled BOOLEAN DEFAULT 1,
  last_attempt_at TEXT,
  last_success_at TEXT,
  last_error TEXT,
  rows_forwarded_total INTEGER DEFAULT 0,
  created_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE site_accruals (
  id                       TEXT PRIMARY KEY,
  station_id               TEXT NOT NULL REFERENCES solax_stations(id) ON DELETE CASCADE,
  site_id                  TEXT REFERENCES om_sites(id) ON DELETE SET NULL,
  participant_id           TEXT NOT NULL,
  period_hour              TEXT NOT NULL,   -- ISO8601 UTC truncated to hour: "2026-06-04T07:00:00Z"
  kwh_delta                REAL NOT NULL DEFAULT 0,     -- kWh generated in this period
  cumulative_kwh           REAL NOT NULL DEFAULT 0,     -- total_kwh snapshot at end of period
  carbon_tco2e             REAL NOT NULL DEFAULT 0,     -- tCO₂e avoided this period
  revenue_zar              REAL NOT NULL DEFAULT 0,     -- ZAR revenue to fund
  savings_zar              REAL NOT NULL DEFAULT 0,     -- ZAR savings for customer
  tariff_rate_used         REAL,                        -- snapshot of fund tariff used
  customer_tariff_rate_used REAL,                       -- snapshot of customer tariff used
  carbon_intensity_used    REAL,                        -- gCO₂e/kWh used
  is_backfill              INTEGER NOT NULL DEFAULT 0,  -- 1 if this is the historical catch-up row
  created_at               TEXT NOT NULL,
  updated_at               TEXT NOT NULL
);

CREATE TABLE sll_kpis (
  id              TEXT PRIMARY KEY,
  loan_id         TEXT REFERENCES loan_originations(id),
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  kpi_name        TEXT NOT NULL,
  kpi_type        TEXT NOT NULL CHECK (kpi_type IN ('emissions_intensity','renewable_pct','sbti_target','water_intensity','safety_ltifr','bbbee_level','jobs_created','custom')),
  baseline_value  REAL,
  target_value    REAL NOT NULL,
  observation_period TEXT NOT NULL,                  -- 'annual','semi_annual'
  margin_step_up_bps INTEGER DEFAULT 0,              -- penalty for missing
  margin_step_down_bps INTEGER DEFAULT 0,            -- reward for meeting
  current_value   REAL,
  status          TEXT DEFAULT 'pending' CHECK (status IN ('pending','met','missed','assured','restated')),
  reporting_year  INTEGER,
  assured_by      TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE solax_backfill_jobs (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  station_id      TEXT NOT NULL,
  device_sn       TEXT,
  plant_name      TEXT,
  status          TEXT NOT NULL DEFAULT 'queued',  -- queued | running | done | failed
  window_start_ms INTEGER NOT NULL,                -- oldest instant to fetch (ms epoch)
  run_end_ms      INTEGER NOT NULL,                -- newest instant (job creation - 1h)
  cursor_end_ms   INTEGER NOT NULL,                -- end of the NEXT chunk to process
  hours_written   INTEGER NOT NULL DEFAULT 0,
  kwh_total       REAL    NOT NULL DEFAULT 0,
  empty_streak    INTEGER NOT NULL DEFAULT 0,        -- consecutive empty chunks after data started; stops the walk at commissioning
  last_error      TEXT,
  started_at      TEXT,
  finished_at     TEXT,
  created_at      TEXT NOT NULL,
  updated_at      TEXT NOT NULL,
  UNIQUE(participant_id, station_id)
);

CREATE TABLE solax_stations (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id) ON DELETE CASCADE,
  site_id         TEXT REFERENCES om_sites(id) ON DELETE SET NULL,
  plant_id        TEXT NOT NULL,        -- SolaX plantId
  plant_name      TEXT,
  device_sn       TEXT NOT NULL,        -- Inverter SN (primary key on SolaX side)
  device_type     INTEGER NOT NULL DEFAULT 1,   -- 1=Inverter, 100=EMS
  business_type   INTEGER NOT NULL DEFAULT 4,   -- 4=C&I
  rated_power_kw  REAL,
  online_status   INTEGER DEFAULT 0,    -- 0=Offline, 1=Online
  last_sync_at    TEXT,
  last_error      TEXT,
  status          TEXT NOT NULL DEFAULT 'active'
                    CHECK(status IN ('active','inactive','error')),
  created_at      TEXT NOT NULL,
  updated_at      TEXT NOT NULL
, manufacturer TEXT NOT NULL DEFAULT 'solax', tariff_rate_zar_per_kwh REAL, lender_participant_id TEXT, carbon_participant_id TEXT, offtaker_participant_id TEXT, carbon_project_id TEXT, tariff_step_date TEXT, tariff_step_rate REAL);

CREATE TABLE spend_category_hints (
  id              TEXT PRIMARY KEY,
  pattern         TEXT NOT NULL,                     -- regex / phrase
  pattern_type    TEXT DEFAULT 'phrase' CHECK (pattern_type IN ('phrase','regex','exact')),
  suggested_activity_code TEXT NOT NULL,             -- joins to esg_emission_factors.activity_code
  suggested_scope INTEGER NOT NULL,
  suggested_scope3_category INTEGER,
  confidence      REAL,
  notes           TEXT
);

CREATE TABLE sqlite_sequence(name,seq);

CREATE TABLE station_telemetry_snapshot (station_id TEXT PRIMARY KEY REFERENCES solax_stations(id) ON DELETE CASCADE, ts TEXT NOT NULL, ac_kw REAL, dc_kw REAL, daily_kwh REAL, total_kwh REAL, battery_soc REAL, temperature_c REAL, online INTEGER NOT NULL DEFAULT 0, raw_json TEXT, updated_at TEXT NOT NULL);

CREATE TABLE statutory_checks (
  id TEXT PRIMARY KEY,
  document_id TEXT NOT NULL REFERENCES contract_documents(id),
  check_type TEXT NOT NULL CHECK (check_type IN ('external_legal','board_approval','shareholder','regulator_nersa','competition','foreign_exchange','other')),
  status TEXT DEFAULT 'pending' CHECK (status IN ('pending','in_progress','approved','rejected','waived')),
  assigned_to TEXT,
  due_date TEXT,
  result TEXT,
  notes TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE stress_results (
  id TEXT PRIMARY KEY,
  scenario_id TEXT NOT NULL REFERENCES stress_scenarios(id),
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  run_at TEXT NOT NULL DEFAULT (datetime('now')),
  period TEXT,
  base_dscr REAL,
  stressed_dscr REAL,
  base_llcr REAL,
  stressed_llcr REAL,
  base_equity_irr REAL,
  stressed_equity_irr REAL,
  notes TEXT,
  run_by TEXT REFERENCES participants(id)
);

CREATE TABLE stress_scenarios (
  id TEXT PRIMARY KEY,
  scenario_name TEXT UNIQUE NOT NULL,
  description TEXT,
  parameters_json TEXT,                -- { tariff_shock_pct, availability_delta, fx_delta, ... }
  created_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE support_cross_tenant_access (
  id              TEXT PRIMARY KEY,
  agent_id        TEXT NOT NULL,
  tenant_accessed TEXT NOT NULL,
  resource_type   TEXT NOT NULL,
  resource_id     TEXT,
  justification   TEXT NOT NULL,
  ticket_id       TEXT,
  accessed_at     TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE support_escalations (
  id              TEXT PRIMARY KEY,
  ticket_id       TEXT NOT NULL,
  escalated_by    TEXT NOT NULL,
  escalated_to    TEXT NOT NULL,
  reason          TEXT NOT NULL,
  status          TEXT NOT NULL DEFAULT 'open'
    CHECK (status IN ('open','accepted','resolved','rejected')),
  resolution      TEXT,
  escalated_at    TEXT NOT NULL DEFAULT (datetime('now')),
  resolved_at     TEXT
);

CREATE TABLE support_ticket_comments (
  id              TEXT PRIMARY KEY,
  ticket_id       TEXT NOT NULL,
  author_id       TEXT NOT NULL,
  body            TEXT NOT NULL,
  visibility      TEXT NOT NULL DEFAULT 'public'
    CHECK (visibility IN ('public','internal')),
  created_at      TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE support_tickets (
  id              TEXT PRIMARY KEY,
  ticket_number   TEXT UNIQUE NOT NULL,
  reporter_id     TEXT NOT NULL,
  tenant_id       TEXT,
  subject         TEXT NOT NULL,
  description     TEXT,
  category        TEXT NOT NULL CHECK (category IN (
    'access','billing','feature_question','bug','data_issue','compliance','other'
  )),
  priority        TEXT NOT NULL DEFAULT 'normal'
    CHECK (priority IN ('low','normal','high','urgent')),
  status          TEXT NOT NULL DEFAULT 'open'
    CHECK (status IN ('open','in_progress','waiting_on_customer','resolved','closed')),
  assignee_id     TEXT,
  resolution      TEXT,
  resolved_at     TEXT,
  resolved_by     TEXT,
  created_at      TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at      TEXT NOT NULL DEFAULT (datetime('now'))
, chain_status TEXT NOT NULL DEFAULT 'open'
  CHECK (chain_status IN (
    'open','triaged','in_progress','awaiting_user',
    'resolved','closed','escalated'
  )), triaged_at TEXT, first_responded_at TEXT, waiting_since TEXT, reopened_at TEXT, escalated_at TEXT, escalation_reason TEXT, next_sla_due_at TEXT, next_sla_window TEXT
  CHECK (next_sla_window IS NULL OR next_sla_window IN ('triage','first_response','resolution')), last_sla_breach_at TEXT, sla_breach_count INTEGER NOT NULL DEFAULT 0, triaged_by TEXT, closed_by TEXT);

CREATE TABLE syndication_participants (
  id              TEXT PRIMARY KEY,
  loan_id         TEXT NOT NULL REFERENCES loan_originations(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  participant_lender_id TEXT,                        -- joins participants(id) for internal lender; nullable for external
  participant_name TEXT NOT NULL,
  commitment_zar  REAL NOT NULL,
  participation_pct REAL,
  role            TEXT CHECK (role IN ('mlp','arranger','underwriter','participant','agent','security_trustee')),
  status          TEXT DEFAULT 'invited' CHECK (status IN ('invited','indicated','committed','documented','funded','withdrew')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE tariff_products (
  id TEXT PRIMARY KEY,
  tariff_code TEXT UNIQUE NOT NULL,
  tariff_name TEXT NOT NULL,
  utility TEXT NOT NULL,            -- 'Eskom','City of Cape Town','City of Johannesburg','NMBM','eThekwini','other'
  category TEXT NOT NULL CHECK (category IN (
    'commercial','industrial','residential','agricultural','public_sector','wheeling'
  )),
  structure_type TEXT NOT NULL CHECK (structure_type IN (
    'flat','tou','stepped_block','demand_based','fixed_plus_energy','hybrid'
  )),
  tou_schedule_json TEXT,           -- { off_peak: {cents_per_kwh, hours: [[22,6]]}, standard: {...}, peak: {...} }
  effective_from TEXT NOT NULL,
  effective_to TEXT,
  source_doc_r2_key TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE tenant_invoices (
  id TEXT PRIMARY KEY,
  tenant_id TEXT NOT NULL REFERENCES tenants(id),
  subscription_id TEXT REFERENCES tenant_subscriptions(id),
  invoice_number TEXT UNIQUE NOT NULL,
  period_start TEXT NOT NULL,
  period_end TEXT NOT NULL,
  line_items_json TEXT,
  subtotal_zar REAL NOT NULL,
  vat_rate REAL DEFAULT 0.15,
  vat_zar REAL,
  total_zar REAL NOT NULL,
  status TEXT NOT NULL DEFAULT 'issued' CHECK (status IN (
    'draft','issued','paid','partial','overdue','disputed','void'
  )),
  issued_at TEXT,
  due_at TEXT,
  paid_at TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE tenant_plans (
  id TEXT PRIMARY KEY,
  plan_code TEXT UNIQUE NOT NULL,
  plan_name TEXT NOT NULL,
  tier TEXT NOT NULL,
  base_monthly_zar REAL NOT NULL,
  included_seats INTEGER DEFAULT 0,
  extra_seat_zar REAL DEFAULT 0,
  included_participants INTEGER DEFAULT 0,
  extra_participant_zar REAL DEFAULT 0,
  feature_set_json TEXT,            -- feature flags inherited by subscribers
  sla_uptime_pct REAL DEFAULT 99.9,
  support_tier TEXT DEFAULT 'business_hours',
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE tenant_provisioning_requests (
  id TEXT PRIMARY KEY,
  requested_name TEXT NOT NULL,
  requested_tier TEXT NOT NULL DEFAULT 'trial',
  admin_email TEXT NOT NULL,
  admin_name TEXT,
  legal_entity TEXT,
  registration_number TEXT,
  vat_number TEXT,
  country TEXT DEFAULT 'ZA',
  expected_participants INTEGER,
  primary_use_case TEXT,
  status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN (
    'pending','approved','rejected','completed','expired'
  )),
  approved_tenant_id TEXT REFERENCES tenants(id),
  rejection_reason TEXT,
  approved_by TEXT REFERENCES participants(id),
  approved_at TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE tenant_rate_limit_events (
  id TEXT PRIMARY KEY,
  tenant_id TEXT NOT NULL REFERENCES tenants(id),
  route_prefix TEXT NOT NULL,
  window_start TEXT NOT NULL,
  denied_count INTEGER DEFAULT 0,
  allowed_count INTEGER DEFAULT 0,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE tenant_rate_limits (
  tenant_id TEXT NOT NULL REFERENCES tenants(id),
  route_prefix TEXT NOT NULL,          -- e.g. '/api/trading' or '*'
  window_seconds INTEGER NOT NULL,
  max_requests INTEGER NOT NULL,
  burst_capacity INTEGER DEFAULT 0,
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (tenant_id, route_prefix)
);

CREATE TABLE tenant_sso_providers (
  id TEXT PRIMARY KEY,
  tenant_id TEXT NOT NULL REFERENCES tenants(id),
  provider_type TEXT NOT NULL CHECK (provider_type IN (
    'entra_id','okta','google_workspace','keycloak','auth0','saml','generic_oidc'
  )),
  display_name TEXT,
  client_id TEXT NOT NULL,
  tenant_identifier TEXT,             -- e.g. Azure AD tenant GUID
  issuer_url TEXT,
  auth_endpoint TEXT,
  token_endpoint TEXT,
  jwks_url TEXT,
  client_secret_kv_key TEXT,          -- KV key holding the client secret
  redirect_uri TEXT,
  allowed_email_domains TEXT,         -- comma-separated list for JIT provisioning
  jit_role TEXT DEFAULT 'offtaker',   -- default role for JIT-created participants
  enabled BOOLEAN DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE tenant_subscriptions (
  id TEXT PRIMARY KEY,
  tenant_id TEXT NOT NULL REFERENCES tenants(id),
  plan_id TEXT NOT NULL REFERENCES tenant_plans(id),
  period_start TEXT NOT NULL,
  period_end TEXT NOT NULL,
  billing_frequency TEXT NOT NULL CHECK (billing_frequency IN ('monthly','quarterly','annual')),
  amount_zar REAL NOT NULL,
  status TEXT NOT NULL DEFAULT 'active' CHECK (status IN ('trialing','active','past_due','cancelled','expired')),
  auto_renew BOOLEAN DEFAULT 1,
  cancelled_at TEXT,
  cancellation_reason TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE tenant_usage_snapshots (
  id TEXT PRIMARY KEY,
  tenant_id TEXT NOT NULL REFERENCES tenants(id),
  snapshot_date TEXT NOT NULL,        -- YYYY-MM-DD
  participant_count INTEGER DEFAULT 0,
  active_participant_count INTEGER DEFAULT 0,
  seat_count INTEGER DEFAULT 0,
  api_calls_count INTEGER DEFAULT 0,
  storage_bytes INTEGER DEFAULT 0,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE (tenant_id, snapshot_date)
);

CREATE TABLE tenants (
  id TEXT PRIMARY KEY,
  slug TEXT UNIQUE NOT NULL,
  display_name TEXT NOT NULL,
  description TEXT,
  created_by TEXT REFERENCES participants(id),
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
, name TEXT, legal_entity TEXT, registration_number TEXT, vat_number TEXT, primary_contact_email TEXT, primary_contact_phone TEXT, billing_email TEXT, country TEXT DEFAULT 'ZA', tier TEXT DEFAULT 'standard', status TEXT DEFAULT 'active', activated_at TEXT, suspended_at TEXT, closed_at TEXT);

CREATE TABLE threads (
  id TEXT PRIMARY KEY,
  entity_type TEXT NOT NULL,
  entity_id TEXT NOT NULL,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  parent_id TEXT,
  content TEXT NOT NULL,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE trade_allocations (
  id                  TEXT PRIMARY KEY,
  match_id            TEXT NOT NULL,              -- trade_matches.id
  order_id            TEXT NOT NULL,              -- trade_orders.id (the side being attributed)
  participant_id      TEXT NOT NULL,              -- desk / sub-account / fund
  allocated_volume_mwh REAL NOT NULL,
  allocated_price_zar  REAL NOT NULL,             -- usually = match price; allowed to differ for internal book transfer
  sub_account         TEXT,                       -- free-text internal label
  lot_id              TEXT,                       -- optional finer lot identifier
  reason              TEXT,
  status              TEXT NOT NULL DEFAULT 'active'
    CHECK (status IN ('active','rolled_back','superseded')),
  created_at          TEXT NOT NULL DEFAULT (datetime('now')),
  created_by          TEXT,
  UNIQUE (match_id, participant_id, sub_account, lot_id)
);

CREATE TABLE trade_confirmations (
  id              TEXT PRIMARY KEY,
  trade_id        TEXT NOT NULL,                     -- joins trade_fills(id)
  participant_id  TEXT NOT NULL,
  counterparty_id TEXT,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  affirmation_status TEXT DEFAULT 'pending' CHECK (affirmation_status IN ('pending','affirmed','disputed','novated','cancelled')),
  affirmed_at     TEXT,
  dispute_reason  TEXT,
  novation_to     TEXT,                              -- new counterparty
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE trade_exceptions (
  id                   TEXT PRIMARY KEY,
  match_id             TEXT NOT NULL,              -- trade_matches.id
  order_id             TEXT NOT NULL,              -- trade_orders.id
  exception_type       TEXT NOT NULL CHECK (exception_type IN (
    'bad_price','off_market','wrong_counterparty','wrong_volume','duplicate_fill','market_halt_override','other'
  )),
  severity             TEXT NOT NULL DEFAULT 'medium'
    CHECK (severity IN ('low','medium','high','critical')),
  status               TEXT NOT NULL DEFAULT 'open'
    CHECK (status IN ('open','investigating','resolved','rejected')),
  reported_by          TEXT NOT NULL,
  reported_at          TEXT NOT NULL DEFAULT (datetime('now')),
  reason               TEXT NOT NULL,
  expected_value       REAL,
  actual_value         REAL,
  resolution_outcome   TEXT CHECK (resolution_outcome IN (
    'cancelled','rebooked','adjusted','waived','escalated','no_action'
  )),
  resolution_notes     TEXT,
  resolved_at          TEXT,
  resolved_by          TEXT,
  rebook_match_id      TEXT,                       -- if outcome='rebooked', the new trade_matches row
  created_at           TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at           TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE trade_fees (
  id                 TEXT PRIMARY KEY,
  match_id           TEXT NOT NULL,                -- trade_matches.id
  order_id           TEXT NOT NULL,                -- trade_orders.id (the side billed)
  participant_id     TEXT NOT NULL,
  fee_type           TEXT NOT NULL CHECK (fee_type IN (
    'brokerage','exchange','clearing','market_data','regulatory','tax','adjustment'
  )),
  basis              TEXT NOT NULL,                -- "0.10 ZAR/MWh", "5 bps of notional", "flat R250"
  amount_zar         REAL NOT NULL,
  reason             TEXT,
  calc_rule_version  TEXT NOT NULL,
  calculated_at      TEXT NOT NULL DEFAULT (datetime('now')),
  applied_by         TEXT,
  UNIQUE (match_id, participant_id, fee_type, calc_rule_version)
);

CREATE TABLE trade_fills (
  id              TEXT PRIMARY KEY,
  order_id        TEXT NOT NULL,
  participant_id  TEXT NOT NULL,
  side            TEXT NOT NULL CHECK (side IN ('buy','sell')),
  energy_type     TEXT,
  matched_volume_mwh REAL NOT NULL,
  matched_price   REAL NOT NULL,
  gross_zar       REAL,
  fee_zar         REAL DEFAULT 0,
  net_zar         REAL,
  executed_at     TEXT DEFAULT (datetime('now')),
  buyer_id        TEXT,
  buyer_name      TEXT,
  seller_id       TEXT,
  seller_name     TEXT,
  match_id        TEXT REFERENCES trade_matches(id),
  shard_key       TEXT
);

CREATE TABLE trade_history (
  id TEXT PRIMARY KEY,
  match_id TEXT NOT NULL REFERENCES trade_matches(id),
  action TEXT NOT NULL,
  actor_id TEXT NOT NULL REFERENCES participants(id),
  details TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE trade_matches (
  id TEXT PRIMARY KEY,
  buy_order_id TEXT NOT NULL REFERENCES trade_orders(id),
  sell_order_id TEXT NOT NULL REFERENCES trade_orders(id),
  matched_volume_mwh REAL NOT NULL,
  matched_price REAL NOT NULL,
  matched_at TEXT DEFAULT (datetime('now')),
  settlement_id TEXT,
  escrow_id TEXT,
  status TEXT DEFAULT 'pending' CHECK (status IN ('pending','settling','settled','disputed','cancelled'))
);

CREATE TABLE trade_order_amendments (id TEXT PRIMARY KEY, order_id TEXT NOT NULL, amended_by TEXT NOT NULL, amended_at TEXT NOT NULL DEFAULT (datetime('now')), prev_price REAL, new_price REAL, prev_volume_mwh REAL NOT NULL, new_volume_mwh REAL NOT NULL, prev_remaining_mwh REAL NOT NULL, new_remaining_mwh REAL NOT NULL, lost_priority INTEGER NOT NULL DEFAULT 0, reason TEXT);

CREATE TABLE trade_order_rejections (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  attempted_at    TEXT NOT NULL DEFAULT (datetime('now')),
  reason_code     TEXT NOT NULL,
  detail          TEXT,
  side            TEXT,
  energy_type     TEXT,
  volume_mwh      REAL,
  price_zar_mwh   REAL,
  notional_zar    REAL,
  snapshot_json   TEXT,        -- credit_limit, open_exposure, free_collateral, position, market_state
  external_ref    TEXT
);

CREATE TABLE trade_orders (
  id TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL REFERENCES participants(id),
  side TEXT NOT NULL CHECK (side IN ('buy','sell')),
  energy_type TEXT NOT NULL,
  volume_mwh REAL NOT NULL,
  price_min REAL,
  price_max REAL,
  delivery_date TEXT,
  delivery_point TEXT,
  market_type TEXT DEFAULT 'bilateral' CHECK (market_type IN ('bilateral','exchange','spot','derivatives')),
  status TEXT DEFAULT 'open' CHECK (status IN ('open','matched','partial','cancelled','expired','closed')),
  parent_order_id TEXT REFERENCES trade_orders(id),
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
, remaining_volume_mwh REAL, price REAL, order_type TEXT DEFAULT 'limit', post_only INTEGER NOT NULL DEFAULT 0, reduce_only INTEGER NOT NULL DEFAULT 0, stop_trigger_price REAL, display_size_mwh REAL, amend_count INTEGER NOT NULL DEFAULT 0, good_till TEXT, posted_at TEXT, time_in_force TEXT, shard_key TEXT, external_ref TEXT);

CREATE TABLE trader_algo_rules (
      id TEXT PRIMARY KEY,
      trader_id TEXT NOT NULL,
      name TEXT NOT NULL,
      side TEXT NOT NULL CHECK (side IN ('buy','sell')),
      energy_type TEXT,
      trigger_below REAL,
      trigger_above REAL,
      size_mwh REAL NOT NULL,
      enabled INTEGER NOT NULL DEFAULT 1,
      last_fired_at TEXT,
      created_at TEXT DEFAULT (datetime('now')),
      updated_at TEXT DEFAULT (datetime('now'))
    );

CREATE TABLE trader_csa_terms (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  counterparty_id TEXT,
  counterparty_name TEXT NOT NULL,
  csa_version     TEXT,
  threshold_zar   REAL,
  independent_amount_zar REAL,
  minimum_transfer_zar REAL,
  eligible_collateral TEXT,                          
  haircut_pct     REAL,
  rounding_zar    REAL,
  base_currency   TEXT DEFAULT 'ZAR',
  governing_law   TEXT,
  status          TEXT DEFAULT 'active' CHECK (status IN ('drafting','signed','active','suspended','terminated')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE trader_hedging_strategies (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  strategy_name   TEXT NOT NULL,
  strategy_type   TEXT NOT NULL CHECK (strategy_type IN ('forward_match','option_collar','swap','swaption','spread','calendar')),
  underlying_exposure_mwh REAL,
  hedge_ratio_pct REAL,
  cost_zar        REAL,
  expected_savings_zar REAL,
  effectiveness_pct REAL,
  start_date      TEXT,
  end_date        TEXT,
  status          TEXT DEFAULT 'proposed' CHECK (status IN ('proposed','approved','active','unwound','expired')),
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE trader_options_positions (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  contract_type   TEXT NOT NULL CHECK (contract_type IN ('european_call','european_put','asian_call','asian_put','swap')),
  underlying      TEXT NOT NULL,                     
  side            TEXT NOT NULL CHECK (side IN ('long','short')),
  strike_zar_per_mwh REAL,
  expiry_date     TEXT,
  volume_mwh      REAL,
  premium_zar     REAL,
  underlying_price_zar REAL,
  implied_vol_pct REAL,
  delta           REAL,
  gamma           REAL,
  vega            REAL,
  theta           REAL,
  mtm_zar         REAL,
  status          TEXT DEFAULT 'open' CHECK (status IN ('open','exercised','expired','closed','assigned')),
  counterparty    TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE trader_pnl_attribution (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  as_of_date      TEXT NOT NULL,
  book            TEXT,                              
  
  realised_pnl_zar REAL DEFAULT 0,
  unrealised_pnl_zar REAL DEFAULT 0,
  
  delta_pnl_zar   REAL DEFAULT 0,
  gamma_pnl_zar   REAL DEFAULT 0,
  vega_pnl_zar    REAL DEFAULT 0,
  theta_pnl_zar   REAL DEFAULT 0,
  
  carry_zar       REAL DEFAULT 0,
  fees_zar        REAL DEFAULT 0,
  fx_pnl_zar      REAL DEFAULT 0,
  total_pnl_zar   REAL,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE trader_positions (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  energy_type     TEXT,
  delivery_date   TEXT,
  net_volume_mwh  REAL DEFAULT 0,
  avg_entry_price REAL,
  mark_price      REAL,
  unrealised_pnl  REAL DEFAULT 0,
  realised_pnl    REAL DEFAULT 0,
  notional        REAL DEFAULT 0,
  updated_at      TEXT DEFAULT (datetime('now')),
  UNIQUE (participant_id, energy_type, delivery_date)
);

CREATE TABLE trader_risk_limits (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  limit_type      TEXT NOT NULL CHECK (limit_type IN ('var_1d','var_10d','position','net_open_volume','tenor','counterparty','sector','concentration','stop_loss')),
  dimension       TEXT,                              
  limit_zar       REAL,
  limit_units     REAL,
  current_zar     REAL DEFAULT 0,
  current_units   REAL DEFAULT 0,
  utilisation_pct REAL,
  breached_at     TEXT,
  approved_by     TEXT,
  expires_at      TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE trader_t2_settlements (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  trade_id        TEXT,
  settlement_date TEXT NOT NULL,
  counterparty    TEXT,
  notional_zar    REAL,
  delivery_volume_mwh REAL,
  cash_leg_zar    REAL,
  physical_leg_mwh REAL,
  dvp_status      TEXT CHECK (dvp_status IN ('pending','matched','settled','failed','disputed')),
  fail_reason     TEXT,
  settled_at      TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE trader_var_calculations (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  as_of_date      TEXT NOT NULL,
  method          TEXT NOT NULL CHECK (method IN ('historical','parametric','monte_carlo')),
  horizon_days    INTEGER NOT NULL,
  confidence_pct  REAL NOT NULL,                     
  var_zar         REAL NOT NULL,
  expected_shortfall_zar REAL,
  portfolio_value_zar REAL,
  
  stress_var_zar  REAL,
  stress_scenario TEXT,
  observation_window_days INTEGER,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE universal_categories (
  code            TEXT PRIMARY KEY,
  domain          TEXT NOT NULL,                     -- 'trading','grid','ipp_project','regulator_tariff','lender_credit','offtaker_demand','climate'
  category_name   TEXT NOT NULL,
  parent_code     TEXT REFERENCES universal_categories(code),
  description     TEXT,
  display_order   INTEGER DEFAULT 0
);

CREATE TABLE universal_pathways (
  id              TEXT PRIMARY KEY,
  pathway_code    TEXT NOT NULL,                     -- 'REIPPPP_AWARDS','SA_DEMAND','JSE_LISTINGS','NPL_RATIO','SAPP_CAPACITY','REG_TARIFF_PATH'
  domain          TEXT NOT NULL CHECK (domain IN (
                    'trading','grid','ipp_project','regulator_tariff','lender_credit',
                    'offtaker_demand','climate','platform'
                  )),
  series_name     TEXT NOT NULL,                     -- 'BW1' / 'national' / 'top_40' / 'BB-rated' etc.
  year            INTEGER NOT NULL,
  value           REAL NOT NULL,
  unit            TEXT NOT NULL,
  source          TEXT,
  notes           TEXT,
  UNIQUE (pathway_code, series_name, year)
);

CREATE TABLE user_view_prefs (
  id             TEXT PRIMARY KEY,
  participant_id TEXT NOT NULL,
  tenant_id      TEXT,
  scope_key      TEXT NOT NULL,
  prefs_json     TEXT NOT NULL DEFAULT '{}',
  updated_at     TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE (participant_id, scope_key)
);

CREATE TABLE utility_bill_validations (
  id              TEXT PRIMARY KEY,
  participant_id  TEXT NOT NULL REFERENCES participants(id),
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  supplier        TEXT NOT NULL,                     -- 'Eskom','City of CT','City of JHB','City Power','eThekwini'
  account_number  TEXT,
  reading_month   TEXT NOT NULL,                     -- YYYY-MM
  billed_kwh      REAL,
  billed_amount_zar REAL,
  metered_kwh     REAL,                              -- from metering_readings
  expected_amount_zar REAL,                          -- computed from tariff schedule
  variance_kwh    REAL,
  variance_zar    REAL,
  status          TEXT DEFAULT 'pending' CHECK (status IN ('pending','validated','dispute_raised','reconciled','paid')),
  dispute_reference TEXT,
  notes           TEXT,
  created_at      TEXT DEFAULT (datetime('now'))
);

CREATE TABLE vault_files (
  id TEXT PRIMARY KEY,
  entity_type TEXT NOT NULL,
  entity_id TEXT NOT NULL,
  file_name TEXT NOT NULL,
  r2_key TEXT NOT NULL,
  mime_type TEXT,
  size_bytes INTEGER,
  uploaded_by TEXT NOT NULL REFERENCES participants(id),
  created_at TEXT DEFAULT (datetime('now'))
);

CREATE TABLE voltage_management_zones (
  id              TEXT PRIMARY KEY,
  tenant_id       TEXT DEFAULT 'default' NOT NULL,
  zone_name       TEXT NOT NULL UNIQUE,
  voltage_level_kv REAL NOT NULL,
  target_voltage_pu REAL DEFAULT 1.0,
  band_low_pu     REAL DEFAULT 0.95,
  band_high_pu    REAL DEFAULT 1.05,
  current_voltage_pu REAL,
  reactive_capability_mvar REAL,
  status          TEXT DEFAULT 'normal' CHECK (status IN ('normal','warn','breach','outage')),
  last_observed_at TEXT,
  notes           TEXT
);

CREATE TABLE waterfall_allocations (
  id TEXT PRIMARY KEY,
  run_id TEXT NOT NULL REFERENCES waterfall_runs(id) ON DELETE CASCADE,
  tranche_id TEXT NOT NULL REFERENCES waterfall_tranches(id),
  amount_allocated_zar REAL NOT NULL,
  shortfall_zar REAL DEFAULT 0,
  notes TEXT
);

CREATE TABLE waterfall_runs (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  waterfall_id TEXT NOT NULL REFERENCES waterfall_structures(id),
  period TEXT NOT NULL,                -- 'Q2-2026'
  period_start TEXT NOT NULL,
  period_end TEXT NOT NULL,
  available_cash_zar REAL NOT NULL,
  total_allocated_zar REAL,
  surplus_after_equity_zar REAL,
  status TEXT NOT NULL DEFAULT 'draft' CHECK (status IN ('draft','executed','reversed')),
  executed_at TEXT,
  executed_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE waterfall_structures (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES ipp_projects(id),
  waterfall_name TEXT NOT NULL,
  effective_from TEXT NOT NULL,
  effective_to TEXT,
  created_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE waterfall_tranches (
  id TEXT PRIMARY KEY,
  waterfall_id TEXT NOT NULL REFERENCES waterfall_structures(id) ON DELETE CASCADE,
  priority INTEGER NOT NULL,           -- 1 = first to be paid
  tranche_name TEXT NOT NULL,
  tranche_type TEXT NOT NULL CHECK (tranche_type IN (
    'opex','tax','senior_interest','senior_principal','dsra','mra','mezzanine','subordinated','equity_distribution','other'
  )),
  target_account_id TEXT,              -- REFERENCES reserve_accounts(id) when applicable
  notes TEXT
);

CREATE TABLE zone_loss_factors (
  id TEXT PRIMARY KEY,
  zone_code TEXT NOT NULL REFERENCES nodal_zones(code),
  effective_month TEXT NOT NULL,    -- YYYY-MM
  loss_factor_pct REAL NOT NULL,    -- e.g. 4.2 = 4.2%
  methodology TEXT,                 -- 'measured','forecast','average_system_loss'
  approved BOOLEAN DEFAULT 0,
  approved_by TEXT REFERENCES participants(id),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE INDEX idx_action_queue_status ON action_queue(status);

CREATE INDEX idx_activities_critical ON project_activities(project_id, is_critical);

CREATE INDEX idx_activities_parent  ON project_activities(parent_id);

